-- Poems batch 70
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b8f4fd23-1f91-4da9-88ef-785b1690dc80','宿大通和尚塔敬贈如上人兼呈常孫二山人','崔曙','唐','唐诗','tang','','[]','支公已寂滅，影塔山上古。',108,'全唐诗/poet.tang.7000.json','["支公已寂滅，影塔山上古。", "更有真僧來，道場救諸苦。", "一承微妙法，寓宿清淨土。", "身心能自觀，色相了無取。", "森森松映月，漠漠雲近戶。", "嶺外飛電明，夜來前山雨。", "然燈見栖鴿，作禮聞信鼓。", "曉霽南軒開，秋華淨天宇。", "願言出世塵，謝爾申及甫。"]'),
('ad5c16d6-cff3-4035-b338-9704f8f5ffea','送薛據之宋州','崔曙','唐','唐诗','tang','','[]','無媒嗟失路，有道亦乘流。',72,'全唐诗/poet.tang.7000.json','["無媒嗟失路，有道亦乘流。", "客處不堪別，異鄉應共愁。", "我生早孤賤，淪落居此州。", "風土至今憶，山河皆昔遊。", "一從文章事，兩京春復秋。", "君去問相識，幾人今白頭。"]'),
('e94c1fc4-e2f5-4640-8b14-38a4b0fef786','山下晚晴','崔曙','唐','唐诗','tang','','[]','寥寥遠天淨，谿路何空濛。',48,'全唐诗/poet.tang.7000.json','["寥寥遠天淨，谿路何空濛。", "斜光照疎雨，秋氣生白虹。", "雲盡山色暝，蕭條西北風。", "故林歸宿處，一葉下梧桐。"]'),
('f7425804-a6da-42c7-9e0a-bc12a48bbf78','潁陽東溪懷古','崔曙','唐','唐诗','tang','','[]','靈溪氛霧歇，皎鏡清心顏。',72,'全唐诗/poet.tang.7000.json','["靈溪氛霧歇，皎鏡清心顏。", "空色不映水，秋聲多在山。", "世人久疎曠，萬物皆自閑。", "白鷺寒更浴，孤雲晴未還。", "昔時讓王者，此地閉玄關。", "無以躡高步，淒涼岑壑間。"]'),
('0f690d2c-30f7-4813-a32f-e78c2ff0e39d','早發交崖山還太室作','崔曙','唐','唐诗','tang','','[]','東林氣微白，寒鳥急高翔。',84,'全唐诗/poet.tang.7000.json','["東林氣微白，寒鳥急高翔。", "吾亦自茲去，北山歸草堂。", "仲冬正三五，日月遙相望。", "蕭蕭過潁上，曨曨辨少陽。", "川冰生積雪，野火出枯桑。", "獨往路難盡，窮陰人易傷。", "傷此無衣客，如何蒙雪霜。"]'),
('cd77a627-ff6a-4e92-a9d7-ed882a4cf979','奉試明堂火珠','崔曙','唐','唐诗','tang','','[]','正位開重屋，凌空出火珠。',48,'全唐诗/poet.tang.7000.json','["正位開重屋，凌空出火珠。", "夜來雙月滿，曙後一星孤。", "天淨光難滅，雲生望欲無。", "遙知太平代，國寶在名都。"]'),
('03c631e1-3f98-4c76-9b80-30cd40017982','途中曉發','崔曙','唐','唐诗','tang','','[]','曉霽長風裏，勞歌赴遠期。',48,'全唐诗/poet.tang.7000.json','["曉霽長風裏，勞歌赴遠期。", "雲輕歸海疾，月滿下山遲。", "旅望因高盡，鄉心遇物悲。", "故林遙不見，況在落花時。"]'),
('e7cc2b53-bf50-4166-9133-c27a4df28790','緱山廟','崔曙','唐','唐诗','tang','','[]','遺廟宿陰陰，孤峰映綠林。',48,'全唐诗/poet.tang.7000.json','["遺廟宿陰陰，孤峰映綠林。", "步隨仙路遠，意入道門深。", "澗水流年月，山雲變古今。", "祗聞風竹裏，猶有鳳笙音。"]'),
('edb61e96-1ead-4897-8dc0-951a7ac9f9cc','同諸公謁啓母祠','崔曙','唐','唐诗','tang','','[]','閟宮凌紫微，芳草閉閑扉。',48,'全唐诗/poet.tang.7000.json','["閟宮凌紫微，芳草閉閑扉。", "帝子復何在，王孫遊不歸。", "春風鳴玉珮，暮雨拂靈衣。", "豈但湘江口，能令懷二妃。"]'),
('1c1d545e-07a1-46a9-bb76-b7473c1fde43','九日登望仙臺呈劉明府容','崔曙','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u666f", "\u767b\u9ad8", "\u91cd\u9633\u8282"]','漢文皇帝有高臺，此日登臨曙色開。',64,'全唐诗/poet.tang.7000.json','["漢文皇帝有高臺，此日登臨曙色開。", "三晉雲山皆北向，二陵風雨自東來。", "關門令尹誰能識，河上仙翁去不回。", "且欲近尋彭澤宰，陶然共醉菊花杯。"]'),
('7c4604a8-beff-415e-b150-daa58ba9ee1d','奉酬中書相公至日圓丘攝事合於中書後閣宿齋移止于集賢院敘懷見寄之作','崔曙','唐','唐诗','tang','','[]','典籍開書府，恩榮避鼎司。',72,'全唐诗/poet.tang.7000.json','["典籍開書府，恩榮避鼎司。", "郊丘資有事，齋戒守無爲。", "宿霧蒙瓊樹，餘香覆玉墀。", "進經逢乙夜，展禮值明時。", "勳共山河列，名同竹帛垂。", "年年佐堯舜，相與致雍熙。"]'),
('08548e78-98b8-4fec-83fe-eefedf6d9615','登水門樓見亡友張貞期題望黃河詩因以感興','崔曙','唐','唐诗','tang','','["\u9ec4\u6cb3"]','吾友東南美，昔聞登此樓。',96,'全唐诗/poet.tang.7000.json','["吾友東南美，昔聞登此樓。", "人隨川上逝，書向壁中留。", "嚴子好真隱，謝公耽遠遊。", "清風初作頌，暇日復銷憂。", "時與文字古，跡將山水幽。", "已孤蒼生望，空見黃河流。", "流落年將晚，悲涼物已秋。", "天高不可問，掩泣赴行舟。"]'),
('5e676e2a-b562-4437-a8b6-2fc58e7556a2','對雨送鄭陵','崔曙','唐','唐诗','tang','','[]','別愁復經雨，別淚還如霰。',24,'全唐诗/poet.tang.7000.json','["別愁復經雨，別淚還如霰。", "寄心海上雲，千里常相見。"]'),
('485ba22a-9f18-4dba-9d39-5c295a9b96d1','嵩山尋馮鍊師不遇','崔曙','唐','唐诗','tang','','[]','青溪訪道凌煙曙，王子仙成已飛去。',32,'全唐诗/poet.tang.7000.json','["青溪訪道凌煙曙，王子仙成已飛去。", "更值空山雷雨時，雲林薄暮歸何處。"]'),
('b03d66f2-b572-48b6-b048-a2bb781bc8b3','贈唐祖二子','王翰','唐','唐诗','tang','','[]','鴻飛遵枉渚，鹿鳴思故羣。',72,'全唐诗/poet.tang.7000.json','["鴻飛遵枉渚，鹿鳴思故羣。", "物情尚勞愛，況乃予別君。", "別時花始發，別後蘭再薰。", "瑤觴滋白露，寶瑟凝涼氛。", "裴徊北林月，悵望南山雲。", "雲月渺千里，音徽不可聞。"]'),
('8bd374be-35e5-45da-a300-9c8ef608005b','飛燕篇','王翰','唐','唐诗','tang','','[]','孝成皇帝本嬌奢，行幸平陽公主家。',240,'全唐诗/poet.tang.7000.json','["孝成皇帝本嬌奢，行幸平陽公主家。", "可憐女兒三五許，䒠茸惜是一園花。", "歌舞向來人不貴，一旦逢君感君意。", "君心見賞不見忘，姊妹雙飛入紫房。", "紫房綵女不得見，專榮固寵昭陽殿。", "紅妝寶鏡珊瑚臺，青瑣銀簧雲母扇。", "日夕風傳歌舞聲，祗擾長信憂人情。", "長信憂人氣欲絕，君王歌吹終不歇。", "朝弄瓊簫下綵雲，夜踏金梯上明月。", "明月薄蝕陽精昏，嬌妬傾城惑至尊。", "已見白虹橫紫極，復聞飛燕啄皇孫。", "皇孫不死燕啄折，女弟一朝如火絕。", "明明天子咸戒之，赫赫宗周襃姒滅。", "古來賢聖歎狐裘，一國荒淫萬國羞。", "安得上方斷馬劒，斬取朱門公子頭。"]'),
('6df299f8-0563-4612-9b09-65bc84221874','飲馬長城窟行','王翰','唐','唐诗','tang','','[]','長安少年無遠圖，一生惟羨執金吾。',224,'全唐诗/poet.tang.7000.json','["長安少年無遠圖，一生惟羨執金吾。", "麒麟前殿拜天子，走馬西擊長城胡。", "胡沙獵獵吹人面，漢虜相逢不相見。", "遙聞鼙鼓動地來，傳道單于夜猶戰。", "此時顧恩寧顧身，爲君一行摧萬人。", "壯士揮戈迴白日，單于濺血染朱輪。", "歸來飲馬長城窟，長城道傍多白骨。", "問之耆老何代人，云是秦王築城卒。", "黃昏塞北無人煙，鬼哭啾啾聲沸天。", "無罪見誅功不賞，孤魂流落此城邊。", "當昔秦王按劒起，諸侯膝行不敢視。", "富國强兵二十年，築怨興徭九千里。", "秦王築城何太愚，天實亡秦非北胡。", "一朝禍起蕭墻內，渭水咸陽不復都。"]'),
('a831474d-8c73-428b-9057-2c153a7111e1','賦得明星玉女壇送廉察尉華陰','王翰','唐','唐诗','tang','','[]','洪河之南曰秦鎮，發地削成五千仞。',208,'全唐诗/poet.tang.7000.json','["洪河之南曰秦鎮，發地削成五千仞。", "三峰離地皆倚天，唯獨中峰特修峻。", "上有明星玉女祠，祠壇高眇路逶迤。", "三十六梯入河漢，樵人往往見蛾眉。", "蛾眉嬋娟又宜笑，一見樵人下靈廟。", "仙車欲駕五雲飛，香扇斜開九華照。", "含情遲佇惜韶年，願侍君邊復中旋。", "江妃玉佩留爲念，嬴女銀簫空自憐。", "仙俗途殊兩情遽，感君無盡辭君去。", "遙見明星是妾家，風飄雪散不知處。", "故人家在西長安，賣藥往來投此山。", "綵雲蕩漾不可見，綠蘿蒙茸鳥綿蠻。", "欲求玉女長生法，日夜燒香應自還。"]'),
('bf841960-0678-4df4-bae7-88c855490346','春女行','王翰','唐','唐诗','tang','','[]','紫臺穹跨連綠波，紅軒鉿匝垂纖羅。',99,'全唐诗/poet.tang.7000.json','["紫臺穹跨連綠波，紅軒鉿匝垂纖羅。", "中有一人金作面，隔幌玲瓏遙可見。", "忽聞黃鳥鳴且悲，鏡邊含笑著春衣。", "羅袖嬋娟似無力，行拾落花比容色。", "落花一度無再春，人生作樂須及辰。", "君不見楚王臺上紅顏子，今日皆成狐兔塵。"]'),
('6dff6090-a3e1-4305-a186-fad81d1900a1','古娥眉怨','王翰','唐','唐诗','tang','','[]','君不見宜春苑中九華殿，飛閣連連直如髮。',323,'全唐诗/poet.tang.7000.json','["君不見宜春苑中九華殿，飛閣連連直如髮。", "白日全含朱鳥窓，流雲半入蒼龍闕。", "宮中綵女夜無事，學鳳吹簫弄清越。", "珠簾北卷待涼風，繡戶南開向明月。", "忽聞天子憶蛾眉，寶鳳銜花揲兩螭。", "傳聲走馬開金屋，夾路鳴環上玉墀。", "長樂彤庭宴華寢，三千美人曳花錦。", "燈前含笑更羅衣，帳裏承恩薦瑤枕。", "不意君心半路迴，求仙別作望仙臺。", "琳琅禁闥遙相憶，紫翠巖房晝不開。", "欲向人間種桃實，先從海底覓蓬萊。", "蓬來可求不可上，孤舟飄緲知何往。", "黃金作盤銅作莖，青天白露掌中擎。", "王母嫣然感君意，雲車羽斾欲相迎。", "飛廉觀前空怨慕，少君何事須相誤。", "一朝埋沒茂陵田，賤妾蛾眉不重顧。", "宮車晚出向南山，仙衛逶迤去不還。", "朝晡泣對麒麟樹，樹下蒼苔日漸斑。", "人生百年夜將半，對酒長歌莫長歎。", "情知白日不可私，一死一生何足筭。"]'),
('57dfd427-2780-4ac6-bb44-3cc39dc202c4','子夜春歌','王翰','唐','唐诗','tang','','[]','春氣滿林香，春遊不可忘。',48,'全唐诗/poet.tang.7000.json','["春氣滿林香，春遊不可忘。", "落花吹欲盡，垂柳折還長。", "桑女淮南曲，金鞍塞北裝。", "行行小垂手，日暮渭川陽。"]'),
('f816fb7e-029f-4c24-a1e2-37adee7fc431','奉和聖製同二相已下羣官樂遊園宴','王翰','唐','唐诗','tang','','[]','未極人心暢，如何帝道明。',72,'全唐诗/poet.tang.7000.json','["未極人心暢，如何帝道明。", "仍嫌酺宴促，復寵樂遊行。", "陸海披珍藏，天河直斗城。", "四關青靄合，數處白雲生。", "飪餗調元氣，歌鐘溢雅聲。", "空慚堯舜日，至德杳難名。"]'),
('f3a8ecd8-09e9-42c3-98c0-015f1d2a7460','奉和聖製送張說上集賢院學士賜宴得筵字','王翰','唐','唐诗','tang','','[]','東堂起集賢，貴得從神仙。',72,'全唐诗/poet.tang.7000.json','["東堂起集賢，貴得從神仙。", "首命台階老，將崇御府員。", "送人鏘玉佩，中使拂瓊筵。", "和樂薰風解，湛恩時雨連。", "長材成磊落，短翮強翩翾。", "徒仰蓬萊地，何階不讓緣。"]'),
('72c72ad2-c3e0-4f21-a419-af79d6dd0f42','奉和聖製送張尚書巡邊','王翰','唐','唐诗','tang','','[]','紫綬尚書印，朱軿丞相車。',120,'全唐诗/poet.tang.7000.json','["紫綬尚書印，朱軿丞相車。", "登朝身許國，出閫將辭家。", "不憚炎蒸苦，親嘗走集賒。", "選徒軍有政，誓卒爾無譁。", "帝樂風初起，王城日半斜。", "寵行流聖作，寅餞照台華。", "騎歷河南樹，旌搖塞北沙。", "榮懷應盡服，嚴殺已先加。", "業峻靈祇保，功成道路嗟。", "寧如鑿空使，遠致石榴花。"]'),
('0445f296-5816-4ab9-a617-7d8ed29088ea','涼州詞二首 一','王翰','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8c6a\u653e", "\u6218\u4e89", "\u8fb9\u585e", "\u5bb4\u996e", "\u4e03\u8a00\u7edd\u53e5"]','葡萄美酒夜光杯，欲飲琵琶馬上催。',32,'全唐诗/poet.tang.7000.json','["葡萄美酒夜光杯，欲飲琵琶馬上催。", "醉臥沙場君莫笑，古來征戰幾人回。"]'),
('1e1b5f1d-d2f5-4a30-afd6-993138cf3d99','涼州詞二首 二','王翰','唐','唐诗','tang','','[]','秦中花鳥已應闌，塞外風沙猶自寒。',32,'全唐诗/poet.tang.7000.json','["秦中花鳥已應闌，塞外風沙猶自寒。", "夜聽胡笳折楊柳，教人意氣憶長安。"]'),
('32d6625b-267a-4a59-8f76-14a4dc97d81f','春日歸思','王翰','唐','唐诗','tang','','[]','楊柳青青杏發花，年光誤客轉思家。',32,'全唐诗/poet.tang.7000.json','["楊柳青青杏發花，年光誤客轉思家。", "不知湖上菱歌女，幾箇春舟在若耶。"]'),
('36517bbc-becc-468f-a76c-082916a9a54c','觀蠻童爲伎之作','王翰','唐','唐诗','tang','','[]','長裙錦帶還留客，廣額青蛾亦效嚬。',32,'全唐诗/poet.tang.7000.json','["長裙錦帶還留客，廣額青蛾亦效嚬。", "共惜不成金谷妓，虛令看殺玉車人。"]'),
('7b25786a-bf83-4daf-b91a-2c7cb81a2bbf','古別離','孟雲卿','唐','唐诗','tang','','[]','朝日上高臺，離人怨秋草。',108,'全唐诗/poet.tang.7000.json','["朝日上高臺，離人怨秋草。", "但見萬里天，不見萬里道。", "君行本迢遠，苦樂良難保。", "宿昔夢同衾，憂心常傾倒。", "含酸欲誰訴，展轉傷懷抱。", "結髮年已遲，征行去何早。", "寒暄有時謝，憔悴難再好。", "人皆算年壽，死者何曾老。", "少壯無見期，水深風浩浩。"]'),
('bd79b598-a286-4537-86aa-567050db4b32','今別離','孟雲卿','唐','唐诗','tang','','[]','結髮生別離，相思復相保。',96,'全唐诗/poet.tang.7000.json','["結髮生別離，相思復相保。", "如何日已久，五變庭中草。", "渺渺大海途，悠悠吳江島。", "但恐不出門，出門無遠道。", "遠道行既難，家貧衣復單。", "嚴風吹積雪，晨起鼻何酸。", "人生各有志，豈不懷所安。", "分明天上日，生死願同歡。"]'),
('0d050f7f-de64-400b-bec5-9240432d51ea','悲哉行','孟雲卿','唐','唐诗','tang','','[]','孤兒去慈親，遠客喪主人。',84,'全唐诗/poet.tang.7000.json','["孤兒去慈親，遠客喪主人。", "莫吟苦辛曲，此曲誰忍聞。", "可聞不可說，去去無期別。", "行人念前程，不待參辰沒。", "朝亦常苦饑，暮亦常苦饑。", "飄飄萬餘里，貧賤多是非。", "少年莫遠遊，遠遊多不歸。"]'),
('1b56a6d9-e90b-4091-8bdb-5529af3b238b','行行且遊獵篇','孟雲卿','唐','唐诗','tang','','[]','少年多武力，勇氣冠幽州。',96,'全唐诗/poet.tang.7000.json','["少年多武力，勇氣冠幽州。", "何以縱心賞，馬啼春草頭。", "遲遲平原上，狐兔奔林丘。", "猛虎忽前逝，俊鷹連下韝。", "俯身逐南北，輕捷固難儔。", "所發無不中，失之如我讐。", "豈唯務馳騁，猗爾暴田疇。", "殘殺非不痛，古來良有由。"]'),
('ba56c4b7-e9a9-4a72-8ddd-dc34ea1e1961','古挽歌','孟雲卿','唐','唐诗','tang','','[]','草草閭巷喧，塗車儼成位。',96,'全唐诗/poet.tang.7000.json','["草草閭巷喧，塗車儼成位。", "冥冥何所須，盡我生人意。", "北邙路非遠，此別終天地。", "臨穴頻撫棺，至哀反無淚。", "爾形未衰老，爾息纔童稚。", "骨肉安可離，皇天若容易。", "房帷即靈帳，庭宇爲哀次。", "薤露歌若斯，人生盡如寄。"]'),
('e638e332-fb02-4328-9c30-c3f581dfa454','放歌行','孟雲卿','唐','唐诗','tang','','[]','吾觀天地圖，世界亦可小。',96,'全唐诗/poet.tang.7000.json','["吾觀天地圖，世界亦可小。", "落落大海中，飄浮數洲島。", "賢愚與蟻蝨，一種同草草。", "地脉日夜流，天衣有時掃。", "東山謁居士，了我生死道。", "目見難噬臍，心通可親腦。", "軒皇竟磨滅，周孔亦衰老。", "永謝當時人，吾將寶非寶。"]'),
('c419cafd-6b8b-4ebe-8e3a-eb3d9c300e89','傷懷贈故人','孟雲卿','唐','唐诗','tang','','[]','稍稍晨鳥翔，淅淅草上霜。',108,'全唐诗/poet.tang.7000.json','["稍稍晨鳥翔，淅淅草上霜。", "人生早罹苦，壽命恐不長。", "二十學已成，三十名不彰。", "豈無同門友，貴賤易中腸。", "驅馬行萬里，悠悠過帝鄉。", "幸因弦歌末，得上君子堂。", "衆樂互喧奏，獨子備笙簧。", "坐中無知音，安得神揚揚。", "願因高風起，上感白日光。"]'),
('c452f516-2d49-4161-b25c-16be79f1ced1','鄴城懷古','孟雲卿','唐','唐诗','tang','','[]','朝發淇水南，將尋北燕路。',144,'全唐诗/poet.tang.7000.json','["朝發淇水南，將尋北燕路。", "魏家舊城闕，寥落無人住。", "伊昔天地屯，曹公獨中據。", "羣臣將北面，白日忽西暮。", "三臺竟寂寞，萬事良難固。", "雄圖安在哉？衰草霑霜露。", "崔嵬長河北，尚見應劉墓。", "古樹藏龍蛇，荒茅伏狐兔。", "永懷故池館，數子連章句。", "逸興驅山河，雄詞變雲霧。", "我行覩遺跡，精爽如可遇。", "斗酒將酹君，悲風白楊樹。"]'),
('9826bcc6-6fe2-40c9-b66a-6ce210b19d28','傷情','孟雲卿','唐','唐诗','tang','','[]','爲長心易憂，早孤意常傷。',108,'全唐诗/poet.tang.7000.json','["爲長心易憂，早孤意常傷。", "出門先躊躇，入戶亦彷徨。", "此生一何苦，前事安可忘。", "兄弟先我沒，孤幼盈我傍。", "舊居近東南，河水新爲梁。", "松柏今在茲，安忍思故鄉。", "四時與日月，萬物各有常。", "秋風已一起，草木無不霜。", "行行當自勉，不忍再思量。"]'),
('80047e73-5f6d-4e7e-928c-568f73f57ef7','傷時二首 一','孟雲卿','唐','唐诗','tang','','[]','徘回宋郊上，不覩平生親。',60,'全唐诗/poet.tang.7000.json','["徘回宋郊上，不覩平生親。", "獨立正傷心，悲風來孟津。", "大方載羣物，生死有常倫。", "虎豹不相食，哀哉人食人。", "豈伊逢世運，天道亮云云。"]'),
('455b06e6-ffa2-4cca-a754-32053f519790','傷時二首 二','孟雲卿','唐','唐诗','tang','','[]','太空流素月，三五何明明。',48,'全唐诗/poet.tang.7000.json','["太空流素月，三五何明明。", "光耀侵白日，賢愚迷至精。", "四時更變化，天道有虧盈。", "常恐今夜沒，須臾還復生。"]'),
('c978518f-34af-4bf0-b02d-77117a93b41b','田園觀雨兼晴後作','孟雲卿','唐','唐诗','tang','','[]','貧賤少情欲，借荒種南陂。',96,'全唐诗/poet.tang.7000.json','["貧賤少情欲，借荒種南陂。", "我非老農圃，安得良土宜。", "秋成不廉儉，歲餘多餒飢。", "顧視倉廩間，有糧不成炊。", "晨登南園上，暮歇清蟬悲。", "早苗既芃芃，晚田尚離離。", "五行孰堪廢，萬物當及時。", "賢哉數夫子，開翅慎勿遲。"]'),
('1c5ec906-b520-4e83-a9ce-e2187e78aaf1','汴河阻風','孟雲卿','唐','唐诗','tang','','[]','清晨自梁宋，挂席之楚荆。',96,'全唐诗/poet.tang.7000.json','["清晨自梁宋，挂席之楚荆。", "出浦風漸惡，傍灘舟欲橫。", "大河噴東注，羣動皆窅冥。", "白霧魚龍氣，黑雲牛馬形。", "蒼茫迷所適，危安懼暫寧。", "信此天地內，孰爲身命輕。", "丈夫苟未達，所向須存誠。", "前路捨舟去，東南仍曉晴。"]'),
('cb137725-18d9-4ebc-b1e5-4d31b7f1c6f5','行路難','孟雲卿','唐','唐诗','tang','','[]','君不見高山萬仞連蒼旻，天長地久成埃塵。',96,'全唐诗/poet.tang.7000.json','["君不見高山萬仞連蒼旻，天長地久成埃塵。", "君不見長松百尺多勁節，狂風暴雨終摧折。", "古今何事無聖賢，吾愛伯陽真乃天。", "金堂玉闕朝羣仙，拍手東海成桑田。", "海中之水慎勿枯，烏鳶啄蚌傷明珠。", "行路難，艱險莫踟躕。"]'),
('4b2b9b23-4d14-49e9-974f-21f7d2ec4eb8','途中寄友人','孟雲卿','唐','唐诗','tang','','[]','昔時聞遠路，謂是等閑行。',48,'全唐诗/poet.tang.7000.json','["昔時聞遠路，謂是等閑行。", "及到求人地，始知爲客情。", "事將公道背，塵遶馬蹄生。", "儻使長如此，便堪休去程。"]'),
('27cb30cd-7b65-4922-8262-40dec810f252','寒食','孟雲卿','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u601d\u4e61"]','二月江南花滿枝，他鄉寒食遠堪悲。',32,'全唐诗/poet.tang.7000.json','["二月江南花滿枝，他鄉寒食遠堪悲。", "貧居往往無煙火，不獨明朝爲子推。"]'),
('e0c912ba-782a-41a0-a759-20475a8c900e','新安江上寄處士','孟雲卿','唐','唐诗','tang','','[]','深潭與淺灘，萬轉出新安。',48,'全唐诗/poet.tang.7000.json','["深潭與淺灘，萬轉出新安。", "人遠禽魚靜，山空水木寒。", "嘯起青蘋末，吟矚白雲端。", "即事遂幽賞，何必挂儒冠。"]'),
('7babe6fc-4b31-4d3e-a946-eb2a178aab48','句','孟雲卿','唐','唐诗','tang','','[]','羣物歸大化，六龍頹西荒。',24,'全唐诗/poet.tang.7000.json','["羣物歸大化，六龍頹西荒。", "安知浮雲外，日月不運行。"]'),
('68f1a2ad-96f1-4a34-81d8-d6f6aa802ca8','聞笛','張巡','唐','唐诗','tang','','["\u6218\u4e89"]','岧嶤試一臨，虜騎附城陰。',48,'全唐诗/poet.tang.7000.json','["岧嶤試一臨，虜騎附城陰。", "不辨風塵色，安知天地心。", "營開邊月近，戰苦陣雲深。", "旦夕更樓上，遙聞橫笛音。"]'),
('6fbf07e9-1484-408d-aa48-108b34d89d3f','守睢陽作','張巡','唐','唐诗','tang','','[]','接戰春來苦，孤城日漸危。',72,'全唐诗/poet.tang.7000.json','["接戰春來苦，孤城日漸危。", "合圍侔月暈，分守若魚麗。", "屢厭黃塵起，時將白羽揮。", "裹瘡猶出陣，飲血更登陴。", "忠信應難敵，堅貞諒不移。", "無人報天子，心計欲何施。"]'),
('8d83271c-bc30-44a1-9826-964884c42856','題衡陽泗州寺','張抃','唐','唐诗','tang','','[]','一水悠悠百粵通，片帆無奈信秋風。',64,'全唐诗/poet.tang.7000.json','["一水悠悠百粵通，片帆無奈信秋風。", "幾層峽浪寒舂月，盡日江天雨打篷。", "漂泊漸搖青草外，鄉關誰念雪園東。", "未知今夜依何處，一點漁燈出葦叢。"]'),
('a987fa09-4041-457f-9d3e-d9fd4b064c27','古意二首 一','賀蘭進明','唐','唐诗','tang','','[]','秦庭初指鹿，羣盜滿山東。',48,'全唐诗/poet.tang.7000.json','["秦庭初指鹿，羣盜滿山東。", "忤意皆誅死，所言誰肯忠。", "武關猶未啓，兵入望夷宮。", "爲祟非涇水，人君道自窮。"]'),
('88cb82da-e206-4a9c-a216-6de0aae0d585','古意二首 二','賀蘭進明','唐','唐诗','tang','','[]','崇蘭生澗底，香氣滿幽林。',48,'全唐诗/poet.tang.7000.json','["崇蘭生澗底，香氣滿幽林。", "采采欲爲贈，何人是同心。", "日暮徙盈把，裴回憂思深。", "慨然紉雜佩，重奏丘中琴。"]'),
('7eb0ae68-c481-4148-a41a-a9f82ba0fd75','行路難五首 一','賀蘭進明','唐','唐诗','tang','','[]','君不見巖下井，百尺不及泉。',74,'全唐诗/poet.tang.7000.json','["君不見巖下井，百尺不及泉。", "君不見山上苗，數寸凌雲煙。", "人生賦命亦如此，何苦太息自憂煎。", "但願親友長含笑，相逢不乏杖頭錢。", "寒夜邀歡須秉燭，豈得常思花柳年。"]'),
('d74cc8a9-b5d5-4fb8-8856-d67dc95efea5','行路難五首 二','賀蘭進明','唐','唐诗','tang','','[]','君不見門前柳，榮耀暫時蕭索久。',62,'全唐诗/poet.tang.7000.json','["君不見門前柳，榮耀暫時蕭索久。", "君不見陌上花，狂風吹去落誰家。", "鄰家思婦見之歎，蓬首不梳心歷亂。", "盛年夫壻長別離，歲暮相逢色已換。"]'),
('ff6eeeae-4e01-426e-90b8-98391b05ec77','行路難五首 三','賀蘭進明','唐','唐诗','tang','','[]','君不見芳樹枝，春花落盡蜂不窺。',64,'全唐诗/poet.tang.7000.json','["君不見芳樹枝，春花落盡蜂不窺。", "君不見梁上泥，秋風始高燕不棲。", "蕩子從軍事征戰，[蛾]眉嬋娟守空閨。", "獨宿自然堪下淚，況復時聞烏夜啼。"]'),
('c72c21de-0a00-4df5-816a-6972aefbb823','行路難五首 四','賀蘭進明','唐','唐诗','tang','','[]','君不見雲中月，暫盈還復缺。',58,'全唐诗/poet.tang.7000.json','["君不見雲中月，暫盈還復缺。", "君不見林下風，聲遠意難窮。", "親故平生或聚散，歡娛未盡尊酒空。", "歎息青青陵上柏，歲寒能有幾人同。"]'),
('31391108-7664-4329-8f46-3e5c3b1cf7f7','行路難五首 五','賀蘭進明','唐','唐诗','tang','','[]','君不見東流水，一去無窮已。',58,'全唐诗/poet.tang.7000.json','["君不見東流水，一去無窮已。", "君不見西郊雲，日夕空氛氳。", "羣鴈裴回不能去，一鴈悲鳴復失羣。", "人生結交在終始，莫以升沈中路分。"]'),
('4bdce47b-964e-4ec9-96e3-5bee4552ab64','夜渡江','閭丘曉','唐','唐诗','tang','','[]','舟人自相報，落日下芳潭。',48,'全唐诗/poet.tang.7000.json','["舟人自相報，落日下芳潭。", "夜火連淮市，春風滿客帆。", "水窮滄海畔，路盡小山南。", "且喜鄉園近，言榮意未甘。"]'),
('0a84422b-f228-4263-8d6f-281b1606d605','奉和劉採訪縉雲南嶺作','庾光先','唐','唐诗','tang','','[]','百越城池枕海圻，永嘉山水復相依。',64,'全唐诗/poet.tang.7000.json','["百越城池枕海圻，永嘉山水復相依。", "懸蘿弱篠垂清淺，宿雨朝暾和翠微。", "鳥訝山經傳不盡，花隨月令數仍稀。", "幸陪謝客題詩句，誰與王孫此地歸。"]'),
('052679c2-9971-417f-b6d9-368e9c711569','思歸寄東林澈上人','韋丹','唐','唐诗','tang','','[]','王事紛紛無暇日，浮生冉冉只如雲。',32,'全唐诗/poet.tang.7000.json','["王事紛紛無暇日，浮生冉冉只如雲。", "已爲平子歸休計，五老巖前必共聞。"]'),
('3c53bea4-f8a0-44f0-8447-e82dfded884b','荅澈公','韋丹','唐','唐诗','tang','','[]','空山泉落松窗靜，閑地草生春日遲。',32,'全唐诗/poet.tang.7000.json','["空山泉落松窗靜，閑地草生春日遲。", "白髮漸多身未退，依依常在永禪師。"]'),
('89a9c38f-b828-4040-9171-69df1e94080c','洛出書','蕭昕','唐','唐诗','tang','','[]','海內昔凋瘵，天網斯浡潏。',72,'全唐诗/poet.tang.7000.json','["海內昔凋瘵，天網斯浡潏。", "龜靈啓聖圖，龍馬負書出。", "大哉明德盛，遠矣彝倫秩。", "地敷作乂功，人免爲魚恤。", "既彰千國理，豈止百川溢。", "永賴至於今，疇庸未云畢。"]'),
('04fa3d61-2d66-45a5-82a5-44c92cdf29e8','臨風舒錦','蕭昕','唐','唐诗','tang','','[]','麗錦疋云終，襜襜展向風。',72,'全唐诗/poet.tang.7000.json','["麗錦疋云終，襜襜展向風。", "花開翻覆翠，色亂動搖紅。", "縷散悠揚裏，文迴照灼中。", "低垂疑步障，吹起作晴虹。", "既與丘遲夢，深知卓氏功。", "還鄉將製服，從此表亨通。"]'),
('62405264-e6cd-4af8-acd5-a576adb5c5c5','東皇太一詞','李希仲','唐','唐诗','tang','','[]','吉日初齊戒，靈巫穆上皇。',48,'全唐诗/poet.tang.7000.json','["吉日初齊戒，靈巫穆上皇。", "焚香布瑤席，鳴珮奠椒漿。", "緩舞花飛滿，清歌水去長。", "迴波送神曲，雲雨滿瀟湘。"]'),
('057ba7ec-5fc3-4658-bba5-26bcb9a0965e','薊北行二首 一','李希仲','唐','唐诗','tang','','[]','旄頭有精芒，胡騎獵秋草。',48,'全唐诗/poet.tang.7000.json','["旄頭有精芒，胡騎獵秋草。", "羽檄南渡河，邊庭用兵早。", "漢家愛征戰，宿將今已老。", "辛苦羽林兒，從戎榆關道。"]'),
('e6627f06-2bc8-4e07-8a10-6c989f81bb40','薊北行二首 二','李希仲','唐','唐诗','tang','','[]','一身救邊速，烽火通薊門。',48,'全唐诗/poet.tang.7000.json','["一身救邊速，烽火通薊門。", "前軍飛鳥斷，格鬬塵沙昏。", "寒日鼓聲急，單于夜將奔。", "當須徇忠義，身死報國恩。"]'),
('e32ab473-2cd8-4fd9-b525-da7826d7f2dd','送妻','楊志堅','唐','唐诗','tang','','["\u9001\u522b"]','平生志業在琴詩，頭上如今有二絲。',64,'全唐诗/poet.tang.7000.json','["平生志業在琴詩，頭上如今有二絲。", "漁父尚知谿谷暗，山妻不信出身遲。", "荆釵任意撩新鬢，明鏡從他別畫眉。", "今日便同行路客，相逢即是下山時。"]'),
('74a7c9f6-9d7f-4558-9d78-c525c98d2737','從張丞相遊南紀城獵戲贈裴迪張參軍','孟浩然','唐','唐诗','tang','','[]','從禽非吾樂，不好雲夢田。',96,'全唐诗/poet.tang.7000.json','["從禽非吾樂，不好雲夢田。", "歲暮登城望，偏令相思懸。", "公卿有幾幾，車騎何翩翩。", "世祿金張貴，官曹幕府賢。", "順時行殺氣，飛刃爭割鮮。", "十里屆賓館，徵聲匝妓筵。", "高標回落日，平楚散芳煙。", "何意狂歌客，從公亦在旃。"]'),
('bb5d1b3e-cadf-4c86-8b44-10dba65534cc','登江中孤嶼贈白雲先生王迥','孟浩然','唐','唐诗','tang','','["\u6000\u4eba", "\u63cf\u5199\u6c34", "\u5199\u6c34"]','悠悠清水江，水落沙嶼出。',72,'全唐诗/poet.tang.7000.json','["悠悠清水江，水落沙嶼出。", "回潭石下深，綠篠岸傍密。", "鮫人潛不見，漁父歌自逸。", "憶與君別時，泛舟如昨日。", "夕陽開返照，中坐興非一。", "南望鹿門山，歸來恨如失。"]'),
('8d85327f-5d8a-476e-a7cd-5bac1bbb8039','晚春臥病寄張八','孟浩然','唐','唐诗','tang','','[]','南陌春將晚，北窗猶臥病。',144,'全唐诗/poet.tang.7000.json','["南陌春將晚，北窗猶臥病。", "林園久不遊，草木一何盛。", "狹逕花障迷，閑庭竹掃淨。", "翠羽戲蘭苕，赬鱗動荷柄。", "念我平生好，江鄉遠從政。", "雲山阻夢思，衾枕勞歌詠。", "歌詠復何爲，同心恨別離。", "世途皆自媚，流俗寡相知。", "賈誼才空逸，安仁鬢欲絲。", "遙情每東注，奔晷復西馳。", "常恐填溝壑，無由振羽儀。", "窮通若有命，欲向論中推。"]'),
('56ca5b29-4bb9-4f12-9200-6bc7c72e4e47','秋登蘭山寄張五','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u79cb\u5929", "\u767b\u9ad8", "\u5c71", "\u6000\u4eba"]','北山白雲裏，隱者自怡悅。',72,'全唐诗/poet.tang.7000.json','["北山白雲裏，隱者自怡悅。", "相望試登高，心飛逐鳥滅。", "愁因薄暮起，興是清秋發。", "時見歸村人，沙行渡頭歇。", "天邊樹若薺，江畔舟如月。", "何當載酒來，共醉重陽節。"]'),
('a5e7848e-5480-4646-ac7c-f9c90208c7d0','入峽寄弟','孟浩然','唐','唐诗','tang','','[]','吾昔與爾輩，讀書常閉門。',120,'全唐诗/poet.tang.7000.json','["吾昔與爾輩，讀書常閉門。", "未嘗冒湍險，豈顧垂堂言。", "自此歷江湖，辛勤難具論。", "往來行旅弊，開鑿禹功存。", "壁立千峰峻，潨流萬壑奔。", "我來凡幾宿，無夕不聞猿。", "浦上搖歸戀，舟中失夢魂。", "淚沾明月峽，心斷鶺鴒原。", "離闊星難聚，秋深露已繁。", "因君下南楚，書此示鄉園。"]'),
('88603c8f-ebce-4856-989e-d2b8e174f8a3','湖中旅泊寄閻九司戶防','孟浩然','唐','唐诗','tang','','[]','桂水通百越，扁舟期曉發。',84,'全唐诗/poet.tang.7000.json','["桂水通百越，扁舟期曉發。", "荆雲蔽三巴，夕望不見家。", "襄王夢行雨，才子謫長沙。", "長沙饒瘴癘，胡爲苦留滯。", "久別思款顏，承歡懷接袂。", "接袂杳無由，徒增旅泊愁。", "清猿不可聽，沿月下湘流。"]'),
('0d320825-392a-4e4a-b045-dbe21c7f48cb','大堤行寄萬七','孟浩然','唐','唐诗','tang','','[]','大堤行樂處，車馬相馳突。',48,'全唐诗/poet.tang.7000.json','["大堤行樂處，車馬相馳突。", "歲歲春草生，踏青二三月。", "王孫挾珠彈，遊女矜羅襪。", "攜手今莫同，江花爲誰發。"]'),
('e1d166f6-4858-4516-b4c7-339c6fc620ac','仲夏歸漢南園寄京邑耆舊','孟浩然','唐','唐诗','tang','','[]','嘗讀高士傳，最嘉陶徵君。',96,'全唐诗/poet.tang.7000.json','["嘗讀高士傳，最嘉陶徵君。", "日耽田園趣，自謂羲皇人。", "予復何爲者，棲棲徒問津。", "中年廢丘壑，上國旅風塵。", "忠欲事明主，孝思侍老親。", "歸來當炎夏，耕稼不及春。", "扇枕北窗下，采芝南澗濱。", "因聲謝同列，吾慕潁陽真。"]'),
('524f2729-a82a-4f6b-af71-910e6b1c3c34','題雲門山寄越府包戶曹徐起居','孟浩然','唐','唐诗','tang','','[]','我行適諸越，夢寐懷所歡。',96,'全唐诗/poet.tang.7000.json','["我行適諸越，夢寐懷所歡。", "久負獨往願，今來恣遊盤。", "台嶺踐磴石，耶溪泝林湍。", "捨舟入香界，登閣憩旃檀。", "晴山秦望近，春水鏡湖寬。", "遠懷佇應接，卑位徒勞安。", "白雲日夕滯，滄海去來觀。", "故國眇天末，良朋在朝端。"]'),
('f49fec29-bba8-41d0-b9d8-d0105982586e','宿揚子津寄潤州長山劉隱士','孟浩然','唐','唐诗','tang','','[]','所思在建業，欲往大江深。',48,'全唐诗/poet.tang.7000.json','["所思在建業，欲往大江深。", "日夕望京口，煙波愁我心。", "心馳茅山洞，目極楓樹林。", "不見少微星，星霜勞夜吟。"]'),
('e20f3d71-054e-48f2-a8ac-080abfe3ac85','書懷貽京邑同好','孟浩然','唐','唐诗','tang','','[]','維先自鄒魯，家世重儒風。',120,'全唐诗/poet.tang.7000.json','["維先自鄒魯，家世重儒風。", "詩體襲遺訓，趨庭霑末躬。", "晝夜常自强，詞翰頗亦工。", "三十既成立，嗟吁命不通。", "慈親向羸老，喜懼在深衷。", "甘脆朝不足，簞瓢夕屢空。", "執鞭慕夫子，捧檄懷毛公。", "感激遂彈冠，安能守固窮。", "當途訴知己，投剌匪求蒙。", "秦楚邈離異，飜飛何日同。"]'),
('06c066e0-890f-4eda-9447-f87cc29bff0c','還山貽湛法師','孟浩然','唐','唐诗','tang','','[]','幼聞無生理，常欲觀此身。',122,'全唐诗/poet.tang.7000.json','["幼聞無生理，常欲觀此身。", "心跡罕兼遂，[崎嶇]多在塵。", "晚途歸舊壑，偶與支公鄰。", "導以微妙法，結爲清淨因。", "煩惱業頓捨，山林情轉殷。", "朝來問疑義，夕話得清真。", "墨妙稱古絕，詞華驚世人。", "禪房閉虛靜，花藥連冬春。", "平石籍琴硯，落泉灑衣巾。", "欲知冥滅意，朝夕海鷗馴。"]'),
('f8afed4e-e8cd-467f-afae-51dc149921f7','夏日南亭懷辛大','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u53cb\u60c5", "\u590f\u5929", "\u6000\u4eba"]','山光忽西落，池月漸東上。',60,'全唐诗/poet.tang.7000.json','["山光忽西落，池月漸東上。", "散髮乘夕涼，開軒臥閑敞。", "荷風送香氣，竹露滴清響。", "欲取鳴琴彈，恨無知音賞。", "感此懷故人，中宵勞夢想。"]'),
('fb0490b5-2c0b-4ce1-b9f8-ca1b553f662c','秋宵月下有懷','孟浩然','唐','唐诗','tang','','["\u6708\u4eae", "\u4e2d\u79cb\u8282", "\u4e2d\u79cb", "\u6292\u60c5", "\u501f\u666f\u6292\u60c5"]','秋空明月懸，光彩露霑濕。',48,'全唐诗/poet.tang.7000.json','["秋空明月懸，光彩露霑濕。", "驚鵲棲未定，飛螢捲簾入。", "庭槐寒影疎，鄰杵夜聲急。", "佳期曠何許，望望空佇立。"]'),
('5b6d7b6f-7371-4aad-842a-abf3d4537946','將適天台留別臨安李主簿','孟浩然','唐','唐诗','tang','','[]','枳棘君尚棲，匏瓜吾豈繫。',84,'全唐诗/poet.tang.7000.json','["枳棘君尚棲，匏瓜吾豈繫。", "念離當夏首，漂泊指炎裔。", "江海非墮遊，田園失歸計。", "定山既早發，漁浦亦宵濟。", "泛泛隨波瀾，行行任艫枻。", "故林日已遠，羣木坐成翳。", "羽人在丹丘，吾亦從此逝。"]'),
('7ed6173a-e61e-4a96-a35e-5fe7f9c73cb4','送丁大鳳進士赴舉呈張九齡','孟浩然','唐','唐诗','tang','','[]','吾觀鷦鷯賦，君負王佐才。',48,'全唐诗/poet.tang.7000.json','["吾觀鷦鷯賦，君負王佐才。", "惜無金張援，十上空歸來。", "棄置鄉園老，翻飛羽翼摧。", "故人今在位，歧路莫遲回。"]'),
('8f660513-b195-4797-96a7-408b446e263b','送吳悅遊韶陽','孟浩然','唐','唐诗','tang','','[]','五色憐鳳雛，南飛適鷓鴣。',48,'全唐诗/poet.tang.7000.json','["五色憐鳳雛，南飛適鷓鴣。", "楚人不相識，何處求椅梧。", "去去日千里，茫茫天一隅。", "安能與斥鷃，決起但槍榆。"]'),
('52873722-b3bf-4aa5-be7f-07f82986ec61','適越留別譙縣張主簿申屠少府','孟浩然','唐','唐诗','tang','','[]','朝乘汴河流，夕次譙縣界。',48,'全唐诗/poet.tang.7000.json','["朝乘汴河流，夕次譙縣界。", "幸值西風吹，得與故人會。", "君學梅福隱，余從伯鸞邁。", "別後能相思，浮雲在吳會。"]'),
('fc13bd5f-5ad3-4308-8042-d3749b6c1c61','送陳七赴西軍','孟浩然','唐','唐诗','tang','','["\u79bb\u522b", "\u53cb\u4eba", "\u8d5e\u626c", "\u6124\u61d1"]','吾觀非常者，碌碌在目前。',48,'全唐诗/poet.tang.7000.json','["吾觀非常者，碌碌在目前。", "君負鴻鵠志，蹉跎書劒年。", "一聞邊烽動，萬里忽爭先。", "余亦赴京國，何當獻凱還。"]'),
('9a908c83-c762-412c-b00e-671e5ba131cb','送從弟邕下第後尋會稽','孟浩然','唐','唐诗','tang','','[]','疾風吹征帆，倏爾向空沒。',48,'全唐诗/poet.tang.7000.json','["疾風吹征帆，倏爾向空沒。", "千里在俄頃，三江坐超忽。", "向來共歡娛，日夕成楚越。", "落羽更分飛，誰能不驚骨。"]'),
('eee0206b-15bf-4a62-bdc3-bb84400d3be8','送辛大之鄂渚不及','孟浩然','唐','唐诗','tang','','["\u6292\u6000", "\u9001\u522b", "\u5b64\u5bc2"]','送君不相見，日暮獨愁緒。',48,'全唐诗/poet.tang.7000.json','["送君不相見，日暮獨愁緒。", "江上空裴回，天邊迷處所。", "郡邑經樊鄧，山河入嵩汝。", "蒲輪去漸遙，石徑徒延佇。"]'),
('6801f70a-aaf2-46ae-beab-bd2e567fc047','江上別流人','孟浩然','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','以我越鄉客，逢君謫居者。',48,'全唐诗/poet.tang.7000.json','["以我越鄉客，逢君謫居者。", "分飛黃鶴樓，流落蒼梧野。", "驛使乘雲去，征帆沿溜下。", "不知從此分，還袂何時把。"]'),
('fc5acef5-c403-43a5-a69f-97256231868c','宴包二融宅','孟浩然','唐','唐诗','tang','','[]','閑居枕清洛，左右接大野。',72,'全唐诗/poet.tang.7000.json','["閑居枕清洛，左右接大野。", "門庭無雜賓，車轍多長者。", "是時方盛夏，風物自瀟灑。", "五日休沐歸，相攜竹林下。", "開襟成歡趣，對酒不能罷。", "煙暝棲鳥迷，余將歸白社。"]'),
('268aae62-5eac-44ea-8f36-f6ef9314ea6e','與王昌齡宴王道士房','孟浩然','唐','唐诗','tang','','[]','歸來臥青山，常夢遊清都。',48,'全唐诗/poet.tang.7000.json','["歸來臥青山，常夢遊清都。", "漆園有傲吏，惠好在招呼。", "書幌神仙籙，畫屏山海圖。", "酌霞復對此，宛似入蓬壺。"]'),
('395bcd77-f628-46a0-9b63-0a26fac694cc','襄陽公宅飲','孟浩然','唐','唐诗','tang','','[]','窈窕夕陽佳，䒠茸春色好。',96,'全唐诗/poet.tang.7000.json','["窈窕夕陽佳，䒠茸春色好。", "欲覓淹留處，無過狹斜道。", "綺席卷龍鬚，香杯浮碼碯。", "北林積修樹，南池生別島。", "手撥金翠花，心迷玉紅草。", "談笑光六義，發論明三倒。", "座非陳子驚，門還魏公掃。", "榮辱應無間，歡娛當共保。"]'),
('31c2aef7-133f-4151-950e-7eea2865a9e1','尋香山湛上人','孟浩然','唐','唐诗','tang','','[]','朝遊訪名山，山遠在空翠。',120,'全唐诗/poet.tang.7000.json','["朝遊訪名山，山遠在空翠。", "氛氳亙百里，日入行始至。", "杖策尋故人，解鞭暫停騎。", "石門殊豁險，篁逕轉森邃。", "法侶欣相逢，清談曉不寐。", "平生慕真隱，累日探奇異。", "野老朝入田，山僧暮歸寺。", "松泉多逸響，苔壁饒古意。", "谷口聞鐘聲，林端識香氣。", "願言投此山，身世兩相棄。"]'),
('893eee5a-08bd-4308-b019-b7d6a692db95','雲門寺西六七里聞符公蘭若最幽與薛八同往','孟浩然','唐','唐诗','tang','','[]','謂予獨迷方，逢子亦在野。',108,'全唐诗/poet.tang.7000.json','["謂予獨迷方，逢子亦在野。", "結交指松柏，問法尋蘭若。", "小溪劣容舟，怪石屢驚馬。", "所居最幽絕，所住皆靜者。", "雲簇興座隅，天空落階下。", "上人亦何聞，塵念都已捨。", "四禪合真如，一切是虛假。", "願承甘露潤，喜得惠風灑。", "依止託山門，誰能效丘也。"]'),
('f1366a20-e085-4e4a-9a79-645be7e27a63','宿天台桐柏觀','孟浩然','唐','唐诗','tang','','[]','海行信風帆，夕宿逗雲島。',108,'全唐诗/poet.tang.7000.json','["海行信風帆，夕宿逗雲島。", "緬尋滄洲趣，近愛赤城好。", "捫蘿亦踐苔，輟櫂恣探討。", "息陰憩桐柏，采秀弄芝草。", "鶴唳清露垂，雞鳴信潮早。", "願言解纓紱，從此去煩惱。", "高步凌四明，玄蹤得三老。", "紛吾遠遊意，學彼長生道。", "日夕望三山，雲濤空浩浩。"]'),
('1338a23c-19fc-4e56-b634-984b02e7fff0','峴潭作','孟浩然','唐','唐诗','tang','','[]','石潭傍隈隩，沙岸曉夤緣。',48,'全唐诗/poet.tang.7000.json','["石潭傍隈隩，沙岸曉夤緣。", "試垂竹竿釣，果得槎頭鯿。", "美人騁金錯，纖手膾紅鮮。", "因謝陸內史，蓴羹何足傳。"]'),
('771875f8-d1a0-44a4-a84f-c4a2f281b5b6','題終南翠微寺空上人房','孟浩然','唐','唐诗','tang','','[]','翠微終南裏，雨後宜返照。',96,'全唐诗/poet.tang.7000.json','["翠微終南裏，雨後宜返照。", "閉關久沈冥，杖策一登眺。", "遂造幽人室，始知靜者妙。", "儒道雖異門，雲林頗同調。", "兩心相喜得，畢景共談笑。", "暝還高窗眠，時見遠山燒。", "緬懷赤城標，更憶臨海嶠。", "風泉有清音，何必蘇門嘯。"]'),
('22be6369-771a-4154-b989-5328ae459209','初春漢中漾舟','孟浩然','唐','唐诗','tang','','[]','羊公峴山下，神女漢臯曲。',72,'全唐诗/poet.tang.7000.json','["羊公峴山下，神女漢臯曲。", "雪罷冰復開，春潭千丈綠。", "輕舟恣來往，探翫無厭足。", "波影搖妓釵，沙光逐人目。", "傾杯魚鳥醉，聯句鸎花續。", "良會難再逢，日入須秉燭。"]'),
('3e504df9-b22d-480e-9e7c-9f8ab8591b91','宿業師山房期丁大不至','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u5199\u666f"]','夕陽度西嶺，羣壑倏已暝。',48,'全唐诗/poet.tang.7000.json','["夕陽度西嶺，羣壑倏已暝。", "松月生夜涼，風泉滿清聽。", "樵人歸欲盡，煙鳥棲初定。", "之子期宿來，孤琴候蘿逕。"]'),
('83c44c92-0198-4004-892f-a1d34a6858da','耶溪泛舟','孟浩然','唐','唐诗','tang','','[]','落景馀清輝，輕橈弄溪渚。',48,'全唐诗/poet.tang.7000.json','["落景馀清輝，輕橈弄溪渚。", "澄明愛水物，臨泛何容與。", "白首垂釣翁，新妝浣紗女。", "相看似相識，脉脉不得語。"]'),
('752944d2-bcb8-4036-a780-c86fd953f2ca','彭蠡湖中望廬山','孟浩然','唐','唐诗','tang','','["\u5e90\u5c71"]','太虛生月暈，舟子知天風。',108,'全唐诗/poet.tang.7000.json','["太虛生月暈，舟子知天風。", "挂席候明發，眇漫平湖中。", "中流見匡阜，勢壓九江雄。", "黤黕容霽色，崢嶸當曉空。", "香爐初上日，瀑布噴成虹。", "久欲追尚子，況茲懷遠公。", "我來限于役，未暇息微躬。", "淮海途將半，星霜歲欲窮。", "寄言巖棲者，畢趣當來同。"]'),
('0236836c-e75b-4b63-bf8d-46439dc02df9','登鹿門山','孟浩然','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u767b\u9ad8", "\u6000\u53e4"]','清曉因興來，乘流越江峴。',120,'全唐诗/poet.tang.7000.json','["清曉因興來，乘流越江峴。", "沙禽近方識，浦樹遙莫辨。", "漸至鹿門山，山明翠微淺。", "巖潭多屈曲，舟檝屢回轉。", "昔聞龐德公，采藥遂不返。", "金澗餌芝朮，石牀臥苔蘚。", "紛吾感耆舊，結攬事攀踐。", "隱迹今尚存，高風邈已遠。", "白雲何時去，丹桂空偃蹇。", "探討意未窮，回艇夕陽晚。"]'),
('c1443129-8490-43d0-8520-63386cf8782a','遊明禪師西山蘭若','孟浩然','唐','唐诗','tang','','[]','西山多奇狀，秀出倚前楹。',72,'全唐诗/poet.tang.7000.json','["西山多奇狀，秀出倚前楹。", "停午收彩翠，夕陽照分明。", "吾師住其下，禪坐證無生。", "結廬就嵌窟，剪苕通往行。", "談空對樵叟，授法與山精。", "日暮方辭去，田園歸冶城。"]'),
('220cabf0-4db3-4bf4-9897-fdbf0a25b579','登望楚山最高頂','孟浩然','唐','唐诗','tang','','["\u5199\u5c71", "\u6292\u6000", "\u8c6a\u8fc8", "\u63cf\u5199\u5c71", "\u671b\u8fdc"]','山水觀形勝，襄陽美會稽。',72,'全唐诗/poet.tang.7000.json','["山水觀形勝，襄陽美會稽。", "最高唯望楚，曾未一攀躋。", "石壁疑削成，衆山比全低。", "晴明試登陟，目極無端倪。", "雲夢掌中小，武陵花處迷。", "暝還歸騎下，蘿月映深谿。"]'),
('aade0f4a-6f9b-4239-85ca-725b32795b6d','疾愈過龍泉寺精舍呈易業二公','孟浩然','唐','唐诗','tang','','[]','停午聞山鐘，起行散愁疾。',84,'全唐诗/poet.tang.7000.json','["停午聞山鐘，起行散愁疾。", "尋林采芝去，轉谷松翠密。", "傍見精舍開，長廊飯僧畢。", "石渠流雪水，金子耀霜橘。", "竹房思舊遊，過憩終永日。", "入洞窺石髓，傍崖采蜂蜜。", "日暮辭遠公，虎溪相送出。"]'),
('34beee01-7e97-4e2d-b1df-015523f16fda','萬山潭作','孟浩然','唐','唐诗','tang','','[]','垂釣坐盤石，水清心亦閑。',48,'全唐诗/poet.tang.7000.json','["垂釣坐盤石，水清心亦閑。", "魚行潭樹下，猿挂島藤間。", "游女昔解佩，傳聞於此山。", "求之不可得，沿月櫂歌還。"]'),
('91e92f66-319c-4cf5-b5c0-08938846a812','與黃侍御北津泛舟','孟浩然','唐','唐诗','tang','','[]','津無蛟龍患，日夕常安流。',84,'全唐诗/poet.tang.7000.json','["津無蛟龍患，日夕常安流。", "本欲避驄馬，何如同鷁舟。", "豈伊今日幸，曾是昔年遊。", "莫奏琴中鶴，且隨波上鷗。", "隄緣九里郭，山面百城樓。", "自顧躬耕者，才非管樂儔。", "聞君薦草澤，從此泛滄洲。"]'),
('fc1488a1-dbea-4dda-9917-33b19d463cc9','洗然弟竹亭','孟浩然','唐','唐诗','tang','','["\u5199\u7af9", "\u5199\u4eba", "\u8a00\u5fd7", "\u5199\u4eba\u8bd7"]','吾與二三子，平生結交深。',48,'全唐诗/poet.tang.7000.json','["吾與二三子，平生結交深。", "俱懷鴻鵠志，昔有鶺鴒心。", "逸氣假毫翰，清風在竹林。", "達是酒中趣，琴上偶然音。"]'),
('4b313eaa-8040-4f8d-b0d6-14c96c6e3e82','山中逢道士雲公','孟浩然','唐','唐诗','tang','','[]','春餘草木繁，耕種滿田園。',156,'全唐诗/poet.tang.7000.json','["春餘草木繁，耕種滿田園。", "酌酒聊自勸，農夫安與言。", "忽聞荆山子，時出桃花源。", "采樵過北谷，賣藥來西村。", "村煙日云夕，榛路有歸客。", "杖策前相逢，依然是疇昔。", "邂逅歡覯止，殷勤敘離隔。", "謂予搏扶桑，輕舉振六翮。", "奈何偶昌運，獨見遺草澤。", "既笑接輿狂，仍憐孔丘厄。", "物情趨勢利，吾道貴閑寂。", "偃息西山下，門庭罕人迹。", "何時還清溪，從爾鍊丹液。"]'),
('506fb234-a294-4502-805e-3843c053d7f4','越中逢天台太乙子','孟浩然','唐','唐诗','tang','','[]','仙穴逢羽人，停艫向前拜。',120,'全唐诗/poet.tang.7000.json','["仙穴逢羽人，停艫向前拜。", "問余涉風水，何處遠行邁。", "登陸尋天台，順流下吳會。", "茲山夙所尚，安得問靈怪。", "上逼青天高，俯臨滄海大。", "雞鳴見日出，常覿仙人斾。", "往來赤城中，逍遙白雲外。", "莓苔異人間，瀑布當空界。", "福庭長自然，華頂舊稱最。", "永此從之遊，何當濟所屆。"]'),
('8271afe1-8fa7-4656-a5fd-2a4c9dd15df1','家園臥疾畢太祝曜見尋','孟浩然','唐','唐诗','tang','','[]','伏枕舊遊曠，笙簧勞夢思。',120,'全唐诗/poet.tang.7000.json','["伏枕舊遊曠，笙簧勞夢思。", "平生重交結，迨此令人疑。", "冰室無煖氣，炎雲空赫曦。", "隙駒不暫駐，日聽涼蟬悲。", "壯圖哀未立，斑白恨吾衰。", "夫子自南楚，緬懷嵩汝期。", "顧予衡茅下，兼致稟物資。", "脫分趨庭禮，殷勤伐木詩。", "脫君車前鞅，設我園中葵。", "斗酒須寒興，明朝難重持。"]'),
('b1d6086c-9973-45f3-891a-56eefc3801da','白雲先生王迥見訪','孟浩然','唐','唐诗','tang','','[]','閑歸日無事，雲臥晝不起。',72,'全唐诗/poet.tang.7000.json','["閑歸日無事，雲臥晝不起。", "有客款柴扉，自云巢居子。", "居閑好芝朮，采藥來城市。", "家在鹿門山，常遊澗澤水。", "手持白羽扇，脚步青芒履。", "聞道鶴書徵，臨流還洗耳。"]'),
('34976884-7b4f-4cc1-9f80-076caf259a16','田園作','孟浩然','唐','唐诗','tang','','["\u6292\u60c5", "\u7530\u56ed"]','弊廬隔塵喧，惟先養恬素。',108,'全唐诗/poet.tang.7000.json','["弊廬隔塵喧，惟先養恬素。", "卜鄰近三徑，植果盈千樹。", "粵余任推遷，三十猶未遇。", "書劒時將晚，丘園日已暮。", "晨興自多懷，晝坐常寡悟。", "沖天羨鴻鵠，爭食羞雞騖。", "望斷金馬門，勞歌采樵路。", "鄉曲無知己，朝端乏親故。", "誰能爲揚雄，一薦甘泉賦。"]'),
('1ab8706d-2305-4651-ae36-6d47a6bd1c78','采樵作','孟浩然','唐','唐诗','tang','','["\u9690\u5c45", "\u5199\u4eba", "\u5199\u666f", "\u5199\u4eba\u8bd7"]','采樵入深山，山深樹重疊。',48,'全唐诗/poet.tang.7000.json','["采樵入深山，山深樹重疊。", "橋崩臥槎擁，路險垂藤接。", "日落伴將稀，山風拂蘿衣。", "長歌負輕策，平野望煙歸。"]'),
('ae57919c-2a2a-45a6-b931-f0aad8edacbc','自潯陽泛舟經明海','孟浩然','唐','唐诗','tang','','[]','大江分九流，淼淼成水鄉。',72,'全唐诗/poet.tang.7000.json','["大江分九流，淼淼成水鄉。", "舟子乘利涉，往來至潯陽。", "因之泛五湖，流浪經三湘。", "觀濤壯枚發，弔屈痛沈湘。", "魏闕心恆在，金門詔不忘。", "遙憐上林雁，冰泮也回翔。"]'),
('81e1e6c2-2dbb-4650-b7a7-1ec27257fe25','早發漁浦潭','孟浩然','唐','唐诗','tang','','[]','東旭早光芒，渚禽已驚聒。',72,'全唐诗/poet.tang.7000.json','["東旭早光芒，渚禽已驚聒。", "臥聞漁浦口，橈聲暗相撥。", "日出氣象分，始知江湖闊。", "美人常晏起，照影弄流沫。", "飲水畏驚猿，祭魚時見獺。", "舟行自無悶，況值晴景豁。"]'),
('445c47d9-3246-4217-9655-bab39a914e01','經七里灘','孟浩然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','予奉垂堂誡，千金非所輕。',132,'全唐诗/poet.tang.7000.json','["予奉垂堂誡，千金非所輕。", "爲多山水樂，頻作泛舟行。", "五嶽追向子，三湘弔屈平。", "湖經洞庭闊，江入新安清。", "復聞嚴陵瀨，乃在茲湍路。", "疊障數百里，沿洄非一趣。", "彩翠相氛氳，別流亂奔注。", "釣磯平可坐，苔磴滑難步。", "猨飲石下潭，鳥還日邊樹。", "觀奇恨來晚，倚櫂惜將暮。", "揮手弄潺湲，從茲洗塵慮。"]'),
('f8d0d861-6be7-4d1b-b54d-28ab7f4b81c0','歲暮海上作','孟浩然','唐','唐诗','tang','','[]','仲尼既云歿，余亦浮于海。',48,'全唐诗/poet.tang.7000.json','["仲尼既云歿，余亦浮于海。", "昏見斗柄回，方知歲星改。", "虛舟任所適，垂釣非有待。", "爲問乘槎人，滄洲復誰在。"]'),
('52d916be-1cd2-490f-84ee-3d507a1c7dac','南歸阻雪','孟浩然','唐','唐诗','tang','','[]','我行滯宛許，日夕望京豫。',72,'全唐诗/poet.tang.7000.json','["我行滯宛許，日夕望京豫。", "曠野莽茫茫，鄉山在何處。", "孤煙村際起，歸雁天邊去。", "積雪復平臯，饑鷹捉寒兔。", "少年弄文墨，屬意在章句。", "十上恥還家，裴回守歸路。"]'),
('58e6008e-cd4a-4098-8c0f-d96e1af09d9e','聽鄭五愔彈琴','孟浩然','唐','唐诗','tang','','["\u5199\u4eba", "\u97f3\u4e50", "\u5199\u4eba\u8bd7"]','阮籍推名飲，清風滿竹林。',48,'全唐诗/poet.tang.7000.json','["阮籍推名飲，清風滿竹林。", "半酣下衫袖，拂拭龍脣琴。", "一杯彈一曲，不覺夕陽沈。", "予意在山水，聞之諧夙心。"]'),
('53ff81f9-2f4d-4aaf-8b42-7b7b5a97d661','同張明府清鏡歎','孟浩然','唐','唐诗','tang','','[]','妾有盤龍鏡，清光常晝發。',48,'全唐诗/poet.tang.7000.json','["妾有盤龍鏡，清光常晝發。", "自從生塵埃，有若霧中月。", "愁來試取照，坐歎生白髮。", "寄語邊塞人，如何久離別。"]'),
('01aa20e7-3ec5-4146-9516-d1d2242be806','庭橘','孟浩然','唐','唐诗','tang','','[]','明發覽羣物，萬木何陰森。',72,'全唐诗/poet.tang.7000.json','["明發覽羣物，萬木何陰森。", "凝霜漸漸水，庭橘似懸金。", "女伴爭攀摘，摘窺礙葉深。", "竝生憐共蒂，相示感同心。", "骨刺紅羅被，香黏翠羽簪。", "擎來玉盤裏，全勝在幽林。"]'),
('55031508-e6f7-4322-b449-f4e23d321e4d','早梅','孟浩然','唐','唐诗','tang','','[]','園中有早梅，年例犯寒開。',36,'全唐诗/poet.tang.7000.json','["園中有早梅，年例犯寒開。", "少婦曾攀折，將歸插鏡臺。", "猶言看不足，更欲剪刀裁。"]'),
('09c4db3a-f443-4b13-8768-3502b5b8e002','清明即事','孟浩然','唐','唐诗','tang','','["\u6000\u4eba", "\u6e05\u660e\u8282", "\u5199\u666f"]','帝里重清明，人心自愁思。',48,'全唐诗/poet.tang.7000.json','["帝里重清明，人心自愁思。", "車聲上路合，柳色東城翠。", "花落草齊生，鸎飛蝶雙戲。", "空堂坐相憶，酌茗聊代醉。"]'),
('0710b58a-d326-462e-893e-767cb053d0d4','和盧明府送鄭十三還京兼寄之什','孟浩然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','昔時風景登臨地，今日衣冠送別筵。',64,'全唐诗/poet.tang.7000.json','["昔時風景登臨地，今日衣冠送別筵。", "醉坐自傾彭澤酒，思歸長望白雲天。", "洞庭一葉驚秋早，濩落空嗟滯江島。", "寄語朝廷當世人，何時重見長安道。"]'),
('9b495a1e-d43e-476f-8e9c-3864d042c649','高陽池送朱二','孟浩然','唐','唐诗','tang','','["\u9001\u522b", "\u6000\u5ff5"]','當昔襄陽雄盛時，山公常醉習家池。',128,'全唐诗/poet.tang.7000.json','["當昔襄陽雄盛時，山公常醉習家池。", "池邊釣女日相隨，妝成照影競來窺。", "澄波澹澹芙蓉發，綠岸毿毿楊柳垂。", "一朝物變人亦非，四面荒涼人徑稀。", "意氣豪華何處在，空餘草露濕羅衣。", "此地朝來餞行者，翻向此中牧征馬。", "征馬分飛日漸斜，見此空爲人所嗟。", "殷勤爲訪桃源路，予亦歸來松子家。"]'),
('e7e13edf-da16-4e83-88d4-b8efe6b40415','鸚鵡洲送王九之江左','孟浩然','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','昔登江上黃鶴樓，遙愛江中鸚鵡洲。',84,'全唐诗/poet.tang.7000.json','["昔登江上黃鶴樓，遙愛江中鸚鵡洲。", "洲勢逶迤遶碧流，鴛鴦鸂鶒滿灘頭。", "灘頭日落沙磧長，金沙熠熠動飆光。", "舟人牽錦纜，浣女結羅裳。", "月明全見蘆花白，風起遙聞杜若香，君行采采莫相忘。"]'),
('0dbac132-ef59-4538-9643-603c63452311','送王七尉松滋得陽臺雲','孟浩然','唐','唐诗','tang','','[]','君不見巫山神女作行雲，霏紅沓翠曉氛氳。',67,'全唐诗/poet.tang.7000.json','["君不見巫山神女作行雲，霏紅沓翠曉氛氳。", "嬋娟流入楚王夢，倏忽還隨零雨分。", "空中飛去復飛來，朝朝暮暮下陽臺。", "愁君此去爲仙尉，便逐行雲去不回。"]'),
('cc0e7ac3-bde4-4491-8ae5-027106709e72','夜歸鹿門山歌','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u5f52\u9690", "\u4e03\u8a00\u53e4\u8bd7"]','山寺鐘鳴晝已昏，漁梁渡頭爭渡喧。',64,'全唐诗/poet.tang.7000.json','["山寺鐘鳴晝已昏，漁梁渡頭爭渡喧。", "人隨沙路向江村，余亦乘舟歸鹿門。", "鹿門月照開煙樹，忽到龐公棲隱處。", "巖扉松徑長寂寥，惟有幽人夜來去。"]'),
('1e193b15-1a2b-4c6e-a64a-23c4eadfbab2','長樂宮','孟浩然','唐','唐诗','tang','','[]','秦城舊來稱窈窕，漢家更衣應不少。',64,'全唐诗/poet.tang.7000.json','["秦城舊來稱窈窕，漢家更衣應不少。", "紅粉邀君在何處，青樓苦夜長難曉。", "長樂宮中鐘暗來，可憐歌舞慣相催。", "歡娛此事今寂寞，惟有年年陵樹哀。"]'),
('165d393f-99c7-4e2f-acb7-96be6e186524','示孟郊','孟浩然','唐','唐诗','tang','','[]','蔓草蔽極野，蘭芝結孤根。',60,'全唐诗/poet.tang.7000.json','["蔓草蔽極野，蘭芝結孤根。", "衆音何其繁，伯牙獨不喧。", "當時高深意，舉世無能分。", "鍾期一見知，山水千秋聞。", "爾其保靜節，薄俗徒云云。"]'),
('51192c53-8821-4948-929a-2ddb51766821','和張丞相春朝對雪','孟浩然','唐','唐诗','tang','','[]','迎氣當春至，承恩喜雪來。',48,'全唐诗/poet.tang.7000.json','["迎氣當春至，承恩喜雪來。", "潤從河漢下，花逼豔陽開。", "不覩豐年瑞，焉知燮理才。", "撒鹽如可擬，願糝和羹梅。"]'),
('409f2e08-6ed5-45f7-8979-e19bb732f1b1','和張明府登鹿門作','孟浩然','唐','唐诗','tang','','[]','忽示登高作，能寬旅寓情。',48,'全唐诗/poet.tang.7000.json','["忽示登高作，能寬旅寓情。", "弦歌既多暇，山水思微清。", "草得風光動，虹因雨氣成。", "謬承巴里和，非敢應同聲。"]'),
('9ddbbcdc-df32-4238-9382-52f059514ff2','和張二自穰縣還途中遇雪','孟浩然','唐','唐诗','tang','','[]','風吹沙海雪，漸作柳園春。',48,'全唐诗/poet.tang.7000.json','["風吹沙海雪，漸作柳園春。", "宛轉隨香騎，輕盈伴玉人。", "歌疑郢中客，態比洛川神。", "今日南歸楚，雙飛似入秦。"]'),
('f97d0ffb-0341-4d90-bfb8-cff3c4b5ddfd','和賈主簿弁九日登峴山','孟浩然','唐','唐诗','tang','','[]','楚萬重陽日，羣公賞讌來。',48,'全唐诗/poet.tang.7000.json','["楚萬重陽日，羣公賞讌來。", "共乘休沐暇，同醉菊花杯。", "逸思高秋發，歡情落景催。", "國人咸寡和，遙媿洛陽才。"]'),
('6975adab-25d0-40c6-af3a-3a05847e7717','望洞庭湖贈張丞相','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u63cf\u5199\u6c34", "\u5c71\u6c34", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u4e94\u8a00\u5f8b\u8bd7"]','八月湖水平，涵虛混太清。',48,'全唐诗/poet.tang.7000.json','["八月湖水平，涵虛混太清。", "氣蒸雲夢澤，波撼岳陽城。", "欲濟無舟楫，端居恥聖明。", "坐觀垂釣者，空有羨魚情。"]'),
('d917d875-586b-414c-842f-753be5c6341d','贈道士參寥','孟浩然','唐','唐诗','tang','','[]','蜀琴久不弄，玉匣細塵生。',48,'全唐诗/poet.tang.7000.json','["蜀琴久不弄，玉匣細塵生。", "絲脆弦將斷，金徽色尚榮。", "知音徒自惜，聾俗本相輕。", "不遇鍾期聽，誰知鸞鳳聲。"]'),
('c87cf33e-e4cd-4a14-b2e8-23f825a963ec','京還贈張維','孟浩然','唐','唐诗','tang','','[]','拂衣何處去，高枕南山南。',48,'全唐诗/poet.tang.7000.json','["拂衣何處去，高枕南山南。", "欲徇五斗祿，其如七不堪。", "早朝非晚起，束帶異抽簪。", "因向智者說，遊魚思舊潭。"]'),
('9c363732-3fc9-4a9d-8ef2-526b78f2a947','題李十四莊兼贈綦毋校書','孟浩然','唐','唐诗','tang','','[]','聞君息陰地，東郭柳林間。',48,'全唐诗/poet.tang.7000.json','["聞君息陰地，東郭柳林間。", "左右瀍澗水，門庭緱氏山。", "抱琴來取醉，垂釣坐乘閑。", "歸客莫相待，尋源殊未還。"]'),
('5290d79a-2997-4b2b-94de-7193b71ba36b','九日龍沙作寄劉大眘虛','孟浩然','唐','唐诗','tang','','[]','龍沙豫章北，九日挂帆過。',48,'全唐诗/poet.tang.7000.json','["龍沙豫章北，九日挂帆過。", "風俗因時見，湖山發興多。", "客中誰送酒，櫂裏自成歌。", "歌竟乘流去，滔滔任夕波。"]'),
('38a65364-18ab-4d5b-916e-92ed2aacc757','寄趙正字','孟浩然','唐','唐诗','tang','','[]','正字芸香閣，幽人竹素園。',48,'全唐诗/poet.tang.7000.json','["正字芸香閣，幽人竹素園。", "經過宛如昨，歸臥寂無喧。", "高鳥能擇木，羚羊漫觸藩。", "物情今已見，從此願忘言。"]'),
('0ebb556e-539d-481d-9308-b64453ce702b','洞庭湖寄閻九','孟浩然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭秋正闊，余欲泛歸船。',48,'全唐诗/poet.tang.7000.json','["洞庭秋正闊，余欲泛歸船。", "莫辨荆吳地，唯餘水共天。", "渺瀰江樹沒，合沓海潮連。", "遲爾爲舟楫，相將濟巨川。"]'),
('0613f575-4f07-4326-8591-603fb3d1da45','秦中感秋寄遠上人','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5f52\u9690", "\u6292\u60c5", "\u4e94\u8a00\u5f8b\u8bd7"]','一丘常欲臥，三徑苦無資。',48,'全唐诗/poet.tang.7000.json','["一丘常欲臥，三徑苦無資。", "北土非吾願，東林懷我師。", "黃金然桂盡，壯志逐年衰。", "日夕涼風至，聞蟬但益悲。"]'),
('e54d3a06-8591-4a33-8c6b-05c2fff77b45','宿永嘉江寄山陰崔少府國輔','孟浩然','唐','唐诗','tang','','[]','我行窮水國，君使入京華。',36,'全唐诗/poet.tang.7000.json','["我行窮水國，君使入京華。", "相去日千里，孤帆天一涯。", "臥聞海潮至，起視江月斜。"]'),
('4424d55d-0179-4785-9660-4c8df95419c5','上巳洛中寄王九迥','孟浩然','唐','唐诗','tang','','[]','卜洛成周地，浮杯上巳筵。',48,'全唐诗/poet.tang.7000.json','["卜洛成周地，浮杯上巳筵。", "鬬雞寒食下，走馬射堂前。", "垂柳金堤合，平沙翠幕連。", "不知王逸少，何處會羣賢。"]'),
('ed983c5a-2e44-40b1-8393-93b64c6820f9','聞裴侍御朏自襄州司戶除豫州司戶因以投寄','孟浩然','唐','唐诗','tang','','[]','故人荆府掾，尚有柏臺威。',48,'全唐诗/poet.tang.7000.json','["故人荆府掾，尚有柏臺威。", "移職自樊衍，芳聲聞帝畿。", "昔余臥林巷，載酒過柴扉。", "松菊無時賞，鄉園欲懶歸。"]'),
('cfae0d5d-d438-4aba-aa2d-436880c795cd','江上寄山陰崔少府國輔','孟浩然','唐','唐诗','tang','','[]','春堤楊柳發，憶與故人期。',48,'全唐诗/poet.tang.7000.json','["春堤楊柳發，憶與故人期。", "草木本無意，榮枯自有時。", "山陰定遠近，江上日相思。", "不及蘭亭會，空吟祓禊詩。"]'),
('0a60a215-c9ac-4290-9870-84f852b0f537','夜泊廬江聞故人在東寺以詩寄之','孟浩然','唐','唐诗','tang','','[]','江路經廬阜，松門入虎谿。',48,'全唐诗/poet.tang.7000.json','["江路經廬阜，松門入虎谿。", "聞君尋寂樂，清夜宿招提。", "石鏡山精怯，禪枝怖鴿棲。", "一燈如悟道，爲照客心迷。"]'),
('b1dad78c-4dd8-4b99-b37b-741ed761f26a','宿桐廬江寄廣陵舊遊','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u63cf\u5199\u6c34", "\u4e94\u8a00\u5f8b\u8bd7", "\u6000\u4eba", "\u5199\u6c34"]','山暝聞猿愁，滄江急夜流。',48,'全唐诗/poet.tang.7000.json','["山暝聞猿愁，滄江急夜流。", "風鳴兩岸葉，月照一孤舟。", "建德非吾土，維揚憶舊遊。", "還將兩行淚，遙寄海西頭。"]'),
('3f88c34b-1018-4218-a9a6-5a92e79ac637','南還舟中寄袁太祝','孟浩然','唐','唐诗','tang','','[]','沿泝非便習，風波厭苦辛。',48,'全唐诗/poet.tang.7000.json','["沿泝非便習，風波厭苦辛。", "忽聞遷谷鳥，來報五陵春。", "嶺北回征帆，巴東問故人。", "桃源何處是，遊子正迷津。"]'),
('bd3c576b-1fa2-4505-bc95-7556193d67f6','東陂遇雨率爾貽謝南池','孟浩然','唐','唐诗','tang','','[]','田家春事起，丁壯就東陂。',48,'全唐诗/poet.tang.7000.json','["田家春事起，丁壯就東陂。", "殷殷雷聲作，森森雨足垂。", "海虹晴始見，河柳潤初移。", "予意在耕鑿，因君問土宜。"]'),
('6f0a1a53-c25f-4ab2-9a62-4bfa8e60b0d6','行至汝墳寄盧徵君','孟浩然','唐','唐诗','tang','','[]','行乏憩予駕，依然見汝墳。',48,'全唐诗/poet.tang.7000.json','["行乏憩予駕，依然見汝墳。", "洛川方罷雪，嵩嶂有殘雲。", "曳曳半空裏，明明五色分。", "聊題一時興，因寄盧徵君。"]'),
('ef0c3a46-8e2f-467e-a93d-8b28da121a51','寄天台道士','孟浩然','唐','唐诗','tang','','[]','海上求仙客，三山望幾時。',48,'全唐诗/poet.tang.7000.json','["海上求仙客，三山望幾時。", "焚香宿華頂，裛露采靈芝。", "屢躡莓苔滑，將尋汗漫期。", "倘因松子去，長與世人辭。"]'),
('c7e4d9b9-671b-4e85-b425-9ebe6009d1e8','唐城館中早發寄楊使君','孟浩然','唐','唐诗','tang','','[]','犯霜驅曉駕，數里見唐城。',48,'全唐诗/poet.tang.7000.json','["犯霜驅曉駕，數里見唐城。", "旅館歸心逼，荒村客思盈。", "訪人留後信，策蹇赴前程。", "欲識離魂斷，長空聽雁聲。"]'),
('52ace890-c01e-4336-bb15-3678b9ee5937','澗南即事貽皎上人','孟浩然','唐','唐诗','tang','','[]','弊廬在郭外，素產惟田園。',48,'全唐诗/poet.tang.7000.json','["弊廬在郭外，素產惟田園。", "左右林野曠，不聞朝市喧。", "釣竿垂北澗，樵唱入南軒。", "書取幽棲事，將尋靜者論。"]'),
('f4b0bd05-ca33-4464-b8f3-878cdc829016','重酬李少府見贈','孟浩然','唐','唐诗','tang','','[]','養疾衡簷下，由來浩氣真。',48,'全唐诗/poet.tang.7000.json','["養疾衡簷下，由來浩氣真。", "五行將禁火，十步任尋春。", "致敬惟桑梓，邀歡即主人。", "回看後彫色，青翠有松筠。"]'),
('811368c7-06fb-4de0-b8a4-2af293cf0d4c','九日懷襄陽','孟浩然','唐','唐诗','tang','','[]','去國似如昨，倏然經杪秋。',48,'全唐诗/poet.tang.7000.json','["去國似如昨，倏然經杪秋。", "峴山不可見，風景令人愁。", "誰采籬下菊，應閑池上樓。", "宜城多美酒，歸與葛彊遊。"]'),
('1eccf8c0-9664-4a4c-ba4c-71942bd3d5c9','初出關旅亭夜坐懷王大校書','孟浩然','唐','唐诗','tang','','[]','向夕槐煙起，蔥蘢池館曛。',50,'全唐诗/poet.tang.7000.json','["向夕槐煙起，蔥蘢池館曛。", "客中無偶坐，關外惜離羣。", "燭至螢光滅，荷枯雨滴聞。", "永懷芸閣友，寂寞滯[揚]雲。"]'),
('258a24ef-f6c4-4d4a-a5f8-75274a7ec3a5','人日登南陽驛門亭子懷漢川諸友','孟浩然','唐','唐诗','tang','','[]','朝來登陟處，不似豔陽時。',48,'全唐诗/poet.tang.7000.json','["朝來登陟處，不似豔陽時。", "異縣殊風物，羈懷多所思。", "剪花驚歲早，看柳訝春遲。", "未有南飛雁，裁書欲寄誰。"]'),
('8e18183e-5a58-4805-b672-1726969d6526','早寒江上有懷','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u601d\u5f52", "\u4e94\u8a00\u5f8b\u8bd7", "\u521d\u4e2d\u53e4\u8bd7", "\u601d\u4e61"]','木落雁南度，北風江上寒。',48,'全唐诗/poet.tang.7000.json','["木落雁南度，北風江上寒。", "我家襄水上，遙隔楚雲端。", "鄉淚客中盡，孤帆天際看。", "迷津欲有問，平海夕漫漫。"]'),
('db81cdd3-a240-4b47-b8d6-e54e3c59ac1a','閑園懷蘇子','孟浩然','唐','唐诗','tang','','[]','林園雖少事，幽獨自多違。',48,'全唐诗/poet.tang.7000.json','["林園雖少事，幽獨自多違。", "向夕開簾坐，庭陰落景微。", "鳥過煙樹宿，螢傍水軒飛。", "感念同懷子，京華去不歸。"]'),
('a700f2fb-51fb-4886-8cc8-1c6565ee9c45','同盧明府餞張郎中除義王府司馬海園作','孟浩然','唐','唐诗','tang','','[]','上國山河列，賢王邸第開。',48,'全唐诗/poet.tang.7000.json','["上國山河列，賢王邸第開。", "故人分職去，潘令寵行來。", "冠蓋趨梁苑，江湘失楚材。", "豫愁軒騎動，賓客散池臺。"]'),
('979af412-5c5f-4252-9134-e42de27da386','送張子容進士赴舉','孟浩然','唐','唐诗','tang','','[]','夕曛山照滅，送客出柴門。',48,'全唐诗/poet.tang.7000.json','["夕曛山照滅，送客出柴門。", "惆悵野中別，殷勤岐路言。", "茂林予偃息，喬木爾飛翻。", "無使谷風誚，須令友道存。"]'),
('3e114ed7-43c7-4362-b26d-fa3e003e2e40','送張參明經舉兼向涇州覲省','孟浩然','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u4eba"]','十五綵衣年，承歡慈母前。',48,'全唐诗/poet.tang.7000.json','["十五綵衣年，承歡慈母前。", "孝廉因歲貢，懷橘向秦川。", "四座推文舉，中郎許仲宣。", "泛舟江上別，誰不仰神仙。"]'),
('1a85b668-87ea-4e34-a0fc-8f35290cd205','送張祥之房陵','孟浩然','唐','唐诗','tang','','[]','我家南渡頭，慣習野人舟。',48,'全唐诗/poet.tang.7000.json','["我家南渡頭，慣習野人舟。", "日夕弄清淺，林湍逆上流。", "山河據形勝，天地生豪酋。", "君意在利往，知音期自投。"]'),
('e2b2a6b7-1588-463e-82c4-fc1d85d42778','送吳宣從事','孟浩然','唐','唐诗','tang','','[]','才有幕中士，寧無塞上勳。',48,'全唐诗/poet.tang.7000.json','["才有幕中士，寧無塞上勳。", "漢兵將滅虜，王粲始從軍。", "旌斾邊庭去，山川地脉分。", "平生一匕首，感激贈夫君。"]'),
('b7a009ac-e24e-49db-b9cd-906b490c475a','送桓子之郢城禮','孟浩然','唐','唐诗','tang','','[]','聞君馳綵騎，躞蹀指南荆。',48,'全唐诗/poet.tang.7000.json','["聞君馳綵騎，躞蹀指南荆。", "爲結潘楊好，言過鄢郢城。", "摽梅詩有贈，羔雁禮將行。", "今夜神仙女，應來感夢情。"]'),
('7f4cacb5-cde8-40de-9b14-e223879cc2f4','留別王侍御維','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5f52\u9690", "\u53cb\u60c5", "\u79bb\u522b", "\u54c0\u6028", "\u4e94\u8a00\u5f8b\u8bd7"]','寂寂竟何待，朝朝空自歸。',48,'全唐诗/poet.tang.7000.json','["寂寂竟何待，朝朝空自歸。", "欲尋芳草去，惜與故人違。", "當路誰相假，知音世所稀。", "秪應守索寞，還掩故園扉。"]'),
('c2763c49-0c78-482f-abd0-bc341079771b','早春潤州送從弟還鄉','孟浩然','唐','唐诗','tang','','["\u957f\u6c5f"]','兄弟遊吳國，庭闈戀楚關。',48,'全唐诗/poet.tang.7000.json','["兄弟遊吳國，庭闈戀楚關。", "已多新歲感，更餞白眉還。", "歸泛西江水，離筵北固山。", "鄉園欲有贈，梅柳著先攀。"]'),
('a7af3c0b-3b9d-4c79-bb31-1c8786680fdd','峴山餞房琯崔宗之','孟浩然','唐','唐诗','tang','','[]','貴賤平生隔，軒車是日來。',48,'全唐诗/poet.tang.7000.json','["貴賤平生隔，軒車是日來。", "青陽一覯止，雲路豁然開。", "祖道衣冠列，分亭驛騎催。", "方期九日聚，還待二星回。"]'),
('d77ca368-a416-4c01-a436-b5d1d3ead16b','送謝錄事之越','孟浩然','唐','唐诗','tang','','[]','清旦江天迥，涼風西北吹。',48,'全唐诗/poet.tang.7000.json','["清旦江天迥，涼風西北吹。", "白雲向吳會，征帆亦相隨。", "想到耶溪日，應探禹穴奇。", "仙書倘相示，予在此山陲。"]'),
('849e9bc2-5db4-49ab-a177-61b0ed446705','洛中送奚三還揚州','孟浩然','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','水國無邊際，舟行共使風。',48,'全唐诗/poet.tang.7000.json','["水國無邊際，舟行共使風。", "羨君從此去，朝夕見鄉中。", "予亦離家久，南歸恨不同。", "音書若有問，江上會相逢。"]'),
('09a0f790-c9d1-4fa4-9029-87c601a34a0d','送告八從軍','孟浩然','唐','唐诗','tang','','[]','男兒一片氣，何必五車書。',48,'全唐诗/poet.tang.7000.json','["男兒一片氣，何必五車書。", "好勇方過我，多才便起予。", "運籌將入幕，養拙就閑居。", "正待功名遂，從君繼兩疎。"]'),
('3e221150-d0e2-44b8-b6e7-e4a791090b07','送元公之鄂渚尋觀主張驂鸞','孟浩然','唐','唐诗','tang','','[]','桃花春水漲，之子忽乘流。',48,'全唐诗/poet.tang.7000.json','["桃花春水漲，之子忽乘流。", "峴首辭蛟浦，江中問鶴樓。", "贈君青竹杖，送爾白蘋洲。", "應是神仙子，相期汗漫遊。"]'),
('ca9800b7-d993-466d-90f1-7a51e80c3bb6','送王五昆季省覲','孟浩然','唐','唐诗','tang','','[]','公子戀庭闈，勞歌涉海涯。',48,'全唐诗/poet.tang.7000.json','["公子戀庭闈，勞歌涉海涯。", "水乘舟檝去，親望老萊歸。", "斜日催烏鳥，清江照綵衣。", "平生急難意，遙仰鶺鴒飛。"]'),
('6ab6d41d-b049-46b6-befa-1f34a9ff39a4','送崔遏','孟浩然','唐','唐诗','tang','','[]','片玉來誇楚，治中作主人。',48,'全唐诗/poet.tang.7000.json','["片玉來誇楚，治中作主人。", "江山增潤色，詞賦動陽春。", "別館當虛敞，離情任吐伸。", "因聲兩京舊，誰念臥漳濱。"]'),
('6954689c-9081-45d8-960c-3d587b079a6a','送盧少府使入秦','孟浩然','唐','唐诗','tang','','[]','楚關望秦國，相去千里餘。',48,'全唐诗/poet.tang.7000.json','["楚關望秦國，相去千里餘。", "州縣勤王事，山河轉使車。", "祖筵江上列，離恨別前書。", "願及芳年賞，嬌鶯二月初。"]'),
('1bedf7d6-42ff-49b2-980f-7d451e1cb90d','送袁十嶺南尋弟','孟浩然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','早聞牛渚詠，今見鶺鴒心。',48,'全唐诗/poet.tang.7000.json','["早聞牛渚詠，今見鶺鴒心。", "羽翼嗟零落，悲鳴別故林。", "蒼梧白雲遠，煙水洞庭深。", "萬里獨飛去，南風遲爾音。"]'),
('051e7f83-3873-4fa7-9819-e8f6d0dcf204','永嘉別張子容','孟浩然','唐','唐诗','tang','','[]','舊國余歸楚，新年子北征。',36,'全唐诗/poet.tang.7000.json','["舊國余歸楚，新年子北征。", "挂帆愁海路，分手戀朋情。", "日夕故園意，汀洲春草生。"]'),
('fcf8c5c3-1478-4ad7-a85d-55e1351a766d','東京留別諸公','孟浩然','唐','唐诗','tang','','[]','吾道昧所適，驅車還向東。',48,'全唐诗/poet.tang.7000.json','["吾道昧所適，驅車還向東。", "主人開舊館，留客醉新豐。", "樹繞溫泉綠，塵遮晚日紅。", "拂衣從此去，高步躡華嵩。"]'),
('43e9425e-7f31-4c3f-99b4-e6da547d6a85','送袁太祝尉豫章','孟浩然','唐','唐诗','tang','','[]','何幸遇休明，觀光來上京。',48,'全唐诗/poet.tang.7000.json','["何幸遇休明，觀光來上京。", "相逢武陵客，獨送豫章行。", "隨牒牽黃綬，離羣會墨卿。", "江南佳麗地，山水舊難名。"]'),
('e9aeb4ff-dc74-49cb-9777-5ddc98253cb0','都下送辛大之鄂','孟浩然','唐','唐诗','tang','','["\u9001\u522b", "\u601d\u4e61"]','南國辛居士，言歸舊竹林。',48,'全唐诗/poet.tang.7000.json','["南國辛居士，言歸舊竹林。", "未逢調鼎用，徒有濟川心。", "予亦忘機者，田園在漢陰。", "因君故鄉去，遙寄式微吟。"]'),
('d39b0639-2392-4ee1-aa16-0aa858b2ebb4','送席大','孟浩然','唐','唐诗','tang','','[]','惜爾懷其寶，迷邦倦客遊。',48,'全唐诗/poet.tang.7000.json','["惜爾懷其寶，迷邦倦客遊。", "江山歷全楚，河洛越成周。", "道路疲千里，鄉園老一丘。", "知君命不偶，同病亦同憂。"]'),
('23e25abf-74e3-4f84-9ee1-f5c7030858b9','送賈昇主簿之荆府','孟浩然','唐','唐诗','tang','','[]','奉使推能者，勤王不暫閑。',48,'全唐诗/poet.tang.7000.json','["奉使推能者，勤王不暫閑。", "觀風隨按察，乘騎度荆關。", "送別登何處，開筵舊峴山。", "征軒明日遠，空望郢門間。"]'),
('5826d16e-068d-45f0-8a86-919e35bc1471','送王大校書','孟浩然','唐','唐诗','tang','','[]','導漾自嶓冢，東流爲漢川。',48,'全唐诗/poet.tang.7000.json','["導漾自嶓冢，東流爲漢川。", "維桑君有意，解纜我開筵。", "雲雨從茲別，林端意渺然。", "尺書能不恡，時望鯉魚傳。"]'),
('4937a4e9-aa26-480f-bc6d-a2239d94f1ef','遊江西留別富陽裴劉二少府','孟浩然','唐','唐诗','tang','','[]','西上遊江西，臨流恨解攜。',48,'全唐诗/poet.tang.7000.json','["西上遊江西，臨流恨解攜。", "千山疊成嶂，萬水瀉爲溪。", "石淺流難泝，藤長險易躋。", "誰憐問津者，歲晏此中迷。"]'),
('3b9a4931-3927-4b33-a72c-f35979a91ec3','廣陵別薛八','孟浩然','唐','唐诗','tang','','[]','士有不得志，棲棲吳楚間。',48,'全唐诗/poet.tang.7000.json','["士有不得志，棲棲吳楚間。", "廣陵相遇罷，彭蠡泛舟還。", "檣出江中樹，波連海上山。", "風帆明日遠，何處更追攀。"]'),
('cebb0a57-e8cd-4af4-a7d3-05a4dc90bf0e','送洗然弟進士舉','孟浩然','唐','唐诗','tang','','[]','獻策金門去，承歡綵服違。',48,'全唐诗/poet.tang.7000.json','["獻策金門去，承歡綵服違。", "以吾一日長，念爾聚星稀。", "昏定須溫席，寒多未授衣。", "桂枝如已擢，早逐雁南飛。"]'),
('b5c19f4e-70c1-4168-b3a4-44008ed7b91c','崔明府宅夜觀妓','孟浩然','唐','唐诗','tang','','[]','白日既云暮，朱顏亦已酡。',48,'全唐诗/poet.tang.7000.json','["白日既云暮，朱顏亦已酡。", "畫堂初點燭，金幌半垂羅。", "長袖平陽曲，新聲子夜歌。", "從來慣留客，茲夕爲誰多。"]'),
('ed74c173-6f97-4bc3-b8f8-d3530882a027','同盧明府早秋宴張郎中海亭','孟浩然','唐','唐诗','tang','','[]','側聽弦歌宰，文書游夏徒。',48,'全唐诗/poet.tang.7000.json','["側聽弦歌宰，文書游夏徒。", "故園欣賞竹，爲邑幸來蘇。", "華省曾聯事，仙舟復與俱。", "欲知臨泛久，荷露漸成珠。"]'),
('b60ea171-1629-4c37-a497-34b66b97c086','盧明府早秋宴張郎中海園即事得秋字','孟浩然','唐','唐诗','tang','','[]','邑有弦歌宰，翔鸞狎野鷗。',48,'全唐诗/poet.tang.7000.json','["邑有弦歌宰，翔鸞狎野鷗。", "眷言華省舊，暫拂海池遊。", "鬱島藏深竹，前溪對舞樓。", "更聞書即事，雲物是清秋。"]'),
('d5de78bc-8cdf-4f9d-b21c-3a9762300ca9','宴榮二山池','孟浩然','唐','唐诗','tang','','[]','甲第開金穴，榮期樂自多。',48,'全唐诗/poet.tang.7000.json','["甲第開金穴，榮期樂自多。", "櫪嘶支遁馬，池養右軍鵝。", "竹引攜琴入，花邀載酒過。", "山公來取醉，時唱接䍦歌。"]'),
('e9944b19-7b4b-47fb-94f5-e9746e9c07a5','夏日與崔二十一同集衛明府宅','孟浩然','唐','唐诗','tang','','[]','言避一時暑，池亭五月開。',48,'全唐诗/poet.tang.7000.json','["言避一時暑，池亭五月開。", "喜逢金馬客，同飲玉人杯。", "舞鶴乘軒至，遊魚擁釣來。", "座中殊未起，簫管莫相催。"]'),
('d2b5090e-e6fe-4d4f-9dd6-fe94ff6d4b5c','清明日宴梅道士房','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7"]','林臥愁春盡，開軒覽物華。',48,'全唐诗/poet.tang.7000.json','["林臥愁春盡，開軒覽物華。", "忽逢青鳥使，邀入赤松家。", "丹竈初開火，仙桃正落花。", "童顏若可駐，何惜醉流霞。"]'),
('95f0a885-bbdc-4a4c-acc7-cb9d8f42eda4','寒夜張明府宅宴','孟浩然','唐','唐诗','tang','','[]','瑞雪初盈尺，寒宵始半更。',48,'全唐诗/poet.tang.7000.json','["瑞雪初盈尺，寒宵始半更。", "列筵邀酒伴，刻燭限詩成。", "香炭金爐煖，嬌弦玉指清。", "醉來方欲臥，不覺曉雞鳴。"]'),
('16943777-44e8-491d-a4a8-fb33f6d2c3c9','宴張別駕新齋','孟浩然','唐','唐诗','tang','','[]','世業傳珪組，江城佐股肱。',48,'全唐诗/poet.tang.7000.json','["世業傳珪組，江城佐股肱。", "高齋徵學問，虛薄濫先登。", "講論陪諸子，文章得舊朋。", "士元多賞激，衰病恨無能。"]'),
('b71d7c9c-7e92-4797-b2c9-8715dd0c2881','與諸子登峴山','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u540a\u53e4\u4f24\u4eca", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e94\u8a00\u5f8b\u8bd7"]','人事有代謝，往來成古今。',48,'全唐诗/poet.tang.7000.json','["人事有代謝，往來成古今。", "江山留勝跡，我輩復登臨。", "水落魚梁淺，天寒夢澤深。", "羊公碑字在，讀罷淚沾襟。"]'),
('bd87caec-0cbf-4003-b5ca-7ee0208c5232','與杭州薛司戶登樟亭樓作','孟浩然','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u666f"]','水樓一登眺，半出青林高。',48,'全唐诗/poet.tang.7000.json','["水樓一登眺，半出青林高。", "帟幕英僚敞，芳筵下客叨。", "山藏伯禹穴，城壓伍胥濤。", "今日觀溟漲，垂綸學釣鼇。"]'),
('87687c59-0427-4eda-81c9-1ab22702709f','尋天台山','孟浩然','唐','唐诗','tang','','[]','吾友太乙子，餐霞臥赤城。',48,'全唐诗/poet.tang.7000.json','["吾友太乙子，餐霞臥赤城。", "欲尋華頂去，不憚惡谿名。", "歇馬憑雲宿，揚帆截海行。", "高高翠微裏，遙見石梁橫。"]'),
('245a8ea8-f347-4cfe-90c2-6b6ef8b1d123','同曹三御史行泛湖歸越','孟浩然','唐','唐诗','tang','','[]','秋入詩人意，巴歌和者稀。',48,'全唐诗/poet.tang.7000.json','["秋入詩人意，巴歌和者稀。", "泛湖同逸旅，吟會是思歸。", "白簡徒推薦，滄洲已拂衣。", "杳冥雲外去，誰不羨鴻飛。"]'),
('b128b1ea-3c7c-48e2-8d21-566d654b10fa','晚泊潯陽望廬山','孟浩然','唐','唐诗','tang','','["\u5e90\u5c71", "\u5199\u666f", "\u6292\u60c5", "\u63cf\u5199\u5c71", "\u5199\u5c71"]','挂席幾千里，名山都未逢。',48,'全唐诗/poet.tang.7000.json','["挂席幾千里，名山都未逢。", "泊舟潯陽郭，始見香爐峰。", "嘗讀遠公傳，永懷塵外蹤。", "東林精舍近，日暮但聞鐘。"]'),
('96fe1282-e447-430f-a22a-72e9caaad9fd','陪張丞相登嵩陽樓','孟浩然','唐','唐诗','tang','','[]','獨步人何在，嵩陽有故樓。',48,'全唐诗/poet.tang.7000.json','["獨步人何在，嵩陽有故樓。", "歲寒問耆舊，行縣擁諸候。", "林莽北彌望，沮漳東會流。", "客中遇知己，無復越鄉憂。"]'),
('83128aff-73de-4b0d-a57d-ae2039b628ae','武陵泛舟','孟浩然','唐','唐诗','tang','','[]','武陵川路狹，前櫂入花林。',48,'全唐诗/poet.tang.7000.json','["武陵川路狹，前櫂入花林。", "莫測幽源裏，仙家信幾深。", "水回青嶂合，雲度綠溪陰。", "坐聽閑猿嘯，彌清塵外心。"]'),
('400cfc13-2169-4520-be44-0a5a1bb32567','與顏錢塘登障樓望潮作','孟浩然','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u548f\u7269", "\u8d5e\u7f8e", "\u548f\u7269\u8bd7", "\u5199\u6c34"]','百里聞雷震，鳴弦暫輟彈。',48,'全唐诗/poet.tang.7000.json','["百里聞雷震，鳴弦暫輟彈。", "府中連騎出，江上待潮觀。", "照日秋雲廻，浮天渤澥寬。", "驚濤來似雪，一坐凜生寒。"]'),
('46555335-434e-41cd-9811-b0376d8144d7','姚開府山池','孟浩然','唐','唐诗','tang','','[]','主人新邸第，相國舊池臺。',48,'全唐诗/poet.tang.7000.json','["主人新邸第，相國舊池臺。", "館是招賢闢，樓因教舞開。", "軒車人已散，簫管鳳初來。", "今日龍門下，誰知文舉才。"]'),
('20855c2b-467c-4ecd-af09-87d46a19a3f8','夏日浮舟過陳大水亭','孟浩然','唐','唐诗','tang','','["\u7530\u56ed", "\u590f\u5929"]','水亭涼氣多，閑櫂晚來過。',48,'全唐诗/poet.tang.7000.json','["水亭涼氣多，閑櫂晚來過。", "澗影見松竹，潭香聞芰荷。", "野童扶醉舞，山鳥助酣歌。", "幽賞未云徧，煙光奈夕何。"]'),
('d80d8466-83b1-4821-ad08-edcdf6c437f0','與白明府遊江','孟浩然','唐','唐诗','tang','','[]','故人來自遠，邑宰復初臨。',48,'全唐诗/poet.tang.7000.json','["故人來自遠，邑宰復初臨。", "執手恨爲別，同舟無異心。", "沿洄洲渚趣，演漾弦歌音。", "誰識躬耕者，年年梁甫吟。"]'),
('709677a9-d6dc-4967-ac80-f6783a0053a2','遊鳳林寺西嶺','孟浩然','唐','唐诗','tang','','[]','共喜年華好，來遊水石間。',48,'全唐诗/poet.tang.7000.json','["共喜年華好，來遊水石間。", "煙容開遠樹，春色滿幽山。", "壺酒朋情洽，琴歌野興閑。", "莫愁歸路暝，招月伴人還。"]'),
('05844dc3-b427-49c9-931f-73ab8e5b98f3','秋日陪李侍御渡松滋江','孟浩然','唐','唐诗','tang','','[]','南紀西江闊，皇華御史雄。',50,'全唐诗/poet.tang.7000.json','["南紀西江闊，皇華御史雄。", "截流寧假楫，挂席自生風。", "僚宷爭攀鷁，魚龍亦避驄。", "坐聽白[雪]唱，翻入櫂歌中。"]'),
('d065f491-380a-4109-a65e-c648bb9eeb33','陪獨孤使君同與蕭員外證登萬山亭','孟浩然','唐','唐诗','tang','','[]','萬山青嶂曲，千騎使君遊。',48,'全唐诗/poet.tang.7000.json','["萬山青嶂曲，千騎使君遊。", "神女鳴環佩，仙郎接獻酬。", "遍觀雲夢野，自愛江城樓。", "何必東南守，空傳沈隱侯。"]'),
('650782bc-3e01-44d2-969a-c49c5694e4a3','秋登張明府海亭','孟浩然','唐','唐诗','tang','','[]','海亭秋日望，委曲見江山。',48,'全唐诗/poet.tang.7000.json','["海亭秋日望，委曲見江山。", "染翰聊題壁，傾壺一解顏。", "歌逢彭澤令，歸賞故園間。", "予亦將琴史，棲遲共取閑。"]'),
('33885176-3272-4f6a-89a1-3673b82b52d6','臨渙裴明府席遇張十一房六','孟浩然','唐','唐诗','tang','','[]','河縣柳林邊，河橋晚泊船。',48,'全唐诗/poet.tang.7000.json','["河縣柳林邊，河橋晚泊船。", "文叨才子會，官喜故人連。", "笑語同今夕，輕肥異往年。", "晨風理歸櫂，吳楚各依然。"]'),
('82f69bc1-db32-4ecf-8029-3c5a56f1e709','梅道士水亭','孟浩然','唐','唐诗','tang','','[]','傲吏非凡吏，名流即道流。',48,'全唐诗/poet.tang.7000.json','["傲吏非凡吏，名流即道流。", "隱居不可見，高論莫能酬。", "水接仙源近，山藏鬼谷幽。", "再來迷處所，花下問漁舟。"]'),
('d60e7f5f-9fd7-404a-aa1e-e3f0b5024526','遊景空寺蘭若','孟浩然','唐','唐诗','tang','','[]','龍象經行處，山腰度石關。',48,'全唐诗/poet.tang.7000.json','["龍象經行處，山腰度石關。", "屢迷青嶂合，時愛綠蘿閑。", "宴息花林下，高談竹嶼間。", "寥寥隔塵事，疑是入雞山。"]'),
('4d19e8d9-4fbb-4d8d-9edf-40b941d3b05b','陪李侍御訪聰上人禪居','孟浩然','唐','唐诗','tang','','[]','欣逢柏臺友，共謁聰公禪。',48,'全唐诗/poet.tang.7000.json','["欣逢柏臺友，共謁聰公禪。", "石室無人到，繩牀見虎眠。", "陰崖常抱雪，枯澗爲生泉。", "出處雖云異，同歡在法筵。"]'),
('d9119ad9-0cb7-46f0-b713-1bc42f5efe88','遊精思觀回王白雲在後','孟浩然','唐','唐诗','tang','','[]','出谷未停午，到家日已曛。',48,'全唐诗/poet.tang.7000.json','["出谷未停午，到家日已曛。", "回瞻下山路，但見牛羊羣。", "樵子暗相失，草蟲寒不聞。", "衡門猶未掩，佇立望夫君。"]'),
('ffcb1174-6051-471d-bc51-4f7b74b04e65','夏日辨玉法師茅齋','孟浩然','唐','唐诗','tang','','[]','夏日茅齋裏，無風坐亦涼。',48,'全唐诗/poet.tang.7000.json','["夏日茅齋裏，無風坐亦涼。", "竹林深筍穊，藤架引梢長。", "燕覓巢窠處，蜂來造蜜房。", "物華皆可翫，花橤四時芳。"]'),
('40f5b51a-791b-4b78-952e-82e288cda0fe','與張折衝遊耆闍寺','孟浩然','唐','唐诗','tang','','[]','釋子彌天秀，將軍武庫才。',48,'全唐诗/poet.tang.7000.json','["釋子彌天秀，將軍武庫才。", "橫行塞北盡，獨步漢南來。", "貝葉傳金口，山樓作賦開。", "因君振嘉藻，江楚氣雄哉。"]'),
('47b4773e-03fc-4234-a59e-5e5c4c153a29','遊精思題觀主山房','孟浩然','唐','唐诗','tang','','[]','誤入桃源裏，初憐竹逕深。',48,'全唐诗/poet.tang.7000.json','["誤入桃源裏，初憐竹逕深。", "方知仙子宅，未有世人尋。", "舞鶴過閑砌，飛猿嘯密林。", "漸通玄妙理，深得坐忘心。"]'),
('e4edaf23-405c-4ace-9882-c347bc3ea45d','宿立公房','孟浩然','唐','唐诗','tang','','[]','支遁初求道，深公笑買山。',48,'全唐诗/poet.tang.7000.json','["支遁初求道，深公笑買山。", "何如石巖趣，自入戶庭間。", "苔潤春泉滿，蘿軒夜月閑。", "能令許玄度，吟臥不知還。"]'),
('4ccd9712-a50d-47f4-b603-bafe4a879f53','尋陳逸人故居','孟浩然','唐','唐诗','tang','','["\u6cf0\u5c71"]','人事一朝盡，荒蕪三徑休。',48,'全唐诗/poet.tang.7000.json','["人事一朝盡，荒蕪三徑休。", "始聞漳浦臥，奄作岱宗遊。", "池水猶含墨，風雲已落秋。", "今宵泉壑裏，何處覓藏舟。"]'),
('5f8e93b2-34fa-4d15-b7e2-fe3672e76753','尋梅道士','孟浩然','唐','唐诗','tang','','[]','彭澤先生柳，山陰道士鵝。',48,'全唐诗/poet.tang.7000.json','["彭澤先生柳，山陰道士鵝。", "我來從所好，停策漢陰多。", "重以觀魚樂，因之鼓枻歌。", "崔徐迹未朽，千載揖清波。"]'),
('37e43255-8176-414b-858f-fa0cf69bc970','陪姚使君題惠上人房','孟浩然','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u5199\u666f", "\u5411\u5f80"]','帶雪梅初煖，含煙柳尚青。',48,'全唐诗/poet.tang.7000.json','["帶雪梅初煖，含煙柳尚青。", "來窺童子偈，得聽法王經。", "會理知無我，觀空厭有形。", "迷心應覺悟，客思未遑寧。"]'),
('aa0cc741-a21b-42e7-8f47-c2553bdec94e','晚春題遠上人南亭','孟浩然','唐','唐诗','tang','','[]','給園支遁隱，虛寂養身和。',48,'全唐诗/poet.tang.7000.json','["給園支遁隱，虛寂養身和。", "春晚羣木秀，間關黃鳥歌。", "林棲居士竹，池養右軍鵝。", "炎月北窗下，清風期再過。"]'),
('965506ed-7133-4826-ad87-abdabc3e23d8','題大禹寺義公禪房','孟浩然','唐','唐诗','tang','','[]','義公習禪處，結構依空林。',48,'全唐诗/poet.tang.7000.json','["義公習禪處，結構依空林。", "戶外一峰秀，階前羣壑深。", "夕陽連雨足，空翠落庭陰。", "看取蓮花淨，應知不染心。"]'),
('56c3b0c4-e278-4ff4-af07-1febf280e064','尋白鶴巖張子容隱居','孟浩然','唐','唐诗','tang','','[]','白鶴青巖半，幽人有隱居。',48,'全唐诗/poet.tang.7000.json','["白鶴青巖半，幽人有隱居。", "階庭空水石，林壑罷樵漁。", "歲月青松老，風霜苦竹疎。", "覩茲懷舊業，回策返吾廬。"]'),
('974bfa5a-da38-4c0f-936f-c7849571d758','題融公蘭若','孟浩然','唐','唐诗','tang','','[]','精舍買金開，流泉遶砌回。',48,'全唐诗/poet.tang.7000.json','["精舍買金開，流泉遶砌回。", "芰荷薰講席，松柏映香臺。", "法雨晴飛去，天花晝下來。", "談玄殊未已，歸騎夕陽催。"]'),
('23410e2c-9358-4604-96bc-13506f2b2ca9','過景空寺故融公蘭若','孟浩然','唐','唐诗','tang','','[]','池上青蓮宇，林間白馬泉。',48,'全唐诗/poet.tang.7000.json','["池上青蓮宇，林間白馬泉。", "故人成異物，過客獨潸然。", "既禮新松塔，還尋舊石筵。", "平生竹如意，猶挂草堂前。"]'),
('0d6cbe25-f63a-448c-8b1f-a5dd2df5ad51','題張野人園廬','孟浩然','唐','唐诗','tang','','[]','與君園廬竝，微尚頗亦同。',48,'全唐诗/poet.tang.7000.json','["與君園廬竝，微尚頗亦同。", "耕釣方自逸，壺觴趣不空。", "門無俗士駕，人有上皇風。", "何處先賢傳，惟稱龐德公。"]'),
('f11c01e5-4f3d-4790-9460-a09b223c9123','李少府與楊九再來','孟浩然','唐','唐诗','tang','','[]','弱歲早登龍，今來喜再逢。',48,'全唐诗/poet.tang.7000.json','["弱歲早登龍，今來喜再逢。", "如何春月柳，猶憶歲寒松。", "煙火臨寒食，笙歌達曙鐘。", "喧喧鬬雞道，行樂羨朋從。"]'),
('7a8980bc-3acf-4173-909b-5a15ac7b990c','尋張五回夜園作','孟浩然','唐','唐诗','tang','','[]','聞就龐公隱，移居近洞湖。',48,'全唐诗/poet.tang.7000.json','["聞就龐公隱，移居近洞湖。", "興來林是竹，歸臥谷名愚。", "挂席樵風便，開軒琴月孤。", "歲寒何用賞，霜落故園蕪。"]'),
('8c855bc1-4c16-4e4f-8154-7fc0626c4ec7','裴司士員司戶見尋','孟浩然','唐','唐诗','tang','','[]','府僚能枉駕，家醞復新開。',48,'全唐诗/poet.tang.7000.json','["府僚能枉駕，家醞復新開。", "落日池上酌，清風松下來。", "廚人具雞黍，稚子摘楊梅。", "誰道山公醉，猶能騎馬回。"]'),
('c1cb5334-51e5-4c2b-b791-2bc74d5d693e','春中喜王九相尋','孟浩然','唐','唐诗','tang','','["\u6625\u5929"]','二月湖水清，家家春鳥鳴。',48,'全唐诗/poet.tang.7000.json','["二月湖水清，家家春鳥鳴。", "林花掃更落，徑草踏還生。", "酒伴來相命，開尊共解酲。", "當杯已入手，歌妓莫停聲。"]'),
('041749fb-f22e-49be-895a-9bd55d5bc691','李氏園林臥疾','孟浩然','唐','唐诗','tang','','[]','我愛陶家趣，園林無俗情。',48,'全唐诗/poet.tang.7000.json','["我愛陶家趣，園林無俗情。", "春雷百卉坼，寒食四鄰清。", "伏枕嗟公幹，歸山羨子平。", "年年白社客，空滯洛陽城。"]'),
('9309205e-1d08-4a7b-99ef-4a05a9ee4370','過故人莊','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u7530\u56ed", "\u53cb\u60c5", "\u521d\u4e2d\u53e4\u8bd7", "\u4e94\u8a00\u5f8b\u8bd7"]','故人具雞黍，邀我至田家。',48,'全唐诗/poet.tang.7000.json','["故人具雞黍，邀我至田家。", "綠樹村邊合，青山郭外斜。", "開筵面場圃，把酒話桑麻。", "待到重陽日，還來就菊花。"]'),
('58d404f3-989e-464e-843b-380f90c154aa','張七及辛大見尋南亭醉作','孟浩然','唐','唐诗','tang','','[]','山公能飲酒，居士好彈箏。',48,'全唐诗/poet.tang.7000.json','["山公能飲酒，居士好彈箏。", "世外交初得，林中契已幷。", "納涼風颯至，逃暑日將傾。", "便就南亭裏，餘尊惜解酲。"]'),
('542cb326-1037-4bd9-b0f6-6479d165dc4c','歲暮歸南山','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6292\u60c5", "\u5931\u610f"]','北闕休上書，南山歸敝廬。',48,'全唐诗/poet.tang.7000.json','["北闕休上書，南山歸敝廬。", "不才明主棄，多病故人疎。", "白髮催年老，青陽逼歲除。", "永懷愁不寐，松月夜窗虛。"]'),
('9fd845d2-6948-480f-879e-019e40d2e32d','南山下與老圃期種瓜','孟浩然','唐','唐诗','tang','','[]','樵牧南山近，林閭北郭賒。',48,'全唐诗/poet.tang.7000.json','["樵牧南山近，林閭北郭賒。", "先人留素業，老圃作鄰家。", "不種千株橘，惟資五色瓜。", "邵平能就我，開徑剪蓬麻。"]'),
('49642de8-9fce-42fa-a30e-e67d80a92ec9','泝江至武昌','孟浩然','唐','唐诗','tang','','[]','家本洞湖上，歲時歸思催。',48,'全唐诗/poet.tang.7000.json','["家本洞湖上，歲時歸思催。", "客心徒欲速，江路苦邅回。", "殘凍因風解，新正度臘開。", "行看武昌柳，髣髴映樓臺。"]'),
('f59f3b55-df15-4226-b0bf-4103bb74e1a1','舟中曉望','孟浩然','唐','唐诗','tang','','[]','挂席東南望，青山水國遙。',48,'全唐诗/poet.tang.7000.json','["挂席東南望，青山水國遙。", "舳艫爭利涉，來往接風潮。", "問我今何去，天台訪石橋。", "坐看霞色曉，疑是赤城標。"]'),
('02214ffe-3a50-4e2c-8dca-038d928eff3b','自洛之越','孟浩然','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u6124\u61d1"]','皇皇三十載，書劒兩無成。',48,'全唐诗/poet.tang.7000.json','["皇皇三十載，書劒兩無成。", "山水尋吳越，風塵厭洛京。", "扁舟泛湖海，長揖謝公卿。", "且樂杯中物，誰論世上名。"]'),
('3e11173c-add7-4d51-a7c7-9fa28a194396','途中遇晴','孟浩然','唐','唐诗','tang','','[]','已失巴陵雨，猶逢蜀坂泥。',48,'全唐诗/poet.tang.7000.json','["已失巴陵雨，猶逢蜀坂泥。", "天開斜景遍，山出晚雲低。", "餘濕猶霑草，殘流尚入溪。", "今宵有明月，鄉思遠悽悽。"]'),
('9c9a812b-17cd-4d10-8a03-a07611947a9d','歸至郢中','孟浩然','唐','唐诗','tang','','[]','遠遊經海嶠，返櫂歸山阿。',48,'全唐诗/poet.tang.7000.json','["遠遊經海嶠，返櫂歸山阿。", "日夕見喬木，鄉關在伐柯。", "愁隨江路盡，喜入郢門多。", "左右看桑土，依然即匪他。"]'),
('63d8dea3-4da6-4eca-888b-5005050c3909','夕次蔡陽館','孟浩然','唐','唐诗','tang','','[]','日暮馬行疾，城荒人住稀。',48,'全唐诗/poet.tang.7000.json','["日暮馬行疾，城荒人住稀。", "聽歌知近楚，投館忽如歸。", "魯堰田疇廣，章陵氣色微。", "明朝拜嘉慶，須著老萊衣。"]'),
('8a6b9883-ec6b-43cf-9378-22426db599f9','他鄉七夕','孟浩然','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u601d\u4e61", "\u4e03\u5915\u8282"]','他鄉逢七夕，旅館益羇愁。',48,'全唐诗/poet.tang.7000.json','["他鄉逢七夕，旅館益羇愁。", "不見穿鍼婦，空懷故國樓。", "緒風初減熱，新月始臨秋。", "誰忍窺河漢，迢迢問斗牛。"]'),
('2c93ca3b-8719-4004-8515-140d83266788','夜泊牛渚趁薛八船不及','孟浩然','唐','唐诗','tang','','[]','星羅牛渚夕，風退鷁舟遲。',48,'全唐诗/poet.tang.7000.json','["星羅牛渚夕，風退鷁舟遲。", "浦漵嘗同宿，煙波忽間之。", "榜歌空裏失，船火望中疑。", "明發泛潮海，茫茫何處期。"]'),
('513a6fc8-e634-4955-9830-7b6f13da87eb','曉入南山','孟浩然','唐','唐诗','tang','','[]','瘴氣曉氛氳，南山復水雲。',48,'全唐诗/poet.tang.7000.json','["瘴氣曉氛氳，南山復水雲。", "鯤飛今始見，鳥墮舊來聞。", "地接長沙近，江從汨渚分。", "賈生曾弔屈，予亦痛斯文。"]'),
('1695f005-7a4d-4cce-8694-df08455000f5','夜渡湘水','孟浩然','唐','唐诗','tang','','[]','客舟貪利涉，闇裏渡湘川。',48,'全唐诗/poet.tang.7000.json','["客舟貪利涉，闇裏渡湘川。", "露氣聞芳杜，歌聲識采蓮。", "榜人投岸火，漁子宿潭煙。", "行侶時相問，潯陽何處邊。"]'),
('50697800-8688-40ca-ac1a-43de223f5d12','赴京途中遇雪','孟浩然','唐','唐诗','tang','','[]','迢遞秦京道，蒼茫藏暮天。',48,'全唐诗/poet.tang.7000.json','["迢遞秦京道，蒼茫藏暮天。", "窮陰連晦朔，積雪滿山川。", "落雁迷沙渚，饑烏集野田。", "客愁空佇立，不見有人煙。"]'),
('efec7307-9053-4578-a033-b1c942f1672b','途次望鄉','孟浩然','唐','唐诗','tang','','[]','客行愁落日，鄉思重相催。',48,'全唐诗/poet.tang.7000.json','["客行愁落日，鄉思重相催。", "況在他山外，天寒夕鳥來。", "雪深迷郢路，雲暗失陽臺。", "可歎悽惶子，高歌誰爲媒。"]'),
('f881c202-e9ce-4128-87f3-3a54dd4442dd','永嘉上浦館逢張八子容','孟浩然','唐','唐诗','tang','','[]','逆旅相逢處，江村日暮時。',48,'全唐诗/poet.tang.7000.json','["逆旅相逢處，江村日暮時。", "衆山遙對酒，孤嶼共題詩。", "廨宇鄰蛟室，人煙接島夷。", "鄉園萬餘里，失路一相悲。"]'),
('e2f17cab-6467-4451-a5d6-129727037dcc','宿武陽即事','孟浩然','唐','唐诗','tang','','[]','川暗夕陽盡，孤舟泊岸初。',48,'全唐诗/poet.tang.7000.json','["川暗夕陽盡，孤舟泊岸初。", "嶺猿相呌嘯，潭嶂似空虛。", "就枕滅明燭，扣舷聞夜漁。", "雞鳴問何處，人物是秦餘。"]'),
('8255598c-9ddd-44f0-b2a1-4e7fcb662dc8','渡揚子江','孟浩然','唐','唐诗','tang','','[]','桂檝中流望，京江兩畔明。',48,'全唐诗/poet.tang.7000.json','["桂檝中流望，京江兩畔明。", "林開揚子驛，山出潤州城。", "海盡邊陰靜，江寒朔吹生。", "更聞楓葉下，淅瀝度秋聲。"]'),
('f8374b43-48b6-42be-993f-1465e20d113f','田家元日','孟浩然','唐','唐诗','tang','','["\u6292\u60c5", "\u6625\u8282", "\u519c\u4e8b"]','昨夜斗回北，今朝歲起東。',48,'全唐诗/poet.tang.7000.json','["昨夜斗回北，今朝歲起東。", "我年已強仕，無祿尚憂農。", "桑野就耕父，荷鋤隨牧童。", "田家占氣候，共說此年豐。"]'),
('d54601a1-c350-4df6-9183-11f1c5203318','九日得新字','孟浩然','唐','唐诗','tang','','[]','初九未成旬，重陽即此晨。',48,'全唐诗/poet.tang.7000.json','["初九未成旬，重陽即此晨。", "登高聞古事，載酒訪幽人。", "落帽恣歡飲，授衣同試新。", "茱萸正可佩，折取寄情親。"]'),
('e7fd7ff3-b5a1-4cf5-ac6d-c05d53b1ecfa','除夜樂城逢張少府','孟浩然','唐','唐诗','tang','','[]','雲海泛甌閩，風潮泊島濱。',48,'全唐诗/poet.tang.7000.json','["雲海泛甌閩，風潮泊島濱。", "何知歲除夜，得見故鄉親。", "余是乘槎客，君爲失路人。", "平生復能幾，一別十餘春。"]'),
('82fcb766-aecd-49f6-b532-69d1267cd6fb','歲除夜會樂城張少府宅','孟浩然','唐','唐诗','tang','','["\u5bb4\u996e", "\u53cb\u60c5", "\u6625\u8282"]','疇昔通家好，相知無間然。',48,'全唐诗/poet.tang.7000.json','["疇昔通家好，相知無間然。", "續明催畫燭，守歲接長筵。", "舊曲梅花唱，新正柏酒傳。", "客行隨處樂，不見度年年。"]'),
('7ab54826-ac0e-4cab-8aef-e9ea4839b7ea','寒夜','孟浩然','唐','唐诗','tang','','[]','閨夕綺窗閉，佳人罷縫衣。',48,'全唐诗/poet.tang.7000.json','["閨夕綺窗閉，佳人罷縫衣。", "理琴開寶匣，就枕臥重幃。", "夜久燈花落，薰籠香氣微。", "錦衾重自煖，遮莫曉霜飛。"]'),
('b2912dc0-60fd-407f-b203-9e4e9a5a4e24','賦得盈盈樓上女','孟浩然','唐','唐诗','tang','','[]','夫壻久離別，青樓空望歸。',48,'全唐诗/poet.tang.7000.json','["夫壻久離別，青樓空望歸。", "妝成卷簾坐，愁思嬾縫衣。", "燕子家家入，楊花處處飛。", "空牀難獨守，誰爲報金徽。"]'),
('0d066c36-ecd4-43ec-8a87-ec5e1afef33f','春意','孟浩然','唐','唐诗','tang','','[]','佳人能畫眉，妝罷出簾帷。',48,'全唐诗/poet.tang.7000.json','["佳人能畫眉，妝罷出簾帷。", "照水空自愛，折花將遺誰。", "春情多豔逸，春意倍相思。", "愁心極楊柳，一種亂如絲。"]'),
('adb33438-0559-4ddf-9083-0ac7f2cf1df7','閨情','孟浩然','唐','唐诗','tang','','[]','一別隔炎涼，君衣忘短長。',48,'全唐诗/poet.tang.7000.json','["一別隔炎涼，君衣忘短長。", "裁縫無處等，以意忖情量。", "畏瘦疑傷窄，防寒更厚裝。", "半啼封裹了，知欲寄誰將。"]'),
('fa42ef19-becc-4ee2-ba26-3b25e938db06','美人分香','孟浩然','唐','唐诗','tang','','[]','豔色本傾城，分香更有情。',48,'全唐诗/poet.tang.7000.json','["豔色本傾城，分香更有情。", "髻鬟垂欲解，眉黛拂能輕。", "舞學平陽態，歌翻子夜聲。", "春風狹斜道，含笑待逢迎。"]'),
('9db26b30-0913-4711-9557-e8d625092adc','傷峴山雲表觀主','孟浩然','唐','唐诗','tang','','[]','少小學書劒，秦吳多歲年。',48,'全唐诗/poet.tang.7000.json','["少小學書劒，秦吳多歲年。", "歸來一登眺，陵谷尚依然。", "豈意餐霞客，溘隨朝露先。", "因之問閭里，把臂幾人全。"]'),
('3acc29be-70aa-4daa-93ea-17435dbfddfc','題梧州陳司馬山齋','孟浩然','唐','唐诗','tang','','["\u6292\u60c5"]','南國無霜霰，連年對物華。',48,'全唐诗/poet.tang.7000.json','["南國無霜霰，連年對物華。", "青林暗換葉，紅橤亦開花。", "春去無山鳥，秋來見海槎。", "流芳雖可悅，會自泣長沙。"]'),
('0f5af383-765a-4d56-b00b-79ee2ccd5111','歲除夜有懷','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7f81\u65c5", "\u4e94\u8a00\u5f8b\u8bd7", "\u6625\u8282", "\u601d\u4e61"]','迢遞三巴路，羈危萬里身。',48,'全唐诗/poet.tang.7000.json','["迢遞三巴路，羈危萬里身。", "亂山殘雪夜，孤燈異鄉人。", "漸與骨肉遠，轉於奴僕親。", "那堪正飄泊，來日歲華新。"]'),
('72e7d327-0142-4e91-a9c1-ea6988cf1a1a','登安陽城樓','孟浩然','唐','唐诗','tang','','[]','縣城南面漢江流，江漲開成南雍州。',64,'全唐诗/poet.tang.7000.json','["縣城南面漢江流，江漲開成南雍州。", "才子乘春來騁望，羣公暇日坐銷憂。", "樓臺晚映青山郭，羅綺晴驕綠水洲。", "向夕波搖明月動，更疑神女弄珠遊。"]'),
('aaad319a-e2a1-4eb0-b943-fcf22f936735','登萬歲樓','孟浩然','唐','唐诗','tang','','[]','萬歲樓頭望故鄉，獨令鄉思更茫茫。',64,'全唐诗/poet.tang.7000.json','["萬歲樓頭望故鄉，獨令鄉思更茫茫。", "天寒雁度堪垂淚，日落猿啼欲斷腸。", "曲引古堤臨凍浦，斜分遠岸近枯楊。", "今朝偶見同袍友，却喜家書寄八行。"]'),
('3de48798-4e30-4693-97ca-3fef9671220b','除夜有懷','孟浩然','唐','唐诗','tang','','[]','五更鐘漏欲相催，四氣推遷往復回。',64,'全唐诗/poet.tang.7000.json','["五更鐘漏欲相催，四氣推遷往復回。", "帳裏殘燈纔去熖，爐中香氣盡成灰。", "漸看春逼芙蓉枕，頓覺寒銷竹葉杯。", "守歲家家應未臥，相思那得夢魂來。"]'),
('528e4d50-713f-4ce4-a051-d895834c7177','春情','孟浩然','唐','唐诗','tang','','[]','青樓曉日珠簾映，紅粉春妝寶鏡催。',64,'全唐诗/poet.tang.7000.json','["青樓曉日珠簾映，紅粉春妝寶鏡催。", "已厭交歡憐枕席，相將遊戲繞池臺。", "坐時衣帶縈纖草，行即裙裾掃落梅。", "更道明朝不當作，相期共鬬管絃來。"]'),
('fd9b6623-1ef8-4794-af81-9abb9f0881c1','長安早春','孟浩然','唐','唐诗','tang','','[]','關戍惟東井，城池起北辰。',72,'全唐诗/poet.tang.7000.json','["關戍惟東井，城池起北辰。", "咸歌太平日，共樂建寅春。", "雪盡青山樹，冰開黑水濱。", "草迎金埒馬，花伴玉樓人。", "鴻漸看無數，鶯歌聽欲頻。", "何當遂榮擢，歸及柳條新。"]'),
('0e57206e-6b37-458e-b7e8-50f1185d50e9','荆門上張丞相','孟浩然','唐','唐诗','tang','','[]','共理分荆國，招賢媿不材。',96,'全唐诗/poet.tang.7000.json','["共理分荆國，招賢媿不材。", "召南風更闡，丞相閣還開。", "覯止欣眉睫，沈淪拔草萊。", "坐登徐孺榻，頻接李膺杯。", "始慰蟬鳴柳，俄看雪間梅。", "四時年籥盡，千里客程催。", "日下瞻歸翼，沙邊厭曝鰓。", "佇聞宣室召，星象列三台。"]'),
('b6e1710a-4d30-437c-9fea-bc32f0f57b59','陪張丞相登荆城樓因寄薊州張使君及浪泊戍主劉家','孟浩然','唐','唐诗','tang','','[]','薊門天北畔，銅柱日南端。',72,'全唐诗/poet.tang.7000.json','["薊門天北畔，銅柱日南端。", "出守聲彌遠，投荒法未寬。", "側身聊倚望，攜手莫同歡。", "白璧無瑕玷，青松有歲寒。", "府中丞相閣，江上使君灘。", "興盡回舟去，方知行路難。"]'),
('c5995ee4-f2d9-46e3-8dd4-fec82bafe040','陪張丞相祠紫蓋山途經玉泉寺','孟浩然','唐','唐诗','tang','','[]','望秩宣王命，齋心待漏行。',120,'全唐诗/poet.tang.7000.json','["望秩宣王命，齋心待漏行。", "青衿列胄子，從事有參卿。", "五馬尋歸路，雙林指化城。", "聞鐘度門近，照膽玉泉清。", "皁蓋依松憩，緇徒擁錫迎。", "天宮上兜率，沙界豁迷明。", "欲就終焉志，恭聞智者名。", "人隨逝水沒，波逐覆舟傾。", "想像若在眼，周流空復情。", "謝公還欲臥，誰與濟蒼生。"]'),
('0ea9c522-80c5-4d5c-bcfb-775bae3d8041','陪張丞相自松滋江東泊渚宮','孟浩然','唐','唐诗','tang','','[]','放溜下松滋，登舟命檝師。',96,'全唐诗/poet.tang.7000.json','["放溜下松滋，登舟命檝師。", "詎忘經濟日，不憚沍寒時。", "洗幘豈獨古，濯纓良在茲。", "政成人自理，機息鳥無疑。", "雲物凝孤嶼，江山辨四維。", "晚來風稍急，冬至日行遲。", "臘響驚雲夢，漁歌激楚辭。", "渚宮何處是，川暝欲安之。"]'),
('9e6f7794-d0f7-47a1-bd3e-6062c16a0f8f','和張判官登萬山亭因贈洪府都督韓公','孟浩然','唐','唐诗','tang','','["\u957f\u6c5f"]','韓公是襄士，日賞城西岑。',120,'全唐诗/poet.tang.7000.json','["韓公是襄士，日賞城西岑。", "結搆意不淺，巖潭趣轉深。", "皇華一動詠，荆國幾謠吟。", "舊徑蘭勿剪，新堤柳欲陰。", "砌傍餘怪石，沙上有閑禽。", "自牧豫章郡，空瞻楓樹林。", "因聲寄流水，善聽在知音。", "耆舊眇不接，崔徐無處尋。", "物情多貴遠，賢俊豈無今。", "遲爾長江暮，澄清一洗心。"]'),
('dd71b080-94ae-41bd-a8ce-a7b43fc85a60','和宋太史北樓新亭','孟浩然','唐','唐诗','tang','','[]','返耕意未遂，日夕登城隅。',72,'全唐诗/poet.tang.7000.json','["返耕意未遂，日夕登城隅。", "誰道山林近，坐爲符竹拘。", "麗譙非改作，軒檻是新圖。", "遠水自嶓冢，長雲吞具區。", "願隨江燕賀，羞逐府僚趨。", "欲識狂歌者，丘園一豎儒。"]'),
('1060b761-fa9f-4c13-b6ad-da1b8cf43248','贈蕭少府','孟浩然','唐','唐诗','tang','','[]','上德如流水，安仁道若山。',72,'全唐诗/poet.tang.7000.json','["上德如流水，安仁道若山。", "聞君秉高節，而得奉清顏。", "鴻漸昇儀羽，牛刀列下班。", "處腴能不潤，居劇體常閑。", "去詐人無諂，除邪吏息姦。", "欲知清與潔，明月照澄灣。"]'),
('d6859788-9f1d-4e91-b870-e2c90921062d','秦中苦雨思歸贈袁左丞賀侍郎','孟浩然','唐','唐诗','tang','','[]','苦學三十載，閉門江漢陰。',96,'全唐诗/poet.tang.7000.json','["苦學三十載，閉門江漢陰。", "用賢遭聖日，羇旅屬秋霖。", "豈直昏墊苦，亦爲權勢沈。", "二毛催白髮，百鎰罄黃金。", "淚憶峴山墮，愁懷湘水深。", "謝公積憤懣，莊舃空謠吟。", "躍馬非吾事，狎鷗宜我心。", "寄言當路者，去矣北山岑。"]'),
('91224327-bb86-42a7-b076-b85e69878220','同張明府碧溪贈答','孟浩然','唐','唐诗','tang','','[]','別業聞新製，同聲和者多。',96,'全唐诗/poet.tang.7000.json','["別業聞新製，同聲和者多。", "還看碧溪答，不羨綠珠歌。", "自有陽臺女，朝朝拾翠過。", "綺筵鋪錦繡，妝牖閉藤蘿。", "秩滿休閑日，春餘景氣和。", "仙鳧能作伴，羅襪共凌波。", "曲島尋花藥，回潭折芰荷。", "更憐斜日照，紅粉豔青娥。"]'),
('6cfd24fe-7fb6-41b5-bb90-7c0eda48d6a2','久滯越中貽謝南池會稽賀少府','孟浩然','唐','唐诗','tang','','[]','陳平無產業，尼父倦東西。',72,'全唐诗/poet.tang.7000.json','["陳平無產業，尼父倦東西。", "負郭昔云翳，問津今亦迷。", "未能忘魏闕，空此滯秦稽。", "兩見夏雲起，再聞春鳥啼。", "懷仙梅福市，訪舊若耶溪。", "聖主賢爲寶，君何隱遯棲。"]'),
('606c8581-c618-44fe-b210-e6b9bd85c215','送韓使君除洪州都曹','孟浩然','唐','唐诗','tang','','[]','述職撫荆衡，分符襲寵榮。',96,'全唐诗/poet.tang.7000.json','["述職撫荆衡，分符襲寵榮。", "往來看擁傳，前後賴專城。", "勿翦棠猶在，波澄水更清。", "重推江漢理，旋改豫章行。", "召父多遺愛，羊公有令名。", "衣冠列祖道，耆舊擁前旌。", "峴首晨風送，江陵夜火迎。", "無才慙孺子，千里媿同聲。"]'),
('80aa5a4b-5b5a-4b58-9d5c-0caf70a39535','送莫甥兼諸昆弟從韓司馬入西軍','孟浩然','唐','唐诗','tang','','[]','念爾習詩禮，未曾違戶庭。',72,'全唐诗/poet.tang.7000.json','["念爾習詩禮，未曾違戶庭。", "平生早偏露，萬里更飄零。", "坐棄三牲養，行觀八陣形。", "飾裝辭故里，謀策赴邊庭。", "壯志吞鴻鵠，遙心伴鶺鴒。", "所從文且武，不戰自應寧。"]'),
('8f7cd549-d714-42ab-8e7a-890b3bc7ec23','峴山送蕭員外之荆州','孟浩然','唐','唐诗','tang','','[]','峴山江岸曲，郢水郭門前。',72,'全唐诗/poet.tang.7000.json','["峴山江岸曲，郢水郭門前。", "自古登臨處，非今獨黯然。", "亭樓明落照，井邑秀通川。", "澗竹生幽興，林風入管弦。", "再飛鵬激水，一舉鶴沖天。", "佇立三荆使，看君駟馬旋。"]'),
('3eef5ead-96d6-4531-8eeb-be21f3a31d68','送王昌齡之嶺南','孟浩然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u53cb\u60c5"]','洞庭去遠近，楓葉早驚秋。',72,'全唐诗/poet.tang.7000.json','["洞庭去遠近，楓葉早驚秋。", "峴首羊公愛，長沙賈誼愁。", "土毛無縞紵，鄉味有槎頭。", "已抱沈痼疾，更貽魑魅憂。", "數年同筆硯，茲夕間衾裯。", "意氣今何在，相思望斗牛。"]'),
('ca9483e0-c192-46da-8579-a8fa5bbc4208','峴山送張去非遊巴東','孟浩然','唐','唐诗','tang','','[]','峴山南郭外，送別每登臨。',72,'全唐诗/poet.tang.7000.json','["峴山南郭外，送別每登臨。", "沙岸江村近，松門山寺深。", "一言予有贈，三峽爾將尋。", "祖席宜城酒，征途雲夢林。", "蹉跎遊子意，眷戀故人心。", "去矣勿淹滯，巴東猿夜吟。"]'),
('a240044b-c1d2-49b9-b181-d29db41637da','奉先張明府休沐還鄉海亭宴集','孟浩然','唐','唐诗','tang','','[]','自君理畿甸，予亦經江淮。',72,'全唐诗/poet.tang.7000.json','["自君理畿甸，予亦經江淮。", "萬里書信斷，數年雲雨乖。", "歸來休澣日，始得賞心諧。", "朱紱恩雖重，滄州趣每懷。", "樹低新舞閣，山對舊書齋。", "何以發秋興，陰蟲鳴夜堦。"]'),
('fa3394ed-7763-4409-b695-7ba2c7aad299','宴張記室宅','孟浩然','唐','唐诗','tang','','[]','甲第金張館，門庭車騎多。',72,'全唐诗/poet.tang.7000.json','["甲第金張館，門庭車騎多。", "家封漢陽郡，文會楚材過。", "曲島浮觴酌，前山入詠歌。", "妓堂花映發，書閣柳逶迤。", "玉指調箏柱，金泥飾舞羅。", "寧知書劒者，歲月獨蹉跎。"]'),
('f933e19d-3030-447f-911e-214f6c712c94','宴崔明府宅夜觀妓','孟浩然','唐','唐诗','tang','','[]','畫堂觀妙妓，長夜正留賓。',72,'全唐诗/poet.tang.7000.json','["畫堂觀妙妓，長夜正留賓。", "燭吐蓮花豔，妝成桃李春。", "髻鬟低舞席，衫袖掩歌脣。", "汗濕偏宜粉，羅輕詎著身。", "調移箏柱促，歡會酒杯頻。", "倘使曹王見，應嫌洛浦神。"]'),
('132cea71-0a7f-46e4-87b5-3ce49c30cb57','盧明府九日峴山宴袁使君張郎中崔員外','孟浩然','唐','唐诗','tang','','[]','宇宙誰開闢，江山此鬱盤。',120,'全唐诗/poet.tang.7000.json','["宇宙誰開闢，江山此鬱盤。", "登臨今古用，風俗歲時觀。", "地理荆州分，天涯楚塞寬。", "百城今刺史，華省舊郎官。", "共美重陽節，俱懷落帽歡。", "酒邀彭澤載，琴輟武城彈。", "獻壽先浮菊，尋幽或藉蘭。", "煙虹鋪藻翰，松竹挂衣冠。", "叔子神如在，山公興未闌。", "傳聞騎馬醉，還向習池看。"]'),
('910cc3ee-4160-436f-8d1d-92b6aee411f0','登龍興寺閣','孟浩然','唐','唐诗','tang','','[]','閣道乘空出，披軒遠目開。',72,'全唐诗/poet.tang.7000.json','["閣道乘空出，披軒遠目開。", "逶迤見江勢，客至屢緣回。", "茲郡何填委，遙山復幾哉。", "蒼蒼皆草木，處處盡樓臺。", "驟雨一陽散，行舟四海來。", "鳥歸餘興遠，周覽更裴回。"]'),
('be11008d-45cc-4d1d-b2ab-b95fc88d9706','登總持寺浮圖','孟浩然','唐','唐诗','tang','','[]','半空躋寶塔，晴望盡京華。',72,'全唐诗/poet.tang.7000.json','["半空躋寶塔，晴望盡京華。", "竹遶渭川遍，山連上苑斜。", "四門開帝宅，阡陌俯人家。", "累劫從初地，爲童憶聚沙。", "一窺功德見，彌益道心加。", "坐覺諸天近，空香送落花。"]'),
('65ba04b2-3834-42ec-aac3-147a9da0c039','與崔二十一遊鏡湖寄包賀二公','孟浩然','唐','唐诗','tang','','[]','試覽鏡湖物，中流到底清。',72,'全唐诗/poet.tang.7000.json','["試覽鏡湖物，中流到底清。", "不知鱸魚味，但識鷗鳥情。", "帆得樵風送，春逢穀雨晴。", "將探夏禹穴，稍背越王城。", "府掾有包子，文章推賀生。", "滄浪醉後唱，因此寄同聲。"]'),
('39482263-8152-41b8-af07-4e18de311e3f','夜登孔伯昭南樓時沈太清朱昇在座','孟浩然','唐','唐诗','tang','','[]','誰家無風月，此地有琴尊。',72,'全唐诗/poet.tang.7000.json','["誰家無風月，此地有琴尊。", "山水會稽郡，詩書孔氏門。", "再來值秋杪，高閣夜無喧。", "華燭罷然蠟，清絃方奏鵾。", "沈生隱侯胤，朱子買臣孫。", "好我意不淺，登茲共話言。"]'),
('7e31ccbb-c82d-4c9f-9976-c81f05d1fe93','陪盧明府泛舟回作','孟浩然','唐','唐诗','tang','','[]','百里行春返，清流逸興多。',72,'全唐诗/poet.tang.7000.json','["百里行春返，清流逸興多。", "鷁舟隨雁泊，江火共星羅。", "已救田家旱，仍醫俗化訛。", "文章推後輩，風雅激頹波。", "高岸迷陵谷，新聲滿櫂歌。", "猶憐不才子，白首未登科。"]'),
('ed11140f-321d-4be7-9f03-b2f9f4c40e54','臘月八日於剡縣石城寺禮拜','孟浩然','唐','唐诗','tang','','[]','石壁開金像，香山倚鐵圍。',72,'全唐诗/poet.tang.7000.json','["石壁開金像，香山倚鐵圍。", "下生彌勒見，回向一心歸。", "竹柏禪庭古，樓臺世界稀。", "夕嵐增氣色，餘照發光輝。", "講席邀談柄，泉堂施浴衣。", "願承功德水，從此濯塵機。"]'),
('ce232659-3a0e-406f-ab50-eb4100f8db51','同獨孤使君東齋作','孟浩然','唐','唐诗','tang','','[]','郎官舊華省，天子命分憂。',72,'全唐诗/poet.tang.7000.json','["郎官舊華省，天子命分憂。", "襄土歲頻旱，隨車雨再流。", "雲陰自南楚，河潤及東周。", "廨宇宜新霽，田家賀有秋。", "竹間殘照入，池上夕陽浮。", "寄謝東陽守，何如八詠樓。"]'),
('ed5b191f-4753-4d8b-9bee-64a0158b3b6a','同王九題就師山房','孟浩然','唐','唐诗','tang','','[]','晚憩支公室，故人逢右軍。',72,'全唐诗/poet.tang.7000.json','["晚憩支公室，故人逢右軍。", "軒窗避炎暑，翰墨動新文。", "竹蔽簷前日，雨隨堦下雲。", "周遊清蔭徧，吟臥夕陽曛。", "江靜櫂歌歇，溪深樵語聞。", "歸途未忍去，攜手戀清芬。"]'),
('6f5c711f-ebf4-4e7c-add1-3702325489c3','冬至後過吳張二子檀溪別業','孟浩然','唐','唐诗','tang','','[]','卜築因自然，檀溪不更穿。',120,'全唐诗/poet.tang.7000.json','["卜築因自然，檀溪不更穿。", "園廬二友接，水竹數家連。", "直與南山對，非關選地偏。", "草堂時偃曝，蘭枻日周旋。", "外事情都遠，中流性所便。", "閑垂太公釣，興發子猷船。", "余亦幽棲者，經過竊慕焉。", "梅花殘臘月，柳色半春天。", "鳥泊隨陽雁，魚藏縮項鯿。", "停杯問山簡，何似習池邊。"]'),
('b73bc857-289d-4b8a-b1f4-f49b51eaae23','韓大使東齋會岳上人諸學士','孟浩然','唐','唐诗','tang','','[]','郡守虛陳榻，林間召楚材。',72,'全唐诗/poet.tang.7000.json','["郡守虛陳榻，林間召楚材。", "山川祈雨畢，雲物喜晴開。", "抗禮尊縫掖，臨流揖渡杯。", "徒攀朱仲李，誰薦和羹梅。", "翰墨緣情製，高深以意裁。", "滄洲趣不遠，何必問蓬萊。"]'),
('56d4bead-dc1a-46d3-a927-219029cce60f','上巳日澗南園期王山人陳七諸公不至','孟浩然','唐','唐诗','tang','','[]','搖艇候明發，花源弄晚春。',96,'全唐诗/poet.tang.7000.json','["搖艇候明發，花源弄晚春。", "在山懷綺季，臨漢憶荀陳。", "上巳期三月，浮杯興十旬。", "坐歌空有待，行樂恨無鄰。", "日晚蘭亭北，煙開曲水濱。", "浴蠶逢姹女，采艾值幽人。", "石壁堪題序，沙場好解紳。", "羣公望不至，虛擲此芳晨。"]'),
('f1a361f1-4112-403d-a52d-e3331caa52b0','齒坐呈山南諸隱','孟浩然','唐','唐诗','tang','','[]','習公有遺坐，高在白雲陲。',72,'全唐诗/poet.tang.7000.json','["習公有遺坐，高在白雲陲。", "樵子不見識，山僧賞自知。", "以余爲好事，攜手一來窺。", "竹露閑夜滴，松風清晝吹。", "從來抱微尚，況復感前規。", "於此無奇策，蒼生奚以爲。"]'),
('ab7dc33f-eee5-4a87-961f-1e1606cf7549','來闍黎新亭作','孟浩然','唐','唐诗','tang','','[]','八解禪林秀，三明給苑才。',96,'全唐诗/poet.tang.7000.json','["八解禪林秀，三明給苑才。", "地偏香界遠，心淨水亭開。", "傍險山查立，尋幽石逕回。", "瑞花長自下，靈藥豈須栽。", "碧網交紅樹，清泉盡綠苔。", "戲魚聞法聚，閑鳥誦經來。", "棄象玄應悟，忘言理必該。", "靜中何所得，吟詠也徒哉。"]'),
('14f2da14-aaf6-41e0-8f4e-6252eeb6043d','西山尋辛諤','孟浩然','唐','唐诗','tang','','[]','漾舟尋水便，因訪故人居。',72,'全唐诗/poet.tang.7000.json','["漾舟尋水便，因訪故人居。", "落日清川裏，誰言獨羨魚。", "石潭窺洞徹，沙岸歷紆徐。", "竹嶼見垂釣，茅齋聞讀書。", "款言忘景夕，清興屬涼初。", "回也一瓢飲，賢哉常晏如。"]'),
('6e5d7a31-e3ec-495d-a383-33bc585b976f','題長安主人壁','孟浩然','唐','唐诗','tang','','[]','久廢南山田，叨陪東閣賢。',72,'全唐诗/poet.tang.7000.json','["久廢南山田，叨陪東閣賢。", "欲隨平子去，猶未獻甘泉。", "枕籍琴書滿，褰帷遠岫連。", "我來如昨日，庭樹忽鳴蟬。", "促織驚寒女，秋風感長年。", "授衣當九月，無褐竟誰憐。"]'),
('c01f9163-b9a6-4673-962c-80aac7ede94e','行出東山望漢川','孟浩然','唐','唐诗','tang','','[]','異縣非吾土，連山盡綠篁。',96,'全唐诗/poet.tang.7000.json','["異縣非吾土，連山盡綠篁。", "平田出郭少，盤坂入雲長。", "萬壑歸於漢，千峰劃彼蒼。", "猿聲亂楚峽，人語帶巴鄉。", "石上攢椒樹，藤間綴蜜房。", "雪餘春未煖，嵐解晝初陽。", "征馬疲登頓，歸帆愛渺茫。", "坐欣沿溜下，信宿見維桑。"]'),
('a39cd422-7092-479b-9131-7fcb40531622','夜泊宣城界','孟浩然','唐','唐诗','tang','','[]','西塞沿江島，南陵問驛樓。',72,'全唐诗/poet.tang.7000.json','["西塞沿江島，南陵問驛樓。", "湖平津濟闊，風止客帆收。", "去去懷前浦，茫茫泛夕流。", "石逢羅剎礙，山泊敬亭幽。", "火識梅根冶，煙迷楊葉洲。", "離家復水宿，相伴賴沙鷗。"]'),
('c8f6bc70-e056-460f-9ad3-f0b53f20f1fe','下灨石','孟浩然','唐','唐诗','tang','','[]','灨石三百里，沿洄千嶂間。',72,'全唐诗/poet.tang.7000.json','["灨石三百里，沿洄千嶂間。", "沸聲常活活，洊勢亦潺潺。", "跳沫魚龍沸，垂藤猿狖攀。", "榜人苦奔峭，而我忘險難。", "放溜情彌愜，登艫目自閑。", "暝帆何處宿，遙指落星灣。"]'),
('b18a462a-cc8a-4e4e-924d-7c4752ca1c73','初年樂城館中臥疾懷歸作','孟浩然','唐','唐诗','tang','','[]','異縣天隅僻，孤帆海畔過。',72,'全唐诗/poet.tang.7000.json','["異縣天隅僻，孤帆海畔過。", "往來鄉信斷，留滯客情多。", "臘月聞雷震，東風感歲和。", "蟄蟲驚戶穴，巢鵲眄庭柯。", "徒對芳尊酒，其如伏枕何。", "歸嶼理舟楫，江海正無波。"]'),
('5461fb74-6384-4ca7-a500-5e5995c78515','醉後贈馬四','孟浩然','唐','唐诗','tang','','[]','四海重然諾，吾嘗聞白眉。',24,'全唐诗/poet.tang.7000.json','["四海重然諾，吾嘗聞白眉。", "秦城遊俠客，相得半酣時。"]'),
('950b73a7-fe4b-4602-8464-1879af1808c0','贈王九','孟浩然','唐','唐诗','tang','','[]','日暮田家遠，山中勿久淹。',24,'全唐诗/poet.tang.7000.json','["日暮田家遠，山中勿久淹。", "歸人須早去，稚子望陶潛。"]'),
('dc934d30-29bf-4462-ba32-38021191e2fd','登峴山亭寄晉陵張少府','孟浩然','唐','唐诗','tang','','[]','峴首風湍急，雲帆若鳥飛。',24,'全唐诗/poet.tang.7000.json','["峴首風湍急，雲帆若鳥飛。", "憑軒試一問，張翰欲來歸。"]'),
('9377b2a8-066c-4fc7-8f1f-2a04bffa75b9','送朱大入秦','孟浩然','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','遊人武陵去，寶劒直千金。',24,'全唐诗/poet.tang.7000.json','["遊人武陵去，寶劒直千金。", "分手脫相贈，平生一片心。"]'),
('a7947239-6143-493d-8fc9-d2512a70151d','送友人之京','孟浩然','唐','唐诗','tang','','[]','君登青雲去，予望青山歸。',24,'全唐诗/poet.tang.7000.json','["君登青雲去，予望青山歸。", "雲山從此別，淚濕薜蘿衣。"]'),
('771d396c-e668-4b45-ac81-74b9b7dc4ad4','送張郎中遷京','孟浩然','唐','唐诗','tang','','[]','碧溪常共賞，朱邸忽遷榮。',24,'全唐诗/poet.tang.7000.json','["碧溪常共賞，朱邸忽遷榮。", "豫有相思意，聞君琴上聲。"]'),
('c17cf6be-bfee-4fef-8357-aa8090f62ddd','同張將薊門觀燈','孟浩然','唐','唐诗','tang','','[]','異俗非鄉俗，新年改故年。',24,'全唐诗/poet.tang.7000.json','["異俗非鄉俗，新年改故年。", "薊門看火樹，疑是燭龍然。"]'),
('d50e6d9c-f94f-46e5-95e3-24e745f58681','張郎中梅園中','孟浩然','唐','唐诗','tang','','[]','綺席鋪蘭杜，珠盤折芰荷。',24,'全唐诗/poet.tang.7000.json','["綺席鋪蘭杜，珠盤折芰荷。", "故園留不住，應是戀絃歌。"]'),
('a7aad8ae-2aec-488d-810a-788fba40d1f1','北澗泛舟','孟浩然','唐','唐诗','tang','','[]','北澗流恆滿，浮舟觸處通。',24,'全唐诗/poet.tang.7000.json','["北澗流恆滿，浮舟觸處通。", "沿洄自有趣，何必五湖中。"]'),
('cb168b3b-d104-4df7-9868-1e1225ddb941','春曉','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6625", "\u5199\u666f", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u60dc\u6625", "\u4e94\u8a00\u7edd\u53e5"]','春眠不覺曉，處處聞啼鳥。',24,'全唐诗/poet.tang.7000.json','["春眠不覺曉，處處聞啼鳥。", "夜來風雨聲，花落知多少。"]'),
('3a84fa6e-4dd0-4e4e-a236-a159949b27ca','洛中訪袁拾遺不遇','孟浩然','唐','唐诗','tang','','[]','洛陽訪才子，江嶺作流人。',24,'全唐诗/poet.tang.7000.json','["洛陽訪才子，江嶺作流人。", "聞說梅花早，何如北地春。"]'),
('05214923-ffd7-46bf-8d9a-184baed55542','尋菊花潭主人不遇','孟浩然','唐','唐诗','tang','','[]','行至菊花潭，村西日已斜。',24,'全唐诗/poet.tang.7000.json','["行至菊花潭，村西日已斜。", "主人登高去，雞犬空在家。"]'),
('6c385476-c68a-4ba6-8c8d-ae240d544d6e','檀溪尋故人','孟浩然','唐','唐诗','tang','','[]','花伴成龍竹，池分躍馬溪。',24,'全唐诗/poet.tang.7000.json','["花伴成龍竹，池分躍馬溪。", "田園人不見，疑向洞中棲。"]'),
('8a1025ff-9245-4515-89e8-6383d60fd8c1','揚子津望京口','孟浩然','唐','唐诗','tang','','[]','北固臨京口，夷山近海濱。',24,'全唐诗/poet.tang.7000.json','["北固臨京口，夷山近海濱。", "江風白浪起，愁殺渡頭人。"]'),
('80d1c689-314f-4fa0-86a6-20aca2182425','同儲十二洛陽道中作','孟浩然','唐','唐诗','tang','','[]','珠彈繁華子，金羈遊俠人。',24,'全唐诗/poet.tang.7000.json','["珠彈繁華子，金羈遊俠人。", "酒酣白日暮，走馬入紅塵。"]'),
('6632feca-d12b-48d4-b90f-5274c1fecaff','初下浙江舟中口號','孟浩然','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','八月觀潮罷，三江越海潯。',24,'全唐诗/poet.tang.7000.json','["八月觀潮罷，三江越海潯。", "回瞻魏闕路，空復子牟心。"]'),
('0bed9b02-991e-4e28-b631-86640147a712','宿建德江','孟浩然','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u63cf\u5199\u6c34", "\u5199\u666f", "\u601d\u4e61", "\u6c34", "\u6708\u4eae"]','移舟泊煙渚，日暮客愁新。',24,'全唐诗/poet.tang.7000.json','["移舟泊煙渚，日暮客愁新。", "野曠天低樹，江清月近人。"]'),
('ebb3d970-b5b1-4891-bc8d-fe0088ca52b1','問舟子','孟浩然','唐','唐诗','tang','','[]','向夕問舟子，前程復幾多。',24,'全唐诗/poet.tang.7000.json','["向夕問舟子，前程復幾多。", "灣頭正堪泊，淮裏足風波。"]'),
('64a2c649-a3cf-4553-8d46-679cb69c3acf','戲題','孟浩然','唐','唐诗','tang','','[]','客醉眠未起，主人呼解酲。',24,'全唐诗/poet.tang.7000.json','["客醉眠未起，主人呼解酲。", "已言雞黍熟，復道甕頭清。"]'),
('5346afe3-87f7-42fe-ac8c-894c2f4bdd20','涼州詞 一','孟浩然','唐','唐诗','tang','','[]','渾成紫檀金屑文，作得琵琶聲入雲。',32,'全唐诗/poet.tang.7000.json','["渾成紫檀金屑文，作得琵琶聲入雲。", "胡地迢迢三萬里，那堪馬上送明君。"]'),
('6e41ffa4-7782-43d7-986a-6feacb837dae','涼州詞 二','孟浩然','唐','唐诗','tang','','[]','異方之樂令人悲，羌笛胡笳不用吹。',32,'全唐诗/poet.tang.7000.json','["異方之樂令人悲，羌笛胡笳不用吹。", "坐看今夜關山月，思殺邊城游俠兒。"]'),
('ba5d5923-d1ff-4b93-879a-55944d3b1489','送新安張少府歸秦中','孟浩然','唐','唐诗','tang','','[]','試登秦嶺望秦川，遙憶青門春可憐。',32,'全唐诗/poet.tang.7000.json','["試登秦嶺望秦川，遙憶青門春可憐。", "仲月送君從此去，瓜時須及邵平田。"]'),
('4fe885f2-1527-4702-8696-86d3b452022a','送杜十四之江南','孟浩然','唐','唐诗','tang','','["\u79bb\u522b"]','荆吳相接水爲鄉，君去春江正淼茫。',32,'全唐诗/poet.tang.7000.json','["荆吳相接水爲鄉，君去春江正淼茫。", "日暮征帆何處泊，天涯一望斷人腸。"]'),
('3f0628cb-dfea-492b-b3a0-e81b609699b1','渡浙江問舟中人','孟浩然','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u6e21\u6c5f", "\u6109\u60a6"]','潮落江平未有風，扁舟共濟與君同。',32,'全唐诗/poet.tang.7000.json','["潮落江平未有風，扁舟共濟與君同。", "時時引領望天末，何處青山是越中。"]'),
('2b598d5c-f1c6-40d0-9780-9dee106fa04c','初秋','孟浩然','唐','唐诗','tang','','["\u79cb\u5929"]','不覺初秋夜漸長，清風習習重淒涼。',32,'全唐诗/poet.tang.7000.json','["不覺初秋夜漸長，清風習習重淒涼。", "炎炎暑退茅齋靜，堦下叢莎有露光。"]'),
('6bcc1566-337f-4c07-8de1-ffa9beb74b63','過融上人蘭若','孟浩然','唐','唐诗','tang','','[]','山頭禪室挂僧衣，窗外無人水鳥飛。',32,'全唐诗/poet.tang.7000.json','["山頭禪室挂僧衣，窗外無人水鳥飛。", "黃昏半在下山路，却聽泉聲戀翠微。"]'),
('d7da0fb7-2297-4d2d-8b2f-57ec832449ea','句','孟浩然','唐','唐诗','tang','','[]','微雲淡河漢，疎雨滴梧桐。',24,'全唐诗/poet.tang.7000.json','["微雲淡河漢，疎雨滴梧桐。", "逐逐懷良馭，蕭蕭顧樂鳴。"]'),
('3cb1e0d4-689a-4519-9ee2-68d8bd8c7c74','古風 一','李白','唐','唐诗','tang','','[]','大雅久不作，吾衰竟誰陳。',144,'全唐诗/poet.tang.7000.json','["大雅久不作，吾衰竟誰陳。", "王風委蔓草，戰國多荆榛。", "龍虎相啖食，兵戈逮狂秦。", "正聲何微茫，哀怨起騷人。", "揚馬激頹波，開流蕩無垠。", "廢興雖萬變，憲章亦已淪。", "自從建安來，綺麗不足珍。", "聖代復元古，垂衣貴清真。", "羣才屬休明，乘運共躍鱗。", "文質相炳煥，衆星羅秋旻。", "我志在刪述，垂輝暎千春。", "希聖如有立，絕筆於獲麟。"]'),
('52d3ace3-2199-48f3-9128-0559fcbeb1cb','古風 二','李白','唐','唐诗','tang','','[]','蟾蜍薄太清，蝕此瑤臺月。',84,'全唐诗/poet.tang.7000.json','["蟾蜍薄太清，蝕此瑤臺月。", "圓光虧中天，金魄遂淪沒。", "螮蝀入紫微，大明夷朝暉。", "浮雲隔兩曜，萬象昏陰霏。", "蕭蕭長門宮，昔是今已非。", "桂蠹花不實，天霜下嚴威。", "沈歎終永夕，感我涕沾衣。"]'),
('00e799f2-e320-4a2c-8690-531df44c0abc','古風 三','李白','唐','唐诗','tang','','[]','秦皇掃六合，虎視何雄哉。',146,'全唐诗/poet.tang.7000.json','["秦皇掃六合，虎視何雄哉。", "飛劒決浮雲，諸侯盡西來。", "明斷自天啓，大略駕羣才。", "收兵鑄金人，函谷正東開。", "銘功會稽嶺，騁望瑯琊臺。", "刑徒七十萬，起土驪山隈。", "尚採不死藥，茫然使心哀。", "連弩射海魚，長鯨正崔嵬。", "額鼻象五嶽，揚波噴雲雷。", "鬐鬣蔽青天，何由覩蓬萊。", "徐[巿]載秦女，樓船幾時迥。", "但見三泉下，金棺葬寒灰。"]'),
('1ea59ee7-8464-4981-82f6-f386332a2c4f','古風 四','李白','唐','唐诗','tang','','[]','鳳飛九千仞，五章備綵珍。',132,'全唐诗/poet.tang.7000.json','["鳳飛九千仞，五章備綵珍。", "銜書且虛歸，空入周與秦。", "橫絕歷四海，所居未得鄰。", "吾營紫河車，千載落風塵。", "藥物秘海嶽，採鉛青溪濱。", "時登大樓山，舉手望仙真。", "羽駕滅去影，飆車絕廻輪。", "尚恐丹液遲，志願不及申。", "徒霜鏡中髮，羞彼鶴上人。", "桃李何處開，此花非我春。", "唯應清都境，長與韓衆親。"]'),
('ae666bb8-1da4-4673-a01e-c8235e7426e4','古風 五','李白','唐','唐诗','tang','','[]','太白何蒼蒼，星辰上森列。',108,'全唐诗/poet.tang.7000.json','["太白何蒼蒼，星辰上森列。", "去天三百里，邈爾與世絕。", "中有綠髮翁，披雲臥松雪。", "不笑亦不語，冥棲在巖穴。", "我來逢真人，長跪問寶訣。", "粲然啓玉齒，授以鍊藥說。", "銘骨傳其語，竦身已電滅。", "仰望不可及，蒼然五情熱。", "吾將營丹砂，永與世人別。"]'),
('3a1189e1-3d49-4791-be62-c9574912a279','古風 六','李白','唐','唐诗','tang','','[]','代馬不思越，越禽不戀燕。',84,'全唐诗/poet.tang.7000.json','["代馬不思越，越禽不戀燕。", "情性有所習，土風固其然。", "昔別雁門關，今戍龍庭前。", "驚沙亂海日，飛雪迷胡天。", "蟣蝨生虎鶡，心魂逐旌旃。", "苦戰功不賞，忠誠難可宣。", "誰憐李飛將，白首沒三邊。"]'),
('6d1f40c7-9d1a-47f6-bb72-e5c31280c6be','古風 七','李白','唐','唐诗','tang','','[]','五鶴西北來，飛飛凌太清。',72,'全唐诗/poet.tang.7000.json','["五鶴西北來，飛飛凌太清。", "仙人綠雲上，自道安期名。", "兩兩白玉童，雙吹紫鸞笙。", "去影忽不見，回風送天聲。", "我欲一問之，飄然若流星。", "願餐金光草，壽與天齊傾。"]'),
('116a9706-0eca-4e95-aaf7-0abfa3c4554e','古風 八','李白','唐','唐诗','tang','','[]','咸陽二三月，宮柳黃金枝。',84,'全唐诗/poet.tang.7000.json','["咸陽二三月，宮柳黃金枝。", "綠幘誰家子，賣珠輕薄兒。", "日暮醉酒歸，白馬驕且馳。", "意氣人所仰，冶遊方及時。", "子雲不曉事，晚獻長楊辭。", "賦達身已老，草玄鬢若絲。", "投閣良可歎，但爲此輩嗤。"]'),
('3a1b3412-39ba-432d-bc88-064b88d8aa24','古風 九','李白','唐','唐诗','tang','','[]','莊周夢胡蝶，胡蝶爲莊周。',60,'全唐诗/poet.tang.7000.json','["莊周夢胡蝶，胡蝶爲莊周。", "一體更變易，萬事良悠悠。", "乃知蓬萊水，復作清淺流。", "青門種瓜人，舊日東陵侯。", "富貴故如此，營營何所求。"]'),
('116561a6-8e41-4ccf-8be4-4507065f8c8d','古風 十','李白','唐','唐诗','tang','','[]','齊有倜儻生，魯連特高妙。',60,'全唐诗/poet.tang.7000.json','["齊有倜儻生，魯連特高妙。", "明月出海底，一朝開光曜。", "却秦振英聲，後世仰末照。", "意輕千金贈，願向平原笑。", "吾亦澹蕩人，拂衣可同調。"]'),
('dd3a2a44-d25c-4ce7-ac54-5c84a4bbbb81','古風 十一','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河走東溟，白日落西海。',60,'全唐诗/poet.tang.7000.json','["黃河走東溟，白日落西海。", "逝川與流光，飄忽不相待。", "春容捨我去，秋髮已衰改。", "人生非寒松，年貌豈長在。", "吾當乘雲螭，吸景駐光彩。"]'),
('06ed6495-bdfd-4667-98ea-6203d2251861','古風 十二','李白','唐','唐诗','tang','','[]','松柏本孤直，難爲桃李顏。',72,'全唐诗/poet.tang.7000.json','["松柏本孤直，難爲桃李顏。", "昭昭嚴子陵，垂釣滄波間。", "身將客星隱，心與浮雲閑。", "長揖萬乘君，還歸富春山。", "清風灑六合，邈然不可攀。", "使我長歎息，冥棲巖石間。"]'),
('39486f9c-ca2e-4aba-a236-c59eb74046b1','古風 十三','李白','唐','唐诗','tang','','[]','君平既棄世，世亦棄君平。',72,'全唐诗/poet.tang.7000.json','["君平既棄世，世亦棄君平。", "觀變窮太易，探元化羣生。", "寂寞綴道論，空簾閉幽情。", "騶虞不虛來，鸑鷟有時鳴。", "安知天漢上，白日懸高名。", "海客去已久，誰人測沈冥。"]'),
('f26bce2d-b068-460a-b58b-b045e2e25f7d','古風 十四','李白','唐','唐诗','tang','','[]','胡關饒風沙，蕭索竟終古。',132,'全唐诗/poet.tang.7000.json','["胡關饒風沙，蕭索竟終古。", "木落秋草黃，登高望戎虜。", "荒城空大漠，邊邑無遺堵。", "白骨橫千霜，嵯峨蔽榛莽。", "借問誰凌虐，天驕毒威武。", "赫怒我聖皇，勞師事鼙鼓。", "陽和變殺氣，發卒騷中土。", "三十六萬人，哀哀淚如雨。", "且悲就行役，安得營農圃。", "不見征戍兒，豈知關山苦。", "李牧今不在，邊人飼豺虎。"]'),
('dd45a2ec-aa2b-40ee-9c8a-b55af89629b8','古風 十五','李白','唐','唐诗','tang','','[]','燕昭延郭隗，遂築黃金臺。',60,'全唐诗/poet.tang.7000.json','["燕昭延郭隗，遂築黃金臺。", "劇辛方趙至，鄒衍復齊來。", "奈何青雲士，棄我如塵埃。", "珠玉買歌笑，糟糠養賢才。", "方知黃鶴舉，千里獨裴回。"]'),
('0127020e-6c3e-4d06-a7a9-4926ed666a52','古風 十六','李白','唐','唐诗','tang','','[]','寶劒雙蛟龍，雪花照芙蓉。',72,'全唐诗/poet.tang.7000.json','["寶劒雙蛟龍，雪花照芙蓉。", "精光射天地，雷騰不可衝。", "一去別金匣，飛沈失相從。", "風胡滅已久，所以潛其鋒。", "吳水深萬丈，楚山邈千重。", "雌雄終不隔，神物會當逢。"]'),
('0052b26a-5f10-4ef0-a98b-09ae1b20a212','古風 十七','李白','唐','唐诗','tang','','[]','金華牧羊兒，乃是紫煙客。',48,'全唐诗/poet.tang.7000.json','["金華牧羊兒，乃是紫煙客。", "我願從之遊，未去髮已白。", "不知繁華子，擾擾何所迫。", "崑山採瓊蘂，可以煉精魄。"]'),
('ac9f6653-4759-41b8-ac15-4463fff27bac','古風 十八','李白','唐','唐诗','tang','','[]','天津三月時，千門桃與李。',192,'全唐诗/poet.tang.7000.json','["天津三月時，千門桃與李。", "朝爲斷腸花，暮逐東流水。", "前水復後水，古今相續流。", "新人非舊人，年年橋上遊。", "雞鳴海色動，謁帝羅公侯。", "月落西上陽，餘輝半城樓。", "衣冠照雲日，朝下散皇州。", "鞍馬如飛龍，黃金絡馬頭。", "行人皆辟易，志氣橫嵩丘。", "入門上高堂，列鼎錯珍羞。", "香風引趙舞，清管隨齊謳。", "七十紫鴛鴦，雙雙戲庭幽。", "行樂爭晝夜，自言度千秋。", "功成身不退，自古多愆尤。", "黃犬空歎息，綠珠成釁讐。", "何如鴟夷子，散髮櫂扁舟。"]'),
('8c8a7e2e-8f4f-4a67-b988-7e18ff9a397c','古風 十九','李白','唐','唐诗','tang','','["\u534e\u5c71", "\u5c71", "\u6e38\u4ed9", "\u751f\u6d3b", "\u4eba\u6c11", "\u540c\u60c5"]','西嶽蓮花山，迢迢見明星。',84,'全唐诗/poet.tang.7000.json','["西嶽蓮花山，迢迢見明星。", "素手把芙蓉，虛步躡太清。", "霓裳曳廣帶，飄拂昇天行。", "邀我登雲臺，高揖衛叔卿。", "恍恍與之去，駕鴻凌紫冥。", "俯視洛陽川，茫茫走胡兵。", "流血塗野草，豺狼盡冠纓。"]'),
('9c83c80d-c727-4248-bdee-f9e7d0620fa7','古風 二十','李白','唐','唐诗','tang','','[]','昔我遊齊都，登華不注峯。',180,'全唐诗/poet.tang.7000.json','["昔我遊齊都，登華不注峯。", "茲山何峻秀，綠翠如芙蓉。", "蕭颯古仙人，了知是赤松。", "借予一白鹿，自挾兩青龍。", "含笑凌倒景，欣然願相從。", "泣與親友別，欲語再三咽。", "勗君青松心，努力保霜雪。", "世路多險艱，白日欺紅顏。", "分手各千里，去去何時還。", "在世復幾時，倏如飄風度。", "空聞紫金經，白首愁相誤。", "撫己忽自笑，沈吟爲誰故。", "名利徒煎熬，安得閑余步。", "終留赤玉舄，東上蓬萊路。", "秦帝如我求，蒼蒼但煙霧。"]'),
('750933f5-19d3-443e-8fed-412d4712e587','古風 二十一','李白','唐','唐诗','tang','','[]','郢客吟白雪，遺響飛青天。',48,'全唐诗/poet.tang.7000.json','["郢客吟白雪，遺響飛青天。", "徒勞歌此曲，舉世誰爲傳。", "試爲巴人唱，和者乃數千。", "吞聲何足道，歎息空淒然。"]'),
('a1237bed-f6ad-4000-9ec3-6834b4faf264','古風 二十二','李白','唐','唐诗','tang','','[]','秦水別隴首，幽咽多悲聲。',84,'全唐诗/poet.tang.7000.json','["秦水別隴首，幽咽多悲聲。", "胡馬顧朔雪，躞蹀長嘶鳴。", "感物動我心，緬然含歸情。", "昔視秋蛾飛，今見春蠶生。", "嫋嫋桑柘葉，萋萋柳垂榮。", "急節謝流水，羈心搖懸旌。", "揮涕且復去，惻愴何時平。"]'),
('aefa9025-6e63-4927-a787-8f732c211705','古風 二十三','李白','唐','唐诗','tang','','[]','秋露白如玉，團團下庭綠。',84,'全唐诗/poet.tang.7000.json','["秋露白如玉，團團下庭綠。", "我行忽見之，寒早悲歲促。", "人生鳥過目，胡乃自結束。", "景公一何愚，牛山淚相續。", "物苦不知足，得隴又望蜀。", "人心若波瀾，世路有屈曲。", "三萬六千日，夜夜當秉燭。"]'),
('ee9f9829-d1b0-4a47-a72a-3d13022cb520','古風 二十四','李白','唐','唐诗','tang','','[]','大車揚飛塵，亭午暗阡陌。',60,'全唐诗/poet.tang.7000.json','["大車揚飛塵，亭午暗阡陌。", "中貴多黃金，連雲開甲宅。", "路逢鬬雞者，冠蓋何輝赫。", "鼻息干虹蜺，行人皆怵惕。", "世無洗耳翁，誰知堯與跖。"]'),
('42a1616c-831e-4d7a-91c5-4c41e54c66c6','古風 二十五','李白','唐','唐诗','tang','','[]','世道日交喪，澆風散淳源。',60,'全唐诗/poet.tang.7000.json','["世道日交喪，澆風散淳源。", "不採芳桂枝，反棲惡木根。", "所以桃李樹，吐花竟不言。", "大運有興沒，羣動爭飛奔。", "歸來廣成子，去入無窮門。"]'),
('518caa01-3b0b-4ed5-8ad3-bb1105723b40','古風 二十六','李白','唐','唐诗','tang','','["\u8ff0\u5fd7", "\u548f\u7269", "\u8377\u82b1", "\u548f\u7269\u8bd7", "\u7ec4\u8bd7"]','碧荷生幽泉，朝日豔且鮮。',60,'全唐诗/poet.tang.7000.json','["碧荷生幽泉，朝日豔且鮮。", "秋花冒綠水，密葉羅青煙。", "秀色空絕世，馨香竟誰傳。", "坐看飛霜滿，凋此紅芳年。", "結根未得所，願託華池邊。"]'),
('0e682445-490c-4e15-bab2-e176cce24cf6','古風 二十七','李白','唐','唐诗','tang','','[]','燕趙有秀色，綺樓青雲端。',60,'全唐诗/poet.tang.7000.json','["燕趙有秀色，綺樓青雲端。", "眉目豔皎月，一笑傾城歡。", "常恐碧草晚，坐泣秋風寒。", "纖手怨玉琴，清晨起長歎。", "焉得偶君子，共乘雙飛鸞。"]'),
('f354845c-a4b2-4850-a2a0-6a638d58c443','古風 二十八','李白','唐','唐诗','tang','','[]','容顏若飛電，時景如飄風。',72,'全唐诗/poet.tang.7000.json','["容顏若飛電，時景如飄風。", "草綠霜已白，日西月復東。", "華鬢不耐秋，颯然成衰蓬。", "古來賢聖人，一一誰成功。", "君子變猿鶴，小人爲沙蟲。", "不及廣成子，乘雲駕輕鴻。"]'),
('49945276-58d4-4d13-bd6d-27ccf65dad12','古風 二十九','李白','唐','唐诗','tang','','[]','三季分戰國，七雄成亂麻。',60,'全唐诗/poet.tang.7000.json','["三季分戰國，七雄成亂麻。", "王風何怨怒，世道終紛拏。", "至人洞玄象，高舉凌紫霞。", "仲尼欲浮海，吾祖之流沙。", "聖賢共淪沒，臨岐胡咄嗟。"]'),
('4ff129f9-a157-4e48-910d-891d4d39de98','古風 三十','李白','唐','唐诗','tang','','[]','玄風變太古，道喪無時還。',84,'全唐诗/poet.tang.7000.json','["玄風變太古，道喪無時還。", "擾擾季葉人，雞鳴趨四關。", "但識金馬門，誰知蓬萊山。", "白首死羅綺，笑歌無時閑。", "綠酒哂丹液，青娥凋素顏。", "大儒揮金椎，琢之詩禮間。", "蒼蒼三株樹，冥目焉能攀。"]'),
('32952fd2-5ea9-4e4b-bc05-e3148fc93824','古風 三十一','李白','唐','唐诗','tang','','[]','鄭客西入關，行行未能已。',60,'全唐诗/poet.tang.7000.json','["鄭客西入關，行行未能已。", "白馬華山君，相逢平原里。", "璧遺鎬池君，明年祖龍死。", "秦人相謂曰，吾屬可去矣。", "一往桃花源，千春隔流水。"]'),
('113394f1-0d71-4dae-a1cf-f5f209bf3dbe','古風 三十二','李白','唐','唐诗','tang','','[]','蓐收肅金氣，西陸弦海月。',60,'全唐诗/poet.tang.7000.json','["蓐收肅金氣，西陸弦海月。", "秋蟬號階軒，感物憂不歇。", "良辰竟何許，大運有淪忽。", "天寒悲風生，夜久衆星沒。", "惻惻不忍言，哀歌逮明發。"]'),
('e8c464a6-9b3b-457e-b75c-5581eff5635e','古風 三十三','李白','唐','唐诗','tang','','[]','北溟有巨魚，身長數千里。',48,'全唐诗/poet.tang.7000.json','["北溟有巨魚，身長數千里。", "仰噴三山雪，橫吞百川水。", "憑陵隨海運，燀赫因風起。", "吾觀摩天飛，九萬方未已。"]'),
('3ea15e4c-3349-44f4-802f-e5be472546c9','古風 三十四','李白','唐','唐诗','tang','','["\u7ec4\u8bd7", "\u6218\u4e89", "\u6292\u6000"]','羽檄如流星，虎符合專城。',144,'全唐诗/poet.tang.7000.json','["羽檄如流星，虎符合專城。", "喧呼救邊急，羣鳥皆夜鳴。", "白日曜紫微，三公運權衡。", "天地皆得一，澹然四海清。", "借問此何爲，荅言楚徵兵。", "渡瀘及五月，將赴雲南征。", "怯卒非戰士，炎方難遠行。", "長號別嚴親，日月慘光晶。", "泣盡繼以血，心摧兩無聲。", "困獸當猛虎，窮魚餌奔鯨。", "千去不一回，投軀豈全生。", "如何舞干戚，一使有苗平。"]'),
('a78a6471-f4b4-4d47-ade3-1d26d137dc7d','古風 三十五','李白','唐','唐诗','tang','','[]','醜女來效顰，還家驚四隣。',84,'全唐诗/poet.tang.7000.json','["醜女來效顰，還家驚四隣。", "壽陵失本步，笑殺邯鄲人。", "一曲斐然子，雕蟲喪天真。", "棘刺造沐猴，三年費精神。", "功成無所用，楚楚且華身。", "大雅思文王，頌聲久崩淪。", "安得郢中質，一揮成斧斤。"]'),
('064c0907-a7e8-4fb4-a28b-54717a9b0b38','古風 三十六','李白','唐','唐诗','tang','','[]','抱玉入楚國，見疑古所聞。',72,'全唐诗/poet.tang.7000.json','["抱玉入楚國，見疑古所聞。", "良寶終見棄，徒勞三獻君。", "直木忌先伐，芳蘭哀自焚。", "盈滿天所損，沈冥道爲羣。", "東海沈碧水，西關乘紫雲。", "魯連及柱史，可以躡清芬。"]'),
('06517d86-a597-4ed6-9880-4807e603942a','古風 三十七','李白','唐','唐诗','tang','','[]','燕臣昔慟哭，五月飛秋霜。',84,'全唐诗/poet.tang.7000.json','["燕臣昔慟哭，五月飛秋霜。", "庶女號蒼天，震風擊齊堂。", "精誠有所感，造化爲悲傷。", "而我竟何辜，遠身金殿傍。", "浮雲蔽紫闥，白日難回光。", "羣沙穢明珠，衆草凌孤芳。", "古來共歎息，流淚空霑裳。"]'),
('73dd417e-e491-4ea5-8dd2-c554e29bdff9','古風 三十八','李白','唐','唐诗','tang','','[]','孤蘭生幽園，衆草共蕪沒。',48,'全唐诗/poet.tang.7000.json','["孤蘭生幽園，衆草共蕪沒。", "雖照陽春暉，復悲高秋月。", "飛霜早淅瀝，綠豔恐休歇。", "若無清風吹，香氣爲誰發。"]'),
('abe109e7-f798-4942-8b34-166b80612ea2','古風 三十九','李白','唐','唐诗','tang','','[]','登高望四海，天地何漫漫。',72,'全唐诗/poet.tang.7000.json','["登高望四海，天地何漫漫。", "霜被羣物秋，風飄大荒寒。", "榮華東流水，萬事皆波瀾。", "白日掩徂輝，浮雲無定端。", "梧桐巢燕雀，枳棘棲鴛鸞。", "且復歸去來，劒歌行路難。"]'),
('f173eefa-4207-4158-9a4b-d16e3f78286b','古風 四十','李白','唐','唐诗','tang','','[]','鳳飢不啄粟，所食唯琅玕。',72,'全唐诗/poet.tang.7000.json','["鳳飢不啄粟，所食唯琅玕。", "焉能與羣雞，刺蹙爭一餐。", "朝鳴崑丘樹，夕飲砥柱湍。", "歸飛海路遠，獨宿天霜寒。", "幸遇王子晉，結交青雲端。", "懷恩未得報，感別空長歎。"]'),
('b06269e7-0997-4c1b-81d0-c96982041406','古風 四十一','李白','唐','唐诗','tang','','[]','朝弄紫沂海，夕披丹霞裳。',84,'全唐诗/poet.tang.7000.json','["朝弄紫沂海，夕披丹霞裳。", "揮手折若木，拂此西日光。", "雲臥遊八極，玉顏已千霜。", "飄飄入無倪，稽首祈上皇。", "呼我遊太素，玉杯賜瓊漿。", "一餐歷萬歲，何用還故鄉。", "永隨長風去，天外恣飄揚。"]'),
('22e27e7a-85e1-4ba2-bb9e-9fbaabb923f6','古風 四十二','李白','唐','唐诗','tang','','[]','搖裔雙白鷗，鳴飛滄江流。',48,'全唐诗/poet.tang.7000.json','["搖裔雙白鷗，鳴飛滄江流。", "宜與海人狎，豈伊雲鶴儔。", "寄形宿沙月，沿芳戲春洲。", "吾亦洗心者，忘機從爾遊。"]'),
('de6fcb78-d56f-4d3e-b456-12f67e91e41b','古風 四十三','李白','唐','唐诗','tang','','[]','周穆八荒意，漢皇萬乘尊。',60,'全唐诗/poet.tang.7000.json','["周穆八荒意，漢皇萬乘尊。", "淫樂心不極，雄豪安足論。", "西海宴王母，北宮邀上元。", "瑤水聞遺歌，玉杯竟空言。", "靈跡成蔓草，徒悲千載魂。"]'),
('b560ff1f-b156-4646-8b84-7d5e3d9e929c','古風 四十四','李白','唐','唐诗','tang','','[]','綠蘿紛葳蕤，繚繞松栢枝。',60,'全唐诗/poet.tang.7000.json','["綠蘿紛葳蕤，繚繞松栢枝。", "草木有所託，歲寒尚不移。", "奈何夭桃色，坐歎葑菲詩。", "玉顏豔紅彩，雲髮非素絲。", "君子恩已畢，賤妾將何爲。"]'),
('3d9cfd71-0c43-478e-baad-fb1740343f2f','古風 四十五','李白','唐','唐诗','tang','','[]','八荒馳驚飆，萬物盡凋落。',48,'全唐诗/poet.tang.7000.json','["八荒馳驚飆，萬物盡凋落。", "浮雲蔽頹陽，洪波振大壑。", "龍鳳脫罔罟，飄颻將安託。", "去去乘白駒，空山詠場藿。"]'),
('cd2124f8-ae92-43f7-bf26-5439d8d5fb3a','古風 四十六','李白','唐','唐诗','tang','','[]','一百四十年，國容何赫然。',84,'全唐诗/poet.tang.7000.json','["一百四十年，國容何赫然。", "隱隱五鳳樓，峨峨橫三川。", "王侯象星月，賓客如雲煙。", "鬬雞金宮裏，蹴鞠瑤臺邊。", "舉動搖白日，指揮回青天。", "當塗何翕忽，失路長棄捐。", "獨有揚執戟，閉關草太玄。"]'),
('3db87ddc-43a0-4209-a06c-71f336fd806a','古風 四十七','李白','唐','唐诗','tang','','[]','桃花開東園，含笑誇白日。',60,'全唐诗/poet.tang.7000.json','["桃花開東園，含笑誇白日。", "偶蒙東風榮，生此豔陽質。", "豈無佳人色，但恐花不實。", "宛轉龍火飛，零落早相失。", "詎知南山松，獨立自蕭飋。"]'),
('8b3c8702-6705-4385-bdb1-ee3f35b8d8ba','古風 四十八','李白','唐','唐诗','tang','','[]','秦皇按寶劒，赫怒震威神。',60,'全唐诗/poet.tang.7000.json','["秦皇按寶劒，赫怒震威神。", "逐日巡海右，驅石駕滄津。", "徵卒空九宇，作橋傷萬人。", "但求蓬島藥，豈思農鳸春。", "力盡功不贍，千載爲悲辛。"]'),
('f7e10bcd-f437-4679-aae6-7ad8f77f1626','古風 四十九','李白','唐','唐诗','tang','','[]','美人出南國，灼灼芙蓉姿。',48,'全唐诗/poet.tang.7000.json','["美人出南國，灼灼芙蓉姿。", "皓齒終不發，芳心空自持。", "由來紫宮女，共妬青蛾眉。", "歸去瀟湘沚，沈吟何足悲。"]'),
('bbc22422-4c55-49cf-90ee-24bb4cd68142','古風 五十','李白','唐','唐诗','tang','','[]','宋國梧臺東，野人得燕石。',48,'全唐诗/poet.tang.7000.json','["宋國梧臺東，野人得燕石。", "誇作天下珍，却哂趙王璧。", "趙璧無緇磷，燕石非貞真。", "流俗多錯誤，豈知玉與珉。"]'),
('551d7161-7d87-4b6a-868d-89dc4071d39b','古風 五十一','李白','唐','唐诗','tang','','[]','殷后亂天紀，楚懷亦已昏。',60,'全唐诗/poet.tang.7000.json','["殷后亂天紀，楚懷亦已昏。", "夷羊滿中野，菉葹盈高門。", "比干諫而死，屈平竄湘源。", "虎口何婉孌，女嬃空嬋媛。", "彭咸久淪沒，此意與誰論。"]'),
('4e8e88b9-b428-4860-aef7-5e5b078ba62e','古風 五十二','李白','唐','唐诗','tang','','[]','青春流驚湍，朱明驟回薄。',48,'全唐诗/poet.tang.7000.json','["青春流驚湍，朱明驟回薄。", "不忍看秋蓬，飄揚竟何託。", "光風滅蘭蕙，白露洒葵藿。", "美人不我期，草木日零落。"]'),
('04929604-1ced-4db8-9437-c97f069927e0','古風 五十三','李白','唐','唐诗','tang','','[]','戰國何紛紛，兵戈亂浮雲。',48,'全唐诗/poet.tang.7000.json','["戰國何紛紛，兵戈亂浮雲。", "趙倚兩虎鬬，晉爲六卿分。", "姦臣欲竊位，樹黨自相羣。", "果然田成子，一旦殺齊君。"]'),
('5fb65711-3aa7-42a3-8dbf-580c83b28b11','古風 五十四','李白','唐','唐诗','tang','','[]','倚劒登高臺，悠悠送春目。',60,'全唐诗/poet.tang.7000.json','["倚劒登高臺，悠悠送春目。", "蒼榛蔽層丘，瓊草隱深谷。", "鳳鳥鳴西海，欲集無珍木。", "鸒斯得所居，蒿下盈萬族。", "晉風日已頹，窮途方慟哭。"]'),
('6830895d-a140-4ce5-aa1e-97bb1aebe9e9','古風 五十五','李白','唐','唐诗','tang','','[]','齊瑟彈東吟，秦弦弄西音。',72,'全唐诗/poet.tang.7000.json','["齊瑟彈東吟，秦弦弄西音。", "慷慨動顏魄，使人成荒淫。", "彼美佞邪子，婉孌來相尋。", "一笑雙白璧，再歌千黃金。", "珍色不貴道，詎惜飛光沈。", "安識紫霞客，瑤臺鳴素琴。"]'),
('714f1a71-8889-4c49-8db4-7ff1bb985697','古風 五十六','李白','唐','唐诗','tang','','[]','越客採明珠，提攜出南隅。',48,'全唐诗/poet.tang.7000.json','["越客採明珠，提攜出南隅。", "清輝照海月，美價傾皇都。", "獻君君按劒，懷寶空長吁。", "魚目復相哂，寸心增煩紆。"]'),
('c14cb8d8-2275-4a11-8d25-3886e18179a1','古風 五十七','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','羽族稟萬化，小大各有依。',48,'全唐诗/poet.tang.7000.json','["羽族稟萬化，小大各有依。", "周周亦何辜，六翮掩不揮。", "願銜衆禽翼，一向黃河飛。", "飛者莫我顧，歎息將安歸。"]'),
('6ab58e8b-ee92-4cb2-a142-075bb08e5560','古風 五十八','李白','唐','唐诗','tang','','[]','我到巫山渚，尋古登陽臺。',48,'全唐诗/poet.tang.7000.json','["我到巫山渚，尋古登陽臺。", "天空綵雲滅，地遠清風來。", "神女去已久，襄王安在哉。", "荒淫竟淪替，樵牧徒悲哀。"]'),
('a9134bf8-16f7-4fc6-a27b-ad2598788bd4','古風 五十九','李白','唐','唐诗','tang','','[]','惻惻泣路岐，哀哀悲素絲。',108,'全唐诗/poet.tang.7000.json','["惻惻泣路岐，哀哀悲素絲。", "路岐有南北，素絲易變移。", "萬事固如此，人生無定期。", "田竇相傾奪，賓客互盈虧。", "世途多飜覆，交道方嶮巇。", "斗酒强然諾，寸心終自疑。", "張陳竟火滅，蕭朱亦星離。", "衆鳥集榮柯，窮魚守枯池。", "嗟嗟失權客，勤問何所規。"]'),
('b6e2618e-d556-44e6-af36-e645989334db','遠別離','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u79bb\u522b", "\u5199\u4eba", "\u6545\u4e8b", "\u5fe7\u56fd\u5fe7\u6c11", "\u6742\u66f2\u6b4c\u8f9e"]','遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。',179,'全唐诗/poet.tang.7000.json','["遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。", "海水直下萬里深，誰人不言此離苦。", "日慘慘兮雲冥冥，猩猩啼煙兮鬼嘯雨。", "我縱言之將何補，皇穹竊恐不照余之忠誠。", "雲憑憑兮欲吼怒，堯舜當之亦禪禹。", "君失臣兮龍爲魚，權歸臣兮鼠變虎。", "或言堯幽囚，舜野死。", "九疑聯綿皆相似，重瞳孤墳竟何是。", "帝子泣兮綠雲間，隨風波兮去無還。", "慟哭兮遠望，見蒼梧之深山。", "蒼梧山崩湘水絕，竹上之淚乃可滅。"]'),
('02a6ea79-3d96-41a6-8b43-43a0190af743','公無渡河','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','黃河西來決崑崙，咆哮萬里觸龍門。',133,'全唐诗/poet.tang.7000.json','["黃河西來決崑崙，咆哮萬里觸龍門。", "波滔天，堯咨嗟，大禹理百川，兒啼不窺家。", "殺湍煙洪水，九州始蠶麻。", "其害乃去，茫然風沙。", "被髮之叟狂而癡，清晨臨流欲奚爲。", "旁人不惜妻止之，公無渡河苦渡之。", "虎可搏，河難憑，公果溺死流海湄。", "有長鯨白齒若雪山，公乎公乎挂罥於其間，箜篌所悲竟不還。"]'),
('f15c4b50-ee89-4927-8cf3-15e3a6a6ab95','蜀道難','李白','唐','唐诗','tang','','["\u5c71\u6c34", "\u6292\u60c5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e"]','噫吁戲！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。',340,'全唐诗/poet.tang.7000.json','["噫吁戲！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。", "爾來四萬八千歲，不與秦塞通人煙。", "西當太白有鳥道，可以橫絕峨眉巔。", "地崩山摧壯士死，然後天梯石棧相鉤連。", "上有六龍回日之高標，下有衝波逆折之回川。", "黃鶴之飛尚不得過，猨猱欲度愁攀援。", "青泥何盤盤，百步九折縈巖巒。", "捫參歷井仰脅息，以手撫膺坐長歎。", "問君西遊何時還？畏途巉巖不可攀。", "但見悲鳥號古木，雄飛雌從繞林間。", "又聞子規啼夜月，愁空山，蜀道之難難於上青天，使人聽此凋朱顏。", "連峯去天不盈尺，枯松倒挂倚絕壁。", "飛湍瀑流爭喧豗，砅厓轉石萬壑雷。", "其險也如此，嗟爾遠道之人胡爲乎來哉！劒閣崢嶸而崔嵬，一夫當關，萬夫莫開。", "所守或匪親，化爲狼與豺。", "朝避猛虎，夕避長蛇。", "磨牙吮血，殺人如麻。", "錦城雖云樂，不如早還家。", "蜀道之難難於上青天，側身西望長咨嗟。"]'),
('c7817c04-eed3-4666-a89f-9a76928fabb7','梁甫吟','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5178\u6545", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4", "\u5148\u79e6\u81f3\u516d\u671d"]','長嘯梁甫吟，何時見陽春。',338,'全唐诗/poet.tang.7000.json','["長嘯梁甫吟，何時見陽春。", "君不見朝歌屠叟辭棘津，八十西來釣渭濱。", "寧羞白髮照清水，逢時吐氣思經綸。", "廣張三千六百釣，風期暗與文王親。", "大賢虎變愚不測，當年頗似尋常人。", "君不見高陽酒徒起草中，長揖山東隆準公。", "入門不拜騁雄辯，兩女輟洗來趨風。", "東下齊城七十二，指揮楚漢如旋蓬。", "狂客落魄尚如此，何況壯士當羣雄。", "我欲攀龍見明主，雷公砰訇震天鼓。", "帝傍投壺多玉女，三時大笑開電光。", "倏爍晦冥起風雨，閶闔九門不可通。", "以額扣關閽者怒，白日不照吾精誠。", "杞國無事憂天傾，䝟貐磨牙競人肉。", "騶虞不折生草莖，手接飛猱搏彫虎。", "側足焦原未言苦，智者可卷愚者豪。", "世人見我輕鴻毛，力排南山三壯士，齊相殺之費二桃。", "吳楚弄兵無劇孟，亞夫咍爾爲徒勞。", "梁甫吟，梁甫吟，聲正悲。", "張公兩龍劒，神物合有時。", "風雲感會起屠釣，大人𡸣屼當安之。"]'),
('49750e0a-0ab2-47b9-9722-cfb63fe45552','烏夜啼','李白','唐','唐诗','tang','','["\u7231\u60c5", "\u8ffd\u5fc6", "\u5973\u5b50"]','黃雲城邊烏欲棲，歸飛啞啞枝上啼。',48,'全唐诗/poet.tang.7000.json','["黃雲城邊烏欲棲，歸飛啞啞枝上啼。", "機中織錦秦川女，碧紗如煙隔窗語。", "停梭悵然憶遠人，獨宿孤房淚如雨。"]'),
('8b792a6a-9307-42bc-b6ba-e028ed6981f8','烏棲曲','李白','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4", "\u4e50\u5e9c", "\u8bbd\u523a"]','姑蘇臺上烏棲時，吳王宮裏醉西施。',32,'全唐诗/poet.tang.7000.json','["姑蘇臺上烏棲時，吳王宮裏醉西施。", "吳歌楚舞歡未畢，青山欲銜半邊日。"]'),
('3cf98d29-f652-4683-ba93-df5da16bd4be','戰城南','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6218\u4e89", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c", "\u8bbd\u523a"]','去年戰桑乾源，今年戰蔥河道。',146,'全唐诗/poet.tang.7000.json','["去年戰桑乾源，今年戰蔥河道。", "洗兵條支海上波，放馬天山雪中草。", "萬里長征戰，三軍盡衰老。", "匈奴以殺戮爲耕作，古來唯見白骨黃沙田。", "秦家築城避胡處，漢家還有烽火然。", "烽火然不息，征戰無已時。", "野戰格鬬死，敗馬號鳴向天悲。", "烏鳶啄人腸，銜飛上挂枯樹枝。", "士卒塗草莽，將軍空爾爲。", "乃知兵者是凶器，聖人不得已而用之。"]'),
('e5e5f969-ddac-4491-9cfe-d77742e1416d','將進酒','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u548f\u7269", "\u6292\u60c5", "\u9f13\u5439\u66f2\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','君不見黃河之水天上來，奔流到海不復迴。',204,'全唐诗/poet.tang.7000.json','["君不見黃河之水天上來，奔流到海不復迴。", "君不見高堂明鏡悲白髮，朝如青絲暮成雪。", "人生得意須盡歡，莫使金樽空對月。", "天生我材必有用，千金散盡還復來。", "烹羊宰牛且爲樂，會須一飲三百盃。", "岑夫子，丹丘生，將進酒，君莫停。", "與君歌一曲，請君爲我側耳聽。", "鐘鼓饌玉不足貴，但願長醉不願醒。", "古來聖賢皆寂寞，惟有飲者留其名。", "陳王昔時宴平樂，斗酒十千恣讙謔。", "主人何爲言少錢，徑須沽取對君酌。", "五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"]'),
('138052b8-1396-4f6b-b0e8-aca814a878ee','行行遊且獵篇','李白','唐','唐诗','tang','','["\u6e38\u730e", "\u8fb9\u585e"]','邊城兒，生年不讀一字書，但將遊獵誇輕趫。',100,'全唐诗/poet.tang.7000.json','["邊城兒，生年不讀一字書，但將遊獵誇輕趫。", "胡馬秋肥宜白草，騎來躡影何矜驕。", "金鞭拂雪揮鳴鞘，半酣呼鷹出遠郊。", "弓彎滿月不虛發，雙鶬迸落連飛髇。", "海邊觀者皆辟易，猛氣英風振沙磧。", "儒生不及游俠人，白首下帷復何益。"]'),
('af2f2138-fb22-49f8-b2f6-57abf04a7a4f','飛龍引二首 一','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u8054\u60f3", "\u4e50\u5e9c", "\u6292\u60c5"]','黃帝鑄鼎於荆山，鍊丹砂。',78,'全唐诗/poet.tang.8000.json','["黃帝鑄鼎於荆山，鍊丹砂。", "丹砂成黃金，騎龍飛上太清家。", "雲愁海思令人嗟，宮中綵女顏如花。", "飄然揮手凌紫霞，從風縱體登鸞車。", "登鸞車，侍軒轅。", "遨遊青天中，其樂不可言。"]'),
('9cb72451-c59d-4d32-84b8-89a529feeceb','飛龍引二首 二','李白','唐','唐诗','tang','','["\u795e\u8bdd", "\u7434\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u6292\u60c5"]','鼎湖流水清且閑，軒轅去時有弓劒。',108,'全唐诗/poet.tang.8000.json','["鼎湖流水清且閑，軒轅去時有弓劒。", "古人傳道留其間，後宮嬋娟多花顏。", "乘鸞飛煙亦不還，騎龍攀天造天關。", "造天關，聞天語，長雲河車載玉女。", "載玉女，過紫皇，紫皇乃賜白兔所擣之藥方，後天而老彫三光。", "下視瑤池見王母，蛾眉蕭颯如秋霜。"]'),
('e41141f3-437d-4bb1-ba8b-a52044e3d17c','天馬歌','李白','唐','唐诗','tang','','[]','天馬來出月支窟，背爲虎文龍翼骨。',276,'全唐诗/poet.tang.8000.json','["天馬來出月支窟，背爲虎文龍翼骨。", "嘶青雲，振綠髮，蘭筋權奇走滅沒。", "騰崑崙，歷西極，四足無一蹶。", "雞鳴刷燕晡秣越，神行電邁躡慌惚。", "天馬呼，飛龍趨，目明長庚臆雙鳧。", "尾如流星首渴烏，口噴紅光汗溝朱。", "曾陪時龍躡天衢，羈金絡月照皇都。", "逸氣稜稜淩九區，白璧如山誰敢沽。", "回頭笑紫燕，但覺爾輩愚。", "天馬奔，戀君軒，駷躍驚矯浮雲飜。", "萬里足躑躅，遙瞻閶闔門。", "不逢寒風子，誰採逸景孫。", "白雲在青天，丘陵遠崔嵬。", "鹽車上峻坂，倒行逆施畏日晚。", "伯樂翦拂中道遺，少盡其力老棄之。", "願逢田子方，惻然爲我悲。", "雖有玉山禾，不能療苦飢。", "嚴霜五月凋桂枝，伏櫪銜冤摧兩眉。", "請君贖獻穆天子，猶堪弄影舞瑤池。"]'),
('c348bc2e-f50d-436b-88b7-c198d63dacfc','行路難三首 一','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u6cb3", "\u52b1\u5fd7", "\u53cb\u60c5", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7"]','金樽清酒斗十千，玉盤珍羞直萬錢。',96,'全唐诗/poet.tang.8000.json','["金樽清酒斗十千，玉盤珍羞直萬錢。", "停杯投筯不能食，拔劒四顧心茫然。", "欲渡黃河冰塞川，將登太行雪滿山。", "閑來垂釣碧溪上，忽復乘舟夢日邊。", "行路難，行路難，多岐路，今安在。", "長風破浪會有時，直挂雲帆濟滄海。"]'),
('801c3192-8001-4238-8ecf-0111f490e84c','行路難三首 二','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u5931\u610f", "\u53f9\u606f", "\u5510\u8bd7\u4e09\u767e\u9996"]','大道如青天，我獨不得出。',119,'全唐诗/poet.tang.8000.json','["大道如青天，我獨不得出。", "羞逐長安社中兒，赤雞白狗賭梨栗。", "彈劒作歌奏苦聲，曳裾王門不稱情。", "淮陰市井笑韓信，漢朝公卿忌賈生。", "君不見昔時燕家重郭隗，擁篲折節無嫌猜。", "劇辛樂毅感恩分，輸肝剖膽效英才。", "昭王白骨縈爛草，誰人更掃黃金臺。", "行路難，歸去來。"]'),
('a7b8e17f-ee93-4bdc-a144-b1ba5ab32bb5','行路難三首 三','李白','唐','唐诗','tang','','["\u4eba\u751f", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u6001\u5ea6"]','有耳莫洗潁川水，有口莫食首陽蕨。',131,'全唐诗/poet.tang.8000.json','["有耳莫洗潁川水，有口莫食首陽蕨。", "含光混世貴無名，何用孤高比雲月。", "吾觀自古賢達人，功成不退皆殞身。", "子胥既棄吳江上，屈原終投湘水濱。", "陸機雄才豈自保，李斯稅駕苦不早。", "華亭鶴唳詎可聞，上蔡蒼鷹何足道。", "君不見吳中張翰稱達生，秋風忽憶江東行。", "且樂生前一杯酒，何須身後千載名。"]'),
('3c1693fc-f4e6-43b7-a66f-6379c3a26eef','長相思','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u4f24\u6000"]','長相思，在長安，絡緯秋啼金井闌。',88,'全唐诗/poet.tang.8000.json','["長相思，在長安，絡緯秋啼金井闌。", "微霜淒淒簟色寒，孤燈不明思欲絕。", "卷帷望月空長歎，美人如花隔雲端。", "上有青冥之長天，下有淥水之波瀾。", "天長路遠魂飛苦，夢魂不到關山難。", "長相思，摧心肝。"]'),
('08ba0dc7-d6da-498a-bcc6-ba3fd176fd40','上留田行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c", "\u8bbd\u523a"]','行至上留田，孤墳何崢嶸。',195,'全唐诗/poet.tang.8000.json','["行至上留田，孤墳何崢嶸。", "積此萬古恨，春草不復生。", "悲風四邊來，腸斷白楊聲。", "借問誰家地，埋沒蒿里塋。", "古老向余言，言是上留田。", "蓬科馬鬣今已平，昔之弟死兄不葬，他人於此舉銘旌。", "一鳥死，百鳥鳴，一獸走，百獸驚。", "桓山之禽別離苦，欲去迴翔不能征。", "田氏倉卒骨肉分，青天白日摧紫荆。", "交柯之木本同形，東枝顦顇西枝榮。", "無心之物尚如此，參商胡乃尋天兵。", "孤竹延陵，讓國揚名。", "高風緬邈，頹波激清。", "尺布之謠，塞耳不能聽。"]'),
('9eda84f1-1d1c-4c2c-ad28-98a3963dcdf3','春日行','李白','唐','唐诗','tang','','["\u6625\u5929", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','深宮高樓入紫清，金作蛟龍盤繡楹。',148,'全唐诗/poet.tang.8000.json','["深宮高樓入紫清，金作蛟龍盤繡楹。", "佳人當窗弄白日，弦將手語彈鳴箏。", "春風吹落君王耳，此曲乃是昇天行。", "因出天池泛蓬瀛，樓船蹙沓波浪驚。", "三千雙蛾獻歌笑，撾鐘考鼓宮殿傾。", "萬姓聚舞歌太平，我無爲，人自寧。", "三十六帝欲相迎，仙人飄翩下雲軿。", "帝不去，留鎬京。", "安能爲軒轅，獨往入窅冥。", "小臣拜獻南山壽，陛下萬古垂鴻名。"]'),
('b0b8f475-e8d1-4690-bc4a-91d01dcb10fc','前有一樽酒行二首 一','李白','唐','唐诗','tang','','[]','春風東來忽相過，金樽淥酒生微波。',72,'全唐诗/poet.tang.8000.json','["春風東來忽相過，金樽淥酒生微波。", "落花紛紛稍覺多，美人欲醉朱顏酡。", "青軒桃李能幾何，流光欺人忽蹉砣。", "君起舞，日西夕，當年意氣不肯平，白髮如絲歎何益。"]'),
('d35fdc56-1086-4d5d-a99d-89fb16438732','前有一樽酒行二首 二','李白','唐','唐诗','tang','','[]','琴奏龍門之綠桐，玉壺美酒清若空。',60,'全唐诗/poet.tang.8000.json','["琴奏龍門之綠桐，玉壺美酒清若空。", "催弦拂柱與君飲，看朱成碧顏始紅。", "胡姬貌如花，當壚笑春風。", "笑春風，舞羅衣，君今不醉將安歸。"]'),
('a16e6544-8974-4234-a881-141beb0b6410','夜坐吟','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u97f3\u4e50", "\u4e50\u5e9c", "\u5973\u5b50"]','冬夜夜寒覺夜長，沈吟久坐坐北堂。',78,'全唐诗/poet.tang.8000.json','["冬夜夜寒覺夜長，沈吟久坐坐北堂。", "冰合井泉月入閨，金缸青凝照悲啼。", "金缸滅，啼轉多。", "掩妾淚，聽君歌。", "歌有聲，妾有情。", "情聲合，兩無違。", "一語不入意，從君萬曲梁塵飛。"]'),
('10465c42-a713-4a5d-9c02-2701a2bf7810','野田黃雀行','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u89c4\u529d", "\u5199\u9e1f", "\u76f8\u548c\u6b4c\u8f9e", "\u9e1f"]','遊莫逐炎洲翠，棲莫近吳宮燕。',46,'全唐诗/poet.tang.8000.json','["遊莫逐炎洲翠，棲莫近吳宮燕。", "吳宮火起焚巢窠，炎洲逐翠遭網羅。", "蕭條兩翅蓬蒿下，縱有鷹鸇奈若何。"]'),
('274f2db5-389b-4c17-b691-014fe104bc37','箜篌謠','李白','唐','唐诗','tang','','["\u54f2\u7406", "\u6742\u6b4c\u8c23\u8f9e", "\u53cb\u60c5"]','攀天莫登龍，走山莫騎虎。',100,'全唐诗/poet.tang.8000.json','["攀天莫登龍，走山莫騎虎。", "貴賤結交心不移，唯有嚴陵及光武。", "周公稱大聖，管蔡寧相容。", "漢謠一斗粟，不與淮南舂。", "兄弟尚路人，吾心安所從。", "他人方寸間，山海幾千重。", "輕言託朋友，對面九疑峯。", "開花必早落，桃李不如松。"]'),
('8d551c27-4ca3-47db-ab84-2aa31be40feb','雉朝飛','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u5b64\u72ec", "\u7231\u60c5", "\u4e50\u5e9c"]','麥隴青青三月時，白雉朝飛挾兩雌。',102,'全唐诗/poet.tang.8000.json','["麥隴青青三月時，白雉朝飛挾兩雌。", "錦衣繡翼何離褷，犢牧採薪感之悲。", "春天和，白日暖。", "啄食飲泉勇氣滿，爭雄鬬死繡頸斷。", "雉子班奏急管弦，傾心酒美盡玉椀。", "枯楊枯楊爾生稊，我獨七十而孤棲。", "彈弦寫恨意不盡，瞑目歸黃泥。"]'),
('9b9bfba7-1d21-4b85-9a0f-5aace405f734','上雲樂','李白','唐','唐诗','tang','','["\u53d9\u4e8b", "\u795e\u8bdd", "\u4e50\u5e9c", "\u6742\u6b4c\u8c23\u8f9e"]','金天之西，白日所沒。',294,'全唐诗/poet.tang.8000.json','["金天之西，白日所沒。", "康老胡雛，生彼月窟。", "巉巖容儀，戌削風骨。", "碧玉炅炅雙目瞳，黃金拳拳兩鬢紅。", "華蓋垂下睫，嵩嶽臨上唇。", "不覩詭譎貌，豈知造化神。", "大道是文康之嚴父，元氣乃文康之老親。", "撫頂弄盤古，推車轉天輪。", "云見日月初生時，鑄冶火精與水銀。", "陽烏未出谷，顧兔半藏身。", "女媧戲黃土，團作愚下人。", "散在六合間，濛濛若沙塵。", "生死了不盡，誰明此胡是仙真。", "西海栽若木，東溟植扶桑。", "別來幾多時，枝葉萬里長。", "中國有七聖，半路頹洪荒。", "陛下應運起，龍飛入咸陽。", "赤眉立盆子，白水興漢光。", "叱咤四海動，洪濤爲簸揚。", "舉足蹋紫微，天關自開張。", "老胡感至德，東來進仙倡。", "五色師子，九苞鳳皇。", "是老胡雞犬，鳴舞飛帝鄉。", "淋漓颯沓，進退成行。"]'),
('6724facd-c665-4f60-9266-2488d09006e3','白鳩辭','李白','唐','唐诗','tang','','[]','鏗鳴鐘，考朗鼓。',124,'全唐诗/poet.tang.8000.json','["鏗鳴鐘，考朗鼓。", "歌白鳩，引拂舞。", "白鳩之白誰與隣，霜衣雪襟誠可珍。", "含哺七子能平均，食不噎，性安馴，首農政，鳴陽春。", "天子刻玉杖，鏤形賜耆人。", "白鷺之白非純真，外潔其色心匪仁。", "闕五德，無司晨，胡爲啄我葭下之紫鱗。", "鷹鸇鵰鶚，貪而好殺。", "鳳凰雖大聖，不願以爲臣。"]'),
('d5ea326e-7443-4a7b-87e9-7d898afa1c85','日出行','李白','唐','唐诗','tang','','["\u8bf4\u7406", "\u6292\u60c5", "\u53d9\u4e8b"]','日出東方隈，似從地底來。',128,'全唐诗/poet.tang.8000.json','["日出東方隈，似從地底來。", "歷天又入海，六龍所舍安在哉？", "其始與終古不息，人非元氣安得與之久裴徊。", "草不謝榮於春風，木不怨落於秋天。", "誰揮鞭策驅四運，萬物興歇皆自然。", "羲和羲和，汝奚汨沒於荒淫之波。", "魯陽何德，駐景揮戈。", "逆道違天，矯誣實多。", "吾將囊括大塊，浩然與溟涬同科。"]'),
('b2768bca-cffd-4616-b1ff-3ead592f6f28','胡無人','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u8c6a\u8fc8"]','嚴風吹霜海草凋，筋幹精堅胡馬驕。',116,'全唐诗/poet.tang.8000.json','["嚴風吹霜海草凋，筋幹精堅胡馬驕。", "漢家戰士三十萬，將軍兼領霍嫖姚。", "流星白羽腰間插，劒花秋蓮光出匣。", "天兵照雪下玉關，虜箭如沙射金甲。", "雲龍風虎盡交回，太白入月敵可摧。", "敵可摧，旄頭滅，履胡之腸涉胡血。", "懸胡青天上，埋胡紫塞傍。", "胡無人，漢道昌。"]'),
('c38a852c-9bf1-4ce5-9c91-80a9d1ec34b0','北風行','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u601d\u5ff5", "\u5199\u96ea", "\u51ac\u5929", "\u5199\u98ce", "\u6292\u60c5"]','燭龍棲寒門，光曜猶旦開。',151,'全唐诗/poet.tang.8000.json','["燭龍棲寒門，光曜猶旦開。", "日月照之何不及此，唯有北風號怒天上來。", "燕山雪花大如席，片片吹落軒轅臺。", "幽州思婦十二月，停歌罷笑雙蛾摧。", "倚門望行人，念君長城苦寒良可哀。", "別時提劒救邊去，遺此虎紋金鞞靫。", "中有一雙白羽箭，蜘蛛結網生塵埃。", "箭空在，人今戰死不復回。", "不忍見此物，焚之已成灰。", "黃河捧土尚可塞，北風雨雪恨難裁。"]'),
('6b5af006-ef8b-4e17-8109-a2824e4e720f','俠客行','李白','唐','唐诗','tang','','["\u8d5e\u9882", "\u5199\u4eba", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','趙客縵胡纓，吳鉤霜雪明。',144,'全唐诗/poet.tang.8000.json','["趙客縵胡纓，吳鉤霜雪明。", "銀鞍照白馬，颯沓如流星。", "十步殺一人，千里不留行。", "事了拂衣去，深藏身與名。", "閑過信陵飲，脫劒膝前橫。", "將炙啖朱亥，持觴勸侯嬴。", "三盃吐然諾，五嶽倒爲輕。", "眼花耳熱後，意氣素霓生。", "救趙揮金槌，邯鄲先震驚。", "千秋二壯士，烜赫大梁城。", "縱死俠骨香，不慙世上英。", "誰能書閤下，白首太玄經。"]'),
('4be77185-992e-4614-9746-de2e73c8a3c3','關山月','李白','唐','唐诗','tang','','["\u4e2d\u79cb", "\u5510\u8bd7\u4e09\u767e\u9996", "\u8fb9\u585e", "\u5c71", "\u601d\u4e61", "\u4e50\u5e9c"]','明月出天山，蒼茫雲海間。',74,'全唐诗/poet.tang.8000.json','["明月出天山，蒼茫雲海間。", "長風幾萬里，吹度玉門關。", "漢下白登道，胡窺青海灣。", "由來征戰地，不見有人還。", "[戍]客望邊色，思歸多苦顏。", "高樓當此夜，歎息未應閑。"]'),
('4afd4e21-8573-4595-b205-ec65a5462c73','獨漉篇','李白','唐','唐诗','tang','','["\u7231\u56fd"]','獨漉水中泥，水濁不見月。',145,'全唐诗/poet.tang.8000.json','["獨漉水中泥，水濁不見月。", "不見月尚可，水深行人沒。", "越鳥從南來，胡鷹亦北渡。", "我欲彎弓向天射，惜其中道失歸路。", "落葉別樹，飄零隨風。", "客無所托，悲與此同。", "羅幃舒卷，似有人開。", "明月直入，無心可猜。", "雄劒挂壁，時時龍鳴。", "不斷犀象，繡澀苔生。", "國耻未雪，何由成名。", "神鷹夢澤，不顧鴟鳶。", "爲君一擊，鵬[摶]鵬九天。"]'),
('ab3b9829-9a24-484e-9c99-1152c7cbfde5','登高丘而望遠','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u767b\u9ad8", "\u8054\u60f3", "\u4e50\u5e9c"]','登高丘，望遠海。',107,'全唐诗/poet.tang.8000.json','["登高丘，望遠海。", "六鼇骨已霜，三山流安在。", "扶桑半摧折，白日沈光彩。", "銀臺金闕如夢中，秦皇漢武空相待。", "精衛費木石，黿鼉無所憑。", "君不見驪山茂陵盡灰滅，牧羊之子來攀登。", "盜賊劫寶玉，精靈竟何能。", "窮兵黷武今如此，鼎湖飛龍安可乘。"]'),
('7527539f-7be4-42a0-a5aa-805fa72c5e38','陽春歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u6625\u5929", "\u4e50\u5e9c", "\u60dc\u6625"]','長安白日照春空，綠楊結烟垂裊風。',56,'全唐诗/poet.tang.8000.json','["長安白日照春空，綠楊結烟垂裊風。", "披香殿前花始紅，流芳發色繡戶中。", "繡戶中，相經過，飛燕皇后輕身舞，紫宮夫人絕世歌。"]'),
('4fc1c656-8a56-498c-8641-e1d2e438b912','楊叛兒','李白','唐','唐诗','tang','','["\u4e50\u66f2", "\u6e05\u5546\u66f2\u8f9e", "\u4e50\u5e9c"]','君歌楊叛兒，妾勸新豐酒。',52,'全唐诗/poet.tang.8000.json','["君歌楊叛兒，妾勸新豐酒。", "何許最關人，烏啼白門柳。", "烏啼隱楊花，君醉留妾家。", "博山爐中沈香火，雙煙一氣凌紫霞。"]'),
('eb42467b-d4b5-4703-b6d8-871a737e0892','雙燕離','李白','唐','唐诗','tang','','["\u5199\u71d5", "\u7231\u60c5", "\u5bd3\u8a00\u8bd7"]','雙燕復雙燕，雙飛令人羨。',76,'全唐诗/poet.tang.8000.json','["雙燕復雙燕，雙飛令人羨。", "玉樓珠閣不獨棲，金窗繡戶長相見。", "柏梁失火去，因入吳王宮。", "吳宮又焚蕩，雛盡巢亦空。", "憔悴一身在，孀雌憶故雄。", "雙飛難再得，傷我寸心中。"]'),
('66121e3b-7ca9-4890-a45d-d34c006c0328','山人勸酒','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u4ed5\u9014", "\u611f\u4f24", "\u4e50\u5e9c"]','蒼蒼雲松，落落綺皓。',130,'全唐诗/poet.tang.8000.json','["蒼蒼雲松，落落綺皓。", "春風爾來爲阿誰，蝴蝶忽然滿芳草。", "秀眉霜雪顏桃花，骨青髓綠長美好。", "稱是秦時避世人，勸酒相歡不知老。", "各守麋鹿志，耻隨龍虎爭。", "歘起佐太子，漢王乃復驚。", "顧謂戚夫人，彼翁羽翼成。", "歸來商山下，泛若雲無情。", "舉觴酹巢由，洗耳何獨清。", "浩歌望嵩嶽，意氣還相傾。"]'),
('0b363f17-455e-4c34-a6b7-924b66a78bda','于闐採花','李白','唐','唐诗','tang','','["\u7528\u4eba", "\u6742\u66f2\u6b4c\u8f9e", "\u611f\u4f24", "\u4e50\u5e9c"]','于闐採花人，自言花相似。',72,'全唐诗/poet.tang.8000.json','["于闐採花人，自言花相似。", "明妃一朝西入胡，胡中美女多羞死。", "乃知漢地多名姝，胡中無花可方比。", "丹青能令醜者妍，無鹽翻在深宮裏。", "自古妬蛾眉，胡沙埋皓齒。"]'),
('9b2e46d4-1af5-467f-a504-a16e25d51d1a','鞠歌行','李白','唐','唐诗','tang','','["\u4ed5\u9014", "\u76f8\u548c\u6b4c\u8f9e", "\u611f\u4f24", "\u4e50\u5e9c"]','玉不自言如桃李，魚目笑之卞和耻。',132,'全唐诗/poet.tang.8000.json','["玉不自言如桃李，魚目笑之卞和耻。", "楚國青蠅何太多，連城白璧遭讒毀。", "荆山長號泣血人，忠臣死爲刖足鬼。", "聽曲知寧戚，夷吾因小妻。", "秦穆五羊皮，買死百里奚。", "洗拂青雲上，當時賤如泥。", "朝歌鼓刀叟，虎變磻谿中。", "一舉釣六合，遂荒營丘東。", "平生渭水曲，誰識此老翁。", "奈何今之人，雙目送飛鴻。"]'),
('47f80106-17f9-4d26-a4e4-6255b3ef872a','幽澗泉','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u97f3\u4e50", "\u611f\u4f24", "\u4e50\u5e9c"]','拂彼白石，彈吾素琴。',113,'全唐诗/poet.tang.8000.json','["拂彼白石，彈吾素琴。", "幽澗愀兮流泉深，善手明徽高張清。", "心寂歷似千古，松颼飀兮萬尋。", "中見愁猨弔影而危處兮，呌秋木而長吟。", "客有哀時失職而聽者，淚淋浪以霑襟。", "乃緝商輟羽，潺湲成音。", "吾但寫聲發情於妙指，殊不知此曲之古今。", "幽澗泉，鳴深林。"]'),
('44c40b37-9d4a-4abe-9b68-007e83e8fb4e','王昭君二首 一','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u5199\u4eba", "\u4e50\u5e9c"]','漢家秦地月，流影照明妃。',72,'全唐诗/poet.tang.8000.json','["漢家秦地月，流影照明妃。", "一上玉關道，天涯去不歸。", "漢月還從東海出，明妃西嫁無來日。", "燕支長寒雪作花，蛾眉憔悴沒胡沙。", "生乏黃金枉圖畫，死留青冢使人嗟。"]'),
('67cde43b-5fa8-404d-a48e-09abb781f603','王昭君二首 二','李白','唐','唐诗','tang','','[]','昭君拂玉鞍，上馬啼紅頰。',24,'全唐诗/poet.tang.8000.json','["昭君拂玉鞍，上馬啼紅頰。", "今日漢宮人，明朝胡地妾。"]'),
('5e663ba8-49eb-41b9-a662-4f42f705d4b6','中山孺子妾歌','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u5931\u610f", "\u6742\u6b4c\u8c23\u8f9e"]','中山孺子妾，特以色見珍。',78,'全唐诗/poet.tang.8000.json','["中山孺子妾，特以色見珍。", "雖然不如延年妹，亦是當時絕世人。", "桃李出深井，花豔驚上春。", "一貴復一賤，關天豈由身。", "芙蓉老秋霜，團扇羞網塵。", "戚姬髡髮入舂市，萬古共悲辛。"]'),
('67b08a36-4eb4-47a1-b8fc-7fc3ee888f3d','荆州歌','李白','唐','唐诗','tang','','[]','白帝城邊足風波，瞿塘五月誰敢過。',40,'全唐诗/poet.tang.8000.json','["白帝城邊足風波，瞿塘五月誰敢過。", "荆州麥熟繭成蛾，繅絲憶君頭緒多，撥穀飛鳴奈妾何。"]'),
('9e402e3c-d2a6-46aa-aaba-1289ab9c5b1d','雉子斑','李白','唐','唐诗','tang','','[]','辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。',96,'全唐诗/poet.tang.8000.json','["辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。", "扇錦翼，雄風生。", "雙雌同飲啄，趫悍誰能爭。", "乍向草中耿介死，不求黃金籠下生。", "天地至廣大，何惜遂物情。", "善卷讓天子，務光亦逃名。", "所貴曠士懷，朗然合太清。"]'),
('f45b5770-f5ae-43a9-a039-c532cd66196a','相逢行','李白','唐','唐诗','tang','','[]','相逢紅塵內，高揖黃金鞭。',24,'全唐诗/poet.tang.8000.json','["相逢紅塵內，高揖黃金鞭。", "萬戶垂楊裏，君家阿那邊。"]'),
('4da568ec-903b-485d-9994-0dd520c74410','有所思','李白','唐','唐诗','tang','','[]','我思仙人乃在碧海之東隅，海寒多天風，白波連山倒蓬壺。',58,'全唐诗/poet.tang.8000.json','["我思仙人乃在碧海之東隅，海寒多天風，白波連山倒蓬壺。", "長鯨噴湧不可涉，撫心茫茫淚如珠。", "西來青鳥東飛去，願寄一書謝麻姑。"]'),
('58d13f67-ff43-4bbb-94d4-bb64f1f5b48f','久別離','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c"]','別來幾春未還家，玉窗五見櫻桃花。',97,'全唐诗/poet.tang.8000.json','["別來幾春未還家，玉窗五見櫻桃花。", "況有錦字書，開緘使人嗟。", "至此腸斷彼心絕，雲鬟綠鬢罷梳結，愁如回飆亂白雪。", "去年寄書報陽臺，今年寄書重相催。", "東風兮東風，爲我吹行雲使西來。", "待來竟不來，落花寂寂委清苔。"]'),
('f51e574b-61c2-45fb-b60d-2de4ecae9ce3','白頭吟','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5973\u5b50", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e", "\u5931\u610f"]','錦水東北流，波蕩雙鴛鴦。',212,'全唐诗/poet.tang.8000.json','["錦水東北流，波蕩雙鴛鴦。", "雄巢漢宮樹，雌弄秦草芳。", "寧同萬死碎綺翼，不忍雲間兩分張。", "此時阿嬌正嬌妬，獨坐長門愁日暮。", "但願君恩顧妾深，豈惜黃金買詞賦。", "相如作賦得黃金，丈夫好新多異心。", "一朝將聘茂陵女，文君因贈白頭吟。", "東流不作西歸水，落花辭條羞故林。", "兔絲固無情，隨風任傾倒。", "誰使女蘿枝，而來强縈抱。", "兩草猶一心，人心不如草。", "莫卷龍鬚席，從他生網絲。", "且留琥珀枕，或有夢來時。", "覆水再收豈滿杯，棄妾已去難重迴。", "古來得意不相負，祇今惟見青陵臺。"]'),
('b15fb5e8-46e1-4266-8371-e2bc1383f840','採蓮曲','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c", "\u8377\u82b1"]','若耶谿傍採蓮女，笑隔荷花共人語。',64,'全唐诗/poet.tang.8000.json','["若耶谿傍採蓮女，笑隔荷花共人語。", "日照新妝水底明，風飄香袂空中舉。", "岸上誰家遊冶郎，三三五五暎垂楊。", "紫騮嘶入落花去，見此踟躕空斷腸。"]'),
('44112ea6-a06c-485d-b2dd-21b94dda7b13','臨江王節士歌','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭白波木葉稀，燕鴻始入吳雲飛。',74,'全唐诗/poet.tang.8000.json','["洞庭白波木葉稀，燕鴻始入吳雲飛。", "吳雲寒，燕鴻苦，風號沙宿瀟湘浦。", "節士悲秋淚如雨，白日當天心。", "照之可以事明主，壯士憤，雄風生。", "安得倚天劒，跨海斬長鯨。"]'),
('9831fd2a-a86f-4def-9bdd-97e5a8759d8a','司馬將軍歌','李白','唐','唐诗','tang','','["\u6218\u58eb", "\u8d5e\u9882", "\u6218\u4e89", "\u6742\u6b4c\u8c23\u8f9e", "\u4e50\u5e9c"]','狂風吹古月，竊弄章華臺。',156,'全唐诗/poet.tang.8000.json','["狂風吹古月，竊弄章華臺。", "北落明星動光彩，南征猛將如雲雷。", "手中電擊倚天劒，直斬長鯨海水開。", "我見樓船壯心目，頗似龍驤下三蜀。", "揚兵習戰張虎旗，江中白浪如銀屋。", "身居玉帳臨河魁，紫髯若戟冠崔嵬。", "細柳開營揖天子，始知灞上爲嬰孩。", "羌笛橫吹阿嚲迴，向月樓中吹落梅。", "將軍自起舞長劒，壯士呼聲動九垓。", "功成獻凱見明主，丹青畫象麒麟臺。"]'),
('4dfa2d12-9bbf-4cd9-80cf-73d7feedc19d','君道曲','李白','唐','唐诗','tang','','[]','大君若天覆，廣運無不至。',56,'全唐诗/poet.tang.8000.json','["大君若天覆，廣運無不至。", "軒后爪牙嘗先太山稽，如心之使臂。", "小白鴻翼於夷吾，劉葛魚水本無二。", "土校可成牆，積德爲厚地。"]'),
('dc53625c-820a-4ac4-987a-45c3b9b9c361','結襪子','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u548f\u53f2\u6000\u53e4", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','燕南壯士吳門豪，筑中置鉛魚隱刀。',32,'全唐诗/poet.tang.8000.json','["燕南壯士吳門豪，筑中置鉛魚隱刀。", "感君恩重許君命，太山一擲輕鴻毛。"]'),
('7de71ee6-bbcf-47c1-a552-3bf83fe88f95','結客少年場行','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u8c6a\u8fc8", "\u4e50\u5e9c"]','紫燕黃金瞳，啾啾搖綠鬉。',120,'全唐诗/poet.tang.8000.json','["紫燕黃金瞳，啾啾搖綠鬉。", "平明相馳逐，結客洛門東。", "少年學劒術，凌轢白猨公。", "珠袍曳錦帶，匕首插吳鴻。", "由來萬夫勇，挾此生雄風。", "託交從劇孟，買醉入新豐。", "笑盡一杯酒，殺人都市中。", "羞道易水寒，從令日貫虹。", "燕丹事不立，虛沒秦帝宮。", "舞陽死灰人，安可與成功。"]'),
('8b867382-97cb-47c3-aa9a-c3fe87346200','長干行二首 一','李白','唐','唐诗','tang','','[]','妾髮初覆額，折花門前劇。',180,'全唐诗/poet.tang.8000.json','["妾髮初覆額，折花門前劇。", "郎騎竹馬來，繞牀弄青梅。", "同居長干里，兩小無嫌猜。", "十四爲君婦，羞顏未嘗開。", "低頭向暗壁，千喚不一迴。", "十五始展眉，願同塵與灰。", "常存抱柱信，豈上望夫臺。", "十六君遠行，瞿塘灩澦堆。", "五月不可觸，猨聲天上哀。", "門前遲行跡，一一生綠苔。", "苔深不能掃，落葉秋風早。", "八月胡蝶來，雙飛西園草。", "感此傷妾心，坐愁紅顏老。", "早晚下三巴，預將書報家。", "相迎不道遠，直至長風沙。"]'),
('eea15433-e507-48d7-acf5-4e9c0baf5172','長干行二首 二','李白','唐','唐诗','tang','','[]','憶妾深閨裏，煙塵不曾識。',144,'全唐诗/poet.tang.8000.json','["憶妾深閨裏，煙塵不曾識。", "嫁與長干人，沙頭候風色。", "五月南風興，思君下巴陵。", "八月西風起，想君發揚子。", "去來悲如何，見少離別多。", "湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。", "淼淼暗無邊，行人在何處？", "好乘浮雲驄，佳期蘭渚東。", "鴛鴦綠蒲上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。", "那作商人婦，愁水復愁風。"]'),
('129c074d-f123-45d1-8062-ba949dcc8c6f','古朗月行','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u6708\u4eae", "\u4e50\u5e9c", "\u6742\u66f2\u6b4c\u8f9e", "\u4e2d\u79cb"]','小時不識月，呼作白玉盤。',96,'全唐诗/poet.tang.8000.json','["小時不識月，呼作白玉盤。", "又疑瑤臺鏡，飛在白雲端。", "仙人垂兩足，桂樹作團團。", "白兔擣藥成，問言與誰餐。", "蟾蜍蝕圓影，大明夜已殘。", "羿昔落九烏，天人清且安。", "陰精此淪惑，去去不足觀。", "憂來其如何，悽愴摧心肝。"]'),
('f952bb0c-ab9e-4025-b771-c25f2e68c6e0','上之回','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c"]','三十六離宮，樓臺與天通。',96,'全唐诗/poet.tang.8000.json','["三十六離宮，樓臺與天通。", "閣道步行月，美人愁烟空。", "恩疎寵不及，桃李傷春風。", "淫樂意何極，金輿向回中。", "萬乘出黃道，千旗揚彩虹。", "前軍細柳北，後騎甘泉東。", "豈問渭川老，寧邀襄野童。", "但慕瑤池宴，歸來樂未窮。"]'),
('d930f6e0-9a15-4d8e-a527-4a4af0264faf','獨不見','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c"]','白馬誰家子，黃龍邊塞兒。',84,'全唐诗/poet.tang.8000.json','["白馬誰家子，黃龍邊塞兒。", "天山三丈雪，豈是遠行時。", "春蕙忽秋草，莎雞鳴西池。", "風摧寒椶響，月入霜閨悲。", "憶與君別年，種桃齊蛾眉。", "桃今百餘尺，花落成枯枝。", "終然獨不見，流淚空自知。"]'),
('37fbfbfd-1054-4eb2-bebf-b9bd36fdf3fc','白紵辭三首 一','李白','唐','唐诗','tang','','[]','揚清歌，發皓齒，北方佳人東隣子。',64,'全唐诗/poet.tang.8000.json','["揚清歌，發皓齒，北方佳人東隣子。", "且吟白紵停綠水，長袖拂面爲君起。", "寒雲夜卷霜海空，胡風吹天飄塞鴻。", "玉顏滿堂樂未終，館娃日落歌吹濛。"]'),
('192d012f-dbdd-4e79-a298-d741ce0d970c','白紵辭三首 二','李白','唐','唐诗','tang','','[]','月寒江清夜沈沈，美人一笑千黃金。',64,'全唐诗/poet.tang.8000.json','["月寒江清夜沈沈，美人一笑千黃金。", "垂羅舞縠揚哀音，郢中白雪且莫吟。", "子夜吳歌動君心，動君心，冀君賞。", "願作天池雙鴛鴦，一朝飛去青雲上。"]'),
('ea94670a-dd28-4d73-b574-bde1a0c70096','白紵辭三首 三','李白','唐','唐诗','tang','','[]','吳刀剪綵縫舞衣，明妝麗服奪春暉。',56,'全唐诗/poet.tang.8000.json','["吳刀剪綵縫舞衣，明妝麗服奪春暉。", "揚眉轉袖若雪飛，傾城獨立世所稀。", "激楚結風醉忘歸，高堂月落燭已微，玉釵挂纓君莫違。"]'),
('49cc1160-8842-4a0a-9a6d-fa2691896914','鳴雁行','李白','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u4eba\u751f", "\u548f\u7269\u8bd7", "\u574e\u5777"]','胡雁鳴，辭燕山，昨發委羽朝度關。',78,'全唐诗/poet.tang.8000.json','["胡雁鳴，辭燕山，昨發委羽朝度關。", "一一銜蘆枝，南飛散落天地間。", "連行接翼往復還，客居煙波寄湘吳。", "凌霜觸雪毛體枯，畏逢矰繳驚相呼。", "聞弦虛墜良可吁，君更彈射何爲乎。"]'),
('1f210fe0-a8a6-4a86-bc29-323c214c7212','妾薄命','李白','唐','唐诗','tang','','["\u54f2\u7406", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','漢帝寵阿嬌，貯之黃金屋。',96,'全唐诗/poet.tang.8000.json','["漢帝寵阿嬌，貯之黃金屋。", "咳唾落九天，隨風生珠玉。", "寵極愛還歇，妬深情却疎。", "長門一步地，不肯暫迴車。", "雨落不上天，水覆難再收。", "君情與妾意，各自東西流。", "昔日芙蓉花，今成斷根草。", "以色事他人，能得幾時好。"]'),
('e14f3c7a-4453-48e0-9296-ff4749acf823','幽州胡馬客歌','李白','唐','唐诗','tang','','["\u538c\u6076", "\u6218\u4e89", "\u751f\u6d3b", "\u8fb9\u585e", "\u4eba\u6c11"]','幽州胡馬客，綠眼虎皮冠。',168,'全唐诗/poet.tang.8000.json','["幽州胡馬客，綠眼虎皮冠。", "笑拂兩隻箭，萬人不可干。", "彎弓若轉月，白雁落雲端。", "雙雙掉鞭行，遊獵向樓蘭。", "出門不顧後，報國死何難。", "天驕五單于，狼戾好兇殘。", "牛馬散北海，割鮮若虎餐。", "雖居燕支山，不道朔雪寒。", "婦女馬上笑，顏如赬玉盤。", "飜飛射鳥獸，花月醉雕鞍。", "旄頭四光芒，爭戰若蜂攢。", "白刃灑赤血，流沙爲之丹。", "名將古誰是，疲兵良可歎。", "何時天狼滅，父子得閑安。"]'),
('2ea1c888-9993-4aae-9019-ae3e8540c426','門有車馬客行','李白','唐','唐诗','tang','','["\u65e0\u5948", "\u4e50\u5e9c", "\u5f52\u4e61", "\u6124\u6168", "\u76f8\u548c\u6b4c\u8f9e"]','門有車馬賓，金鞍曜朱輪。',156,'全唐诗/poet.tang.8000.json','["門有車馬賓，金鞍曜朱輪。", "謂從丹霄落，乃是故鄉親。", "呼兒掃中堂，坐客論悲辛。", "對酒兩不飲，停觴淚盈巾。", "歎我萬里遊，飄飄三十春。", "空談帝王略，紫綬不挂身。", "雄劒藏玉匣，陰符生素塵。", "廓落無所合，流離湘水濱。", "借問宗黨間，多爲泉下人。", "生苦百戰役，死託萬鬼隣。", "北風揚胡沙，埋翳周與秦。", "大運且如此，蒼穹寧匪仁。", "惻愴竟何道，存亡任大鈞。"]'),
('097b32ad-0a73-44c6-a709-f351b531b1fd','君子有所思行','李白','唐','唐诗','tang','','["\u65e0\u5948", "\u4e50\u5e9c", "\u6742\u66f2\u6b4c\u8f9e", "\u6124\u6168"]','紫閣連終南，青冥天倪色。',132,'全唐诗/poet.tang.8000.json','["紫閣連終南，青冥天倪色。", "凭崖望咸陽，宮闕羅北極。", "萬井驚畫出，九衢如弦直。", "渭水銀河清，橫天流不息。", "朝野盛文物，衣冠何翕赩。", "廄馬散連山，軍容威絕域。", "伊臯運元化，衛霍輸筋力。", "歌鐘樂未休，榮去老還逼。", "圓光過滿缺，太陽移中昃。", "不散東海金，何爭西飛匿。", "無作牛山悲，惻愴淚沾臆。"]'),
('7ab63c87-1bed-4f96-8fa4-8431f0f41635','東海有勇婦','李白','唐','唐诗','tang','','["\u6b4c\u9882", "\u4fa0\u4e49", "\u5987\u5973", "\u4e50\u5e9c", "\u821e\u66f2\u6b4c\u8f9e"]','梁山感杞妻，慟哭爲之傾。',228,'全唐诗/poet.tang.8000.json','["梁山感杞妻，慟哭爲之傾。", "金石忽蹔開，都由激深情。", "東海有勇婦，何慚蘇子卿。", "學劒越處子，超然若流星。", "損軀報夫讎，萬死不顧生。", "白刃耀素雪，蒼天感精誠。", "十步兩躩躍，三呼一交兵。", "斬首掉國門，蹴踏五藏行。", "豁此伉儷憤，粲然大義明。", "北海李使君，飛章奏天庭。", "捨罪警風俗，流芳播滄瀛。", "名在列女籍，竹帛已光榮。", "淳于免詔獄，漢主爲緹縈。", "津妾一櫂歌，脫父於嚴刑。", "十子若不肖，不如一女英。", "豫讓斬空衣，有心竟無成。", "要離殺慶忌，壯夫所素輕。", "妻子亦何辜，焚之買虛聲。", "豈如東海婦，事立獨揚名。"]'),
('930d51d8-bb63-49f3-881a-e3a90f3ea030','黃葛篇','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u7231\u60c5", "\u5973\u5b50"]','黃葛生洛溪，黃花自綿冪。',72,'全唐诗/poet.tang.8000.json','["黃葛生洛溪，黃花自綿冪。", "青烟蔓長條，繚繞幾百尺。", "閨人費素手，採緝作絺綌。", "縫爲絕國衣，遠寄日南客。", "蒼梧大火落，暑服莫輕擲。", "此物雖過時，是妾手中跡。"]'),
('03af61b5-34a7-40bd-98a2-26ef86291097','白馬篇','李白','唐','唐诗','tang','','["\u4fa0\u5ba2", "\u7231\u56fd", "\u5199\u9a6c", "\u9a6c", "\u58ee\u5fd7"]','龍馬花雪毛，金鞍五陵豪。',120,'全唐诗/poet.tang.8000.json','["龍馬花雪毛，金鞍五陵豪。", "秋霜切玉劒，落日明珠袍。", "鬬雞事萬乘，軒蓋一何高。", "弓摧南山虎，手接太行猱。", "酒後競風采，三杯弄寶刀。", "殺人如剪草，劇孟同遊遨。", "發憤去函谷，從軍向臨洮。", "叱咤萬戰場，匈奴盡奔逃。", "歸來使酒氣，未肯拜蕭曹。", "羞入原憲室，荒淫隱蓬蒿。"]'),
('cfb66f37-ac9a-4054-bc83-c8f71c2da690','鳳吹笙曲','李白','唐','唐诗','tang','','["\u4e0d\u820d", "\u79bb\u522b", "\u9001\u522b"]','仙人十五愛吹笙，學得崑丘彩鳳鳴。',128,'全唐诗/poet.tang.8000.json','["仙人十五愛吹笙，學得崑丘彩鳳鳴。", "始聞鍊氣餐金液，復道朝天赴玉京。", "玉京迢迢幾千里，鳳笙去去無窮已。", "欲歎離聲發絳脣，更嗟別調流纖指。", "此時惜別詎堪聞，此地相看未忍分。", "重吟真曲和清吹，却奏仙歌響綠雲。", "綠雲紫氣向函關，訪道應尋緱氏山。", "莫學吹笙王子晉，一遇浮丘斷不還。"]'),
('716047ac-0c4b-4cf0-8eab-b2e93d55bf19','怨歌行','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5973\u5b50", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e", "\u5931\u610f"]','十五入漢宮，花顏笑春紅。',108,'全唐诗/poet.tang.8000.json','["十五入漢宮，花顏笑春紅。", "君王選玉色，侍寢金屏中。", "薦枕嬌夕月，卷衣戀春風。", "寧知趙飛燕，奪寵恨無窮。", "沈憂能傷人，綠鬢成霜蓬。", "一朝不得意，世事徒爲空。", "鷫鸘換美酒，舞衣罷雕龍。", "寒苦不忍言，爲君奏絲桐。", "腸斷弦亦絕，悲心夜忡忡。"]'),
('d757fff5-bff2-4c3e-9df8-c306ea5e489d','塞下曲六首 一','李白','唐','唐诗','tang','','["\u5199\u96ea", "\u751f\u6d3b", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u96ea", "\u8fb9\u585e", "\u519b\u65c5"]','五月天山雪，無花祗有寒。',48,'全唐诗/poet.tang.8000.json','["五月天山雪，無花祗有寒。", "笛中聞折柳，春色未曾看。", "曉戰隨金鼓，宵眠抱玉鞍。", "願將腰下劒，直爲斬樓蘭。"]'),
('bd80e304-1b28-45ae-8c3c-89cd35d0ff09','塞下曲六首 二','李白','唐','唐诗','tang','','[]','天兵下北荒，胡馬欲南飲。',48,'全唐诗/poet.tang.8000.json','["天兵下北荒，胡馬欲南飲。", "橫戈從百戰，直爲銜恩甚。", "握雪海上餐，拂沙隴頭寢。", "何當破月氏，然後方高枕。"]'),
('0f89ef74-fab4-4182-8c3b-34fcfa26660b','塞下曲六首 三','李白','唐','唐诗','tang','','[]','駿馬似風飆，鳴鞭出渭橋。',48,'全唐诗/poet.tang.8000.json','["駿馬似風飆，鳴鞭出渭橋。", "彎弓辭漢月，插羽破天驕。", "陣解星芒盡，營空海霧消。", "功成畫麟閣，獨有霍嫖姚。"]'),
('c58780c4-0293-429a-8d5e-e2620c92db94','塞下曲六首 四','李白','唐','唐诗','tang','','[]','白馬黃金塞，雲砂遶夢思。',60,'全唐诗/poet.tang.8000.json','["白馬黃金塞，雲砂遶夢思。", "那堪愁苦節，遠憶邊城兒。", "螢飛秋窗滿，月度霜閨遲。", "摧殘梧桐葉，蕭颯沙棠枝。", "無時獨不見，流淚空自知。"]'),
('b1baa58f-51e8-4c06-8b76-5a5c4b4cef69','塞下曲六首 五','李白','唐','唐诗','tang','','[]','塞虜乘秋下，天兵出漢家。',48,'全唐诗/poet.tang.8000.json','["塞虜乘秋下，天兵出漢家。", "將軍分虎竹，戰士臥龍沙。", "邊月隨弓影，胡霜拂劒花。", "玉關殊未入，少婦莫長嗟。"]'),
('c549213a-54bb-4424-9efb-843364635500','塞下曲六首 六','李白','唐','唐诗','tang','','[]','烽火動沙漠，連照甘泉雲。',48,'全唐诗/poet.tang.8000.json','["烽火動沙漠，連照甘泉雲。", "漢皇按劒起，還召李將軍。", "兵氣天上合，鼓聲隴底聞。", "橫行負勇氣，一戰淨妖氛。"]'),
('af4989e0-ea67-4d2e-b694-cffc6aceec73','來日大難','李白','唐','唐诗','tang','','[]','來日一身，攜糧負薪。',120,'全唐诗/poet.tang.8000.json','["來日一身，攜糧負薪。", "道長食盡，苦口焦脣。", "今日醉飽，樂過千春。", "仙人相存，誘我遠學。", "海淩三山，陸憩五嶽。", "乘龍天飛，目瞻兩角。", "授以仙藥，金丹滿握。", "蟪蛄蒙恩，深愧短促。", "思填東海，强銜一木。", "道重天地，軒師廣成。", "蟬翼九五，以求長生。", "下士大笑，如蒼蠅聲。"]'),
('a525205a-0567-429e-a2c5-38240aca5741','塞上曲','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u8fb9\u585e"]','大漢無中策，匈奴犯渭橋。',72,'全唐诗/poet.tang.8000.json','["大漢無中策，匈奴犯渭橋。", "五原秋草綠，胡馬一何驕。", "命將征西極，橫行陰山側。", "燕支落漢家，婦女無華色。", "轉戰渡黃河，休兵樂事多。", "蕭條清萬里，瀚海寂無波。"]'),
('a65e5646-14b1-4f75-924b-bbf262b242d7','玉階怨','李白','唐','唐诗','tang','','["\u5b64\u72ec", "\u5bab\u6028", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','玉階生白露，夜久侵羅襪。',24,'全唐诗/poet.tang.8000.json','["玉階生白露，夜久侵羅襪。", "却下水晶簾，玲瓏望秋月。"]'),
('af9b5f9f-e863-4db9-9e47-7988aa2b22b4','襄陽曲四首 一','李白','唐','唐诗','tang','','[]','襄陽行樂處，歌舞白銅鞮。',24,'全唐诗/poet.tang.8000.json','["襄陽行樂處，歌舞白銅鞮。", "江城回淥水，花月使人迷。"]'),
('1b564007-c5e3-40d6-be95-5a00188b407c','襄陽曲四首 二','李白','唐','唐诗','tang','','[]','山公醉酒時，酩酊高陽下。',24,'全唐诗/poet.tang.8000.json','["山公醉酒時，酩酊高陽下。", "頭上白接䍦，倒著還騎馬。"]'),
('7f007e41-e85f-40bc-a93d-dd4a08cca239','襄陽曲四首 三','李白','唐','唐诗','tang','','[]','峴山臨漢江，水綠沙如雪。',24,'全唐诗/poet.tang.8000.json','["峴山臨漢江，水綠沙如雪。", "上有墮淚碑，青苔久磨滅。"]'),
('57f6ddfe-f729-4973-83f6-66817a720ce3','襄陽曲四首 四','李白','唐','唐诗','tang','','[]','且醉習家池，莫看墮淚碑。',24,'全唐诗/poet.tang.8000.json','["且醉習家池，莫看墮淚碑。", "山公欲上馬，笑殺襄陽兒。"]'),
('86fa9ad6-3cf7-4ef9-9804-32155d837120','大堤曲','李白','唐','唐诗','tang','','["\u89e6\u666f\u4f24\u60c5", "\u6e05\u5546\u66f2\u8f9e", "\u601d\u4e61", "\u4e50\u5e9c"]','漢水臨襄陽，花開大堤暖。',48,'全唐诗/poet.tang.8000.json','["漢水臨襄陽，花開大堤暖。", "佳期大堤下，淚向南雲滿。", "春風無復情，吹我夢魂散。", "不見眼中人，天長音信斷。"]'),
('b35291b7-f63e-45c3-8ef9-f7ad98807627','宮中行樂詞八首 一','李白','唐','唐诗','tang','','[]','小小生金屋，盈盈在紫微。',48,'全唐诗/poet.tang.8000.json','["小小生金屋，盈盈在紫微。", "山花插寶髻，石竹繡羅衣。", "每出深宮裏，常隨步輦歸。", "只愁歌舞散，化作綵雲飛。"]'),
('970e8456-5bf7-43fa-b8b3-227dac0e9051','宮中行樂詞八首 二','李白','唐','唐诗','tang','','[]','柳色黃金嫩，梨花白雪香。',48,'全唐诗/poet.tang.8000.json','["柳色黃金嫩，梨花白雪香。", "玉樓巢翡翠，金殿鎖鴛鴦。", "選妓隨雕輦，徵歌出洞房。", "宮中誰第一，飛燕在昭陽。"]'),
('379bc0cf-6d26-46c4-a51c-244e516e6a41','宮中行樂詞八首 三','李白','唐','唐诗','tang','','[]','盧橘爲秦樹，蒲萄出漢宮。',48,'全唐诗/poet.tang.8000.json','["盧橘爲秦樹，蒲萄出漢宮。", "煙花宜落日，絲管醉春風。", "笛奏龍吟水，簫鳴鳳下空。", "君王多樂事，還與萬方同。"]'),
('0b26f0b8-4006-4755-95c7-5a0e99a9acdd','宮中行樂詞八首 四','李白','唐','唐诗','tang','','[]','玉樹春歸日，金宮樂事多。',48,'全唐诗/poet.tang.8000.json','["玉樹春歸日，金宮樂事多。", "後庭朝未入，輕輦夜相過。", "笑出花間語，嬌來竹下歌。", "莫教明月去，留著醉嫦蛾。"]'),
('99b8c08d-15ad-48d7-a567-21e90ad205b6','宮中行樂詞八首 五','李白','唐','唐诗','tang','','[]','繡戶香風暖，紗窗曙色新。',48,'全唐诗/poet.tang.8000.json','["繡戶香風暖，紗窗曙色新。", "宮花爭笑日，池草暗生春。", "綠樹聞歌鳥，青樓見舞人。", "昭陽桃李月，羅綺自相親。"]'),
('ca7c63a3-907e-43ed-9e2f-0ec18619dcb0','宮中行樂詞八首 六','李白','唐','唐诗','tang','','[]','今日明光裏，還須結伴遊。',48,'全唐诗/poet.tang.8000.json','["今日明光裏，還須結伴遊。", "春風開紫殿，天樂下朱樓。", "豔舞全知巧，嬌歌半欲羞。", "更憐花月夜，宮女笑藏鉤。"]'),
('8da550b7-9278-4649-9124-960110bf7b1a','宮中行樂詞八首 七','李白','唐','唐诗','tang','','[]','寒雪梅中盡，春風柳上歸。',48,'全唐诗/poet.tang.8000.json','["寒雪梅中盡，春風柳上歸。", "宮鶯嬌欲醉，簷燕語還飛。", "遲日明歌席，新花豔舞衣。", "晚來移綵仗，行樂泥光輝。"]'),
('21b11745-2b29-46e3-bde8-29ef351a4f47','宮中行樂詞八首 八','李白','唐','唐诗','tang','','[]','水綠南薰殿，花紅北闕樓。',48,'全唐诗/poet.tang.8000.json','["水綠南薰殿，花紅北闕樓。", "鶯歌聞太液，鳳吹繞瀛洲。", "素女鳴珠珮，天人弄綵毬。", "今朝風日好，宜入未央遊。"]'),
('948fa40a-492e-4fa1-99f4-b002ae87cd24','清平調詞三首 一','李白','唐','唐诗','tang','','["\u5973\u5b50", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8d5e\u7f8e", "\u8fd1\u4ee3\u66f2\u8f9e"]','雲想衣裳花想容，春風拂檻露華濃。',32,'全唐诗/poet.tang.8000.json','["雲想衣裳花想容，春風拂檻露華濃。", "若非羣玉山頭見，會向瑤臺月下逢。"]'),
('99167d13-8e2c-4b75-bf93-62b0682dfdd0','清平調詞三首 二','李白','唐','唐诗','tang','','["\u5973\u5b50", "\u8fd1\u4ee3\u66f2\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','一枝穠豔露凝香，雲雨巫山枉斷腸。',32,'全唐诗/poet.tang.8000.json','["一枝穠豔露凝香，雲雨巫山枉斷腸。", "借問漢宮誰得似，可憐飛燕倚新妝。"]'),
('3b706bb8-c836-4637-bec3-3fa2adc88ca7','清平調詞三首 三','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u5199\u4eba", "\u82b1", "\u5199\u82b1", "\u8fd1\u4ee3\u66f2\u8f9e"]','名花傾國兩相歡，長得君王帶笑看。',32,'全唐诗/poet.tang.8000.json','["名花傾國兩相歡，長得君王帶笑看。", "觧釋春風無限恨，沈香亭北倚闌干。"]'),
('b3de1566-b132-4c39-800a-7f72fc5d31bc','入朝曲','李白','唐','唐诗','tang','','[]','金陵控海浦，淥水帶吳京。',84,'全唐诗/poet.tang.8000.json','["金陵控海浦，淥水帶吳京。", "鐃歌列騎吹，颯沓引公卿。", "槌鐘速嚴妝，伐鼓啓重城。", "天子憑玉几，劒履若雲行。", "日出照萬戶，簪裾爛明星。", "朝罷沐浴閑，遨遊閬風亭。", "濟濟雙闕下，歡娛樂恩榮。"]'),
('fd2c5587-72ba-4657-a633-b96c9838abb7','秦女休行','李白','唐','唐诗','tang','','["\u6b4c\u9882", "\u590d\u4ec7", "\u5987\u5973", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','西門秦氏女，秀色如瓊花。',108,'全唐诗/poet.tang.8000.json','["西門秦氏女，秀色如瓊花。", "手揮白楊刀，清晝殺讐家。", "羅袖灑赤血，英氣凌紫霞。", "直上西山去，關吏相邀遮。", "壻爲燕國王，身被詔獄加。", "犯刑若履虎，不畏落爪牙。", "素頸未及斷，摧眉伏泥沙。", "金雞忽放赦，大辟得寬賒。", "何慙聶政姊，萬古共驚嗟。"]'),
('87899f62-0eef-41ed-9037-409f4af8cd77','秦女卷衣','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u7231\u60c5", "\u4e50\u5e9c"]','天子居未央，妾侍卷衣裳。',60,'全唐诗/poet.tang.8000.json','["天子居未央，妾侍卷衣裳。", "顧無紫宮寵，敢拂黃金牀。", "水至亦不去，熊來尚可當。", "微身奉日月，飄若螢之光。", "願君采葑菲，無以下體妨。"]'),
('6f222122-d8aa-4484-9fd5-422dcc204c04','東武吟','李白','唐','唐诗','tang','','["\u4ed5\u9014", "\u65e0\u5948", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','好古笑流俗，素聞賢達風。',204,'全唐诗/poet.tang.8000.json','["好古笑流俗，素聞賢達風。", "方希佐明主，長揖辭成功。", "白日在高天，迴光燭微躬。", "恭承鳳凰詔，歘起雲蘿中。", "清切紫霄迥，優游丹禁通。", "君王賜顏色，聲價凌煙虹。", "乘輿擁翠蓋，扈從金城東。", "寶馬麗絕景，錦衣入新豐。", "依巖望松雪，對酒鳴絲桐。", "因學揚子雲，獻賦甘泉宮。", "天書美片善，清芬播無窮。", "歸來入咸陽，談笑皆王公。", "一朝去金馬，飄落成飛蓬。", "賓客日疎散，玉樽亦已空。", "才力猶可倚，不慙世上雄。", "閑作東武吟，曲盡情未終。", "書此謝知己，吾尋黃綺翁。"]'),
('a23853df-1c19-414e-9941-6dd7892ac707','邯鄲才人嫁爲廝養卒婦','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','妾本崇臺女，揚蛾入丹闕。',60,'全唐诗/poet.tang.8000.json','["妾本崇臺女，揚蛾入丹闕。", "自倚顏如花，寧知有凋歇。", "一辭玉階下，去若朝雲沒。", "每憶邯鄲城，深宮夢秋月。", "君王不可見，惆悵至明發。"]'),
('5d0a5f9b-80a6-447e-8acb-08b3fd30b8b5','出自薊北門行','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u6218\u4e89", "\u751f\u6d3b", "\u4e50\u5e9c"]','虜陣橫北荒，胡星耀精芒。',144,'全唐诗/poet.tang.8000.json','["虜陣橫北荒，胡星耀精芒。", "羽書速驚電，烽火晝連光。", "虎竹救邊急，戎車森已行。", "明主不安席，按劒心飛揚。", "推轂出猛將，連旗登戰場。", "兵威衝絕幕，殺氣凌穹蒼。", "列卒赤山下，開營紫塞傍。", "孟冬風沙緊，旌旗颯凋傷。", "畫角悲海月，征衣卷天霜。", "揮刃斬樓蘭，彎弓射賢王。", "單于一平蕩，種落自奔亡。", "收功報天子，行歌歸咸陽。"]'),
('07b54f1c-f69e-4f95-906e-7fe4742c2ffb','洛陽陌','李白','唐','唐诗','tang','','[]','白玉誰家郎，回車渡天津。',24,'全唐诗/poet.tang.8000.json','["白玉誰家郎，回車渡天津。", "看花東陌上，驚動洛陽人。"]'),
('bd4449d3-dd2d-4648-baea-eca59123dc21','北上行','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6101\u82e6", "\u6218\u4e89", "\u4eba\u6c11", "\u540c\u60c5"]','北上何所苦，北上緣太行。',168,'全唐诗/poet.tang.8000.json','["北上何所苦，北上緣太行。", "磴道盤且峻，巉巖凌穹蒼。", "馬足蹶側石，車輪摧高岡。", "沙塵接幽州，烽火連朔方。", "殺氣毒劒戟，嚴風裂衣裳。", "奔鯨夾黃河，鑿齒屯洛陽。", "前行無歸日，返顧思舊鄉。", "慘戚冰雪裏，悲號絕中腸。", "尺布不掩體，皮膚劇枯桑。", "汲水澗谷阻，採薪隴坂長。", "猛虎又掉尾，磨牙皓秋霜。", "草木不可餐，飢飲零露漿。", "歎此北上苦，停驂爲之傷。", "何日王道平，開顏覩天光。"]'),
('4eec103c-1a08-4b20-bfc1-bc30763b935e','短歌行','李白','唐','唐诗','tang','','["\u60dc\u65f6", "\u76f8\u548c\u6b4c\u8f9e", "\u4eba\u751f", "\u65f6\u95f4"]','白日何短短，百年苦易滿。',84,'全唐诗/poet.tang.8000.json','["白日何短短，百年苦易滿。", "蒼穹浩茫茫，萬劫太極長。", "麻姑垂兩鬢，一半已成霜。", "天公見玉女，大笑億千場。", "吾欲攬六龍，迴車挂扶桑。", "北斗酌美酒，勸龍各一觴。", "富貴非所願，與人駐顏光。"]'),
('19e77d27-3601-4830-94ca-b812ac4ac1c3','空城雀','李白','唐','唐诗','tang','','["\u5fd7\u5411", "\u65e0\u5948", "\u4e50\u5e9c", "\u5199\u9e1f", "\u6742\u66f2\u6b4c\u8f9e", "\u9e1f"]','嗷嗷空城雀，身計何戚促。',72,'全唐诗/poet.tang.8000.json','["嗷嗷空城雀，身計何戚促。", "本與鷦鷯羣，不隨鳳凰族。", "提攜四黃口，飲乳未嘗足。", "食君糠粃餘，嘗恐烏鳶逐。", "耻涉太行險，羞營覆車粟。", "天命有定端，守分絕所欲。"]'),
('676a45c2-64d9-4159-9695-6c3b24fc5193','發白馬','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6218\u4e89", "\u5199\u9a6c", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u9a6c"]','將軍發白馬，旌節度黃河。',96,'全唐诗/poet.tang.8000.json','["將軍發白馬，旌節度黃河。", "簫鼓聒川嶽，滄溟湧濤波。", "武安有振瓦，易水無寒歌。", "鐵騎若雪山，飲流涸滹沱。", "揚兵獵月窟，轉戰略朝那。", "倚劒登燕然，邊烽列嵯峨。", "蕭條萬里外，耕作五原多。", "一掃清大漠，包虎戢金戈。"]'),
('f81bc9aa-b41d-48af-a861-8a8c782ac0d3','陌上桑','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u5199\u4eba", "\u5fe0\u8d1e", "\u4e50\u5e9c", "\u8d5e\u7f8e"]','美女渭橋東，春還事蠶作。',108,'全唐诗/poet.tang.8000.json','["美女渭橋東，春還事蠶作。", "五馬如飛龍，青絲結金絡。", "不知誰家子，調笑來相謔。", "妾本秦羅敷，玉顏豔名都。", "綠條映素手，採桑向城隅。", "使君且不顧，況復論秋胡。", "寒螿愛碧草，鳴鳳棲青梧。", "託心自有處，但怪旁人愚。", "徒令白日暮，高駕空踟躕。"]'),
('bbc355b2-ee47-42cc-8694-f9b783ec5e79','枯魚過河泣','李白','唐','唐诗','tang','','[]','白龍改常服，偶被豫且制。',60,'全唐诗/poet.tang.8000.json','["白龍改常服，偶被豫且制。", "誰使爾爲魚，徒勞訴天帝。", "作書報鯨鯢，勿恃風濤勢。", "濤落歸泥沙，翻遭螻蟻噬。", "萬乘慎出入，柏人以爲識。"]'),
('2c417fd4-9798-43ae-b2ea-4fba4400af3f','丁督護歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u4e50\u5e9c", "\u519c\u6c11"]','雲陽上征去，兩岸饒商賈。',72,'全唐诗/poet.tang.8000.json','["雲陽上征去，兩岸饒商賈。", "吳牛喘月時，拖船一何苦。", "水濁不可飲，壺漿半成土。", "一唱督護歌，心摧淚如雨。", "萬人鑿磐石，無由達江滸。", "君看石芒碭，掩淚悲千古。"]'),
('3bd7db76-e850-4560-af60-0b930a7e648a','相逢行','李白','唐','唐诗','tang','','["\u9057\u61be", "\u76f8\u548c\u6b4c\u8f9e", "\u7406\u60f3", "\u4e50\u5e9c", "\u79ef\u6781"]','朝騎五花馬，謁帝出銀臺。',180,'全唐诗/poet.tang.8000.json','["朝騎五花馬，謁帝出銀臺。", "秀色誰家子，雲車珠箔開。", "金鞭遙指點，玉勒近遲回。", "夾轂相借問，疑從天上來。", "蹙入青綺門，當歌共銜杯。", "銜杯暎歌扇，似月雲中見。", "相見不得親，不如不相見。", "相見情已深，未語可知心。", "胡爲守空閨，孤眠愁錦衾。", "錦衾與羅幃，纏綿會有時。", "春風正澹蕩，暮雨來何遲。", "願因三青鳥，更報長相思。", "光景不待人，須臾髮成絲。", "當年失行樂，老去徒傷悲。", "持此道密意，毋令曠佳期。"]'),
('a56d7021-f30a-4391-93ae-d6467d57b921','千里思','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u540c\u60c5", "\u4e50\u5e9c"]','李陵沒胡沙，蘇武還漢家。',48,'全唐诗/poet.tang.8000.json','["李陵沒胡沙，蘇武還漢家。", "迢迢五原關，朔雪亂邊花。", "一去隔絕國，思歸但長嗟。", "鴻雁向西北，因書報天涯。"]'),
('c5f3b0ad-d3f4-438d-aa54-a6b8445c6b03','樹中草','李白','唐','唐诗','tang','','["\u547d\u8fd0", "\u6292\u60c5", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','鳥銜野田草，誤入枯桑裏。',48,'全唐诗/poet.tang.8000.json','["鳥銜野田草，誤入枯桑裏。", "客土植危根，逢春猶不死。", "草木雖無情，因依尚可生。", "如何同枝葉，各自有枯榮。"]'),
('ae248db2-43b1-4195-8b26-aea30fb8790a','君馬黃','李白','唐','唐诗','tang','','["\u77e5\u5df1", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c"]','君馬黃，我馬白。',80,'全唐诗/poet.tang.8000.json','["君馬黃，我馬白。", "馬色雖不同，人心本無隔。", "共作遊冶盤，雙行洛陽陌。", "長劒既照曜，高冠何赩赫。", "各有千金裘，俱爲五侯客。", "猛虎落陷穽，壯夫時屈厄。", "相知在急難，獨好亦何益。"]'),
('6fecb8c7-f8f0-4dd1-a3f4-3175599f83e2','擬古','李白','唐','唐诗','tang','','[]','融融白玉輝，暎我青蛾眉。',48,'全唐诗/poet.tang.8000.json','["融融白玉輝，暎我青蛾眉。", "寶鏡似空水，落花如風吹。", "出門望帝子，蕩漾不可期。", "安得黃鶴羽，一報佳人知。"]'),
('e7702c0f-2cce-49fe-97b7-5d0abd5953d3','折楊柳','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6625\u5929", "\u5973\u5b50", "\u4e50\u5e9c", "\u6a2a\u5439\u66f2\u8f9e"]','垂楊拂綠水，搖豔東風年。',48,'全唐诗/poet.tang.8000.json','["垂楊拂綠水，搖豔東風年。", "花明玉關雪，葉暖金牕煙。", "美人結長想，對此心淒然。", "攀條折春色，遠寄龍庭前。"]'),
('d1b51727-f72a-4eb6-82db-99a458271ac2','少年子','李白','唐','唐诗','tang','','[]','青雲年少子，挾彈章臺左。',48,'全唐诗/poet.tang.8000.json','["青雲年少子，挾彈章臺左。", "鞍馬四邊開，突如流星過。", "金丸落飛鳥，夜入瓊樓臥。", "夷齊是何人，獨守西山餓。"]'),
('65e8aaff-bbd3-445f-ad03-782789c9a5d0','紫騮馬','李白','唐','唐诗','tang','','["\u5199\u9a6c", "\u4e50\u5e9c", "\u6a2a\u5439\u66f2\u8f9e", "\u601d\u4e61", "\u8fb9\u585e", "\u9a6c"]','紫騮行且嘶，雙翻碧玉蹄。',48,'全唐诗/poet.tang.8000.json','["紫騮行且嘶，雙翻碧玉蹄。", "臥流不肯渡，似惜錦障泥。", "白雪關山遠，黃雲海戍迷。", "揮鞭萬里去，安得念春閨。"]'),
('e68a4fa2-c681-4716-9e24-04b76dd1e723','少年行二首 一','李白','唐','唐诗','tang','','[]','擊筑飲美酒，劒歌易水湄。',48,'全唐诗/poet.tang.8000.json','["擊筑飲美酒，劒歌易水湄。", "經過燕太子，結託幷州兒。", "少年負壯氣，奮烈自有時。", "因擊魯句踐，爭博勿相欺。"]'),
('75f41e72-ce1e-46d8-873d-6a2f5463e234','少年行二首 二','李白','唐','唐诗','tang','','[]','五陵年少金市東，銀鞍白馬度春風。',32,'全唐诗/poet.tang.8000.json','["五陵年少金市東，銀鞍白馬度春風。", "落花踏盡遊何處，笑入胡姬酒肆中。"]'),
('3cd762f4-f2ea-44d4-92f2-e9a6d0bf2b56','白鼻騧','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u8c6a\u8fc8", "\u5199\u666f"]','銀鞍白鼻騧，綠地障泥錦。',28,'全唐诗/poet.tang.8000.json','["銀鞍白鼻騧，綠地障泥錦。", "細雨春風花落時，揮鞭直就胡姬飲。"]'),
('5afcefcb-9c1a-4ca0-8fac-e5889937dea4','豫章行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u6218\u4e89", "\u4e50\u5e9c", "\u540c\u60c5"]','胡風吹代馬，北擁魯陽關。',132,'全唐诗/poet.tang.8000.json','["胡風吹代馬，北擁魯陽關。", "吳兵照海雪，西討何時還。", "半渡上遼津，黃雲慘無顏。", "老母與子別，呼天野草間。", "白馬繞旌旗，悲鳴相追攀。", "白楊秋月苦，早落豫章山。", "本爲休明人，斬虜素不閑。", "豈惜戰鬬死，爲君掃兇頑。", "精感石沒羽，豈云憚險艱。", "樓船若鯨飛，波蕩落星灣。", "此曲不可奏，三軍鬢成斑。"]'),
('61f23379-7a06-48dd-b68c-a93ddf4315af','沐浴子','李白','唐','唐诗','tang','','[]','沐芳莫彈冠，浴蘭莫振衣。',36,'全唐诗/poet.tang.8000.json','["沐芳莫彈冠，浴蘭莫振衣。", "處世忌太潔，至人貴藏暉。", "滄浪有釣叟，吾與爾同歸。"]'),
('c00c6453-c7d2-4ca6-84a9-c37cf5a196d1','高句驪','李白','唐','唐诗','tang','','[]','金花折風帽，白馬小遲回。',24,'全唐诗/poet.tang.8000.json','["金花折風帽，白馬小遲回。", "翩翩舞廣袖，似鳥海東來。"]'),
('36a924f7-a805-4c5b-aee5-89cec3d4b6cd','舍利弗','李白','唐','唐诗','tang','','[]','金繩界寶地，珍木蔭瑤池。',24,'全唐诗/poet.tang.8000.json','["金繩界寶地，珍木蔭瑤池。", "雲間妙音奏，天際法蠡吹。"]'),
('ca2c489a-e433-4c0f-8248-77d354f0665e','靜夜思','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u65b0\u4e50\u5e9c\u8f9e", "\u601d\u4e61", "\u4e2d\u79cb", "\u4e00\u5e74\u7ea7\u4e0a\u518c", "\u6708\u4eae"]','牀前看月光，疑是地上霜。',24,'全唐诗/poet.tang.8000.json','["牀前看月光，疑是地上霜。", "舉頭望山月，低頭思故鄉。"]'),
('e26acba5-04cc-4459-aadd-2e23ea5026af','淥水曲','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c", "\u8377\u82b1"]','淥水明秋月，南湖採白蘋。',24,'全唐诗/poet.tang.8000.json','["淥水明秋月，南湖採白蘋。", "荷花嬌欲語，愁殺蕩舟人。"]'),
('bbd5eeec-ef92-46be-a389-e254dd0549f5','鳳凰曲','李白','唐','唐诗','tang','','[]','嬴女吹玉簫，吟弄天上春。',36,'全唐诗/poet.tang.8000.json','["嬴女吹玉簫，吟弄天上春。", "青鸞不獨去，更有攜手人。", "影滅彩雲斷，遺聲落西秦。"]'),
('e82acb34-729a-41ea-bc99-75c28c90c9a2','鳳臺曲','李白','唐','唐诗','tang','','[]','嘗聞秦帝女，傳得鳳凰聲。',48,'全唐诗/poet.tang.8000.json','["嘗聞秦帝女，傳得鳳凰聲。", "是日逢仙子，當時別有情。", "人吹綵簫去，天借綠雲迎。", "曲在身不返，空餘弄玉名。"]'),
('8da2fb55-b15b-4e42-a060-a7dddacbc6d3','從軍行','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u4e50\u5e9c", "\u5efa\u529f\u7acb\u4e1a"]','從軍玉門道，逐虜金微山。',48,'全唐诗/poet.tang.8000.json','["從軍玉門道，逐虜金微山。", "笛奏梅花曲，刀開明月環。", "鼓聲鳴海上，兵氣擁雲間。", "願斬單于首，長驅靜鐵關。"]'),
('e9486b34-2104-4ab3-bfdd-8c4140b04c2a','秋思','李白','唐','唐诗','tang','','["\u5199\u666f", "\u7434\u66f2\u6b4c\u8f9e", "\u79cb\u5929", "\u4e50\u5e9c", "\u611f\u4f24"]','春陽如昨日，碧樹鳴黃鸝。',48,'全唐诗/poet.tang.8000.json','["春陽如昨日，碧樹鳴黃鸝。", "蕪然蕙草暮，颯爾涼風吹。", "天秋木葉下，月冷莎雞悲。", "坐愁羣芳歇，白露凋華滋。"]'),
('7277c420-9f3f-4093-a5b2-6331494721e8','春思','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e94\u8a00\u53e4\u8bd7", "\u6625\u5929", "\u575a\u8d1e", "\u5987\u5973"]','燕草如碧絲，秦桑低綠枝。',36,'全唐诗/poet.tang.8000.json','["燕草如碧絲，秦桑低綠枝。", "當君懷歸日，是妾斷腸時。", "春風不相識，何事入羅幃。"]'),
('817cdd6d-d0e2-4b48-9117-fd9a88fee1a7','秋思','李白','唐','唐诗','tang','','["\u60b2\u4f24", "\u79cb\u5929", "\u6292\u6000"]','燕支黃葉落，妾望自登臺。',48,'全唐诗/poet.tang.8000.json','["燕支黃葉落，妾望自登臺。", "海上碧雲斷，單于秋色來。", "胡兵沙塞合，漢使玉關回。", "征客無歸日，空悲蕙草摧。"]'),
('57203d7f-380c-4052-b21b-d1ea79fbe231','子夜吳歌 春歌','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6e05\u5546\u66f2\u8f9e", "\u6625\u5929", "\u5973\u5b50", "\u4e50\u5e9c", "\u8d5e\u7f8e"]','秦地羅敷女，採桑綠水邊。',36,'全唐诗/poet.tang.8000.json','["秦地羅敷女，採桑綠水邊。", "素手青條上，紅妝白日鮮。", "蠶飢妾欲去，五馬莫留連。"]'),
('abb3e465-f10e-43dd-b564-a5de08010478','子夜吳歌 夏歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u590f\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u54f2\u7406", "\u5199\u4eba"]','鏡湖三百里，菡萏發荷花。',36,'全唐诗/poet.tang.8000.json','["鏡湖三百里，菡萏發荷花。", "五月西施採，人看隘若耶。", "回舟不待月，歸去越王家。"]'),
('baccf46a-41c4-4a0f-b90f-37cc35b04a64','子夜吳歌 秋歌','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u5987\u5973", "\u79cb\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','長安一片月，萬戶擣衣聲。',36,'全唐诗/poet.tang.8000.json','["長安一片月，萬戶擣衣聲。", "秋風吹不盡，總是玉關情。", "何日平胡虜，良人罷遠征。"]'),
('f990af2e-d929-48da-a9b3-fdbc706ca4a3','子夜吳歌 冬歌','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u5987\u5973", "\u51ac\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','明朝驛使發，一夜絮征袍。',36,'全唐诗/poet.tang.8000.json','["明朝驛使發，一夜絮征袍。", "素手抽針冷，那堪把剪刀。", "裁縫寄遠道，幾日到臨洮。"]'),
('d6b2fb13-c1bf-4c00-80fc-fd24f908c86e','對酒行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u4eba\u751f", "\u4e50\u5e9c", "\u611f\u6168"]','松子栖金華，安期入蓬海。',60,'全唐诗/poet.tang.8000.json','["松子栖金華，安期入蓬海。", "此人古之仙，羽化竟何在。", "浮生速流電，倏忽變光彩。", "天地無凋換，容顏有遷改。", "對酒不肯飲，含情欲誰待。"]'),
('54bb87e8-3846-432a-95b7-6d951997bed9','估客行','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u6f02\u6cca", "\u5199\u4eba\u8bd7"]','海客乘天風，將船遠行役。',24,'全唐诗/poet.tang.8000.json','["海客乘天風，將船遠行役。", "譬如雲中鳥，一去無蹤跡。"]'),
('e6f4c79e-4f13-447c-9c90-c8f957c6701b','擣衣篇','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6000\u4eba", "\u6101\u82e6", "\u5987\u5973"]','閨裏佳人年十餘，嚬蛾對影恨離居。',208,'全唐诗/poet.tang.8000.json','["閨裏佳人年十餘，嚬蛾對影恨離居。", "忽逢江上春歸燕，銜得雲中尺素書。", "玉手開緘長歎息，狂夫猶戍交河北。", "萬里交河水北流，願爲雙燕泛中洲。", "君邊雲擁青絲騎，妾處苔生紅粉樓。", "樓上春風日將歇，誰能攬鏡看愁髮。", "曉吹員管隨落花，夜擣戎衣向明月。", "明月高高刻漏長，真珠簾箔掩蘭堂。", "橫垂寶幄同心結，半拂瓊筵蘇合香。", "瓊筵寶幄連枝錦，燈燭熒熒照孤寢。", "有便憑將金剪刀，爲君留下相思枕。", "摘盡庭蘭不見君，紅巾拭淚生氤氳。", "明年若更征邊塞，願作陽臺一叚雲。"]'),
('a9c6795e-e76e-4805-a268-6263a733bd66','少年行','李白','唐','唐诗','tang','','[]','君不見淮南少年游俠客，白日毬獵夜擁擲。',243,'全唐诗/poet.tang.8000.json','["君不見淮南少年游俠客，白日毬獵夜擁擲。", "呼盧百萬終不惜，報讎千里如咫尺。", "少年游俠好經過，渾身裝束皆綺羅。", "蕙蘭相隨喧妓女，風光去處滿笙歌。", "驕矜自言不可有，俠士堂中養來久。", "好鞍好馬乞與人，十千五千旋沽酒。", "赤心用盡爲知己，黃金不惜栽桃李。", "桃李栽來幾度春，一回花落一回新。", "府縣盡爲門下客，王侯皆是平交人。", "男兒百年且樂命，何須徇書受貧病。", "男兒百年且榮身，何須徇節甘風塵。", "衣冠半是征戰士，窮儒浪作林泉民。", "遮莫枝根長百丈，不如當代多還往。", "遮莫姻親連帝城，不如當身自簪纓。", "看取富貴眼前者，何用悠悠身後名。"]'),
('0cbca79c-cbbf-47f3-afd3-f96e151c2678','長歌行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u7406\u60f3", "\u4e50\u5e9c", "\u5efa\u529f\u7acb\u4e1a"]','桃李待日開，榮華照當年。',120,'全唐诗/poet.tang.8000.json','["桃李待日開，榮華照當年。", "東風動百物，草木盡欲言。", "枯枝無醜葉，涸水吐清泉。", "大力運天地，羲和無停鞭。", "功名不早著，竹帛將何宣。", "桃李務青春，誰能貫白日。", "富貴與神仙，蹉跎成兩失。", "金石猶銷鑠，風霜無久質。", "畏落日月後，强歡歌與酒。", "秋霜不惜人，倏忽侵蒲柳。"]'),
('427d3ea5-681b-4689-90f4-6da4f116ef11','長相思 一','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e50\u5e9c"]','日色已盡花含煙，月明欲素愁不眠。',82,'全唐诗/poet.tang.8000.json','["日色已盡花含煙，月明欲素愁不眠。", "趙瑟初停鳳凰柱，蜀琴欲奏鴛鴦弦。", "此曲有意無人傳，願隨春風寄燕然，憶君迢迢隔青天。", "昔日橫波目，今成流淚泉。", "不信妾腸斷，歸來看取明鏡前。"]'),
('12792cda-8a0c-4af3-b338-c6fbe036b865','長相思 二','李白','唐','唐诗','tang','','[]','美人在時花滿堂，美人去後空餘牀。',56,'全唐诗/poet.tang.8000.json','["美人在時花滿堂，美人去後空餘牀。", "牀中繡被卷不寢，至今三載猶聞香。", "香亦竟不滅，人亦竟不來。", "相思黃葉落，白露點青苔。"]'),
('174d0a8f-1350-4736-92d3-5c9f16fcff1f','猛虎行','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','朝作猛虎行，暮作猛虎吟。',340,'全唐诗/poet.tang.8000.json','["朝作猛虎行，暮作猛虎吟。", "腸斷非關隴頭水，淚下不爲雍門琴。", "旌旗繽紛兩河道，戰鼓驚山欲顛倒。", "秦人半作燕地囚，胡馬翻銜洛陽草。", "一輸一失關下兵，朝降夕叛幽薊城。", "巨鼇未斬海水動，魚龍奔走安得寧。", "頗似楚漢時，翻覆無定止。", "朝過博浪沙，暮入淮陰市。", "張良未遇韓信貧，劉項存亡在兩臣。", "蹔到下邳受兵略，來投漂母作主人。", "賢哲棲棲古如此，今時亦棄青雲士。", "有策不敢犯龍鱗，竄身南國避胡塵。", "寶書玉劒挂高閣，金鞍駿馬散故人。", "昨日方爲宣城客，掣鈴交通二千石。", "有時六博快壯心，遶牀三匝呼一擲。", "楚人每道張旭奇，心藏風雲世莫知。", "三吳邦伯皆顧盼，四海雄俠兩追隨。", "蕭曹曾作沛中吏，攀龍附鳳當有時。", "溧陽酒樓三月春，楊花茫茫愁殺人。", "胡雛綠眼吹玉笛，吳歌白紵飛梁塵。", "丈夫相見且爲樂，槌牛撾鼓會衆賓。", "我從此去釣東海，得魚笑寄情相親。"]'),
('37b09928-1193-4162-903a-d788c99863d8','去婦詞','李白','唐','唐诗','tang','','[]','古來有棄婦，棄婦有歸處。',290,'全唐诗/poet.tang.8000.json','["古來有棄婦，棄婦有歸處。", "今日妾辭君，辭君遣何去。", "本家零落盡，慟哭來時路。", "憶昔未嫁君，聞君却周旋。", "綺羅錦繡段，有贈黃金千。", "十五許嫁君，二十移所天。", "自從結髮日未幾，離君緬山川。", "家家盡歡喜，孤妾長自憐。", "幽閨多怨思，盛色無十年。", "相思若循還，枕席生流泉。", "流泉咽不掃，獨夢關山道。", "及此見君歸，君歸妾已老。", "物情惡衰賤，新寵方妍好。", "掩淚出故房，傷心劇秋草。", "自妾爲君妻，君東妾在西。", "羅幃到曉恨，玉貌一生啼。", "自從離別久，不覺塵埃厚。", "嘗嫌玳瑁孤，猶羨鴛鴦偶。", "歲華逐霜霰，賤妾何能久。", "寒沼落芙蓉，秋風散楊柳。", "以比顦顇顏，空持舊物還。", "餘生欲何寄，誰肯相牽攀。", "君恩既斷絕，相見何年月。", "悔傾連理杯，虛作同心結。"]'),
('569ee61d-350a-4d24-b320-b2e99ca54dd7','襄陽歌','李白','唐','唐诗','tang','','[]','落日欲沒峴山西，倒著接䍦花下迷。',237,'全唐诗/poet.tang.8000.json','["落日欲沒峴山西，倒著接䍦花下迷。", "襄陽小兒齊拍手，攔街爭唱白銅鞮。", "傍人借問笑何事，笑殺山翁醉似泥。", "鸕鷀杓，鸚鵡杯，百年三萬六千日，一日須傾三百杯。", "遙看漢水鴨頭綠，恰似葡萄初醱醅。", "此江若變作春酒，壘麴便築糟丘臺。", "千金駿馬換小妾，笑坐雕鞍歌落梅。", "車傍側挂一壺酒，鳳笙龍管行相摧。", "咸陽市中歎黃犬，何如月下傾金罍。", "君不見晉朝羊公一片石，龜頭剝落生莓苔。", "淚亦不能爲之墮，心亦不能爲之哀。", "清風朗月不用一錢買，玉山自倒非人推。", "舒州杓，力士鐺，李白與爾同死生。", "襄王雲雨今安在，江水東流猨夜聲。"]'),
('b6cf8d2d-6d88-4914-84c9-61f5cf52cfc1','南都行','李白','唐','唐诗','tang','','[]','南都信佳麗，武闕橫西關。',120,'全唐诗/poet.tang.8000.json','["南都信佳麗，武闕橫西關。", "白水真人居，萬商羅鄽闤。", "高樓對紫陌，甲第連青山。", "此地多英豪，邈然不可攀。", "陶朱與五羖，名播天壤間。", "麗華秀玉色，漢女嬌朱顏。", "清歌遏流雲，豔舞有餘閑。", "遨遊盛宛洛，冠蓋隨風還。", "走馬紅陽城，呼鷹白河灣。", "誰識臥龍客，長吟愁鬢斑。"]'),
('5945ca23-1072-44ab-9e3a-04b8bbc3c74d','江上吟','李白','唐','唐诗','tang','','[]','木蘭之枻沙棠舟，玉簫金管坐兩頭。',96,'全唐诗/poet.tang.8000.json','["木蘭之枻沙棠舟，玉簫金管坐兩頭。", "美酒尊中置千斛，載妓隨波任去留。", "仙人有待乘黃鶴，海客無心隨白鷗。", "屈平詞賦懸日月，楚王臺榭空山丘。", "興酣落筆搖五嶽，詩成笑傲凌滄洲。", "功名富貴若長在，漢水亦應西北流。"]'),
('11c0a3c7-dbae-46d3-bb72-7b75b76ba02e','侍從宜春苑奉詔賦龍池柳色初青聽新鶯百囀歌','李白','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','東風已綠瀛洲草，紫殿紅樓覺春好，池南柳色半青青。',136,'全唐诗/poet.tang.8000.json','["東風已綠瀛洲草，紫殿紅樓覺春好，池南柳色半青青。", "縈烟嫋娜拂綺城，垂絲百尺挂雕楹。", "上有好鳥相和鳴，間關早得春風情。", "春風卷入碧雲去，千門萬戶皆春聲。", "是時君王在鎬京，五雲垂暉耀紫清。", "仗出金宮隨日轉，天回玉輦繞花行。", "始向蓬萊看舞鶴，還過茝石聽新鶯。", "新鶯飛繞上林苑，願入簫韶雜鳳笙。"]'),
('e6173ae4-186d-4ac0-8804-2ab36ecf4606','玉壺吟','李白','唐','唐诗','tang','','["\u5954\u653e", "\u5199\u4eba", "\u58ee\u5fd7", "\u5199\u4eba\u8bd7"]','烈士擊玉壺，壯心惜暮年。',124,'全唐诗/poet.tang.8000.json','["烈士擊玉壺，壯心惜暮年。", "三杯拂劒舞秋月，忽然高詠涕泗漣。", "鳳凰初下紫泥詔，謁帝稱觴登御筵。", "揄揚九重萬乘主，謔浪赤墀青瑣賢。", "朝天數換飛龍馬，勅賜珊瑚白玉鞭。", "世人不識東方朔，大隱金門是謫仙。", "西施宜笑復宜嚬，醜女效之徒累身。", "君王雖愛蛾眉好，無奈宮中妬殺人。"]'),
('c23e8a0a-bc62-4f63-99b5-5d6032ccafe9','豳歌行上新平長史兄粲','李白','唐','唐诗','tang','','[]','豳谷稍稍振庭柯，涇水浩浩揚湍波。',160,'全唐诗/poet.tang.8000.json','["豳谷稍稍振庭柯，涇水浩浩揚湍波。", "哀鴻酸嘶暮聲急，愁雲蒼慘寒氣多。", "憶昨去家此爲客，荷花初紅柳條碧。", "中宵出飲三百杯，明朝歸揖二千石。", "寧知流寓變光輝，胡霜蕭颯繞客衣。", "寒灰寂寞憑誰暖，落葉飄揚何處歸。", "吾兄行樂窮曛旭，滿堂有美顏如玉。", "趙女長歌入綵雲，燕姬醉舞嬌紅燭。", "狐裘獸炭酌流霞，壯士悲吟寧見嗟。", "前榮後枯相翻覆，何惜餘光及棣華。"]'),
('15394b6f-365e-4ac8-9eaf-1d394d41c58c','西嶽雲臺歌送丹丘子','李白','唐','唐诗','tang','','["\u534e\u5c71", "\u9ec4\u6cb3", "\u9001\u522b", "\u5c71\u6c34"]','西嶽崢嶸何壯哉，黃河如絲天際來。',176,'全唐诗/poet.tang.8000.json','["西嶽崢嶸何壯哉，黃河如絲天際來。", "黃河萬里觸山動，盤渦轂轉秦地雷。", "榮光休氣紛五彩，千年一清聖人在。", "巨靈咆哮擘兩山，洪波噴箭射東海。", "三峯却立如欲摧，翠崖丹谷高掌開。", "白帝金精運元氣，石作蓮花雲作臺。", "雲臺閣道連窈冥，中有不死丹丘生。", "明星玉女備灑掃，麻姑搔背指爪輕。", "我皇手把天地戶，丹丘談天與天語。", "九重出入生光輝，東來蓬萊復西歸。", "玉漿儻惠故人飲，騎二茅龍上天飛。"]'),
('1596c459-4184-412c-9538-e0a663e00d42','元丹丘歌','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','元丹丘，愛神仙，朝飲潁川之清流，暮還嵩岑之紫烟，三十六峰長周旋。',64,'全唐诗/poet.tang.8000.json','["元丹丘，愛神仙，朝飲潁川之清流，暮還嵩岑之紫烟，三十六峰長周旋。", "長周旋，躡星虹，身騎飛龍耳生風。", "橫河跨海與天通，我知爾遊心無窮。"]'),
('e21baa8a-c2cb-48eb-822b-2041486980da','扶風豪士歌','李白','唐','唐诗','tang','','["\u6292\u60c5"]','洛陽三月飛胡沙，洛陽城中人怨嗟。',208,'全唐诗/poet.tang.8000.json','["洛陽三月飛胡沙，洛陽城中人怨嗟。", "天津流水波赤血，白骨相撐如亂麻。", "我亦東奔向吳國，浮雲四塞道路賒。", "東方日出啼早鴉，城門人開掃落花。", "梧桐楊柳拂金井，來醉扶風豪士家。", "扶風豪士天下奇，意氣相傾山可移。", "作人不倚將軍勢，飲酒豈顧尚書期。", "雕盤綺食會衆客，吳歌趙舞香風吹。", "原嘗春陵六國時，開心寫意君所知。", "堂中各有三千士，明日報恩知是誰。", "撫長劒，一揚眉，清水白石何離離。", "脫吾帽，向君笑，飲君酒，爲君吟。", "張良未逐赤松去，橋邊黃石知我心。"]'),
('a3b648df-c3d8-4f61-904f-e50cc5864f0a','同族弟金城尉叔卿燭照山水壁畫歌','李白','唐','唐诗','tang','','[]','高堂粉壁圖蓬瀛，燭前一見滄洲清。',116,'全唐诗/poet.tang.8000.json','["高堂粉壁圖蓬瀛，燭前一見滄洲清。", "洪波洶湧山崢嶸，皎若丹丘隔海望赤城。", "光中乍喜嵐氣滅，謂逢山陰晴後雪。", "迴溪碧流寂無喧，又如秦人月下窺花源。", "了然不覺清心魂，祗將疊嶂鳴秋猨。", "與君對此歡未歇，放歌行吟達明發。", "却顧海客揚雲帆，便欲因之向溟渤。"]'),
('f3883a24-6c95-430b-863e-caa570aa90a1','白毫子歌','李白','唐','唐诗','tang','','[]','淮南小山白毫子，乃在淮南小山裏。',112,'全唐诗/poet.tang.8000.json','["淮南小山白毫子，乃在淮南小山裏。", "夜臥松下雲，朝餐石中髓。", "小山連緜向江開，碧峰巉巖綠水迴。", "余配白毫子，獨酌流霞杯。", "拂花弄琴坐青苔，綠蘿樹下春風來。", "南窗蕭颯松聲起，憑崖一聽清心耳。", "可得見，未得親。", "八公攜手五雲去，空餘桂樹愁殺人。"]'),
('14febea6-9b81-4ef4-9b50-b1b6138a161c','梁園吟','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u8c6a\u653e"]','我浮黃雲去京闕，挂席欲進波連山。',264,'全唐诗/poet.tang.8000.json','["我浮黃雲去京闕，挂席欲進波連山。", "天長水闊厭遠涉，訪古始及平臺間。", "平臺爲客憂思多，對酒遂作梁園歌。", "却憶蓬池阮公詠，因吟淥水揚洪波。", "洪波浩蕩迷舊國，路遠西歸安可得。", "人生達命豈暇愁，且飲美酒登高樓。", "平頭奴子搖大扇，五月不熱疑清秋。", "玉盤楊梅爲君設，吳鹽如花皎白雪。", "持鹽把酒但飲之，莫學夷齊事高潔。", "昔人豪貴信陵君，今人耕種信陵墳。", "荒城虛照碧山月，古木盡入蒼梧雲。", "粱王宮闕今安在？枚馬先歸不相待。", "舞影歌聲散綠池，空餘汴水東流海。", "沈吟此事淚滿衣，黃金買醉未能歸。", "連呼五白行六博，分曹賭酒酣馳輝。", "歌且謠，意方遠，東山高臥時起來，欲濟蒼生未應晚。"]'),
('fa4aebdb-e612-4a09-9c23-2f02617ccf69','鳴臯歌送岑徵君','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u793e\u4f1a", "\u653f\u6cbb", "\u63ed\u9732", "\u6124\u61d1"]','若有人兮思鳴臯，阻積雪兮心煩勞。',362,'全唐诗/poet.tang.8000.json','["若有人兮思鳴臯，阻積雪兮心煩勞。", "洪河凌競不可以徑度，冰龍鱗兮難容舠。", "邈仙山之峻極兮，聞天籟之嘈嘈。", "霜厓縞皓以合沓兮，若長風扇海湧滄溟之波濤。", "玄猨綠羆，舔舕崟岌。", "危柯振石，駭膽慄魄，羣呼而相號。", "峯崢嶸以路絕，挂星辰於巖㟼。", "送君之歸兮，動鳴臯之新作。", "交鼓吹兮彈絲，觴清泠之池閣。", "君不行兮何待，若反顧之黃鶴。", "掃梁園之羣英，振大雅於東洛。", "巾征軒兮歷阻折，尋幽居兮越巘崿。", "盤白石兮坐素月，琴松風兮寂萬壑。", "望不見兮心氛氳，蘿冥冥兮霰紛紛。", "水橫洞以下淥，波小聲而上聞。", "虎嘯谷而生風，龍藏溪而吐雲。", "寡鶴清唳，飢鼯嚬呻。", "魂獨處此幽默兮，愀空山而愁人。", "雞聚族以爭食，鳳孤飛而無隣。", "蝘蜓嘲龍，魚目混珍。", "嫫母衣錦，西施負薪。", "若使巢由桎梏於軒冕兮，亦奚異乎夔龍蹩躠於風塵。", "哭何苦而救楚，笑何誇而却秦。", "吾誠不能學二子沽名矯節以耀世兮，固將棄天地而遺身。"]'),
('ec25cdb5-9da2-4142-9fdb-0560787f854d','鳴臯歌奉餞從翁清歸五厓山居','李白','唐','唐诗','tang','','[]','憶昨鳴臯夢裏還，手弄素月清潭間。',132,'全唐诗/poet.tang.8000.json','["憶昨鳴臯夢裏還，手弄素月清潭間。", "覺時枕席非碧山，側身西望阻秦關。", "麒膦閣上春還早，著書却憶伊陽好。", "青松來風吹古道，綠蘿飛花覆烟草。", "我家仙翁愛清真，才雄草聖凌古人，欲臥鳴臯絕世塵。", "鳴臯微茫在何處？五厓峽水橫樵路。", "身披翠雲裘，袖拂紫烟去。", "去時應過嵩少間，相思爲折三花樹。"]'),
('7159e6e2-2682-4984-9d32-43f5acefb97c','勞勞亭歌','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u58ee\u5fd7\u672a\u916c", "\u611f\u6168"]','金陵勞勞送客堂，蔓草離離生道傍。',80,'全唐诗/poet.tang.8000.json','["金陵勞勞送客堂，蔓草離離生道傍。", "古情不盡東流水，此地悲風愁白楊。", "我乘素舸同康樂，朗詠清川飛夜霜。", "昔聞牛渚吟五章，今來何謝袁家郎。", "苦竹寒聲動秋月，獨宿空簾歸夢長。"]'),
('58462be4-aa40-4a7f-a879-1c38832a838c','橫江詞六首 一','李白','唐','唐诗','tang','','[]','人道橫江好，儂道橫江惡。',28,'全唐诗/poet.tang.8000.json','["人道橫江好，儂道橫江惡。", "一風三日吹倒山，白浪高於瓦官閣。"]'),
('c16cfbee-41fc-4170-a5f5-c8bf3793fd36','橫江詞六首 二','李白','唐','唐诗','tang','','[]','海潮南去過潯陽，牛渚由來險馬當。',32,'全唐诗/poet.tang.8000.json','["海潮南去過潯陽，牛渚由來險馬當。", "橫江欲渡風波惡，一水牽愁萬里長。"]'),
('bbe66c93-b169-4720-87de-e4bcc325b874','橫江詞六首 三','李白','唐','唐诗','tang','','[]','橫江西望阻西秦，漢水東連揚子津。',32,'全唐诗/poet.tang.8000.json','["橫江西望阻西秦，漢水東連揚子津。", "白浪如山那可渡，狂風愁殺峭帆人。"]'),
('902ee0e4-1534-4353-bc48-5acefc0fdfd6','橫江詞六首 四','李白','唐','唐诗','tang','','[]','海神來過惡風迴，浪打天門石壁開。',32,'全唐诗/poet.tang.8000.json','["海神來過惡風迴，浪打天門石壁開。", "浙江八月何如此，濤似連山噴雪來。"]'),
('4b77bc04-02d5-49ea-ac32-438ab33eadb2','橫江詞六首 五','李白','唐','唐诗','tang','','[]','橫江館前津吏迎，向余東指海雲生。',32,'全唐诗/poet.tang.8000.json','["橫江館前津吏迎，向余東指海雲生。", "郎今欲渡緣何事，如此風波不可行。"]'),
('6dd83676-e8ed-4d6e-ae39-7337590ed2f4','橫江詞六首 六','李白','唐','唐诗','tang','','[]','月暈天風霧不開，海鯨東蹙百川迴。',32,'全唐诗/poet.tang.8000.json','["月暈天風霧不開，海鯨東蹙百川迴。", "驚波一起三山動，公無渡河歸去來。"]'),
('53b6b263-edaa-41a6-b7c2-b896c22de8c4','金陵城西樓月下吟','李白','唐','唐诗','tang','','[]','金陵夜寂涼風發，獨上高樓望吳越。',64,'全唐诗/poet.tang.8000.json','["金陵夜寂涼風發，獨上高樓望吳越。", "白雲暎水搖空城，白露垂珠滴秋月。", "月下沈吟久不歸，古來相接眼中稀。", "解道澄江淨如練，令人長憶謝玄暉。"]'),
('738b8857-2149-414e-87ae-0213953d78ee','東山吟','李白','唐','唐诗','tang','','[]','攜妓東土山，悵然悲謝安。',80,'全唐诗/poet.tang.8000.json','["攜妓東土山，悵然悲謝安。", "我妓今朝如花月，他妓古墳荒草寒。", "白雞夢後三百歲，洒酒澆君同所歡。", "酣來自作青海舞，秋風吹落紫綺冠。", "彼亦一時，此亦一時，浩浩洪流之詠何必奇。"]'),
('6961a819-c817-459d-aa25-fde06e991df7','僧伽歌','李白','唐','唐诗','tang','','[]','真僧法號號僧伽，有時與我論三車。',128,'全唐诗/poet.tang.8000.json','["真僧法號號僧伽，有時與我論三車。", "問言誦咒幾千徧，口道恆河沙復沙。", "此僧本住南天竺，爲法頭陀來此國。", "戒得長天秋月明，心如世上青蓮色。", "意清淨，貌稜稜，亦不減，亦不增。", "瓶裏千年鐵柱骨，手中萬歲胡孫藤。", "嗟予落魄江淮久，罕遇真僧說空有。", "一言散盡波羅夷，再禮渾除犯輕垢。"]'),
('0bc47782-7c80-4541-87f1-d1a657e2c24a','白雲歌送劉十六歸山','李白','唐','唐诗','tang','','["\u5199\u4e91", "\u6292\u60c5", "\u9001\u522b"]','楚山秦山皆白雲，白雲處處長隨君。',50,'全唐诗/poet.tang.8000.json','["楚山秦山皆白雲，白雲處處長隨君。", "長隨君，君入楚山裏，雲亦隨君渡湘水。", "湘水上，女蘿衣，白雲堪臥君早歸。"]'),
('8e6c43ff-126c-4e1d-a4df-cd6e8adc31a6','白雲歌送友人','李白','唐','唐诗','tang','','[]','楚山秦山多白雲，白雲䖏䖏長隨君。',48,'全唐诗/poet.tang.8000.json','["楚山秦山多白雲，白雲䖏䖏長隨君。", "君今還入楚山裏，雲亦隨君渡湘水。", "水上女蘿衣白雲，早卧早行君早起。"]'),
('9d90b9ba-9e08-4f8d-ae30-f159dfb7fc94','金陵歌送別范宣','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u5199\u7269", "\u6292\u60c5", "\u6000\u53e4", "\u9001\u4eba", "\u548f\u53f2"]','石頭巉巖如虎踞，凌波欲過滄江去。',160,'全唐诗/poet.tang.8000.json','["石頭巉巖如虎踞，凌波欲過滄江去。", "鍾山龍盤走勢來，秀色橫分歷陽樹。", "四十餘帝三百秋，功名事跡隨東流。", "白馬小兒誰家子，泰清之歲來關囚。", "金陵昔時何壯哉，席卷英豪天下來。", "冠蓋散爲烟霧盡，金輿玉座成寒灰。", "扣劒悲吟空咄嗟，梁陳白骨亂如麻。", "天子龍沈景陽井，誰歌玉樹後庭花。", "此地傷心不能道，目下離離長春草。", "送爾長江萬里心，他年來訪南山老。"]'),
('ae50afae-05a7-43c5-b362-0eecf9f49622','笑歌行','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u501f\u53e4\u8bbd\u4eca", "\u5199\u4eba\u8bd7"]','笑矣乎，笑矣乎！君不見曲如鉤，古人知爾封公侯。',237,'全唐诗/poet.tang.8000.json','["笑矣乎，笑矣乎！君不見曲如鉤，古人知爾封公侯。", "君不見直如弦，古人知爾死道邊。", "張儀所以只掉三寸舌，蘇秦所以不墾二傾田。", "笑矣乎，笑矣乎！君不見滄浪老人歌一曲，還道滄浪濯吾足。", "平生不解謀此身，虛作離騷遣人讀。", "笑矣乎，笑矣乎！趙有豫讓楚屈平，賣身買得千年名。", "巢由洗耳有何益，夷齊餓死終無成。", "君愛身後名，我愛眼前酒。", "飲酒眼前樂，虛名何處有。", "男兒窮通當有時，曲腰向君君不知。", "猛虎不看几上肉，洪鑪不鑄囊中錐。", "笑矣乎，笑矣乎！甯武子，朱買臣，扣角行歌背負薪。", "今日逢君君不識，豈得不如佯狂人。"]'),
('4a9f5cbb-1d9e-4d3b-a205-50d81461f6ab','悲歌行','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u72ec", "\u7406\u60f3", "\u6000\u624d\u4e0d\u9047"]','悲來乎，悲來乎！主人有酒且莫斟，聽我一曲悲來吟。',248,'全唐诗/poet.tang.8000.json','["悲來乎，悲來乎！主人有酒且莫斟，聽我一曲悲來吟。", "悲來不吟還不笑，天下無人知我心。", "君有數斗酒，我有三尺琴。", "琴鳴酒樂兩相得，一杯不啻千鈞金。", "悲來乎，悲來乎！天雖長，地雖久，金玉滿堂應不守。", "富貴百年能幾何，死生一度人皆有。", "孤猨坐啼墳上月，且須一盡杯中酒。", "悲來乎，悲來乎！鳳皇不至河無圖，微子去之箕子奴。", "漢帝不憶李將軍，楚王放却屈大夫。", "悲來乎，悲來乎！秦家李斯早追悔，虛名撥向身之外。", "范子何曾愛五湖，功成名遂身自退。", "劒是一夫用，書能知姓名。", "惠施不肯干萬乘，卜式未必窮一經。", "還須黑頭取方伯，莫謾白首爲儒生。"]'),
('86dd7753-11d3-48b5-a2ec-75967ea97855','秋浦歌十七首 一','李白','唐','唐诗','tang','','[]','秋浦長似秋，蕭條使人愁。',60,'全唐诗/poet.tang.8000.json','["秋浦長似秋，蕭條使人愁。", "客愁不可度，行上東大樓。", "正西望長安，下見江水流。", "寄言向江水，汝意憶儂不。", "遙傳一掬淚，爲我達揚州。"]'),
('63e6182c-66e4-4c79-9f65-08b63903cfae','秋浦歌十七首 二','李白','唐','唐诗','tang','','["\u9ec4\u5c71"]','秋浦猨夜愁，黃山堪白頭。',48,'全唐诗/poet.tang.8000.json','["秋浦猨夜愁，黃山堪白頭。", "清溪非隴水，翻作斷腸流。", "欲去不得去，薄遊成久遊。", "何年是歸日，雨淚下孤舟。"]'),
('fba10bdf-612f-40f3-abba-ed86cced0940','秋浦歌十七首 三','李白','唐','唐诗','tang','','[]','秋浦錦駝鳥，人間天上稀。',24,'全唐诗/poet.tang.8000.json','["秋浦錦駝鳥，人間天上稀。", "山雞羞淥水，不敢照毛衣。"]'),
('c2d84136-3150-4fd8-9d94-c18b7fb44b71','秋浦歌十七首 四','李白','唐','唐诗','tang','','[]','兩鬢入秋浦，一朝颯已衰。',24,'全唐诗/poet.tang.8000.json','["兩鬢入秋浦，一朝颯已衰。", "猨聲催白髮，長短盡成絲。"]'),
('d2e41acb-dbb9-4e5c-86ff-39def83514c0','秋浦歌十七首 五','李白','唐','唐诗','tang','','[]','秋浦多白猨，超騰若飛雪。',24,'全唐诗/poet.tang.8000.json','["秋浦多白猨，超騰若飛雪。", "牽引條上兒，飲弄水中月。"]'),
('b815ccc6-739b-4ef4-867f-9dfc9c66734e','秋浦歌十七首 六','李白','唐','唐诗','tang','','[]','愁作秋浦客，強看秋浦花。',24,'全唐诗/poet.tang.8000.json','["愁作秋浦客，強看秋浦花。", "山川如剡縣，風日似長沙。"]'),
('9d337413-1a74-44a9-aa6d-c1798fe81b59','秋浦歌十七首 七','李白','唐','唐诗','tang','','[]','醉上山公馬，寒歌甯戚牛。',24,'全唐诗/poet.tang.8000.json','["醉上山公馬，寒歌甯戚牛。", "空吟白石爛，淚滿黑貂裘。"]'),
('258cad70-5cd1-4373-b1ee-118b2d0cd0a4','秋浦歌十七首 八','李白','唐','唐诗','tang','','[]','秋浦千重嶺，水車嶺最奇。',24,'全唐诗/poet.tang.8000.json','["秋浦千重嶺，水車嶺最奇。", "天傾欲墮石，水拂寄生枝。"]'),
('8e5c232e-a4c8-4868-9d39-35434a26691a','秋浦歌十七首 九','李白','唐','唐诗','tang','','[]','江祖一片石，青天掃畫屏。',24,'全唐诗/poet.tang.8000.json','["江祖一片石，青天掃畫屏。", "題詩留萬古，綠字錦苔生。"]'),
('88ad039a-16f3-4ea6-8c56-e4394531e039','秋浦歌十七首 十','李白','唐','唐诗','tang','','[]','千千石楠樹，萬萬女貞林。',36,'全唐诗/poet.tang.8000.json','["千千石楠樹，萬萬女貞林。", "山山白鷺滿，澗澗白猨吟。", "君莫向秋浦，猨聲碎客心。"]'),
('58a66aff-d6a6-4e67-b96b-a9887ee4b7ea','秋浦歌十七首 十一','李白','唐','唐诗','tang','','[]','邏人（一作「叉」）橫鳥道，江祖出魚梁。',38,'全唐诗/poet.tang.8000.json','["邏人（一作「叉」）橫鳥道，江祖出魚梁。", "水急客舟（一作「行」）疾，山花拂面香。"]'),
('452a8a79-20e5-4322-96a8-657ab4222472','秋浦歌十七首 十二','李白','唐','唐诗','tang','','[]','水如一匹練，此地即平天。',24,'全唐诗/poet.tang.8000.json','["水如一匹練，此地即平天。", "耐可乘明月，看花上酒船。"]'),
('07710d64-db0a-419e-8a9c-f1afa44c58e0','秋浦歌十七首 十三','李白','唐','唐诗','tang','','[]','淥水淨素月，月明白鷺飛。',24,'全唐诗/poet.tang.8000.json','["淥水淨素月，月明白鷺飛。", "郎聽採菱女，一道夜歌歸。"]'),
('11fbf0a3-2f39-400e-832f-4c8ed3931fa8','秋浦歌十七首 十四','李白','唐','唐诗','tang','','[]','爐火照天地，紅星亂紫煙。',24,'全唐诗/poet.tang.8000.json','["爐火照天地，紅星亂紫煙。", "赧郎明月夜，歌曲動寒川。"]'),
('968dcfca-7d80-478e-a18b-ba69afe93346','秋浦歌十七首 十五','李白','唐','唐诗','tang','','[]','白髮三千丈，緣愁似個長。',24,'全唐诗/poet.tang.8000.json','["白髮三千丈，緣愁似個長。", "不知明鏡裡，何處得秋霜。"]'),
('2e7b87c1-be9b-4e4b-a4cb-02f1ab2950fc','秋浦歌十七首 十六','李白','唐','唐诗','tang','','[]','秋浦田舍翁，採魚水中宿。',24,'全唐诗/poet.tang.8000.json','["秋浦田舍翁，採魚水中宿。", "妻子張白鷴，結罝暎深竹。"]'),
('26e801ac-cc4c-43dc-b55d-65ee6fc94f05','秋浦歌十七首 十七','李白','唐','唐诗','tang','','[]','桃波（一作「陂」）一步地，了了語聲聞。',31,'全唐诗/poet.tang.8000.json','["桃波（一作「陂」）一步地，了了語聲聞。", "闇與山僧別，低頭禮白雲。"]'),
('703a3f52-3784-4006-862a-c0ad356ba855','當塗趙炎少府粉圖山水歌','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','峨眉高出西極天，羅浮直與南溟連。',240,'全唐诗/poet.tang.8000.json','["峨眉高出西極天，羅浮直與南溟連。", "名公繹思揮彩筆，驅山走海置眼前。", "滿堂空翠如可掃，赤城霞氣蒼梧烟。", "洞庭瀟湘意渺綿，三江七澤情洄沿。", "驚濤洶湧向何處，孤舟一去迷歸年。", "征帆不動亦不旋，飄如隨風落天邊。", "心搖目斷興難盡，幾時可到三山巔。", "西峯崢嶸噴流泉，橫石蹙水波潺湲。", "東厓合沓蔽輕霧，深林雜樹空芊綿。", "此中冥昧失晝夜，隱几寂聽無鳴蟬。", "長松之下列羽客，對坐不語南昌仙。", "南昌仙人趙夫子，妙年歷落青雲士。", "訟庭無事羅衆賓，杳然如在丹青裏。", "五色粉圖安足珍，真仙可以全吾身。", "若待功成拂衣去，武陵桃花笑殺人。"]'),
('1faa66c1-a135-4c95-a0f8-ecbd47e2a0a5','永王東巡歌十一首 一','李白','唐','唐诗','tang','','[]','永王正月東出師，天子遙分龍虎旗。',32,'全唐诗/poet.tang.8000.json','["永王正月東出師，天子遙分龍虎旗。", "樓船一舉風波靜，江漢翻爲雁鶩池。"]'),
('9cabfb03-bef9-4898-ad85-6d92db0a5aaf','永王東巡歌十一首 二','李白','唐','唐诗','tang','','[]','三川北虜亂如麻，四海南奔似永嘉。',32,'全唐诗/poet.tang.8000.json','["三川北虜亂如麻，四海南奔似永嘉。", "但用東山謝安石，爲君談笑靜胡沙。"]'),
('bdcabbfe-c183-4260-a7ae-85a854bad316','永王東巡歌十一首 三','李白','唐','唐诗','tang','','[]','雷鼓嘈嘈喧武昌，雲旗獵獵過尋陽。',32,'全唐诗/poet.tang.8000.json','["雷鼓嘈嘈喧武昌，雲旗獵獵過尋陽。", "秋毫不犯三吳悅，春日遙看五色光。"]'),
('a853c307-f382-4dcd-9c16-d12a385f6961','永王東巡歌十一首 四','李白','唐','唐诗','tang','','[]','龍蟠虎踞帝王州，帝子金陵訪古丘。',32,'全唐诗/poet.tang.8000.json','["龍蟠虎踞帝王州，帝子金陵訪古丘。", "春風試暖昭陽殿，明月還過鳷鵲樓。"]'),
('29e61048-40c2-4b98-997b-774bb0248964','永王東巡歌十一首 五','李白','唐','唐诗','tang','','[]','二帝巡遊俱未迴，五陵松栢使人哀。',32,'全唐诗/poet.tang.8000.json','["二帝巡遊俱未迴，五陵松栢使人哀。", "諸侯不救河南地，更喜賢王遠道來。"]'),
('2e0654dd-58d9-40d2-a2fa-b3266cac2d46','永王東巡歌十一首 六','李白','唐','唐诗','tang','','[]','丹陽北固是吳關，畫出樓臺雲水間。',32,'全唐诗/poet.tang.8000.json','["丹陽北固是吳關，畫出樓臺雲水間。", "千巖烽火連滄海，兩岸旌旗繞碧山。"]'),
('07f7fe66-f3c9-4c6b-afd1-d955bcdeeb87','永王東巡歌十一首 七','李白','唐','唐诗','tang','','[]','王出三山按五湖，樓船跨海次陪都。',32,'全唐诗/poet.tang.8000.json','["王出三山按五湖，樓船跨海次陪都。", "戰艦森森羅虎士，征帆一一引龍駒。"]'),
('432c5149-2416-4bc3-b484-4896e19eefda','永王東巡歌十一首 八','李白','唐','唐诗','tang','','[]','長風挂席勢難迴，海動山傾古月摧。',32,'全唐诗/poet.tang.8000.json','["長風挂席勢難迴，海動山傾古月摧。", "君看帝子浮江日，何似龍驤出峽來。"]'),
('35111e31-f468-4698-9369-f4e34208388c','永王東巡歌十一首 九','李白','唐','唐诗','tang','','[]','祖龍浮海不成橋，漢武尋陽空射蛟。',32,'全唐诗/poet.tang.8000.json','["祖龍浮海不成橋，漢武尋陽空射蛟。", "我王樓艦輕秦漢，却似文皇欲渡遼。"]'),
('3ba4db31-89c7-4f13-bcbf-c68d421096be','永王東巡歌十一首 十','李白','唐','唐诗','tang','','[]','帝寵賢王入楚關，掃清江漢始應還。',32,'全唐诗/poet.tang.8000.json','["帝寵賢王入楚關，掃清江漢始應還。", "初從雲夢開朱邸，更取金陵作小山。"]'),
('94873c8c-d4b9-47cd-aa64-b088fae16c7e','永王東巡歌十一首 十一','李白','唐','唐诗','tang','','[]','試借君王玉馬鞭，指揮戎虜坐瓊筵。',32,'全唐诗/poet.tang.8000.json','["試借君王玉馬鞭，指揮戎虜坐瓊筵。", "南風一掃胡塵靜，西入長安到日邊。"]'),
('86008f97-e77d-4330-b507-64c35210be12','上皇西巡南京歌十首 一','李白','唐','唐诗','tang','','[]','胡塵輕拂建章臺，聖主西巡蜀道來。',32,'全唐诗/poet.tang.8000.json','["胡塵輕拂建章臺，聖主西巡蜀道來。", "劒壁門高五千尺，石爲樓閣九天開。"]'),
('1bde3214-e68d-4780-a7ff-a62953c0ed13','上皇西巡南京歌十首 二','李白','唐','唐诗','tang','','[]','九天開出一成都，萬戶千門入畫圖。',32,'全唐诗/poet.tang.8000.json','["九天開出一成都，萬戶千門入畫圖。", "草樹雲山如錦繡，秦川得及此間無。"]'),
('1040f25c-51cc-4fb6-902f-d62d086a43b6','上皇西巡南京歌十首 三','李白','唐','唐诗','tang','','[]','華陽春樹號新豐，行入新都若舊宮。',32,'全唐诗/poet.tang.8000.json','["華陽春樹號新豐，行入新都若舊宮。", "柳色未饒秦地綠，花光不滅上陽紅。"]'),
('7dd0f071-7518-40dc-aeca-5e07188e6bff','上皇西巡南京歌十首 四','李白','唐','唐诗','tang','','[]','誰道君王行路難，六龍西幸萬人歡。',32,'全唐诗/poet.tang.8000.json','["誰道君王行路難，六龍西幸萬人歡。", "地轉錦江成渭水，天迴玉壘作長安。"]'),
('69f2d8e0-00b0-4451-bf8b-531913ee370d','上皇西巡南京歌十首 五','李白','唐','唐诗','tang','','[]','萬國同風共一時，錦江何謝曲江池。',32,'全唐诗/poet.tang.8000.json','["萬國同風共一時，錦江何謝曲江池。", "石鏡更明天上月，後宮親得照蛾眉。"]'),
('045ef334-ce56-4dc5-bf77-231901ea062c','上皇西巡南京歌十首 六','李白','唐','唐诗','tang','','[]','濯錦清江萬里流，雲帆龍舸下揚州。',32,'全唐诗/poet.tang.8000.json','["濯錦清江萬里流，雲帆龍舸下揚州。", "北地雖誇上林苑，南京還有散花樓。"]'),
('722942a4-98d7-46a1-9fc9-ed44851445a5','上皇西巡南京歌十首 七','李白','唐','唐诗','tang','','[]','錦水東流繞錦城，星橋北挂象天星。',32,'全唐诗/poet.tang.8000.json','["錦水東流繞錦城，星橋北挂象天星。", "四海此中朝聖主，峨眉山下列仙庭。"]'),
('c4300913-b648-459b-9ee9-bc762945e2b7','上皇西巡南京歌十首 八','李白','唐','唐诗','tang','','[]','秦開蜀道置金牛，漢水元通星漢流。',32,'全唐诗/poet.tang.8000.json','["秦開蜀道置金牛，漢水元通星漢流。", "天子一行遺聖跡，錦城長作帝王州。"]'),
('8802a2bb-09ca-4bcc-8bb5-016c3456f599','上皇西巡南京歌十首 九','李白','唐','唐诗','tang','','[]','水綠天青不起塵，風光和暖勝三秦。',32,'全唐诗/poet.tang.8000.json','["水綠天青不起塵，風光和暖勝三秦。", "萬國烟花隨玉輦，西來添作錦江春。"]'),
('e62ccfb6-dcdc-4980-b9bb-b5f87c0450f1','上皇西巡南京歌十首 十','李白','唐','唐诗','tang','','[]','劒閣重關蜀北門，上皇歸馬若雲屯。',32,'全唐诗/poet.tang.8000.json','["劒閣重關蜀北門，上皇歸馬若雲屯。", "少帝長安開紫極，雙懸日月照乾坤。"]'),
('343cf232-56ef-4cfe-88dd-3781c0b57cb5','峨眉山月歌','李白','唐','唐诗','tang','','["\u5199\u666f", "\u79cb\u5929", "\u6e38\u5386", "\u521d\u4e2d\u53e4\u8bd7", "\u5c71", "\u5e26\u6709\u5730\u540d"]','峨眉山月半輪秋，影入平羌江水流。',32,'全唐诗/poet.tang.8000.json','["峨眉山月半輪秋，影入平羌江水流。", "夜發清溪向三峽，思君不見下渝州。"]'),
('0108be7b-0780-4442-a496-16776f20be59','峨眉山月歌送蜀僧晏入中京','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c", "\u6708\u4eae", "\u601d\u4e61"]','我在巴東三峽時，西看明月憶峨眉。',128,'全唐诗/poet.tang.8000.json','["我在巴東三峽時，西看明月憶峨眉。", "月出峨眉照滄海，與人萬里長相隨。", "黃鶴樓前月華白，此中忽見峨眉客。", "峨眉山月還送君，風吹西到長安陌。", "長安大道橫九天，峨眉山月照秦川。", "黃金獅子乘高座，白玉麈尾談重玄。", "我似浮雲殢吳越，君逢聖主遊丹闕。", "一振高名滿帝都，歸時還弄峨眉月。"]'),
('7b6687bc-57ab-4615-b185-938386eebd37','赤壁歌送別','李白','唐','唐诗','tang','','["\u9001\u522b", "\u5730\u540d", "\u5e26\u6709\u5730\u540d", "\u548f\u53f2\u6000\u53e4"]','二龍爭戰決雌雄，赤壁樓船掃地空。',64,'全唐诗/poet.tang.8000.json','["二龍爭戰決雌雄，赤壁樓船掃地空。", "烈火張天照雲海，周瑜於此破曹公。", "君去滄江望澄碧，鯨鯢唐突留餘跡。", "一一書來報故人，我欲因之壯心魄。"]'),
('9f6b918f-4920-4c2d-b53c-dc9a2c1c3e2c','江夏行','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','憶昔嬌小姿，春心亦自持。',216,'全唐诗/poet.tang.8000.json','["憶昔嬌小姿，春心亦自持。", "爲言嫁夫壻，得免長相思。", "誰知嫁商賈，令人却愁苦。", "自從爲夫妻，何曾在鄉土。", "去年下揚州，相送黃鶴樓。", "眼看帆去遠，心逐江水流。", "只言期一載，誰謂歷三秋。", "使妾腸欲斷，恨君情悠悠。", "東家西舍同時發，北去南來不逾月。", "未知行李遊何方，作箇音書能斷絕。", "適來往南浦，欲問西江船。", "正見當壚女，紅粧二八年。", "一種爲人妻，獨自多悲悽。", "對鏡便垂淚，逢人只欲啼。", "不如輕薄兒，旦暮長相隨。", "悔作商人婦，青春長別離。", "如今正好同懽樂，君去容華誰得知。"]'),
('76a8f569-4175-4352-bbfe-973112a384d1','懷仙歌','李白','唐','唐诗','tang','','[]','一鶴東飛過滄海，放心散漫知何在。',64,'全唐诗/poet.tang.8000.json','["一鶴東飛過滄海，放心散漫知何在。", "仙人浩歌望我來，應攀玉樹長相待。", "堯舜之事不足驚，自餘囂囂直可輕。", "巨鼇莫戴三山去，我欲蓬萊頂上行。"]'),
('20f54408-5677-4714-b6de-b6caa8a217e1','玉真仙人詞','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','玉真之仙人，時往太華峰。',48,'全唐诗/poet.tang.8000.json','["玉真之仙人，時往太華峰。", "清晨鳴天鼓，飆歘騰雙龍。", "弄電不輟手，行雲本無蹤。", "幾時入少室，王母應相逢。"]'),
('157866b0-85c6-4602-a388-0db895a50c55','清溪行','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u843d\u5bde", "\u5199\u6c34"]','清溪清我心，水色異諸水。',48,'全唐诗/poet.tang.8000.json','["清溪清我心，水色異諸水。", "借問新安江，見底何如此。", "人行明鏡中，鳥度屏風裏。", "向晚猩猩啼，空悲遠遊子。"]'),
('94eb3754-819e-4e04-b880-76f1ae3e3849','詶殷明佐見贈五雲裘歌','李白','唐','唐诗','tang','','[]','我吟謝朓詩上語，朔風颯颯吹飛雨。',254,'全唐诗/poet.tang.8000.json','["我吟謝朓詩上語，朔風颯颯吹飛雨。", "謝朓已沒青山空，後來繼之有殷公。", "粉圖珍裘五雲色，曄如晴天散彩虹。", "文章彪炳光陸離，應是素娥玉女之所爲。", "輕如松花落金粉，濃似苔錦含碧滋。", "遠山積翠橫海島，殘霞飛丹暎江草。", "凝毫採掇花露容，幾年功成奪天造。", "故人贈我我不違，著令山水含清暉。", "頓驚謝康樂，詩興生我衣。", "襟前林壑斂暝色，袖上雲霞收夕霏。", "羣仙長歎驚此物，千厓萬嶺相縈鬱。", "身騎白鹿行飄颻，手翳紫芝笑披拂。", "相如不足跨鷫鸘，王恭鶴氅安可方。", "瑤臺雪花數千點，片片吹落春風香。", "爲君持此凌蒼蒼，上朝三十六玉皇。", "下窺夫子不可及，矯首相思空斷腸。"]'),
('ba666719-7bea-4a74-a186-cf8f7bcec5c7','臨路歌','李白','唐','唐诗','tang','','[]','大鵬飛兮振八裔，中天摧兮力不濟。',47,'全唐诗/poet.tang.8000.json','["大鵬飛兮振八裔，中天摧兮力不濟。", "餘風激兮萬世，遊扶桑兮挂石袂。", "後人得之傳此，仲尼亡兮誰爲出涕。"]'),
('7d5ab58d-0ac1-474d-97fa-84c35096e952','古意','李白','唐','唐诗','tang','','["\u5987\u5973", "\u95fa\u6028"]','君爲女蘿草，妾作兔絲花。',108,'全唐诗/poet.tang.8000.json','["君爲女蘿草，妾作兔絲花。", "輕條不自引，爲逐春風斜。", "百丈託遠松，纏綿成一家。", "誰言會面易，各在青山厓。", "女蘿發馨香，兔絲斷人腸。", "枝枝相糾結，葉葉競飄揚。", "生子不知根，因誰共芬芳。", "中巢雙翡翠，上宿紫鴛鴦。", "若識二草心，海潮亦可量。"]'),
('d912de08-eb32-49f7-823c-ee17e6e71d12','山鷓鴣詞','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5386\u53f2", "\u4f24\u6000"]','苦竹嶺頭秋月輝，苦竹南枝鷓鴣飛。',80,'全唐诗/poet.tang.8000.json','["苦竹嶺頭秋月輝，苦竹南枝鷓鴣飛。", "嫁得燕山胡雁壻，欲銜我向雁門歸。", "山雞翟雉來相勸，南禽多被北禽欺。", "紫塞嚴霜如劒戟，蒼梧欲巢難背違。", "我今誓死不能去，哀鳴驚呌淚沾衣。"]'),
('d9b93d29-cfb2-4de3-8c3f-90a7ba821fb6','歷陽壯士勤將軍名思齊歌','李白','唐','唐诗','tang','','[]','太古歷陽郡，化爲洪川在。',48,'全唐诗/poet.tang.8000.json','["太古歷陽郡，化爲洪川在。", "江山猶鬱盤，龍虎祕光彩。", "蓄洩數千載，風雲何霮䨴。", "特生勤將軍，神力百夫倍。"]'),
('2996e939-ef11-4845-971b-c4915ae754fb','草書歌行','李白','唐','唐诗','tang','','[]','少年上人號懷素，草書天下稱獨步。',211,'全唐诗/poet.tang.8000.json','["少年上人號懷素，草書天下稱獨步。", "墨池飛出北溟魚，筆鋒殺盡中山兔。", "八月九月天氣涼，酒徒詞客滿高堂。", "牋麻素絹排數廂，宣州石硯墨色光。", "吾師醉後倚繩牀，須臾掃盡數千張。", "飄風驟雨驚颯颯，落花飛雪何茫茫。", "起來向壁不停手，一行數字大如斗。", "怳怳如聞神鬼驚，時時只見龍蛇走。", "左盤右蹙如驚電，狀同楚漢相攻戰。", "湖南七郡凡幾家，家家屏障書題徧。", "王逸少，張伯英，古來幾許浪得名。", "張顛老死不足數，我師此義不師古。", "古來萬事貴天生，何必要公孫大娘渾脫舞。"]'),
('8b7a5d82-7f6a-4f90-a042-2e97c5867206','和盧侍御通塘曲','李白','唐','唐诗','tang','','["\u5199\u7269", "\u6292\u60c5", "\u5199\u666f", "\u8d5e\u7f8e"]','君誇通塘好，通塘勝耶溪。',208,'全唐诗/poet.tang.8000.json','["君誇通塘好，通塘勝耶溪。", "通塘在何處，遠在尋陽西。", "青蘿嫋嫋挂烟樹，白鷴處處聚沙堤。", "石門中斷平湖出，百丈金潭照雲日。", "何處滄浪垂釣翁，鼓櫂漁歌趣非一。", "相逢不相識，出沒繞通塘。", "浦邊清水明素足，別有浣沙吳女郎。", "行盡綠潭潭轉幽，疑是武陵春碧流。", "秦人雞犬桃花裏，將比通塘渠見羞。", "通塘不忍別，十去九遲回。", "偶逢佳境心已醉，忽有一鳥從天來。", "月出青山送行子，四邊苦竹秋聲起。", "長吟白雪望星河，雙垂兩足揚素波。", "梁鴻德耀會稽日，寧知此中樂事多。"]'),
('9d1b6a18-571c-4f25-bfdb-3fe260115c3f','贈孟浩然','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8d60\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u656c\u7231"]','吾愛孟夫子，風流天下聞。',48,'全唐诗/poet.tang.8000.json','["吾愛孟夫子，風流天下聞。", "紅顏棄軒冕，白首臥松雲。", "醉月頻中聖，迷花不事君。", "高山安可仰，徒此揖清芬。"]'),
('ef2c9c01-038b-441d-b947-95c0046c0061','贈從兄襄陽少府皓','李白','唐','唐诗','tang','','["\u53cb\u60c5"]','結髮未識事，所交盡豪雄。',108,'全唐诗/poet.tang.8000.json','["結髮未識事，所交盡豪雄。", "却秦不受賞，擊晉寧爲功。", "小節豈足言，退耕舂陵東。", "歸來無產業，生事如轉蓬。", "一朝烏裘敝，百鎰黃金空。", "彈劒徒激昂，出門悲路窮。", "吾兄青雲士，然諾聞諸公。", "所以陳片言，片言貴情通。", "棣華儻不接，甘與秋草同。"]'),
('66fbdf3a-5429-40a4-8ba8-396fb7ad8506','淮海對雪贈傅靄','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba"]','朔雪落吳天，從風渡溟渤。',48,'全唐诗/poet.tang.8000.json','["朔雪落吳天，從風渡溟渤。", "海樹成陽春，江沙浩明月。", "興從剡溪起，思繞梁園發。", "寄君郢中歌，曲罷心斷絕。"]'),
('f8b115f0-1f90-4f95-8b31-96dd1223e674','贈徐安宜','李白','唐','唐诗','tang','','[]','白田見楚老，歌詠徐安宜。',108,'全唐诗/poet.tang.8000.json','["白田見楚老，歌詠徐安宜。", "製錦不擇地，操刀良在茲。", "清風動百里，惠化聞京師。", "浮人若雲歸，耕種滿郊岐。", "川光淨麥隴，日色明桑枝。", "訟息但長嘯，賓來或解頤。", "青橙拂戶牖，白水流園池。", "遊子滯安邑，懷恩未忍辭。", "翳君樹桃李，歲晚託深期。"]'),
('9678f941-ae8f-489b-ac31-7864158b26e3','贈任城盧主簿','李白','唐','唐诗','tang','','[]','海鳥知天風，竄身魯門東。',48,'全唐诗/poet.tang.8000.json','["海鳥知天風，竄身魯門東。", "臨觴不能飲，矯翼思凌空。", "鐘鼓不爲樂，烟霜誰與同。", "歸飛未忍去，流淚謝鴛鴻。"]'),
('f970d4db-74a1-45c3-b409-58359aecb709','早秋贈裴十七仲堪','李白','唐','唐诗','tang','','[]','遠海動風色，吹愁落天涯。',144,'全唐诗/poet.tang.8000.json','["遠海動風色，吹愁落天涯。", "南星變大火，熱氣餘丹霞。", "光景不可迴，六龍轉天車。", "荆人泣美玉，魯叟悲匏瓜。", "功業若夢裏，撫琴發長嗟。", "裴生信英邁，屈起多才華。", "歷抵海岱豪，結交魯朱家。", "復攜兩少女，豔色驚荷葩。", "雙歌入青雲，但惜白日斜。", "窮溟出寶貝，大澤饒龍蛇。", "明主儻見收，烟霞路非賒。", "時命若不會，歸應鍊丹砂。"]'),
('0be52b7d-9f9a-46fc-b1ca-f41e98eee07d','贈范金卿二首 一','李白','唐','唐诗','tang','','[]','君子枉清盼，不知東走迷。',120,'全唐诗/poet.tang.8000.json','["君子枉清盼，不知東走迷。", "離家來幾月，絡緯鳴中閨。", "桃李君不言，攀花願成蹊。", "那能吐芳信，惠好相招攜。", "我有結綠珍，久藏濁水泥。", "時人棄此物，乃與燕珉齊。", "摭拭欲贈之，申眉路無梯。", "遼東慙白豕，楚客羞山雞。", "徒有獻芹心，終流泣玉啼。", "祗應自索漠，留舌示山妻。"]'),
('d9b03c5e-292d-45d3-83ff-c9a1330f9016','贈范金卿二首 二','李白','唐','唐诗','tang','','[]','范宰不買名，弦歌對前楹。',60,'全唐诗/poet.tang.8000.json','["范宰不買名，弦歌對前楹。", "爲邦默自化，日覺冰壺清。", "百里雞犬靜，千廬機杼鳴。", "浮人少蕩析，愛客多逢迎。", "遊子覩嘉政，因之聽頌聲。"]'),
('d0789a72-1155-4a6f-b42d-1f7111023821','贈瑕丘王少府','李白','唐','唐诗','tang','','[]','皎皎鸞鳳姿，飄飄神仙氣。',84,'全唐诗/poet.tang.8000.json','["皎皎鸞鳳姿，飄飄神仙氣。", "梅生亦何事，來作南昌尉。", "清風佐鳴琴，寂寞道爲貴。", "一見過所聞，操持難與羣。", "毫揮魯邑訟，目送瀛洲雲。", "我隱屠釣下，爾當玉石分。", "無由接高論，空此仰清芬。"]'),
('802b7363-b528-4107-952d-1c1b7a1c0420','東魯見狄博通','李白','唐','唐诗','tang','','[]','去年別我向何處，有人傳道遊江東。',32,'全唐诗/poet.tang.8000.json','["去年別我向何處，有人傳道遊江東。", "謂言挂席度滄海，却來應是無長風。"]'),
('4c7dd791-00bd-4bbc-baee-4c09520c1111','見京兆韋參軍量移東陽二首 一','李白','唐','唐诗','tang','','[]','潮水還歸海，流人却到吳。',24,'全唐诗/poet.tang.8000.json','["潮水還歸海，流人却到吳。", "相逢問愁苦，淚盡日南珠。"]'),
('13be75df-3568-4f7d-bfc3-f65a4ebcafe5','見京兆韋參軍量移東陽二首 二','李白','唐','唐诗','tang','','[]','聞說金華渡，東連五百灘。',48,'全唐诗/poet.tang.8000.json','["聞說金華渡，東連五百灘。", "全勝若耶好，莫道此行難。", "猨嘯千谿合，松風五月寒。", "他年一攜手，搖艇入新安。"]'),
('9e763265-a5c2-4fda-9a2d-f8826098442e','贈丹陽橫山周處士惟長','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u8d60\u522b", "\u501f\u666f\u6292\u60c5", "\u8d5e\u7f8e", "\u53cb\u4eba"]','周子橫山隱，開門臨城隅。',96,'全唐诗/poet.tang.8000.json','["周子橫山隱，開門臨城隅。", "連峯入戶牖，勝概凌方壺。", "時作白紵詞，放歌丹陽湖。", "水色傲溟渤，川光秀菰蒲。", "當其得意時，心與天壤俱。", "閑雲隨舒卷，安識身有無。", "抱石耻獻玉，沈泉笑探珠。", "羽化如可作，相攜上清都。"]'),
('4e1d96f5-bf22-49e2-9124-4de3af7cab5a','玉真公主別館苦雨贈衛尉張卿二首 一','李白','唐','唐诗','tang','','[]','秋坐金張館，繁陰晝不開。',84,'全唐诗/poet.tang.8000.json','["秋坐金張館，繁陰晝不開。", "空烟迷雨色，蕭颯望中來。", "翳翳昏墊苦，沈沈憂恨催。", "清秋何以慰，白酒盈吾杯。", "吟詠思管樂，此人已成灰。", "獨酌聊自勉，誰貴經綸才。", "彈劒謝公子，無魚良可哀。"]'),
('a8df1ac8-97df-41c3-bac1-ff323e94a4cf','玉真公主別館苦雨贈衛尉張卿二首 二','李白','唐','唐诗','tang','','["\u5199\u96e8", "\u6292\u60c5", "\u8d60\u522b", "\u79cb\u5929", "\u96e8"]','苦雨思白日，浮雲何由卷。',168,'全唐诗/poet.tang.8000.json','["苦雨思白日，浮雲何由卷。", "稷卨和天人，陰陽乃驕蹇。", "秋霖劇倒井，昏霧橫絕巘。", "欲往咫尺塗，遂成山川限。", "潨潨奔溜聞，浩浩驚波轉。", "泥沙塞中途，牛馬不可辨。", "飢從漂母食，閑綴羽陵簡。", "園家逢秋蔬，藜藿不滿眼。", "蟏蛸結思幽，蟋蟀傷褊淺。", "廚竈無青煙，刀机生綠蘚。", "投筯解鷫鸘，換酒醉北堂。", "丹徒布衣者，慷慨未可量。", "何時黃金盤，一斛薦檳榔。", "功成拂衣去，搖曳滄洲傍。"]'),
('ce0fcb64-2151-41bb-94cb-09c45861a5a9','贈韋祕書子春二首 一','李白','唐','唐诗','tang','','["\u52b1\u5fd7"]','谷口鄭子真，躬耕在巖石。',132,'全唐诗/poet.tang.8000.json','["谷口鄭子真，躬耕在巖石。", "高名動京師，天下皆籍籍。", "斯人竟不起，雲臥從所適。", "苟無濟代心，獨善亦何益。", "惟君家世者，偃息逢休明。", "談天信浩蕩，說劒紛縱橫。", "謝公不徒然，起來爲蒼生。", "祕書何寂寂，無乃羈豪英。", "且復歸碧山，安能戀金闕。", "舊宅樵漁地，蓬蒿已應沒。", "却顧女几峯，胡顏見雲月。"]'),
('fdcd9921-6616-4f9f-8904-b47b7b0a1e6d','贈韋祕書子春二首 二','李白','唐','唐诗','tang','','[]','徒爲風塵苦，一官已白鬚。',60,'全唐诗/poet.tang.8000.json','["徒爲風塵苦，一官已白鬚。", "氣同萬里合，訪我來瓊都。", "披雲覩青天，捫蝨話良圖。", "留侯將綺里，出處未云殊。", "終與安社稷，功成去五湖。"]'),
('cfa440f7-c8ee-49a4-a2f3-58741a500d81','贈韋侍御黃裳二首 一','李白','唐','唐诗','tang','','[]','太華生長松，亭亭凌霜雪。',72,'全唐诗/poet.tang.8000.json','["太華生長松，亭亭凌霜雪。", "天與百尺高，豈爲微飆折。", "桃李賣陽豔，路人行且迷。", "春光掃地盡，碧葉成黃泥。", "願君學長松，慎勿作桃李。", "受屈不改心，然後知君子。"]'),
('006df741-146a-46a4-a1c4-70361fdf1bb0','贈韋侍御黃裳二首 二','李白','唐','唐诗','tang','','[]','見君乘驄馬，知上太山道。',48,'全唐诗/poet.tang.8000.json','["見君乘驄馬，知上太山道。", "此地果摧輪，全身以爲寶。", "我如豐年玉，棄置秋田草。", "但勖冰壺心，無爲嘆衰老。"]'),
('e6a59299-39f1-4f85-bebb-a1e4008bf181','贈薛校書','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u6292\u6000", "\u58ee\u5fd7\u672a\u916c"]','我有吳越曲，無人知此音。',48,'全唐诗/poet.tang.8000.json','["我有吳越曲，無人知此音。", "姑蘇成蔓草，麋鹿空悲吟。", "未誇觀濤作，空鬱釣鼇心。", "舉手謝東海，虛行歸故林。"]'),
('ee9e27ac-445b-4018-8153-0cb44a29e2ad','贈何七判官昌浩','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u7406\u60f3"]','有時忽惆悵，匡坐至夜分。',96,'全唐诗/poet.tang.8000.json','["有時忽惆悵，匡坐至夜分。", "平明空嘯咤，思欲解世紛。", "心隨長風去，吹散萬里雲。", "羞作濟南生，九十誦古文。", "不然拂劒起，沙漠收奇勳。", "老死阡陌間，何因揚清芬。", "夫子今管樂，英才冠三軍。", "終與同出處，豈將沮溺羣。"]'),
('92886e52-6348-4f27-a8fa-e7cd136e0ac4','讀諸葛武侯傳書懷贈長安崔少府叔封昆季','李白','唐','唐诗','tang','','[]','漢道昔云季，羣雄方戰爭。',132,'全唐诗/poet.tang.8000.json','["漢道昔云季，羣雄方戰爭。", "霸圖各未立，割據資豪英。", "赤伏起頹運，臥龍得孔明。", "當其南陽時，隴畝躬自耕。", "魚水三顧合，風雲四海生。", "武侯立岷蜀，壯志吞咸京。", "何人先見許，但有崔州平。", "余亦草間人，頗懷拯物情。", "晚途值子玉，華髮同衰榮。", "託意在經濟，結交爲弟兄。", "毋令管與鮑，千載獨知名。"]'),
('64cdd579-10d2-44ae-a331-73970e878f63','贈郭將軍','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5c06\u519b", "\u5199\u4eba", "\u6000\u624d\u4e0d\u9047"]','將軍少年出武威，入掌銀臺護紫微。',64,'全唐诗/poet.tang.8000.json','["將軍少年出武威，入掌銀臺護紫微。", "平明拂劒朝天去，薄暮垂鞭醉酒歸。", "愛子臨風吹玉笛，美人向月舞羅衣。", "疇昔雄豪如夢裏，相逢且欲醉春暉。"]'),
('ae129bba-5c25-4b46-a6a5-2e467e7b2920','駕去溫泉後贈楊山人','李白','唐','唐诗','tang','','[]','少年落魄楚漢間，風塵蕭瑟多苦顏。',128,'全唐诗/poet.tang.8000.json','["少年落魄楚漢間，風塵蕭瑟多苦顏。", "自言管葛竟誰許，長吁莫錯還閉關。", "一朝君王垂拂拭，剖心輸丹雪胸臆。", "忽蒙白日回景光，直上青雲生羽翼。", "幸陪鸞輦出鴻都，身騎飛龍天馬駒。", "王公大人借顏色，金璋紫綬來相趨。", "當時結交何紛紛，片言道合惟有君。", "待吾盡節報明主，然後相攜臥白雲。"]'),
('7d8e64cc-1adb-4d1f-85e7-875e1b063c00','溫泉侍從歸逢故人','李白','唐','唐诗','tang','','[]','漢帝長楊苑，誇胡羽獵歸。',48,'全唐诗/poet.tang.8000.json','["漢帝長楊苑，誇胡羽獵歸。", "子雲叨侍從，獻賦有光輝。", "激賞搖天筆，承恩賜御衣。", "逢君奏明主，他日共飜飛。"]'),
('c60324e6-18da-4762-97d1-ecfed20ba078','贈裴十四','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','朝見裴叔則，朗如行玉山。',60,'全唐诗/poet.tang.8000.json','["朝見裴叔則，朗如行玉山。", "黃河落天走東海，萬里寫入胸懷間。", "身騎白黿不敢度，金高南山買君顧。", "裴回六合無相知，飄若浮雲且西去。"]'),
('e79cb34a-007d-402f-b98a-0ac390b86282','贈崔侍郎','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河二尺鯉，本在孟津居。',48,'全唐诗/poet.tang.8000.json','["黃河二尺鯉，本在孟津居。", "點額不成龍，歸來伴凡魚。", "故人東海客，一見借吹噓。", "風濤儻相見，更欲凌崑墟。"]'),
('0d7b203e-e8f9-4d8d-829d-da221f460101','述德兼陳情上哥舒大夫','李白','唐','唐诗','tang','','[]','天爲國家孕英才，森森矛戟擁靈臺。',64,'全唐诗/poet.tang.8000.json','["天爲國家孕英才，森森矛戟擁靈臺。", "浩蕩深謀噴江海，縱橫逸氣走風雷。", "丈夫立身有如此，一呼三軍皆披靡。", "衛青謾作大將軍，白起真成一豎子。"]'),
('f889b4d7-00c5-49cd-ab29-655f9e9cac0c','雪讒詩贈友人','李白','唐','唐诗','tang','','[]','嗟予沈迷，猖獗已久。',250,'全唐诗/poet.tang.8000.json','["嗟予沈迷，猖獗已久。", "五十知非，古人嘗有。", "立言補過，庶存不朽。", "包荒匿瑕，蓄此頑醜。", "月出致譏，貽愧皓首。", "感悟遂晚，事往日遷。", "白璧何辜，青蠅屢前。", "羣輕折軸，下沈黃泉。", "衆毛飛骨，上凌青天。", "萋斐暗成，貝錦粲然。", "泥沙聚埃，珠玉不鮮。", "洪燄爍山，發自纖煙。", "蒼波蕩日，起于微涓。", "交亂四國，播于八埏。", "拾塵掇蜂，疑聖猜賢。", "哀哉悲夫！誰察予之貞堅。", "彼婦人之猖狂，不如鵲之彊彊。", "彼婦人之淫昏，不如鶉之奔奔。", "坦蕩君子，無悅簧言。", "擢髮續罪，罪乃孔多。", "傾海流惡，惡無以過。", "人生實難，逢此織羅。", "積毀銷金，沈憂作歌。", "天未喪文，其如余何。"]'),
('61de265c-c660-4e5c-938d-eaa4ee246ba1','贈參寥子','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5199\u4eba\u8bd7"]','白鶴飛天書，南荆訪高士。',108,'全唐诗/poet.tang.8000.json','["白鶴飛天書，南荆訪高士。", "五雲在峴山，果得參寥子。", "骯髒辭故園，昂藏入君門。", "天子分玉帛，百官接話言。", "毫墨時灑落，探玄有奇作。", "著論窮天人，千春祕麟閣。", "長揖不受官，拂衣歸林巒。", "余亦去金馬，藤蘿同所歡。", "相思在何處，桂樹青雲端。"]'),
('7ebf752f-dc8e-4e89-96bc-7d5891f54d6d','贈饒陽張司戶燧','李白','唐','唐诗','tang','','[]','朝飲蒼梧泉，夕棲碧海煙。',108,'全唐诗/poet.tang.8000.json','["朝飲蒼梧泉，夕棲碧海煙。", "寧知鸞鳳意，遠託椅桐前。", "慕藺豈曩古，攀嵇是當年。", "愧非黃石老，安識子房賢。", "功業嗟落日，容華棄徂川。", "一語已道意，三山期著鞭。", "蹉跎人間世，寥落壺中天。", "獨見遊物祖，探元窮化先。", "何當共攜手，相與排冥筌。"]'),
('f842c81f-4987-4cac-a897-52ac75a8e773','贈清漳明府姪聿','李白','唐','唐诗','tang','','["\u5199\u666f", "\u5199\u4eba", "\u8d60\u8bd7", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','我李百萬葉，柯條布中州。',240,'全唐诗/poet.tang.8000.json','["我李百萬葉，柯條布中州。", "天開青雲器，日爲蒼生憂。", "小邑且割雞，大刀佇烹牛。", "雷聲動四境，惠與清漳流。", "弦歌詠唐堯，脫落隱簪組。", "心和得天真，風俗猶太古。", "牛羊散阡陌，夜寢不扃戶。", "問此何以然，賢人宰吾土。", "舉邑樹桃李，垂陰亦流芬。", "河堤繞綠水，桑柘連青雲。", "趙女不冶容，提籠晝成羣。", "繰絲鳴機杼，百里聲相聞。", "訟息鳥下堦，高臥披道帙。", "蒲鞭挂簷枝，示耻無撲抶。", "琴清月當戶，人寂風入室。", "長嘯無一言，陶然上皇逸。", "白玉壺冰水，壺中見底清。", "清光洞毫髮，皎潔照羣情。", "趙北美佳政，燕南播高名。", "過客覽行謠，因之誦德聲。"]'),
('d76d2936-a725-4564-8019-2f9672c127bf','贈臨洺縣令皓弟','李白','唐','唐诗','tang','','[]','陶令去彭澤，茫然太古心。',48,'全唐诗/poet.tang.8000.json','["陶令去彭澤，茫然太古心。", "大音自成曲，但奏無弦琴。", "釣水路非遠，連鼇意何深。", "終期龍伯國，與爾相招尋。"]'),
('de5c5ebb-0ae3-4e86-a8c6-489f44ca71ec','贈郭季鷹','李白','唐','唐诗','tang','','[]','河東郭有道，於世若浮雲。',48,'全唐诗/poet.tang.8000.json','["河東郭有道，於世若浮雲。", "盛德無我位，清光獨暎君。", "耻將雞並食，長與鳳爲羣。", "一擊九千仞，相期凌紫氛。"]'),
('51834578-720b-4ede-9ef2-2c5aebe15b47','鄴中贈王大','李白','唐','唐诗','tang','','[]','一身竟無託，遠與孤蓬征。',180,'全唐诗/poet.tang.8000.json','["一身竟無託，遠與孤蓬征。", "千里失所依，復將落葉幷。", "中途偶良朋，問我將何行。", "欲獻濟時策，此心誰見明。", "君王制六合，海塞無交兵。", "壯士伏草間，沈憂亂縱橫。", "飄飄不得意，昨發南都城。", "紫燕櫪下嘶，青萍匣中鳴。", "投軀寄天下，長嘯尋豪英。", "耻學瑯琊人，龍蟠事躬耕。", "富貴吾自取，建功及春榮。", "我願執爾手，爾方達我情。", "相知同一己，豈惟弟與兄。", "抱子弄白雲，琴歌發清聲。", "臨別意難盡，各希存令名。"]'),
('56dfaaf5-7987-4db7-a126-0fd319535c15','贈華州王司士','李白','唐','唐诗','tang','','[]','淮水不絕濤瀾高，盛德未泯生英髦。',32,'全唐诗/poet.tang.8000.json','["淮水不絕濤瀾高，盛德未泯生英髦。", "知君先負廟堂器，今日還須贈寶刀。"]'),
('98126631-cee9-4e83-b214-afbba3233f2e','贈盧徵君昆弟','李白','唐','唐诗','tang','','[]','明主訪賢逸，雲泉今已空。',72,'全唐诗/poet.tang.8000.json','["明主訪賢逸，雲泉今已空。", "二盧竟不起，萬乘高其風。", "河上喜相得，壺中趣每同。", "滄州即此地，觀化遊無窮。", "水落海上清，鼇背覩方蓬。", "與君弄倒景，攜手凌星虹。"]'),
('7c0c14e2-d8e9-4691-902c-ce616809f62f','贈新平少年','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u8a00\u5fd7", "\u6000\u624d\u4e0d\u9047", "\u548f\u53f2"]','韓信在淮陰，少年相欺凌。',108,'全唐诗/poet.tang.8000.json','["韓信在淮陰，少年相欺凌。", "屈體若無骨，壯心有所憑。", "一遭龍顏君，嘯咤從此興。", "千金答漂母，萬古共嗟稱。", "而我竟何爲，寒苦坐相仍。", "長風入短袂，兩手如懷冰。", "故友不相恤，新交寧見矜。", "摧殘檻中虎，羈紲韝上鷹。", "何時騰風雲，搏擊申所能。"]'),
('dd0e56ab-818a-4cae-8e88-ebc59f31366e','贈崔侍郎','李白','唐','唐诗','tang','','[]','長劒一杯酒，男兒方寸心。',120,'全唐诗/poet.tang.8000.json','["長劒一杯酒，男兒方寸心。", "洛陽因劇孟，託宿話胸襟。", "但仰山嶽秀，不知江海深。", "長安復攜手，再顧重千金。", "君乃輶軒佐，予叨翰墨林。", "高風摧秀木，虛彈落驚禽。", "不取回舟興，而來命駕尋。", "扶搖應借力，桃李願成陰。", "笑吐張儀舌，愁爲莊舃吟。", "誰憐明月夜，腸斷聽秋砧。"]'),
('04423e53-a15c-47e2-b57b-5cb8a78f453b','走筆贈獨孤駙馬','李白','唐','唐诗','tang','','[]','都尉朝天躍馬歸，香風吹人花亂飛。',96,'全唐诗/poet.tang.8000.json','["都尉朝天躍馬歸，香風吹人花亂飛。", "銀鞍紫鞚照雲日，左顧右盼生光輝。", "是時僕在金門裏，待詔公車謁天子。", "長揖蒙垂國士恩，壯心剖出酬知己。", "一別蹉跎朝市間，青雲之交不可攀。", "儻其公子重回顧，何必侯嬴長抱關。"]'),
('310a01a7-2e75-4fba-be00-3d69b1af41f7','贈嵩山焦鍊師','李白','唐','唐诗','tang','','[]','二室凌青天，三花含紫煙。',144,'全唐诗/poet.tang.8000.json','["二室凌青天，三花含紫煙。", "中有蓬海客，宛疑麻姑仙。", "道在喧莫染，跡高想已綿。", "時餐金鵝蘂，屢讀青苔篇。", "八極恣遊憩，九垓長周旋。", "下瓢酌潁水，舞鶴來伊川。", "還歸空山上，獨拂秋霞眠。", "蘿月挂朝鏡，松風鳴夜弦。", "潛光隱嵩嶽，鍊魄棲雲幄。", "霓裳何飄颻，鳳吹轉緜邈。", "願同西王母，下顧東方朔。", "紫書儻可傳，銘骨誓相學。"]'),
('8a043a23-9681-46c5-ae30-b8aaff569326','口號贈徵君鴻','李白','唐','唐诗','tang','','[]','陶令辭彭澤，梁鴻入會稽。',48,'全唐诗/poet.tang.8000.json','["陶令辭彭澤，梁鴻入會稽。", "我尋高士傳，君與古人齊。", "雲臥留丹壑，天書降紫泥。", "不知楊伯起，早晚向關西。"]'),
('ac06cfdc-adad-4ca5-9304-ee48522b8172','上李邕','李白','唐','唐诗','tang','','[]','大鵬一日同風起，摶搖直上九萬里。',64,'全唐诗/poet.tang.8000.json','["大鵬一日同風起，摶搖直上九萬里。", "假令風歇時下來，猶能簸却滄溟水。", "世人見我恆殊調，聞余大言皆冷笑。", "宣父猶能畏後生，丈夫未可輕年少。"]'),
('83d1b9ba-9fea-4abd-a179-34251325ca3b','贈張公洲革處士','李白','唐','唐诗','tang','','["\u8d5e\u9882", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','列子居鄭圃，不將衆庶分。',96,'全唐诗/poet.tang.8000.json','["列子居鄭圃，不將衆庶分。", "革侯遁南浦，常恐楚人聞。", "抱甕灌秋蔬，心閑遊天雲。", "每將瓜田叟，耕種漢水濆。", "時登張公洲，入獸不亂羣。", "井無桔槔事，門絕刺繡文。", "長揖二千石，遠辭百里君。", "斯爲真隱者，吾黨慕清芬。"]'),
('9f36a17f-7ee3-49b8-8a0a-52533946c162','秋日鍊藥院鑷白髮贈元六兄林宗','李白','唐','唐诗','tang','','[]','木落識歲秋，瓶冰知天寒。',120,'全唐诗/poet.tang.8000.json','["木落識歲秋，瓶冰知天寒。", "桂枝日已綠，拂雪凌雲端。", "弱齡接光景，矯翼攀鴻鸞。", "投分三十載，榮枯同所歡。", "長吁望青雲，鑷白坐相看。", "秋顏入曉鏡，壯髮凋危冠。", "窮與鮑生賈，饑從漂母餐。", "時來極天人，道在豈吟嘆。", "樂毅方適趙，蘇秦初說韓。", "卷舒固在我，何事空摧殘。"]'),
('a75693da-8ff2-4807-8a46-9233406ee780','書情題蔡舍人雄','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','嘗高謝太傅，攜妓東山門。',288,'全唐诗/poet.tang.8000.json','["嘗高謝太傅，攜妓東山門。", "楚舞醉碧雲，吳歌斷清猨。", "蹔因蒼生起，談笑安黎元。", "余亦愛此人，丹霄冀飛飜。", "遭逢聖明主，敢進興亡言。", "白璧竟何辜，青蠅遂成冤。", "一朝去京國，十載客梁園。", "猛犬吠九關，殺人憤精魂。", "皇穹雪冤枉，白日開氛昏。", "泰階得夔龍，桃李滿中原。", "倒海索明月，凌山採芳蓀。", "媿無橫草功，虛負雨露恩。", "跡謝雲臺閣，心隨天馬轅。", "夫子王佐才，而今復誰論。", "層飆振六翮，不日思騰騫。", "我縱五湖櫂，煙濤恣崩奔。", "夢釣子陵湍，英風緬猶存。", "彼希客星隱，弱植不足援。", "千里一迴首，萬里一長歌。", "黃鶴不復來，清風愁奈何。", "舟浮瀟湘月，山倒洞庭波。", "投汨笑古人，臨濠得天和。", "閑時田畝中，搔背牧雞鵝。", "別離解相訪，應在武陵多。"]'),
('cfa27348-43dd-4ad5-a05a-dcad4e95b48c','憶襄陽舊遊贈馬少府巨','李白','唐','唐诗','tang','','[]','昔爲大堤客，曾上山公樓。',96,'全唐诗/poet.tang.8000.json','["昔爲大堤客，曾上山公樓。", "開牕碧嶂滿，拂鏡滄江流。", "高冠佩雄劒，長揖韓荆州。", "此地別夫子，今來思舊遊。", "朱顏君未老，白髮我先秋。", "壯志恐蹉跎，功名若雲浮。", "歸心結遠夢，落日懸春愁。", "空思羊叔子，墮淚峴山頭。"]'),
('7e9530c1-fd7d-494d-97ed-4e180cafa536','對雪獻從兄虞城宰','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','昨夜梁園裏，弟寒兄不知。',24,'全唐诗/poet.tang.8000.json','["昨夜梁園裏，弟寒兄不知。", "庭前看玉樹，腸斷憶連枝。"]'),
('b84c71b5-0f31-4a49-9401-c0512d51ff6c','訪道安陵遇蓋還爲余造真籙臨別留贈','李白','唐','唐诗','tang','','[]','清水見白石，仙人識青童。',192,'全唐诗/poet.tang.8000.json','["清水見白石，仙人識青童。", "安陵蓋夫子，十歲與天通。", "懸河與微言，談論安可窮。", "能令二千石，撫背驚神聰。", "揮毫贈新詩，高價掩山東。", "至今平原客，感激慕清風。", "學道北海仙，傳書蘂珠宮。", "丹田了玉闕，白日思雲空。", "爲我草真籙，天人慙妙工。", "七元洞豁落，八角輝星虹。", "三災蕩璿璣，蛟龍翼微躬。", "舉手謝天地，虛無齊始終。", "黃金滿高堂，荅荷難克充。", "下笑世上士，沈魂北羅酆。", "昔日萬乘墳，今成一科蓬。", "贈言若可重，實此輕華嵩。"]'),
('2efb1caa-24f6-4479-b4bc-6db4599d52cb','贈崔郎中宗之','李白','唐','唐诗','tang','','[]','胡雁拂海翼，翱翔鳴素秋。',132,'全唐诗/poet.tang.8000.json','["胡雁拂海翼，翱翔鳴素秋。", "驚雲辭沙朔，飄蕩迷河洲。", "有如飛蓬人，去逐萬里遊。", "登高望浮雲，彷彿如舊丘。", "日從海傍沒，水向天邊流。", "長嘯倚孤劒，目極心悠悠。", "歲晏歸去來，富貴安可求。", "仲尼七十說，歷聘莫見收。", "魯連逃千金，珪組豈可酬。", "時哉苟不會，草木爲我儔。", "希君同攜手，長往南山幽。"]'),
('4e28ff60-3d3f-41fa-9266-9049803a4691','贈崔諮議','李白','唐','唐诗','tang','','[]','綠驥本天馬，素非伏櫪駒。',60,'全唐诗/poet.tang.8000.json','["綠驥本天馬，素非伏櫪駒。", "長嘶向清風，倏忽凌九區。", "何言西北至，却走東南隅。", "世道有飜覆，前期難豫圖。", "希君一翦拂，猶可騁中衢。"]'),
('2404e804-be38-46ba-b07b-194672bf204c','贈昇州王使君忠臣','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','六代帝王國，三吳佳麗城。',48,'全唐诗/poet.tang.8000.json','["六代帝王國，三吳佳麗城。", "賢人當重寄，天子借高名。", "巨海一邊靜，長江萬里清。", "應須救趙策，未肯棄侯嬴。"]'),
('abc568f8-8579-484a-a090-e138bcdb2035','贈別從甥高五','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u6292\u60c5", "\u5199\u4eba", "\u8d5e\u7f8e", "\u8d60\u522b", "\u6124\u61d1"]','魚目高泰山，不如一璵璠。',240,'全唐诗/poet.tang.8000.json','["魚目高泰山，不如一璵璠。", "賢甥即明月，聲價動天門。", "能成吾宅相，不減魏陽元。", "自顧寡籌略，功名安所存。", "五木思一擲，如繩繫窮猨。", "櫪中駿馬空，堂上醉人喧。", "黃金久已罄，爲報故交恩。", "聞君隴西行，使我驚心魂。", "與爾共飄颻，雲天各飛飜。", "江水流或卷，此心難具論。", "貧家羞好客，語拙覺辭繁。", "三朝空錯莫，對飯却慚冤。", "自笑我非夫，生事多契闊。", "蓄積萬古憤，向誰得開豁。", "天地一浮雲，此身乃毫末。", "忽見無端倪，太虛可包括。", "去去何足道，臨岐空復愁。", "肝膽不楚越，山河亦衾裯。", "雲龍若相從，明主會見收。", "成功解相訪，溪水桃花流。"]'),
('b7d4ce94-7937-494e-a303-f51135733d56','贈裴司馬','李白','唐','唐诗','tang','','[]','翡翠黃金縷，繡成歌舞衣。',108,'全唐诗/poet.tang.8000.json','["翡翠黃金縷，繡成歌舞衣。", "若無雲間月，誰可比光輝。", "秀色一如此，多爲衆女譏。", "君恩移昔愛，失寵秋風歸。", "愁苦不窺隣，泣上流黃機。", "天寒素手冷，夜長燭復微。", "十日不滿匹，鬢蓬亂若絲。", "猶是可憐人，容華世中稀。", "向君發皓齒，顧我莫相違。"]'),
('32daa6b2-3621-49c2-8afc-069e16464eda','敘舊贈江陽宰陸調','李白','唐','唐诗','tang','','[]','泰伯讓天下，仲雍揚波濤。',252,'全唐诗/poet.tang.8000.json','["泰伯讓天下，仲雍揚波濤。", "清風蕩萬古，跡與星辰高。", "開吳食東溟，陸氏世英髦。", "多君秉古節，嶽立冠人曹。", "風流少年時，京洛事遊遨。", "腰間延陵劒，玉帶明珠袍。", "我昔鬬雞徒，連延五陵豪。", "邀遮相組織，呵嚇來煎熬。", "君開萬叢人，鞍馬皆辟易。", "告急清憲臺，脫余北門厄。", "間宰江陽邑，翦棘樹蘭芳。", "城門何肅穆，五月飛秋霜。", "好鳥集珍木，高才列華堂。", "時從府中歸，絲管儼成行。", "但苦隔遠道，無由共銜觴。", "江北荷花開，江南楊梅熟。", "正好飲酒時，懷賢在心目。", "掛席拾海月，乘風下長川。", "多沽新豐醁，滿載剡溪船。", "中途不遇人，直到爾門前。", "大笑同一醉，取樂平生年。"]'),
('c01d511c-b1ba-4f54-b6d7-3d1976853061','贈從孫義興宰銘','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5199\u4eba\u8bd7"]','天子思茂宰，天枝得英才。',276,'全唐诗/poet.tang.8000.json','["天子思茂宰，天枝得英才。", "朗然清秋月，獨出映吳臺。", "落筆生綺繡，操刀振風雷。", "蠖屈雖百里，鵬騫望三台。", "退食無外事，琴堂向山開。", "綠水寂以閑，白雲有時來。", "河陽富奇藻，彭澤縱名杯。", "所恨不見之，猶如仰昭回。", "元惡昔滔天，疲人散幽草。", "驚川無活鱗，舉邑罕遺老。", "誓雪會稽恥，將奔宛陵道。", "亞相素所重，投刃應桑林。", "獨坐傷激揚，神融一開襟。", "絃歌欣再理，和樂醉人心。", "蠹政除害馬，傾巢有歸禽。", "壺漿候君來，聚舞共謳吟。", "農人棄簔笠，蠶女墮纓簪。", "歡笑相拜賀，則知惠愛深。", "歷職吾所聞，稱賢爾爲最。", "化洽一邦上，名馳三江外。", "峻節貫雲霄，通方堪遠大。", "能文變風俗，好客留軒蓋。", "他日一來遊，因之嚴光瀨。"]'),
('09aa2f43-14d5-48bd-a363-c8cc52b79925','草創大還贈柳官迪','李白','唐','唐诗','tang','','[]','天地爲橐籥，周流行太易。',240,'全唐诗/poet.tang.8000.json','["天地爲橐籥，周流行太易。", "造化合元符，交媾騰精魄。", "自然成妙用，孰知其指的。", "羅絡四季間，綿微無一隙。", "日月更出沒，雙光豈云隻。", "姹女乘河車，黃金充轅軛。", "執樞相管轄，摧伏傷羽翮。", "朱鳥張炎威，白虎守本宅。", "相煎成苦老，消鑠凝津液。", "髣髴明窗塵，死灰同至寂。", "擣冶入赤色，十二周律曆。", "赫然稱大還，與道本無隔。", "白日可撫弄，清都在咫尺。", "北酆落死名，南斗上生籍。", "抑予是何者，身在方士格。", "才術信縱橫，世途自輕擲。", "吾求仙棄俗，君曉損勝益。", "不向金闕遊，思爲玉皇客。", "鸞車速風電，龍騎無鞭策。", "一舉上九天，相攜同所適。"]'),
('1ea485a2-3b64-4620-b3ee-9db7957d1406','贈崔司戶文昆季','李白','唐','唐诗','tang','','[]','雙珠出海底，俱是連城珍。',180,'全唐诗/poet.tang.8000.json','["雙珠出海底，俱是連城珍。", "明月兩特達，餘輝傍照人。", "英聲振名都，高價動殊鄰。", "豈伊箕山故，特以風期親。", "惟昔不自媒，擔簦西入秦。", "攀龍九天上，忝列歲星臣。", "布衣侍丹墀，密勿草絲綸。", "才微惠渥重，讒巧生緇磷。", "一去已十載，今來復盈旬。", "清霜入曉鬢，白露生衣巾。", "側見綠水亭，開門列華茵。", "千金散義士，四坐無凡賓。", "欲折月中桂，持爲寒者薪。", "路傍已竊笑，天路將何因。", "垂恩儻丘山，報德有微身。"]'),
('edb138a4-d3fe-4756-b99a-fb0de2c818b6','贈溧陽宋少府陟','李白','唐','唐诗','tang','','[]','李斯未相秦，且逐東門兔。',120,'全唐诗/poet.tang.8000.json','["李斯未相秦，且逐東門兔。", "宋玉事襄王，能爲高唐賦。", "常聞綠水曲，忽此相逢遇。", "掃灑青天開，豁然披雲霧。", "葳甤紫鸞鳥，巢在崑山樹。", "驚風西北吹，飛落南溟去。", "早懷經濟策，特受龍顏顧。", "白玉棲青蠅，君臣忽行路。", "人生感分義，貴欲呈丹素。", "何日清中原，相期廓天步。"]'),
('de7fcf8a-b3f8-4431-a50e-f5f5f3cf78a1','戲贈鄭溧陽','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u751f\u6d3b", "\u8d5e\u7f8e", "\u95f2\u9002", "\u5199\u4eba\u8bd7"]','陶令日日醉，不知五柳春。',48,'全唐诗/poet.tang.8000.json','["陶令日日醉，不知五柳春。", "素琴本無弦，漉酒用葛巾。", "清風北牕下，自謂羲皇人。", "何時到栗里，一見平生親。"]'),
('8b64c987-9747-4113-b68b-956c5a74a9a2','贈僧崖公','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','昔在朗陵東，學禪白眉空。',216,'全唐诗/poet.tang.8000.json','["昔在朗陵東，學禪白眉空。", "大地了鏡徹，迴旋寄輪風。", "攬彼造化力，持爲我神通。", "晚謁泰山君，親見日沒雲。", "中夜臥山月，拂衣逃人羣。", "授余金仙道，曠劫未始聞。", "冥機發天光，獨朗謝垢氛。", "虛舟不繫物，觀化遊江濆。", "江濆遇同聲，道崖乃僧英。", "說法動海嶽，遊方化公卿。", "手秉玉麈尾，如登白樓亭。", "微言注百川，亹亹信可聽。", "一風鼓羣有，萬籟各自鳴。", "啓閉八牕牖，託宿掣電霆。", "自言歷天台，搏壁躡翠屏。", "凌兢石橋去，恍惚入青冥。", "昔往今來歸，絕景無不經。", "何日更攜手，乘杯向蓬瀛。"]'),
('75d710be-1a60-444e-8e34-371cf0f9d56e','遊溧陽北湖亭望瓦屋山懷古贈同旅','李白','唐','唐诗','tang','','[]','朝登北湖亭，遙望瓦屋山。',168,'全唐诗/poet.tang.8000.json','["朝登北湖亭，遙望瓦屋山。", "天清白露下，始覺秋風還。", "遊子託主人，仰觀眉睫間。", "目色送飛鴻，邈然不可攀。", "長吁相勸勉，何事來吳關。", "聞有貞義女，振窮溧水灣。", "清光了在眼，白日如披顏。", "高墳五六墩，崒兀棲猛虎。", "遺跡翳九泉，芳名動千古。", "子胥昔乞食，此女傾壺漿。", "運開展宿憤，入楚鞭平王。", "凜冽天地間，聞名若懷霜。", "壯夫或未達，十步九太行。", "與君拂衣去，萬里同翱翔。"]'),
('94819d98-45d2-4502-a306-2d1c9cff38d4','醉後贈從甥高鎮','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u4f24\u6000", "\u6000\u624d\u4e0d\u9047"]','馬上相逢揖馬鞭，客中相見客中憐。',144,'全唐诗/poet.tang.8000.json','["馬上相逢揖馬鞭，客中相見客中憐。", "欲邀擊筑悲歌飲，正值傾家無酒錢。", "江東風光不借人，枉殺落花空自春。", "黃金逐手快意盡，昨日破產今朝貧。", "丈夫何事空嘯傲，不如燒却頭上巾。", "君爲進士不得進，我被秋霜生旅鬢。", "時清不及英豪人，三尺童兒重廉藺。", "匣中盤劒裝䱜魚，閑在腰間未用渠。", "且將換酒與君醉，醉歸託宿吳專諸。"]'),
('996b4503-801b-489f-ae0e-1559e0475817','崔秋浦柳少府','李白','唐','唐诗','tang','','[]','秋浦舊蕭索，公庭人吏稀。',60,'全唐诗/poet.tang.8000.json','["秋浦舊蕭索，公庭人吏稀。", "因君樹桃李，此地忽芳菲。", "搖筆望白雲，開簾當翠微。", "時來引山月，縱酒酣清暉。", "而我愛夫子，淹留未忍歸。"]'),
('2f4d5865-eba5-4c02-ac53-1250d3d4c7aa','贈崔秋浦三首 一','李白','唐','唐诗','tang','','[]','吾愛崔秋浦，宛然陶令風。',48,'全唐诗/poet.tang.8000.json','["吾愛崔秋浦，宛然陶令風。", "門前五楊柳，井上二梧桐。", "山鳥下廳事，簷花落酒中。", "懷君未忍去，惆悵意無窮。"]'),
('ed77a4c0-6438-4ab5-9953-27dc57e4779f','贈崔秋浦三首 二','李白','唐','唐诗','tang','','[]','崔令學陶令，北牕常晝眠。',48,'全唐诗/poet.tang.8000.json','["崔令學陶令，北牕常晝眠。", "抱琴時弄月，取意任無弦。", "見客但傾酒，爲官不愛錢。", "東臯春事起，種黍早歸田。"]'),
('ab19feb0-04d7-441e-89e0-7580b407c8cd','贈崔秋浦三首 三','李白','唐','唐诗','tang','','[]','河陽花作縣，秋浦玉爲人。',48,'全唐诗/poet.tang.8000.json','["河陽花作縣，秋浦玉爲人。", "地逐名賢好，風隨惠化春。", "水從天漢落，山逼畫屏新。", "應念金門客，投沙弔楚臣。"]'),
('5c0f9c61-580a-42ff-a0ab-fcc322af93b3','望九華贈青陽韋仲堪','李白','唐','唐诗','tang','','[]','昔在九江上，遙望九華峰。',48,'全唐诗/poet.tang.8000.json','["昔在九江上，遙望九華峰。", "天河掛綠水，秀出九芙蓉。", "我欲一揮手，誰人可相從。", "君爲東道主，於此臥雲松。"]'),
('ec900f91-f6b5-48e6-ac23-9558b41f9c8a','贈王判官時余歸隱居廬山屏風疊','李白','唐','唐诗','tang','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56", "\u9ec4\u9e64\u697c"]','昔別黃鶴樓，蹉跎淮海秋。',156,'全唐诗/poet.tang.8000.json','["昔別黃鶴樓，蹉跎淮海秋。", "俱飄零落葉，各散洞庭流。", "中年不相見，蹭蹬遊吳越。", "何處我思君，天台綠蘿月。", "會稽風月好，却遶剡溪迴。", "雲山海上出，人物鏡中來。", "一度浙江北，十年醉楚臺。", "荆門倒屈宋，梁苑傾鄒枚。", "苦笑我誇誕，知音安在哉。", "大盜割鴻溝，如風掃秋葉。", "吾非濟代人，且隱屏風疊。", "中夜天中望，憶君思見君。", "明朝拂衣去，永與海鷗羣。"]'),
('602f1647-233b-4a4e-9aa0-cb11c90fac9c','在水軍宴贈幕府諸侍御','李白','唐','唐诗','tang','','["\u53d9\u4e8b", "\u7231\u56fd", "\u8d5e\u626c"]','月化五白龍，翻飛凌九天。',180,'全唐诗/poet.tang.8000.json','["月化五白龍，翻飛凌九天。", "胡沙驚北海，電掃洛陽川。", "虜箭雨宮闕，皇輿成播遷。", "英王受廟略，秉鉞清南邊。", "雲旗卷海雪，金戟羅江煙。", "聚散百萬人，弛張在一賢。", "霜臺降羣彥，水國奉戎旃。", "繡服開宴語，天人借樓船。", "如登黃金臺，遙謁紫霞仙。", "卷身編蓬下，冥機四十年。", "寧知草間人，腰下有龍泉。", "浮雲在一決，誓欲清幽燕。", "願與四座公，靜談金匱篇。", "齊心戴朝恩，不惜微軀捐。", "所冀旄頭滅，功成追魯連。"]'),
('eb6cf52e-4b9f-49bd-bcf2-51314dc7a16c','贈武十七諤幷序','李白','唐','唐诗','tang','','[]','馬如一匹練，明日過吳門。',96,'全唐诗/poet.tang.8000.json','["馬如一匹練，明日過吳門。", "乃是要離客，西來欲報恩。", "笑開燕匕首，拂拭竟無言。", "狄犬吠清洛，天津成塞垣。", "愛子隔東魯，空悲斷腸猨。", "林回棄白璧，千里阻同奔。", "君爲我致之，輕齎涉淮原。", "精誠合天道，不媿遠遊魂。"]'),
('7522f3a7-04f9-4114-8973-eb57c93a2017','贈閭丘宿松','李白','唐','唐诗','tang','','[]','阮籍爲太守，乘驢上東平。',96,'全唐诗/poet.tang.8000.json','["阮籍爲太守，乘驢上東平。", "剖竹十日間，一朝風化清。", "偶來拂衣去，誰測主人情。", "夫子理宿松，浮雲知古城。", "掃地物莽然，秋來百草生。", "飛鳥還舊巢，遷人返躬耕。", "何慙宓子賤，不減陶淵明。", "吾知千載後，却掩二賢名。"]'),
('eed9b030-eed4-4c4a-86a9-a509e780fd26','獄中上崔相渙','李白','唐','唐诗','tang','','[]','胡馬渡洛水，血流征戰場。',72,'全唐诗/poet.tang.8000.json','["胡馬渡洛水，血流征戰場。", "千門閉秋景，萬姓危朝霜。", "賢相燮元氣，再欣海縣康。", "台庭有夔龍，列宿粲成行。", "羽翼三元聖，發輝兩太陽。", "應念覆盆下，雪泣拜天光。"]'),
('e52d1c6a-60e1-41e2-b664-dcaa855eec1c','中丞宋公以吳兵三千赴河南軍次尋陽脫余之囚參謀幕府因贈之','李白','唐','唐诗','tang','','[]','獨坐清天下，專征出海隅。',96,'全唐诗/poet.tang.8000.json','["獨坐清天下，專征出海隅。", "九江皆渡虎，三郡盡還珠。", "組練明秋浦，樓船入郢都。", "風高初選將，月滿欲平胡。", "殺氣橫千里，軍聲動九區。", "白猨慙劒術，黃石借兵符。", "戎虜行當翦，鯨鯢立可誅。", "自憐非劇孟，何以佐良圖。"]'),
('f190880a-4ece-4fab-9853-b67eb441042c','流夜郎贈辛判官','李白','唐','唐诗','tang','','[]','昔在長安醉花柳，五侯七貴同杯酒。',112,'全唐诗/poet.tang.8000.json','["昔在長安醉花柳，五侯七貴同杯酒。", "氣岸遙凌豪士前，風流肯落他人後。", "夫子紅顏我少年，章臺走馬著金鞭。", "文章獻納麒麟殿，歌舞淹留玳瑁筵。", "與君自謂長如此，寧知草動風塵起。", "函谷忽驚胡馬來，秦宮桃李向明開。", "我愁遠謫夜郎去，何日金雞放赦回。"]'),
('d2873fe6-8634-4ec0-b80b-16f3fc913f53','贈劉都使','李白','唐','唐诗','tang','','[]','東平劉公幹，南國秀餘芳。',120,'全唐诗/poet.tang.8000.json','["東平劉公幹，南國秀餘芳。", "一鳴即朱紱，五十佩銀章。", "飲冰事戎幕，衣錦華水鄉。", "銅官幾萬人，諍訟清玉堂。", "吐言貴珠玉，落筆迴風霜。", "而我謝明主，銜哀投夜郎。", "歸家酒債多，門客粲成行。", "高談滿四座，一日傾千觴。", "所求竟無緒，裘馬欲摧藏。", "主人若不顧，明發釣滄浪。"]'),
('44fb14b9-0270-49d8-89b7-3f396c535f6b','贈常侍御','李白','唐','唐诗','tang','','[]','安石在東山，無心濟天下。',84,'全唐诗/poet.tang.8000.json','["安石在東山，無心濟天下。", "一起振橫流，功成復瀟灑。", "大賢有卷舒，季葉輕風雅。", "匡復屬何人，君爲知音者。", "傳聞武安將，氣振長平瓦。", "燕趙期洗清，周秦保宗社。", "登朝若有言，爲訪南遷賈。"]'),
('b0eb6d91-a53f-4ba6-ba0e-f42f1b508f19','贈易秀才','李白','唐','唐诗','tang','','[]','少年解長劒，投贈即分離。',72,'全唐诗/poet.tang.8000.json','["少年解長劒，投贈即分離。", "何不斷犀象，精光暗往時。", "蹉跎君自惜，竄逐我因誰。", "地遠虞翻老，秋深宋玉悲。", "空摧芳桂色，不屈古松姿。", "感激平生意，勞歌寄此辭。"]'),
('4429abf8-a575-4067-b572-1ec4e31bc925','經亂離後天恩流夜郎憶舊遊書懷贈江夏韋太守良宰','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u9ec4\u9e64\u697c", "\u957f\u8bd7", "\u8d60\u522b", "\u5fe7\u6124", "\u81ea\u4f20"]','天上白玉京，十二樓五城。',288,'全唐诗/poet.tang.8000.json','["天上白玉京，十二樓五城。", "仙人撫我頂，結髮受長生。", "誤逐世間樂，頗窮理亂情。", "九十六聖君，浮雲挂空名。", "天地賭一擲，未能望戰爭。", "試涉霸王略，將期軒冕榮。", "時命乃大謬，棄之海上行。", "學劒翻自哂，爲文竟何成。", "劒非萬人敵，文竊四海聲。", "兒戲不足道，五噫出西京。", "臨當欲去時，慷慨淚沾纓。", "嘆君倜儻才，標舉冠羣英。", "開筵引祖帳，慰此遠徂征。", "鞍馬若浮雲，送余驃騎亭。", "歌鍾不盡意，白日落昆明。", "十月到幽州，戈鋋若羅星。", "君王棄北海，掃地借長鯨。", "呼吸走百川，燕然可摧傾。", "心知不得語，却欲棲蓬瀛。", "彎弧懼天狼，挾矢不敢張。", "攬涕黃金臺，呼天哭昭王。", "無人貴駿骨，騄耳空騰驤。", "樂毅儻再生，于今亦奔亡。", "蹉跎不得意，驅馬還貴鄉。"]'),
('90edd84c-05d9-4f52-8364-252e435a0074','江夏使君叔席上贈史郎中','李白','唐','唐诗','tang','','[]','鳳凰丹禁裏，銜出紫泥書。',84,'全唐诗/poet.tang.8000.json','["鳳凰丹禁裏，銜出紫泥書。", "昔放三湘去，今還萬死餘。", "仙郎久爲別，客舍問何如。", "涸轍思流水，浮雲失舊居。", "多慙華省貴，不以逐臣疎。", "復如竹林下，叨陪芳宴初。", "希君生羽翼，一化北溟魚。"]'),
('cfd56752-c1d6-4a16-9cbc-89e46b6f3be8','博平鄭太守自廬山千里相尋入江夏北市門見訪却之武陵立馬贈別','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','大梁貴公子，氣蓋蒼梧雲。',144,'全唐诗/poet.tang.8000.json','["大梁貴公子，氣蓋蒼梧雲。", "若無三千客，誰道信陵君。", "救趙復存魏，英威天下聞。", "邯鄲能屈節，訪博從毛薛。", "夷門得隱淪，而與侯生親。", "仍要鼓刀者，乃是袖槌人。", "好士不盡心，何能保其身。", "多君重然諾，意氣遙相託。", "五馬入市門，金鞍照城郭。", "都忘虎竹貴，且與荷衣樂。", "去去桃花源，何時見歸軒。", "相思無終極，腸斷朗江猨。"]'),
('5ae6306b-b91f-4004-a662-08b25538f28e','江上贈竇長史','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','漢求季布魯朱家，楚逐伍胥去章華。',96,'全唐诗/poet.tang.8000.json','["漢求季布魯朱家，楚逐伍胥去章華。", "萬里南遷夜郎國，三年歸及長風沙。", "聞道青雲貴公子，錦帆游戲西江水。", "人疑天上坐樓船，水淨霞明兩重綺。", "相約相期何太深，棹歌搖艇月中尋。", "不同珠履三千客，別欲論交一片心。"]'),
('1b00ef2a-8516-4b42-b1cf-6aaebca65ca0','贈王漢陽','李白','唐','唐诗','tang','','[]','天落白玉棺，王喬辭葉縣。',96,'全唐诗/poet.tang.8000.json','["天落白玉棺，王喬辭葉縣。", "一去未千年，漢陽復相見。", "猶乘飛鳧舃，尚識仙人面。", "鬢髮何青青，童顏皎如練。", "吾曾弄海水，清淺嗟三變。", "果愜麻姑言，時光速流電。", "與君數杯酒，可以窮歡宴。", "白雲歸去來，何事坐交戰。"]'),
('142b27f0-534b-419c-a9b7-b88e7e5f5a7c','贈漢陽輔錄事二首 一','李白','唐','唐诗','tang','','[]','聞君罷官意，我抱漢川湄。',48,'全唐诗/poet.tang.8000.json','["聞君罷官意，我抱漢川湄。", "借問久疎索，何如聽訟時。", "天清江月白，心靜海鷗知。", "應念投沙客，空餘弔屈悲。"]'),
('e109d594-3635-43ad-aa8f-36d820bcbd1b','贈漢陽輔錄事二首 二','李白','唐','唐诗','tang','','[]','鸚鵡洲橫漢陽渡，水引寒煙沒江樹。',64,'全唐诗/poet.tang.8000.json','["鸚鵡洲橫漢陽渡，水引寒煙沒江樹。", "南浦登樓不見君，君今罷官在何處？", "漢口雙魚白錦鱗，令傳尺素報情人。", "其中字數無多少，祗是相思秋復春。"]'),
('1a16c704-8bd3-4806-81c3-675cc27230f8','江夏贈韋南陵冰','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','胡驕馬驚沙塵起，胡雛飲馬天津水。',276,'全唐诗/poet.tang.8000.json','["胡驕馬驚沙塵起，胡雛飲馬天津水。", "君爲張掖近酒泉，我竄三巴九千里。", "天地再新法令寬，夜郎遷客帶霜寒。", "西憶故人不可見，東風吹夢到長安。", "寧期此地忽相遇，驚喜茫如墮煙霧。", "玉簫金管喧四筵，苦心不得申長句。", "昨日繡衣傾綠尊，病如桃李竟何言。", "昔騎天子大宛馬，今乘款段諸侯門。", "賴遇南平豁方寸，復兼夫子持清論。", "有似山開萬里雲，四望青天解人悶。", "人悶還心悶，苦辛長苦辛。", "愁來飲酒二千石，寒灰重暖生陽春。", "山公醉後能騎馬，別是風流賢主人。", "頭陀雲月多僧氣，山水何曾稱人意。", "不然鳴笳按鼓戲滄流，呼取江南女兒歌櫂謳。", "我且爲君槌碎黃鶴樓，君亦爲吾倒却鵡鸚洲。", "赤壁爭雄如夢裏，且須歌舞寬離憂。"]'),
('6f58597e-964d-40be-a11c-7c417d6de32e','贈盧司戶','李白','唐','唐诗','tang','','[]','秋色無遠近，出門盡寒山。',36,'全唐诗/poet.tang.8000.json','["秋色無遠近，出門盡寒山。", "白雲遙相識，待我蒼梧間。", "借問盧耽鶴，西飛幾歲還。"]'),
('bd64f135-e0f7-4e64-b62b-305d16cfc6e2','贈從弟南平太守之遙二首 一','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u8c0a"]','少年不得意，落魄無安居。',248,'全唐诗/poet.tang.8000.json','["少年不得意，落魄無安居。", "願隨任公子，欲釣吞舟魚。", "常時飲酒逐風景，壯心遂與功名疎。", "蘭生谷底人不鋤，雲在高山空卷舒。", "漢家天子馳駟馬，赤軍蜀道迎相如。", "天門九重謁聖人，龍顏一解四海春。", "彤庭左右呼萬歲，拜賀明主收沈淪。", "翰林秉筆回英眄，麟閣崢嶸誰可見。", "承恩初入銀臺門，著書獨在金鑾殿。", "龍鉤雕鐙白玉鞍，象牀綺席黃金盤。", "當時笑我微賤者，却來請謁爲交歡。", "一朝謝病遊江海，疇昔相知幾人在。", "前門長揖後門關，今日結交明日改。", "愛君山岳心不移，隨君雲霧迷所爲。", "夢得池塘生春草，使我長價登樓詩。", "別後遙傳臨海作，可見羊何共和之。"]'),
('a9f00848-7c46-467d-888c-e9bebe78167a','贈從弟南平太守之遙二首 二','李白','唐','唐诗','tang','','[]','東平與南平，今古兩步兵。',48,'全唐诗/poet.tang.8000.json','["東平與南平，今古兩步兵。", "素心愛美酒，不是顧專城。", "謫官桃源去，尋花幾處行。", "秦人如舊識，出戶笑相迎。"]'),
('574102be-b63f-4370-b187-4078e6ce44ba','贈潘侍御論錢少陽','李白','唐','唐诗','tang','','[]','繡衣柱史何昂藏，鐵冠白筆橫秋霜。',80,'全唐诗/poet.tang.8000.json','["繡衣柱史何昂藏，鐵冠白筆橫秋霜。", "三軍論事多引納，堦前虎士羅干將。", "雖無二十五老者，且有一翁錢少陽。", "眉如松雪齊四皓，調笑可以安儲皇。", "君能禮此最下士，九州拭目瞻清光。"]'),
('6b1e6556-5ba1-4be4-84aa-551518f746f5','贈柳圓','李白','唐','唐诗','tang','','[]','竹實滿秋浦，鳳來何苦飢。',48,'全唐诗/poet.tang.8000.json','["竹實滿秋浦，鳳來何苦飢。", "還同月下鵲，三繞未安枝。", "夫子即瓊樹，傾柯拂羽儀。", "懷君戀明德，歸去日相思。"]'),
('d35654bd-c4c4-45cd-be19-2d47b0bc092a','流夜郎半道承恩放還兼欣剋復之美書懷示息秀才','李白','唐','唐诗','tang','','[]','黃口爲人羅，白龍乃魚服。',240,'全唐诗/poet.tang.8000.json','["黃口爲人羅，白龍乃魚服。", "得罪豈怨天，以愚陷網目。", "鯨鯢未翦滅，豺狼屢翻覆。", "悲作楚地囚，何日秦庭哭。", "遭逢二明主，前後兩遷逐。", "去國愁夜郎，投身竄荒谷。", "半道雪屯蒙，曠如鳥出籠。", "遙欣剋復美，光武安可同。", "天子巡劒閣，儲皇守扶風。", "揚袂正北辰，開襟攬羣雄。", "胡兵出月窟，雷破關之東。", "左掃因右拂，旋收洛陽宮。", "迴輿入咸京，席卷六合通。", "叱咤開帝業，手成天地功。", "大駕還長安，兩日忽再中。", "一朝讓寶位，劒璽傳無窮。", "媿無秋豪力，誰念矍鑠翁。", "弋者何所慕，高飛仰冥鴻。", "棄劒學丹砂，臨鑪雙玉童。", "寄言息夫子，歲晚陟方蓬。"]'),
('bdd6a23e-199e-41ab-8924-869aa168ad8f','贈張相鎬二首 一','李白','唐','唐诗','tang','','[]','神器難竊弄，天狼窺紫宸。',288,'全唐诗/poet.tang.8000.json','["神器難竊弄，天狼窺紫宸。", "六龍遷白日，四海暗胡塵。", "昊穹降元宰，君子方經綸。", "澹然養浩氣，歘起持大鈞。", "秀骨象山嶽，英謀合鬼神。", "佐漢解鴻門，生唐爲後身。", "擁旄秉金鉞，伐鼓乘朱輪。", "虎將如雷霆，總戎向東巡。", "諸侯拜馬首，猛士騎鯨鱗。", "澤被魚鳥悅，令行草木春。", "聖智不失時，建功及良辰。", "醜虜安足紀，可貽幗與巾。", "倒瀉溟海珠，盡爲入幕珍。", "馮異獻赤伏，鄧生倏來臻。", "庶同昆陽舉，再覩漢儀新。", "昔爲管將鮑，中奔吳隔秦。", "一生欲報主，百代思榮親。", "其事竟不就，哀哉難重陳。", "臥病宿松山，蒼茫空四鄰。", "風雲激壯志，枯槁驚常倫。", "聞君自天來，目張氣益振。", "亞夫得劇孟，敵國空無人。", "捫蝨對桓公，願得論悲辛。", "大塊方噫氣，何辭鼓青蘋。"]'),
('eb308ac7-facf-4d88-9f84-de866c9f62f6','贈張相鎬二首 二','李白','唐','唐诗','tang','','[]','本家隴西人，先爲漢邊將。',216,'全唐诗/poet.tang.8000.json','["本家隴西人，先爲漢邊將。", "功略葢天地，名飛青雲上。", "苦戰竟不侯，富年頗惆悵。", "世傳崆峒勇，氣激金風壯。", "英烈遺厥孫，百代神猶王。", "十五觀奇書，作賦凌相如。", "龍顏惠殊寵，麟閣憑天居。", "晚途未云已，蹭蹬遭讒毀。", "想像晉末時，崩騰胡塵起。", "衣冠陷鋒鏑，戎虜盈朝市。", "石勒窺神州，劉聰劫天子。", "撫劒夜吟嘯，雄心日千里。", "誓欲斬鯨鯢，澄清洛陽水。", "六合灑霖雨，萬物無彫枯。", "我揮一杯水，自笑何區區。", "因人恥成事，貴欲決良圖。", "滅虜不言功，飄然陟蓬壺。", "惟有安期舃，留之滄海隅。"]'),
('2661ebda-b1c5-452d-9d09-b59ed3b45d16','聞謝楊兒吟猛虎詞因此有贈','李白','唐','唐诗','tang','','[]','同州隔秋浦，聞吟猛虎詞。',24,'全唐诗/poet.tang.8000.json','["同州隔秋浦，聞吟猛虎詞。", "晨朝來借問，知是謝楊兒。"]'),
('9ded0e0f-8e24-4119-8536-896fb91f4fd4','宿清溪主人','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u591c\u665a", "\u5b64\u5bc2", "\u58ee\u5fd7\u672a\u916c"]','夜到清溪宿，主人碧巖裏。',36,'全唐诗/poet.tang.8000.json','["夜到清溪宿，主人碧巖裏。", "簷楹挂星斗，枕席響風水。", "月落西山時，啾啾夜猨起。"]'),
('a3c2d519-801e-4419-892f-b7affa1e7762','繫尋陽上崔相渙三首 一','李白','唐','唐诗','tang','','[]','邯鄲四十萬，同日陷長平。',24,'全唐诗/poet.tang.8000.json','["邯鄲四十萬，同日陷長平。", "能迴造化筆，或冀一人生。"]'),
('db9952a3-612e-4fb3-ae54-79cc011cb1db','繫尋陽上崔相渙三首 二','李白','唐','唐诗','tang','','[]','毛遂不墮井，曾參寧殺人。',36,'全唐诗/poet.tang.8000.json','["毛遂不墮井，曾參寧殺人。", "虛言誤公子，投杼惑慈親。", "白璧雙明月，方知一玉真。"]'),
('b2f40d4f-0c75-4fb4-b325-3e508749facf','繫尋陽上崔相渙三首 三','李白','唐','唐诗','tang','','[]','虛傳一片雨，枉作陽臺神。',28,'全唐诗/poet.tang.8000.json','["虛傳一片雨，枉作陽臺神。", "縱爲夢裏相隨去，不是襄王傾國人。"]'),
('5f4a8832-1953-41cf-b202-a15e5faa5f48','巴陵贈賈舍人','李白','唐','唐诗','tang','','[]','賈生西望憶京華，湘浦南遷莫怨嗟。',32,'全唐诗/poet.tang.8000.json','["賈生西望憶京華，湘浦南遷莫怨嗟。", "聖主恩深漢文帝，憐君不遣到長沙。"]'),
('79d04ecd-ef45-4094-a8a4-c3d9fffdebd0','贈別舍人弟臺卿之江南','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','去國客行遠，還山秋夢長。',132,'全唐诗/poet.tang.8000.json','["去國客行遠，還山秋夢長。", "梧桐落金井，一葉飛銀牀。", "覺罷攬明鏡，鬢毛颯已霜。", "良圖委蔓草，古貌成枯桑。", "欲道心下事，時人疑夜光。", "因爲洞庭葉，飄落之瀟湘。", "令弟經濟士，謫居我何傷。", "潛虬隱尺水，著論談興亡。", "客遇王子喬，口傳不死方。", "入洞過天地，登真朝玉皇。", "吾將撫爾背，揮手遂翱翔。"]'),
('e458c7a9-9749-4e9e-8ec0-c07ab91f5d9d','醉後贈王歷陽','李白','唐','唐诗','tang','','[]','書禿千兔毫，詩裁兩牛腰。',48,'全唐诗/poet.tang.8000.json','["書禿千兔毫，詩裁兩牛腰。", "筆蹤起龍虎，舞袖拂雲霄。", "雙歌二胡姬，更奏遠清朝。", "舉酒挑朔雪，從君不相饒。"]'),
('626d358d-52d3-4619-88cc-3b9772b90faf','贈歷陽褚司馬','李白','唐','唐诗','tang','','[]','北堂千萬壽，侍奉有光輝。',48,'全唐诗/poet.tang.8000.json','["北堂千萬壽，侍奉有光輝。", "先同稚子舞，更著老萊衣。", "因爲小兒啼，醉倒月下歸。", "人聞無此樂，此樂世中稀。"]'),
('e14e0303-5597-492f-8b24-7a968803e809','對雪醉後贈王歷陽','李白','唐','唐诗','tang','','[]','有身莫犯飛龍鱗，有手莫辮猛虎鬚。',112,'全唐诗/poet.tang.8000.json','["有身莫犯飛龍鱗，有手莫辮猛虎鬚。", "君看昔日汝南市，白頭仙人隱玉壺。", "子猷聞風動窻竹，相邀共醉杯中綠。", "歷陽何異山陰時，白雪飛花亂人目。", "君家有酒我何愁，客多樂酣秉燭遊。", "謝尚自能鸜鵒舞，相如免脫鷫鸘裘。", "清晨鼓櫂過江去，千里相思明月樓。"]'),
('ebd3c20e-ff69-47f8-8847-c3d7b2b0a091','贈宣城宇文太守兼呈崔侍御','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u6292\u60c5", "\u5199\u4eba"]','白若白鷺鮮，清如清唳蟬。',288,'全唐诗/poet.tang.8000.json','["白若白鷺鮮，清如清唳蟬。", "受氣有本性，不爲外物遷。", "飲水箕山上，食雪首陽顛。", "迴車避朝歌，掩口去盜泉。", "岧嶢廣成子，倜儻魯仲連。", "卓絕二公外，丹心無間然。", "昔攀六龍飛，今作百鍊鉛。", "懷恩欲報主，投佩向北燕。", "彎弓綠弦開，滿月不憚堅。", "閑騎駿馬獵，一射兩虎穿。", "回旋若流光，轉背落雙鳶。", "胡虜三嘆息，兼知五兵權。", "鎗鎗突雲將，却掩我之妍。", "多逢剿絕兒，先著祖生鞭。", "據鞍空矍鑠，壯志竟誰宣。", "蹉跎復來歸，憂恨坐相煎。", "無風難破浪，失計長江邊。", "危苦惜頹光，金波忽三圓。", "時遊敬亭上，閑聽松風眠。", "或弄宛溪月，虛舟信洄沿。", "顏公二十萬，盡付酒家錢。", "興發每取之，聊向醉中仙。", "過此無一事，靜談秋水篇。", "君從九卿來，水國有豐年。"]'),
('f4a74d37-6238-4149-a99f-6dfd4871c97f','贈宣城趙太守悅','李白','唐','唐诗','tang','','[]','趙得寶符盛，山河功業存。',288,'全唐诗/poet.tang.8000.json','["趙得寶符盛，山河功業存。", "三千堂上客，出入擁平原。", "六國揚清風，英聲何喧喧。", "大賢茂遠業，虎竹光南藩。", "錯落千丈松，虬龍盤古根。", "枝下無俗草，所植唯蘭蓀。", "憶在南陽時，始承國士恩。", "公爲柱下史，脫繡歸田園。", "伊昔簪白筆，幽都逐遊魂。", "持斧冠三軍，霜清天北門。", "差池宰兩邑，鶚立重飛翻。", "焚香入蘭臺，起草多芳言。", "夔龍一顧重，矯翼凌翔鵷。", "赤縣揚雷聲，彊項聞至尊。", "驚飆頹秀木，跡屈道彌敦。", "出牧歷三郡，所居猛獸奔。", "遷人同衛鶴，謬上懿公軒。", "自笑東郭履，側慙狐白溫。", "閑吟步竹石，精義忘朝昏。", "顦顇成醜士，風雲何足論。", "獮猴騎土牛，羸馬夾雙轅。", "願借羲皇景，爲人照覆盆。", "溟海不振蕩，何由縱鵬鯤。", "所期玄津白，倜儻假騰騫。"]'),
('3cac4f75-c3a3-4760-a886-52bacdc596f8','贈從弟宣州長史昭','李白','唐','唐诗','tang','','[]','淮南望江南，千里碧山對。',144,'全唐诗/poet.tang.8000.json','["淮南望江南，千里碧山對。", "我行倦過之，半落青天外。", "宗英佐雄郡，水陸相控帶。", "長川豁中流，千里瀉吳會。", "君心亦如此，包納無小大。", "搖筆起風霜，推誠結仁愛。", "訟庭垂桃李，賓館羅軒蓋。", "何意蒼梧雲，飄然忽相會。", "才將聖不偶，命與時俱背。", "獨立山海間，空老聖明代。", "知音不易得，撫劒增感慨。", "當結九萬期，中途莫先退。"]'),
('78e45e06-868d-49e0-a5e6-62fc878a50c4','於五松山贈南陵常贊府','李白','唐','唐诗','tang','','[]','爲草當作蘭，爲木當作松。',156,'全唐诗/poet.tang.8000.json','["爲草當作蘭，爲木當作松。", "蘭秋香風遠，松寒不改容。", "松蘭相因依，蕭艾徒丰茸。", "雞與雞幷食，鸞與鸞同枝。", "揀珠去沙礫，但有珠相隨。", "遠客投名賢，真堪寫懷抱。", "若惜方寸心，待誰可傾倒。", "虞卿棄趙相，便與魏齊行。", "海上五百人，同日死田橫。", "當時不好賢，豈傳千古名。", "願君同心人，於我少留情。", "寂寂還寂寂，出門迷所適。", "長鋏歸來乎，秋風思歸客。"]'),
('4b6b24f6-4341-40c5-9ee3-b51d9b4341ab','自梁園至敬亭山見會公談陵陽山水兼期同遊因有此贈','李白','唐','唐诗','tang','','["\u9ec4\u5c71", "\u4e5d\u534e\u5c71", "\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929"]','我隨秋風來，瑤草恐衰歇。',240,'全唐诗/poet.tang.8000.json','["我隨秋風來，瑤草恐衰歇。", "中途寡名山，安得弄雲月。", "渡江如昨日，黃葉向人飛。", "敬亭愜素尚，弭櫂流清輝。", "冰谷明且秀，陵巒抱江城。", "粲粲吳與史，衣冠耀天京。", "水國饒英奇，潛光臥幽草。", "會公真名僧，所在即爲寶。", "開堂振白拂，高論橫青雲。", "雪山掃粉壁，墨客多新文。", "爲余話幽棲，且述陵陽美。", "天開白龍潭，月映清秋水。", "黃山望石柱，突兀誰開張。", "黃鶴久不來，子安在蒼茫。", "東南焉可窮，山鳥飛絕處。", "稠疊千萬峰，相連入雲去。", "聞此期振策，歸來空閉關。", "相思如明月，可望不可攀。", "何當移白足，早晚凌蒼山。", "且寄一書札，令予解愁顏。"]'),
('2c3c2f6b-ad7b-4fc1-a9d7-ced3af99f6e9','贈友人三首 一','李白','唐','唐诗','tang','','[]','蘭生不當戶，別是閑庭草。',60,'全唐诗/poet.tang.8000.json','["蘭生不當戶，別是閑庭草。", "夙被霜露欺，紅榮已先老。", "謬接瑤華枝，結根君王池。", "顧無馨香美，叨沐清風吹。", "餘芳若可佩，卒歲長相隨。"]'),
('786d292a-3b4f-4780-ab21-34e00f6ed18c','贈友人三首 二','李白','唐','唐诗','tang','','[]','袖中趙匕首，買自徐夫人。',108,'全唐诗/poet.tang.8000.json','["袖中趙匕首，買自徐夫人。", "玉匣閉霜雪，經燕復歷秦。", "其事竟不捷，淪落歸沙塵。", "持此願投贈，與君同急難。", "荆卿一去後，壯士多摧殘。", "長號易水上，爲我揚波瀾。", "鑿井當及泉，張帆當濟川。", "廉夫唯重義，駿馬不勞鞭。", "人生貴相知，何必金與錢。"]'),
('eedb33b4-fdcb-41a5-8d7d-96c3d44b5929','贈友人三首 三','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','慢世薄功業，非無胷中畫。',144,'全唐诗/poet.tang.8000.json','["慢世薄功業，非無胷中畫。", "謔浪萬古賢，以爲兒童劇。", "立產如廣費，匡君懷長策。", "但苦山北寒，誰知道南宅。", "歲酒上逐風，霜鬢兩邊白。", "蜀主思孔明，晉家望安石。", "時人列五鼎，談笑期一擲。", "虎伏被胡塵，漁歌遊海濱。", "弊裘恥妻嫂，長劒託交親。", "夫子秉家義，羣公難與隣。", "莫持西江水，空許東溟臣。", "他日青雲去，黃金報主人。"]'),
('4f7ff344-d530-4d17-8545-64e7e11ae25e','陳情贈友人','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba", "\u53d9\u4e8b"]','延陵有寶劒，價重千黃金。',264,'全唐诗/poet.tang.8000.json','["延陵有寶劒，價重千黃金。", "觀風歷上國，暗許故人深。", "歸來挂墳松，萬古知其心。", "懦夫感達節，壯士激青衿。", "鮑生薦夷吾，一舉置齊相。", "斯人無良朋，豈有青雲望。", "臨財不苟取，推分固詞讓。", "後世稱其賢，英風邈難尚。", "論交但若此，友道孰云喪。", "多君騁逸藻，掩映當時人。", "舒文振頹波，秉德冠彝倫。", "卜居乃此地，共井爲比隣。", "清琴弄雲月，美酒娛冬春。", "薄德中見捐，忽之如遺塵。", "英豪未豹變，自古多艱辛。", "他人縱以疎，君意宜獨親。", "奈何成離居，相去復幾許。", "飄風吹雲霓，蔽目不得語。", "投珠冀相報，按劒恐相距。", "所思採芳蘭，欲贈隔荆渚。", "沈憂心若醉，積恨淚如雨。", "願假東壁輝，餘光照貧女。"]'),
('2a1cef11-7bd7-4e86-90db-d5622b12557c','贈從弟冽','李白','唐','唐诗','tang','','[]','楚人不識鳳，重價求山雞。',168,'全唐诗/poet.tang.8000.json','["楚人不識鳳，重價求山雞。", "獻主昔云是，今來方覺迷。", "自居漆園北，久別咸陽西。", "風飄落日去，節變流鶯啼。", "桃李寒未開，幽關豈來蹊。", "逢君發花萼，若與青雲齊。", "及此桑葉綠，春蠶起中閨。", "日出布穀鳴，田家擁鋤犂。", "顧余乏尺土，東作誰相攜。", "傅說降霖雨，公輸造雲梯。", "羌戎事未息，君子悲塗泥。", "報國有長策，成功羞執珪。", "無由謁明主，杖策還蓬藜。", "他年爾相訪，知我在磻溪。"]'),
('34ea27c9-4378-4a90-a528-3bfd1f31940c','贈閭丘處士','李白','唐','唐诗','tang','','[]','賢人有素業，乃在沙塘陂。',72,'全唐诗/poet.tang.8000.json','["賢人有素業，乃在沙塘陂。", "竹影掃秋月，荷衣落古池。", "閑讀山海經，散帙臥遙帷。", "且耽田家樂，遂曠林中期。", "野酌勸芳酒，園蔬烹露葵。", "如能樹桃李，爲我結茅茨。"]'),
('25f3ac1b-d579-4704-80d2-1d48a1865ce7','贈錢徵君少陽','李白','唐','唐诗','tang','','["\u5fe7\u6124", "\u6625\u5929", "\u611f\u6168", "\u6292\u6000", "\u996e\u9152"]','白玉一杯酒，綠楊三月時。',48,'全唐诗/poet.tang.8000.json','["白玉一杯酒，綠楊三月時。", "春風餘幾日，兩鬢各成絲。", "秉燭唯須飲，投竿也未遲。", "如逢渭川獵，猶可帝王師。"]'),
('725af0dd-9a6e-4534-9afd-b7c35eaa54e0','贈宣州靈源寺仲濬公','李白','唐','唐诗','tang','','[]','敬亭白雲氣，秀色連蒼梧。',72,'全唐诗/poet.tang.8000.json','["敬亭白雲氣，秀色連蒼梧。", "下映雙溪水，如天落鏡湖。", "此中積龍象，獨許濬公殊。", "風韻逸江左，文章動海隅。", "觀心同水月，解領得明珠。", "今日逢支遁，高談出有無。"]'),
('a0c0fff7-0adb-4b54-b0af-ac71f5c0036e','贈僧朝美','李白','唐','唐诗','tang','','[]','水客凌洪波，長鯨湧溟海。',84,'全唐诗/poet.tang.8000.json','["水客凌洪波，長鯨湧溟海。", "百川隨龍舟，噓吸竟安在。", "中有不死者，探得明月珠。", "高價傾宇宙，餘輝照江湖。", "苞卷金縷褐，蕭然若空無。", "誰人識此寶，竊笑有狂夫。", "了心何言說，各勉黃金軀。"]'),
('1c26c1c1-738a-4b40-92ca-47f918bbbccd','贈僧行融','李白','唐','唐诗','tang','','[]','梁有湯惠休，常從鮑照遊。',96,'全唐诗/poet.tang.8000.json','["梁有湯惠休，常從鮑照遊。", "峨眉史懷一，獨映陳公出。", "卓絕二道人，結交鳳與麟。", "行融亦俊發，吾知有英骨。", "海若不隱珠，驪龍吐明月。", "大海乘虛舟，隨波任安流。", "賦詩旃檀閣，縱酒鸚鵡洲。", "待我適東越，相攜上白樓。"]'),
('3284a2cb-0844-4ff8-b3ca-976dd1ba5d23','贈黃山胡公求白鷴','李白','唐','唐诗','tang','','["\u9ec4\u5c71", "\u5199\u9e1f", "\u6292\u6000", "\u8d5e\u7f8e", "\u5fd7\u5411", "\u9e1f"]','請以雙白璧，買君雙白鷴。',72,'全唐诗/poet.tang.8000.json','["請以雙白璧，買君雙白鷴。", "白鷴白如錦，白雪恥容顏。", "照影玉潭裏，刷毛琪樹間。", "夜棲寒月靜，朝步落花閑。", "我願得此鳥，翫之坐碧山。", "胡公能輟贈，籠寄野人還。"]'),
('39e352e5-3e19-4fab-8dff-adf9dea2b380','登敬亭山南望懷古贈竇主簿','李白','唐','唐诗','tang','','[]','敬亭一迴首，目盡天南端。',120,'全唐诗/poet.tang.8000.json','["敬亭一迴首，目盡天南端。", "仙者五六人，常聞此遊盤。", "谿流琴高水，石聳麻姑壇。", "白龍降陵陽，黃鶴呼子安。", "羽化騎日月，雲行翼鴛鸞。", "下視宇宙間，四溟皆波瀾。", "汰絕目下事，從之復何難。", "百歲落半途，前期浩漫漫。", "彊食不成味，清晨起長嘆。", "願隨子明去，鍊火燒金丹。"]'),
('9358ac19-de26-49ad-a115-d23d60474627','經亂後將避地剡中留贈崔宣城','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u6218\u4e89", "\u5206\u522b"]','雙鵝飛洛陽，五馬渡江徼。',240,'全唐诗/poet.tang.8000.json','["雙鵝飛洛陽，五馬渡江徼。", "何意上東門，胡雛更長嘯。", "中原走豺虎，烈火焚宗廟。", "太白晝經天，頹陽掩餘照。", "王城皆蕩覆，世路成奔峭。", "四海望長安，嚬眉寡西笑。", "蒼生疑落葉，白骨空相弔。", "連兵似雪山，破敵誰能料。", "我垂北溟翼，且學南山豹。", "崔子賢主人，歡娛每相召。", "胡牀紫玉笛，却坐青雲呌。", "楊花滿州城，置酒同臨眺。", "忽思剡溪去，水石遠清妙。", "雪盡天地明，風開湖山貌。", "悶爲洛生詠，醉發吳越調。", "赤霞動金光，日足森海嶠。", "獨散萬古意，閑垂一溪釣。", "猨近天上啼，人移月邊櫂。", "無以墨綬苦，來求丹砂要。", "華髮長折腰，將貽陶公誚。"]'),
('ff0a0705-6342-41a1-880d-13a5e69e8c29','獻從叔當塗宰陽冰','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','金鏡霾六國，亡新亂天經。',288,'全唐诗/poet.tang.8000.json','["金鏡霾六國，亡新亂天經。", "焉知高光起，自有羽翼生。", "蕭曹安𡸣屼，耿賈摧欃槍。", "吾家有季父，傑出聖代英。", "雖無三台位，不借四豪名。", "激昂風雲氣，終協龍虎精。", "弱冠燕趙來，賢彥多逢迎。", "魯連善談笑，季布折公卿。", "遙知禮數絕，常恐不合幷。", "惕想結宵夢，素心久已冥。", "顧慙青雲器，謬奉玉樽傾。", "山陽五百年，綠竹忽再榮。", "高歌振林木，大笑喧雷霆。", "落筆灑篆文，崩雲使人驚。", "吐辭又炳煥，五色羅華星。", "秀句滿江國，高才掞天庭。", "宰邑艱難時，浮雲空古城。", "居人若薙草，掃地無纖莖。", "惠澤及飛走，農夫盡歸耕。", "廣漢水萬里，長流玉琴聲。", "雅頌播吳越，還如泰階平。", "小子別金陵，來時白下亭。", "羣鳳憐客鳥，差池相哀鳴。", "各拔五色毛，意重泰山輕。"]'),
('56db3199-dc52-430b-974d-3a2b0bdbb8c6','書懷贈南陵常贊府','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u58ee\u5fd7\u672a\u916c", "\u6000\u624d\u4e0d\u9047", "\u6124\u61d1"]','歲星入漢年，方朔見明主。',252,'全唐诗/poet.tang.8000.json','["歲星入漢年，方朔見明主。", "調笑當時人，中天謝雲雨。", "一去麒麟閣，遂將朝市乖。", "故交不過門，秋草日上階。", "當時何特達，獨與我心諧。", "置酒凌歊臺，歡娛未曾歇。", "歌動白紵山，舞迴天門月。", "問我心中事，爲君前致辭。", "君看我才能，何似魯仲尼。", "大聖猶不遇，小儒安足悲。", "雲南五月中，頻喪渡瀘師。", "毒草殺漢馬，張兵奪雲旗。", "至今西二河，流血擁僵屍。", "將無七擒略，魯女惜園葵。", "咸陽天下樞，累歲人不足。", "雖有數斗玉，不如一盤粟。", "賴得契宰衡，持釣慰風俗。", "自顧無所用，辭家方來歸。", "霜驚壯士髮，淚滿逐臣衣。", "以此不安席，蹉跎身世違。", "終當滅衛謗，不受魯人譏。"]'),
('d1737db3-ddf4-4eae-9c91-c16c9a03e41e','贈汪倫','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u4e8c\u5e74\u7ea7\u4e0a\u518c", "\u53cb\u60c5", "\u9001\u522b", "\u79bb\u522b", "\u6c34"]','李白乘舟將欲行，忽聞岸上踏歌聲。',32,'全唐诗/poet.tang.8000.json','["李白乘舟將欲行，忽聞岸上踏歌聲。", "桃花潭水深千尺，不及汪倫送我情。"]'),
('064fe17e-fe88-4e01-a859-84adca604ebc','安陸白兆山桃花嵒寄劉侍御綰','李白','唐','唐诗','tang','','[]','雲臥三十年，好閑復愛仙。',132,'全唐诗/poet.tang.8000.json','["雲臥三十年，好閑復愛仙。", "蓬壺雖冥絕，鸞鶴心悠然。", "歸來桃花嵒，得憩雲窗眠。", "對嶺人共語，飲潭猨相連。", "時昇翠微上，邈若羅浮巔。", "兩岑抱東壑，一嶂橫西天。", "樹雜日易隱，崖傾月難圓。", "芳草換野色，飛蘿搖春煙。", "入遠構石室，選幽開上田。", "獨此林下意，杳無區中緣。", "永辭霜臺客，千載方來旋。"]'),
('419d1ec1-102a-4928-8fb9-2be4dc160d0c','淮南臥病書懷寄蜀中趙徵君蕤','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u62b1\u8d1f", "\u58ee\u5fd7\u672a\u916c"]','吳會一浮雲，飄如遠行客。',132,'全唐诗/poet.tang.8000.json','["吳會一浮雲，飄如遠行客。", "功業莫從就，歲光屢奔迫。", "良圖俄棄損，衰疾乃綿劇。", "古琴藏虛匣，長劒挂空壁。", "楚冠懷鍾儀，越吟比莊舃。", "國門遙天外，鄉路遠山隔。", "朝憶相如臺，夜夢子雲宅。", "旅情初結緝，秋氣方寂歷。", "風入松下清，露出草間白。", "故人不可見，幽夢誰與適。", "寄書西飛鴻，贈爾慰離析。"]'),
('ff5cf55e-bce2-4e08-b9a0-77987bedc39a','寄弄月溪吳山人','李白','唐','唐诗','tang','','[]','嘗聞龐德公，家住洞湖水。',72,'全唐诗/poet.tang.8000.json','["嘗聞龐德公，家住洞湖水。", "終身棲鹿門，不入襄陽市。", "夫君弄明月，滅景清淮裏。", "高蹤邈難追，可與古人比。", "清揚杳莫覩，白雲空望美。", "待我辭人間，攜手訪松子。"]'),
('bfc85b07-5bc5-42cb-8544-0e76f6a15680','秋山寄衛尉張卿及王徵君','李白','唐','唐诗','tang','','[]','何以折相贈，白花青桂枝。',48,'全唐诗/poet.tang.8000.json','["何以折相贈，白花青桂枝。", "月華若夜雪，見此令人思。", "雖然剡溪興，不異山陰時。", "明發懷二子，空吟招隱詩。"]'),
('eb48e420-6508-44b6-9861-ec7ae959b266','望終南山寄紫閣隱者','李白','唐','唐诗','tang','','["\u7ec8\u5357\u5c71", "\u5411\u5f80", "\u751f\u6d3b", "\u5199\u666f", "\u6292\u60c5", "\u9690\u5c45"]','出門見南山，引領意無限。',60,'全唐诗/poet.tang.8000.json','["出門見南山，引領意無限。", "秀色難爲名，蒼翠日在眼。", "有時白雲起，天際自舒卷。", "心中與之然，託興每不淺。", "何當造幽人，滅跡棲絕巘。"]'),
('c01d1d5f-d7ed-4eef-85a2-f22229f01293','夕霽杜陵登樓寄韋繇','李白','唐','唐诗','tang','','[]','浮陽滅霽景，萬物生秋容。',96,'全唐诗/poet.tang.8000.json','["浮陽滅霽景，萬物生秋容。", "登樓送遠目，伏檻觀羣峰。", "原野曠超緬，關河紛雜重。", "清暉映竹日，翠色明雲松。", "蹈海寄遐想，還山迷舊蹤。", "徒然迫晚暮，未果諧心胷。", "結桂空佇立，折麻恨莫從。", "思君達永夜，長樂聞疎鐘。"]'),
('4925add5-c83c-4dce-b56c-5b7f47f25539','秋夜宿龍門香山寺奉寄王方城十七丈奉國瑩上人從弟幼成令問','李白','唐','唐诗','tang','','[]','朝發汝海東，暮棲龍門中。',108,'全唐诗/poet.tang.8000.json','["朝發汝海東，暮棲龍門中。", "水寒夕波急，木落秋山空。", "望極九霄迥，賞幽萬壑通。", "目皓沙上月，心清松下風。", "玉斗橫網戶，銀河耿花宮。", "興在趣方逸，歡餘情未終。", "鳳駕憶王子，虎溪懷遠公。", "桂枝坐蕭瑟，棣華不復同。", "流恨寄伊水，盈盈焉可窮。"]'),
('a25fa0eb-d488-4fae-b528-820545fbb06a','春日獨坐寄鄭明府','李白','唐','唐诗','tang','','[]','燕麥青青遊子悲，河堤弱柳鬱金枝。',64,'全唐诗/poet.tang.8000.json','["燕麥青青遊子悲，河堤弱柳鬱金枝。", "長條一拂春風去，盡日飄揚無定時。", "我在河南別離久，那堪坐此對窻牖。", "情人道來竟不來，何人共醉新豐酒。"]'),
('298dce1e-06ee-40c7-8ba4-8880c4936ad8','寄淮南友人','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba"]','紅顏悲舊國，青歲歇芳洲。',48,'全唐诗/poet.tang.8000.json','["紅顏悲舊國，青歲歇芳洲。", "不待金門詔，空持寶劒遊。", "海雲迷驛道，江月隱鄉樓。", "復作淮南客，因逢桂樹留。"]'),
('ceaabade-da26-45b9-adb0-9b5193b2c187','沙丘城下寄杜甫','李白','唐','唐诗','tang','','["\u6000\u5ff5", "\u53cb\u60c5", "\u53e4\u4f53"]','我來竟何事，高臥沙丘城。',48,'全唐诗/poet.tang.8000.json','["我來竟何事，高臥沙丘城。", "城邊有古樹，日夕連秋聲。", "魯酒不可醉，齊歌空復情。", "思君若汶水，浩蕩寄南征。"]'),
('18447fa7-c2b3-4d8a-9327-d146752305f3','聞丹丘子於城北營石門幽居中有高鳳遺跡僕離羣遠懷亦有棲遁之志因敘舊以寄之','李白','唐','唐诗','tang','','[]','春華滄江月，秋色碧海雲。',264,'全唐诗/poet.tang.8000.json','["春華滄江月，秋色碧海雲。", "離居盈寒暑，對此長思君。", "思君楚水南，望君淮山北。", "夢魂雖飛來，會面不可得。", "疇昔在嵩陽，同衾臥羲皇。", "綠蘿笑簪紱，丹壑賤巖廊。", "晚途各分析，乘興任所適。", "僕在雁門關，君爲峨眉客。", "心懸萬里外，影滯兩鄉隔。", "長劒復歸來，相逢洛陽陌。", "陌上何喧喧，都令心意煩。", "迷津覺路失，託勢隨風飜。", "以茲謝朝列，長嘯歸故園。", "故園恣閑逸，求古散縹帙。", "久欲入名山，婚娶殊未畢。", "人生信多故，世事豈惟一。", "念此憂如焚，悵然若有失。", "聞君臥石門，宿昔契彌敦。", "方從桂樹隱，不羨桃花源。", "高風起遐曠，幽人跡復存。", "松風清瑤瑟，溪月湛芳樽。", "安居偶佳賞，丹心期此論。"]'),
('5223cc8b-73be-4823-95f5-77e7ab0a2e48','淮陰書懷寄王宗成','李白','唐','唐诗','tang','','[]','沙墩至梁苑，二十五長亭。',144,'全唐诗/poet.tang.8000.json','["沙墩至梁苑，二十五長亭。", "大舶夾雙艣，中流鵝鸛鳴。", "雲天掃空碧，川嶽涵餘清。", "飛鳧從西來，適與佳興幷。", "眷言王喬舃，婉孌故人情。", "復此親懿會，而增交道榮。", "沿洄且不定，飄忽悵徂征。", "暝投淮陰宿，欣得漂母迎。", "斗酒烹黃雞，一餐感素誠。", "予爲楚壯士，不是魯諸生。", "有德必報之，千金恥爲輕。", "緬書羇孤意，遠寄櫂歌聲。"]'),
('143d4c2b-89ef-4b8a-b6bd-462e0ee80571','聞王昌齡左遷龍標遙有此寄','李白','唐','唐诗','tang','','["\u5199\u666f", "\u601d\u4e61", "\u53cb\u60c5", "\u4e03\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u521d\u4e2d\u53e4\u8bd7"]','楊花落盡子規啼，聞道龍標過五溪。',32,'全唐诗/poet.tang.8000.json','["楊花落盡子規啼，聞道龍標過五溪。", "我寄愁心與明月，隨風直到夜郎西。"]'),
('cf5c6aa6-64e8-4d4d-b2d3-24904860d660','寄王屋山人孟大融','李白','唐','唐诗','tang','','["\u53cb\u60c5"]','我昔東海上，勞山餐紫霞。',76,'全唐诗/poet.tang.8000.json','["我昔東海上，勞山餐紫霞。", "親見安期公，食棗大如瓜。", "中年謁漢主，不愜還歸家。", "朱顏謝春輝，白髮見生涯。", "所期就金液，飛步登雲車。", "願隨夫子天壇上，閑與仙人掃落花。"]'),
('fd2d4808-fd20-4f70-816d-1fcde61bf1b5','憶舊遊寄譙郡元參軍','李白','唐','唐诗','tang','','["\u53cb\u60c5", "\u6000\u5ff5"]','憶昔洛陽董糟丘，爲余天津橋南造酒樓。',398,'全唐诗/poet.tang.8000.json','["憶昔洛陽董糟丘，爲余天津橋南造酒樓。", "黃金白璧買歌笑，一醉累月輕王侯。", "海內賢豪青雲客，就中與君心莫逆。", "迥山轉海不作難，傾情倒意無所惜。", "我向淮南攀桂枝，君留洛北愁夢思。", "不忍別，還相隨，相隨迢迢訪仙城。", "三十六曲水迴縈，一溪初入千花明。", "萬壑度盡松風聲，銀鞍金絡倒平地，漢東太守來相迎。", "紫陽之真人，邀我吹玉笙。", "餐霞樓上動仙樂，嘈然宛似鸞鳳鳴。", "袖長管催欲輕舉，漢中太守醉起舞。", "手持錦袍覆我身，我醉橫眠枕其股。", "當筵意氣凌九霄，星離雨散不終朝，分飛楚關山水遙。", "余既還山尋故巢，君亦歸家渡渭橋。", "君家嚴君勇貔虎，作尹幷州遏戎虜。", "五月相呼度太行，摧輪不道羊腸苦。", "行來北涼歲月深，感君貴義輕黃金。", "瓊杯綺食青玉案，使我醉飽無歸心。", "時時出向城西曲，晉祠流水如碧玉。", "浮舟弄水簫鼓鳴，微波龍鱗莎草綠。", "興來攜妓恣經過，其若楊花似雪何。", "紅粧欲醉宜斜日，百尺清潭寫翠娥。", "翠娥嬋娟初月輝，美人更唱舞羅衣。", "清風吹歌人空去，歌曲自繞行雲飛。"]'),
('2a0533d8-6508-48ab-9cfa-384bd1308de1','月夜江行寄崔員外宗之','李白','唐','唐诗','tang','','[]','飄飄江風起，蕭颯海樹秋。',96,'全唐诗/poet.tang.8000.json','["飄飄江風起，蕭颯海樹秋。", "登艫美清夜，挂席移輕舟。", "月隨碧山轉，水合青天流。", "杳如星河上，但覺雲林幽。", "歸路方浩浩，徂川去悠悠。", "徒悲蕙草歇，復聽菱歌愁。", "岸曲迷後浦，沙明瞰前洲。", "懷君不可見，望遠增離憂。"]'),
('fde2b52d-15c3-4d98-98bf-7e4af7853ede','宿白鷺洲寄楊江寧','李白','唐','唐诗','tang','','[]','朝別朱雀門，暮棲白鷺洲。',72,'全唐诗/poet.tang.8000.json','["朝別朱雀門，暮棲白鷺洲。", "波光搖海月，星影入城樓。", "望美金陵宰，如思瓊樹憂。", "徒令魂入夢，飜覺夜成秋。", "綠水解人意，爲余西北流。", "因聲玉琴裏，蕩漾寄君愁。"]'),
('991e28f2-1ddb-4e26-9733-2bba76386fdd','新林浦阻風寄友人','李白','唐','唐诗','tang','','[]','潮水定可信，天風難與期。',108,'全唐诗/poet.tang.8000.json','["潮水定可信，天風難與期。", "清晨西北轉，薄暮東南吹。", "以此難挂席，佳期益相思。", "海月破圓影，菰蔣生綠池。", "昨日北湖梅，開花已滿枝。", "今朝東門柳，夾道垂青絲。", "歲物忽如此，我來定幾時。", "紛紛江上雪，草草客中悲。", "明發新林浦，空吟謝朓詩。"]'),
('d7850fc8-4941-4c5e-b282-2853bbe3e70d','寄韋南陵冰余江上乘興訪之遇尋顏尚書笑有此贈','李白','唐','唐诗','tang','','[]','南船正東風，北船來自緩。',132,'全唐诗/poet.tang.8000.json','["南船正東風，北船來自緩。", "江上相逢借問君，語笑未了風吹斷。", "聞君攜伎訪情人，應爲尚書不顧身。", "堂上三千珠履客，甕中百斛金陵春。", "恨我阻此樂，淹留楚江濱。", "月色醉遠客，山花開欲然。", "春風狂殺人，一日劇三年。", "乘興嫌太遲，焚却子猷船。", "夢見五柳枝，已堪挂馬鞭。", "何日到彭澤，長歌陶令前。"]'),
('5cf2626d-5277-4bc9-afb5-6d0d2562cdad','題情深樹寄象公','李白','唐','唐诗','tang','','[]','腸斷枝上猨，淚添山下樽。',24,'全唐诗/poet.tang.8000.json','["腸斷枝上猨，淚添山下樽。", "白雲見我去，亦爲我飛翻。"]'),
('370f0a3c-5b12-4cc8-a40e-697fb9c5590e','北山獨酌寄韋六','李白','唐','唐诗','tang','','[]','巢父將許由，未聞買山隱。',120,'全唐诗/poet.tang.8000.json','["巢父將許由，未聞買山隱。", "道存跡自高，何憚去人近。", "紛吾下茲嶺，地閑喧亦泯。", "門橫羣岫開，水鑿衆泉引。", "屏高而在雲，竇深莫能準。", "川光晝昏凝，林氣夕淒緊。", "於焉摘朱果，兼得養玄牝。", "坐月觀寶書，拂霜弄瑤軫。", "傾壺事幽酌，顧影還獨盡。", "念君風塵游，傲爾令自哂。"]'),
('0a33174f-965c-4636-8f9b-8fb94b858c0f','寄當塗趙少府炎','李白','唐','唐诗','tang','','[]','晚登高樓望，木落雙江清。',48,'全唐诗/poet.tang.8000.json','["晚登高樓望，木落雙江清。", "寒山饒積翠，秀色連州城。", "目送楚雲盡，心悲胡雁聲。", "相思不可見，迴首故人情。"]'),
('3638c98b-8b8e-4847-a0b9-9c54e2ce6e5e','寄東魯二稚子','李白','唐','唐诗','tang','','[]','吳地桑葉綠，吳蠶已三眠。',156,'全唐诗/poet.tang.8000.json','["吳地桑葉綠，吳蠶已三眠。", "我家寄東魯，誰種龜陰田。", "春事已不及，江行復茫然。", "南風吹歸心，飛墮酒樓前。", "樓東一株桃，枝葉拂青煙。", "此樹我所種，別來向三年。", "桃今與樓齊，我行尚未旋。", "嬌女字平陽，折花倚桃邊。", "折花不見我，淚下如流泉。", "小兒名伯禽，與姊亦齊肩。", "雙行桃樹下，撫背復誰憐。", "念此失次第，肝腸日憂煎。", "裂素寫遠意，因之汶陽川。"]'),
('08e81f11-6bc9-4416-bf6e-55d770d4fb92','獨酌清溪江石上寄權昭夷','李白','唐','唐诗','tang','','[]','我攜一樽酒，獨上江祖石。',60,'全唐诗/poet.tang.8000.json','["我攜一樽酒，獨上江祖石。", "自從天地開，更長幾千尺。", "舉杯向天笑，天迴日西照。", "永願坐此石，長垂嚴陵釣。", "寄謝山中人，可與爾同調。"]'),
('cbabd3ac-79d7-4c55-a602-0ef317bea2f9','禪房懷友人岑倫','李白','唐','唐诗','tang','','[]','嬋娟羅浮月，搖豔桂水雲。',192,'全唐诗/poet.tang.8000.json','["嬋娟羅浮月，搖豔桂水雲。", "美人竟獨往，而我安得羣。", "一朝語笑隔，萬里懽情分。", "沈吟綵霞沒，夢寐羣芳歇。", "歸鴻渡三湘，遊子在百粵。", "邊塵染衣劒，白日彫華髮。", "春風變楚關，秋聲落吳山。", "草木結悲緒，風沙淒苦顏。", "朅來已永久，頹思如循環。", "飄飄限江裔，想像空留滯。", "離憂每醉心，別淚徒盈袂。", "坐愁青天末，出望黃雲蔽。", "目極何悠悠，梅花南嶺頭。", "空長滅征鳥，水闊無還舟。", "寶劒終難託，金囊非易求。", "歸來儻有問，桂樹山之幽。"]'),
('4e491c2f-c3c8-487f-8e76-63bd0a811b30','廬山謠寄盧侍御虛舟','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5e90\u5c71", "\u9ec4\u9e64\u697c", "\u5199\u666f", "\u5f52\u9690", "\u4e03\u8a00\u53e4\u8bd7"]','我本楚狂人，鳳歌笑孔丘。',220,'全唐诗/poet.tang.8000.json','["我本楚狂人，鳳歌笑孔丘。", "手持綠玉杖，朝別黃鶴樓。", "五嶽尋仙不辭遠，一生好入名山遊。", "廬山秀出南斗傍，屏風九疊雲錦張，影落明湖青黛光。", "金闕前開二峰長，銀河倒挂三石梁。", "香爐瀑布遙相望，迴厓沓嶂凌蒼蒼。", "翠影紅霞映朝日，鳥飛不到吳天長。", "登高壯觀天地間，大江茫茫去不還。", "黃雲萬里動風色，白波九道流雪山。", "好爲廬山謠，興因廬山發。", "閑窺石鏡清我心，謝公行處蒼苔沒。", "早服還丹無世情，琴心三疊道初成。", "遙見仙人綵雲裏，手把芙蓉朝玉京。", "先期汗漫九垓上，願接盧敖遊太清。"]'),
('b191e602-b7d6-4eae-b9b4-600affd2a481','下尋陽城汎彭蠡寄黃判官','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u8d5e\u7f8e"]','浪動灌嬰井，尋陽江上風。',72,'全唐诗/poet.tang.8000.json','["浪動灌嬰井，尋陽江上風。", "開帆入天鏡，直向彭湖東。", "落景轉疎雨，晴雲散遠空。", "名山發佳興，清賞亦何窮。", "石鏡挂遙月，香爐滅彩虹。", "相思俱對此，舉目與君同。"]'),
('90cb58db-fcab-454d-b5fe-178e6d5b4ff6','書情寄從弟邠州長史昭','李白','唐','唐诗','tang','','[]','自笑客行久，我行定幾時。',96,'全唐诗/poet.tang.8000.json','["自笑客行久，我行定幾時。", "綠楊已可折，攀取最長枝。", "翩翩弄春色，延佇寄相思。", "誰言貴此物，意願重瓊蕤。", "昨夢見惠連，朝吟謝公詩。", "東風引碧草，不覺生華池。", "臨翫忽云夕，杜鵑夜鳴悲。", "懷君芳歲歇，庭樹落紅滋。"]'),
('64b4d54f-cfac-4f5c-bdfa-60063975a47f','寄王漢陽','李白','唐','唐诗','tang','','[]','南湖秋月白，王宰夜相邀。',48,'全唐诗/poet.tang.8000.json','["南湖秋月白，王宰夜相邀。", "錦帳郎官醉，羅衣舞女嬌。", "笛聲喧沔鄂，歌曲上雲霄。", "別後空愁我，相思一水遙。"]'),
('9b3e2250-6bfc-4ade-b89c-f3df7c622586','春日歸山寄孟浩然','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u6625\u5929", "\u5199\u666f", "\u8d5e\u7f8e"]','朱紱遺塵境，青山謁梵筵。',96,'全唐诗/poet.tang.8000.json','["朱紱遺塵境，青山謁梵筵。", "金繩開覺路，寶筏度迷川。", "嶺樹攢飛栱，嵒花覆谷泉。", "墖形標海月，樓勢出江煙。", "香氣三天下，鐘聲萬壑連。", "荷秋珠已滿，松密蓋初圓。", "鳥聚疑聞法，龍參若護禪。", "媿非流水韻，叨入伯牙弦。"]'),
('7269d2d6-e426-4083-8869-2a12dedf9f95','流夜郎永華寺寄尋陽羣官','李白','唐','唐诗','tang','','[]','朝別凌煙樓，賢豪滿行舟。',60,'全唐诗/poet.tang.8000.json','["朝別凌煙樓，賢豪滿行舟。", "暝投永華寺，賓散予獨醉。", "願結九江流，添成萬行淚。", "寫意寄廬嶽，何當來此地。", "天命有所懸，安得苦愁思。"]'),
('3e3ca5d2-67e8-4fc9-9294-350c16699678','流夜郎至西塞驛寄裴隱','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u81ea\u7136", "\u5199\u666f"]','揚帆借天風，水驛苦不緩。',96,'全唐诗/poet.tang.8000.json','["揚帆借天風，水驛苦不緩。", "平明及西塞，已先投沙伴。", "迴巒引羣峰，橫蹙楚山斷。", "砯衝萬壑會，震沓百川滿。", "龍怪潛溟波，俟時救炎旱。", "我行望雷雨，安得霑枯散。", "鳥去天路長，人愁春光短。", "空將澤畔吟，寄爾江南管。"]'),
('bf60c55c-69c4-45e8-a07c-a13a39619aa3','自漢陽病酒歸寄王明府','李白','唐','唐诗','tang','','["\u559c\u60a6", "\u6292\u60c5"]','去歲左遷夜郎道，琉璃硯水長枯槁。',92,'全唐诗/poet.tang.8000.json','["去歲左遷夜郎道，琉璃硯水長枯槁。", "今年敕放巫山陽，蛟龍筆翰生輝光。", "聖主還聽子虛賦，相如却與論文章。", "願掃鸚鵡洲，與君醉百場。", "嘯起白雲飛七澤，歌吟淥水動三湘。", "莫惜連船沽美酒，千金一擲買春芳。"]'),
('be77ebcd-07a2-48f3-8ac9-8290a154dbe6','望漢陽柳色寄王宰','李白','唐','唐诗','tang','','[]','漢陽江上柳，望客引東枝。',48,'全唐诗/poet.tang.8000.json','["漢陽江上柳，望客引東枝。", "樹樹花如雪，紛紛亂若絲。", "春風傳我意，草木別前知。", "寄謝弦歌宰，西來定未遲。"]'),
('f7a8ab10-7d41-4091-9f86-0e4b3bde6196','江夏寄漢陽輔錄事','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','誰道此水廣，狹如一匹練。',120,'全唐诗/poet.tang.8000.json','["誰道此水廣，狹如一匹練。", "江夏黃鶴樓，青山漢陽縣。", "大語猶可聞，故人難可見。", "君草陳琳檄，我書魯連箭。", "報國有壯心，龍顏不迴眷。", "西飛精衛鳥，東海何由填。", "鼓角徒悲鳴，樓船習征戰。", "抽劒步霜月，夜行空庭徧。", "長呼結浮雲，埋沒顧榮扇。", "他日觀軍容，投壺接高宴。"]'),
('423c1905-c138-41b5-8eb8-33a6a41171f3','早春寄王漢陽','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6625\u5929"]','聞道春還未相識，走傍寒梅訪消息。',64,'全唐诗/poet.tang.8000.json','["聞道春還未相識，走傍寒梅訪消息。", "昨夜東風入武陽，陌頭楊柳黃金色。", "碧水浩浩雲茫茫，美人不來空斷腸。", "預拂青山一片石，與君連日醉壺觴。"]'),
('5c88243f-1960-4e49-895d-0e2398b973e6','江上寄巴東故人','李白','唐','唐诗','tang','','[]','漢水波浪遠，巫山雲雨飛。',48,'全唐诗/poet.tang.8000.json','["漢水波浪遠，巫山雲雨飛。", "東風吹客夢，西落此中時。", "覺後思白帝，佳人與我違。", "瞿塘饒賈客，音信莫令稀。"]'),
('3496ba9e-7d59-4027-b052-887c6f54825f','江上寄元六林宗','李白','唐','唐诗','tang','','["\u4eba\u751f", "\u6292\u6000", "\u5199\u666f", "\u79cb\u5929", "\u6000\u624d\u4e0d\u9047"]','霜落江始寒，楓葉綠未脫。',120,'全唐诗/poet.tang.8000.json','["霜落江始寒，楓葉綠未脫。", "客行悲清秋，永路苦不達。", "滄波眇川汜，白日隱天末。", "停櫂依林巒，驚猿相呌聒。", "夜分河漢轉，起視溟漲闊。", "涼風何蕭蕭，流水鳴活活。", "浦沙淨如洗，海月明可掇。", "蘭交空懷思，瓊樹詎解渴。", "勗哉滄洲心，歲晚庶不奪。", "幽賞頗自得，興遠與誰豁。"]'),
('ff73ae4f-014f-4779-9c70-abf1a7614dd8','寄從弟宣州長史昭','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','爾佐宣州郡，守官清且閑。',48,'全唐诗/poet.tang.8000.json','["爾佐宣州郡，守官清且閑。", "常誇雲月好，邀我敬亭山。", "五落洞庭葉，三江遊未還。", "相思不可見，歎息損朱顏。"]'),
('c172189d-9be5-467f-a258-3e15ca56c884','涇溪東亭寄鄭少府諤','李白','唐','唐诗','tang','','[]','我遊東亭不見君，沙上行將白鷺羣。',64,'全唐诗/poet.tang.8000.json','["我遊東亭不見君，沙上行將白鷺羣。", "白鷺行時散飛去，又如雪點青山雲。", "欲往涇溪不辭遠，龍門蹙波虎眼轉。", "杜鵑花開春已闌，歸向陵陽釣魚晚。"]'),
('30994057-c0f7-4839-aff6-4d912a65e415','宣州九日聞崔四侍御與宇文太守遊敬亭余時登響山不同此賞醉後寄崔侍御二首 一','李白','唐','唐诗','tang','','["\u53cb\u60c5", "\u91cd\u9633\u8282", "\u611f\u53f9"]','九日茱萸熟，插鬢傷早白。',156,'全唐诗/poet.tang.8000.json','["九日茱萸熟，插鬢傷早白。", "登高望山海，滿目悲古昔。", "遠訪投沙人，因爲逃名客。", "故交竟誰在，獨有崔亭伯。", "重陽不相知，載酒任所適。", "手持一枝菊，調笑二千石。", "日暮岸幘歸，傳呼隘阡陌。", "彤襜雙白鹿，賓從何輝赫。", "夫子在其間，遂成雲霄隔。", "良辰與美景，兩地方虛擲。", "晚從南峰歸，蘿月下水壁。", "却登郡樓望，松色寒轉碧。", "咫尺不可親，棄我如遺舃。"]'),
('d086ca66-0649-4b3b-9349-c5ce12825d78','宣州九日聞崔四侍御與宇文太守遊敬亭余時登響山不同此賞醉後寄崔侍御二首 二','李白','唐','唐诗','tang','','[]','九卿天上落，五馬道傍來。',72,'全唐诗/poet.tang.8000.json','["九卿天上落，五馬道傍來。", "列戟朱門曉，褰幃碧嶂開。", "登高望遠海，召客得英才。", "紫綬懽情洽，黃花逸興催。", "山從圖上見，溪即鏡中迴。", "遙羨重陽作，應過戲馬臺。"]'),
('aa6cab85-4f83-4345-af8a-7ffeb0447ae9','寄崔侍御','李白','唐','唐诗','tang','','["\u4eba\u751f", "\u53cb\u60c5", "\u76f8\u601d"]','宛溪霜夜聽猿愁，去國長爲不繫舟。',64,'全唐诗/poet.tang.8000.json','["宛溪霜夜聽猿愁，去國長爲不繫舟。", "獨憐一雁飛南海，却羨雙溪解北流。", "高人屢解陳蕃榻，過客難登謝朓樓。", "此處別離同落葉，朝朝分散敬亭秋。"]'),
('107b5580-f95e-4803-865c-5b6c6e25c90a','涇溪南藍山下有落星潭可以卜築余泊舟石上寄何判官昌浩','李白','唐','唐诗','tang','','["\u5199\u5c71", "\u53cb\u4eba", "\u529d\u8beb", "\u63cf\u5199\u5c71", "\u9690\u5c45"]','藍岑竦天壁，突兀如鯨額。',72,'全唐诗/poet.tang.8000.json','["藍岑竦天壁，突兀如鯨額。", "奔蹙橫澄潭，勢吞落星石。", "沙帶秋月明，水搖寒山碧。", "佳鏡宜緩櫂，清輝能留客。", "恨君阻歡遊，使我自驚惕。", "所期俱卜築，結茅鍊金液。"]'),
('7c270f72-0b5b-47b2-a940-9084b117c9c1','早過漆林渡寄萬巨','李白','唐','唐诗','tang','','[]','西經大藍山，南來漆林渡。',96,'全唐诗/poet.tang.8000.json','["西經大藍山，南來漆林渡。", "水色倒空青，林煙橫積素。", "漏流昔吞翕，沓浪競奔注。", "潭落天上星，龍開水中霧。", "嶢巖注公柵，突兀陳焦墓。", "嶺峭紛上干，川明屢迴顧。", "因思萬夫子，解渴同瓊樹。", "何日覩清光，相歡詠佳句。"]'),
('005b52e9-ee73-494b-b318-734b7278bd8a','遊敬亭寄崔侍御','李白','唐','唐诗','tang','','[]','我家敬亭下，輙繼謝公作。',120,'全唐诗/poet.tang.8000.json','["我家敬亭下，輙繼謝公作。", "相去數百年，風期宛如昨。", "登高素秋月，下望青山郭。", "俯視鴛鴦羣，飲啄自鳴躍。", "夫子雖蹭蹬，瑤臺雪中鶴。", "獨立窺浮雲，其心在寥廓。", "時來顧我笑，一飯葵與藿。", "世路如秋風，相逢盡蕭索。", "腰間玉具劒，意許無遺諾。", "壯士不可輕，相期在雲閣。"]'),
('d7ee6c92-bb81-420a-bd3a-d9b9392ee2d5','三山望金陵寄殷淑','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u591c\u665a"]','三山懷謝朓，水澹望長安。',48,'全唐诗/poet.tang.8000.json','["三山懷謝朓，水澹望長安。", "蕪沒河陽縣，秋江正北看。", "盧龍霜氣冷，鳷鵲月光寒。", "耿耿憶瓊樹，天涯寄一懽。"]'),
('330102f7-2088-43aa-b5b3-573c1e00688d','自金陵泝流過白璧山翫月達天門寄句容王主簿','李白','唐','唐诗','tang','','["\u5929\u95e8\u5c71", "\u6292\u60c5", "\u5199\u666f", "\u53cb\u4eba"]','滄江泝流歸，白璧見秋月。',84,'全唐诗/poet.tang.8000.json','["滄江泝流歸，白璧見秋月。", "秋月照白璧，皓如山陰雪。", "幽人停宵征，賈客忘早發。", "進帆天門山，迴首牛渚沒。", "川長信風來，日出宿霧歇。", "故人在咫尺，新賞成胡越。", "寄君青蘭花，惠好庶不絕。"]'),
('49929f71-f38b-4979-bf87-51b84379a94d','寄上吳王三首 一','李白','唐','唐诗','tang','','[]','淮王愛八公，攜手綠雲中。',48,'全唐诗/poet.tang.8000.json','["淮王愛八公，攜手綠雲中。", "小子忝枝葉，亦攀丹桂叢。", "謬以詞賦重，而將枚馬同。", "何日背淮水，東之觀土風。"]'),
('0f4418dd-2978-46b9-ba18-13e7b821d066','寄上吳王三首 二','李白','唐','唐诗','tang','','[]','坐嘯廬江靜，閑聞進玉觴。',24,'全唐诗/poet.tang.8000.json','["坐嘯廬江靜，閑聞進玉觴。", "去時無一物，東壁挂胡牀。"]'),
('b9967d42-821c-4429-8d49-36b98557e70b','寄上吳王三首 三','李白','唐','唐诗','tang','','[]','英明廬江守，聲譽廣平籍。',48,'全唐诗/poet.tang.8000.json','["英明廬江守，聲譽廣平籍。", "灑掃黃金臺，招邀青雲客。", "客曾與天通，出入清禁中。", "襄王憐宋玉，願入蘭臺宮。"]'),
('14e574e8-1a27-4f34-8158-66a8548ddc00','秋日魯郡堯祠亭上宴別杜補闕范侍御','李白','唐','唐诗','tang','','["\u8c6a\u653e", "\u6292\u60c5", "\u9001\u522b", "\u53cb\u4eba", "\u79cb\u5929"]','我覺秋興逸，誰云秋興悲。',84,'全唐诗/poet.tang.8000.json','["我覺秋興逸，誰云秋興悲。", "山將落日去，水與晴空宜。", "魯酒白玉壺，送行駐金羈。", "歇鞍憩古木，解帶挂橫枝。", "歌鼓川上亭，曲度神飆吹。", "雲歸碧海夕，鴈沒青天時。", "相失各萬里，茫然空爾思。"]');
